(12, '\r\n<button class=\"Btn\">\r\n   <svg class=\"svgIcon\" viewBox=\"0 0 384 512\" height=\"1em\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M169.4 470.6c12.5 12.5 32.8 12.5 45.3 0l160-160c12.5-12.5 12.5-32.8 0-45.3s-32.8-12.5-45.3 0L224 370.8 224 64c0-17.7-14.3-32-32-32s-32 14.3-32 32l0 306.7L54.6 265.4c-12.5-12.5-32.8-12.5-45.3 0s-12.5 32.8 0 45.3l160 160z\"></path></svg>\r\n   <span class=\"icon2\"></span>\r\n   <span class=\"tooltip\">Download</span>\r\n</button>', '.Btn {\n  width: 50px;\n  height: 50px;\n  border: none;\n  border-radius: 50%;\n  background-color: rgb(27, 27, 27);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  position: relative;\n  transition-duration: .3s;\n  box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.11);\n}\n\n.svgIcon {\n  fill: rgb(214, 178, 255);\n}\n\n.icon2 {\n  width: 18px;\n  height: 5px;\n  border-bottom: 2px solid rgb(182, 143, 255);\n  border-left: 2px solid rgb(182, 143, 255);\n  border-right: 2px solid rgb(182, 143, 255);\n}\n\n.tooltip {\n  position: absolute;\n  right: -105px;\n  opacity: 0;\n  background-color: rgb(12, 12, 12);\n  color: white;\n  padding: 5px 10px;\n  border-radius: 5px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition-duration: .2s;\n  pointer-events: none;\n  letter-spacing: 0.5px;\n}\n\n.tooltip::before {\n  position: absolute;\n  content: \"\";\n  width: 10px;\n  height: 10px;\n  background-color: rgb(12, 12, 12);\n  background-size: 1000%;\n  background-position: center;\n  transform: rotate(45deg);\n  left: -5%;\n  transition-duration: .3s;\n}\n\n.Btn:hover .tooltip {\n  opacity: 1;\n  transition-duration: .3s;\n}\n\n.Btn:hover {\n  background-color: rgb(150, 94, 255);\n  transition-duration: .3s;\n}\n\n.Btn:hover .icon2 {\n  border-bottom: 2px solid rgb(235, 235, 235);\n  border-left: 2px solid rgb(235, 235, 235);\n  border-right: 2px solid rgb(235, 235, 235);\n}\n\n.Btn:hover .svgIcon {\n  fill: rgb(255, 255, 255);\n  animation: slide-in-top 0.6s cubic-bezier(0.250, 0.460, 0.450, 0.940) both;\n}\n\n@keyframes slide-in-top {\n  0% {\n    transform: translateY(-10px);\n    opacity: 0;\n  }\n\n  100% {\n    transform: translateY(0px);\n    opacity: 1;\n  }\n}\n'),
(13, '\r\n<button class=\"continue-application\">\r\n    <div>\r\n        <div class=\"pencil\"></div>\r\n        <div class=\"folder\">\r\n            <div class=\"top\">\r\n                <svg viewBox=\"0 0 24 27\">\r\n                    <path d=\"M1,0 L23,0 C23.5522847,-1.01453063e-16 24,0.44771525 24,1 L24,8.17157288 C24,8.70200585 23.7892863,9.21071368 23.4142136,9.58578644 L20.5857864,12.4142136 C20.2107137,12.7892863 20,13.2979941 20,13.8284271 L20,26 C20,26.5522847 19.5522847,27 19,27 L1,27 C0.44771525,27 6.76353751e-17,26.5522847 0,26 L0,1 C-6.76353751e-17,0.44771525 0.44771525,1.01453063e-16 1,0 Z\"></path>\r\n                </svg>\r\n            </div>\r\n            <div class=\"paper\"></div>\r\n        </div>\r\n    </div>\r\n    Continue Application\r\n</button>', '\r\n.continue-application {\r\n  --color: #fff;\r\n  --background: #404660;\r\n  --background-hover: #3A4059;\r\n  --background-left: #2B3044;\r\n  --folder: #F3E9CB;\r\n  --folder-inner: #BEB393;\r\n  --paper: #FFFFFF;\r\n  --paper-lines: #BBC1E1;\r\n  --paper-behind: #E1E6F9;\r\n  --pencil-cap: #fff;\r\n  --pencil-top: #275EFE;\r\n  --pencil-middle: #fff;\r\n  --pencil-bottom: #5C86FF;\r\n  --shadow: rgba(13, 15, 25, .2);\r\n  border: none;\r\n  outline: none;\r\n  cursor: pointer;\r\n  position: relative;\r\n  border-radius: 5px;\r\n  font-size: 14px;\r\n  font-weight: 500;\r\n  line-height: 19px;\r\n  -webkit-appearance: none;\r\n  -webkit-tap-highlight-color: transparent;\r\n  padding: 17px 29px 17px 69px;\r\n  transition: background 0.3s;\r\n  color: var(--color);\r\n  background: var(--bg, var(--background));\r\n}\r\n\r\n.continue-application > div {\r\n  top: 0;\r\n  left: 0;\r\n  bottom: 0;\r\n  width: 53px;\r\n  position: absolute;\r\n  overflow: hidden;\r\n  border-radius: 5px 0 0 5px;\r\n  background: var(--background-left);\r\n}\r\n\r\n.continue-application > div .folder {\r\n  width: 23px;\r\n  height: 27px;\r\n  position: absolute;\r\n  left: 15px;\r\n  top: 13px;\r\n}\r\n\r\n.continue-application > div .folder .top {\r\n  left: 0;\r\n  top: 0;\r\n  z-index: 2;\r\n  position: absolute;\r\n  transform: translateX(var(--fx, 0));\r\n  transition: transform 0.4s ease var(--fd, 0.3s);\r\n}\r\n\r\n.continue-application > div .folder .top svg {\r\n  width: 24px;\r\n  height: 27px;\r\n  display: block;\r\n  fill: var(--folder);\r\n  transform-origin: 0 50%;\r\n  transition: transform 0.3s ease var(--fds, 0.45s);\r\n  transform: perspective(120px) rotateY(var(--fr, 0deg));\r\n}\r\n\r\n.continue-application > div .folder:before, .continue-application > div .folder:after,\r\n.continue-application > div .folder .paper {\r\n  content: \"\";\r\n  position: absolute;\r\n  left: var(--l, 0);\r\n  top: var(--t, 0);\r\n  width: var(--w, 100%);\r\n  height: var(--h, 100%);\r\n  border-radius: 1px;\r\n  background: var(--b, var(--folder-inner));\r\n}\r\n\r\n.continue-application > div .folder:before {\r\n  box-shadow: 0 1.5px 3px var(--shadow), 0 2.5px 5px var(--shadow), 0 3.5px 7px var(--shadow);\r\n  transform: translateX(var(--fx, 0));\r\n  transition: transform 0.4s ease var(--fd, 0.3s);\r\n}\r\n\r\n.continue-application > div .folder:after,\r\n.continue-application > div .folder .paper {\r\n  --l: 1px;\r\n  --t: 1px;\r\n  --w: 21px;\r\n  --h: 25px;\r\n  --b: var(--paper-behind);\r\n}\r\n\r\n.continue-application > div .folder:after {\r\n  transform: translate(var(--pbx, 0), var(--pby, 0));\r\n  transition: transform 0.4s ease var(--pbd, 0s);\r\n}\r\n\r\n.continue-application > div .folder .paper {\r\n  z-index: 1;\r\n  --b: var(--paper);\r\n}\r\n\r\n.continue-application > div .folder .paper:before, .continue-application > div .folder .paper:after {\r\n  content: \"\";\r\n  width: var(--wp, 14px);\r\n  height: 2px;\r\n  border-radius: 1px;\r\n  transform: scaleY(0.5);\r\n  left: 3px;\r\n  top: var(--tp, 3px);\r\n  position: absolute;\r\n  background: var(--paper-lines);\r\n  box-shadow: 0 12px 0 0 var(--paper-lines), 0 24px 0 0 var(--paper-lines);\r\n}\r\n\r\n.continue-application > div .folder .paper:after {\r\n  --tp: 6px;\r\n  --wp: 10px;\r\n}\r\n\r\n.continue-application > div .pencil {\r\n  height: 2px;\r\n  width: 3px;\r\n  border-radius: 1px 1px 0 0;\r\n  top: 8px;\r\n  left: 105%;\r\n  position: absolute;\r\n  z-index: 3;\r\n  transform-origin: 50% 19px;\r\n  background: var(--pencil-cap);\r\n  transform: translateX(var(--pex, 0)) rotate(35deg);\r\n  transition: transform 0.4s ease var(--pbd, 0s);\r\n}\r\n\r\n.continue-application > div .pencil:before, .continue-application > div .pencil:after {\r\n  content: \"\";\r\n  position: absolute;\r\n  display: block;\r\n  background: var(--b, linear-gradient(var(--pencil-top) 55%, var(--pencil-middle) 55.1%, var(--pencil-middle) 60%, var(--pencil-bottom) 60.1%));\r\n  width: var(--w, 5px);\r\n  height: var(--h, 20px);\r\n  border-radius: var(--br, 2px 2px 0 0);\r\n  top: var(--t, 2px);\r\n  left: var(--l, -1px);\r\n}\r\n\r\n.continue-application > div .pencil:before {\r\n  -webkit-clip-path: polygon(0 5%, 5px 5%, 5px 17px, 50% 20px, 0 17px);\r\n  clip-path: polygon(0 5%, 5px 5%, 5px 17px, 50% 20px, 0 17px);\r\n}\r\n\r\n.continue-application > div .pencil:after {\r\n  --b: none;\r\n  --w: 3px;\r\n  --h: 6px;\r\n  --br: 0 2px 1px 0;\r\n  --t: 3px;\r\n  --l: 3px;\r\n  border-top: 1px solid var(--pencil-top);\r\n  border-right: 1px solid var(--pencil-top);\r\n}\r\n\r\n.continue-application:before, .continue-application:after {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 10px;\r\n  height: 2px;\r\n  border-radius: 1px;\r\n  background: var(--color);\r\n  transform-origin: 9px 1px;\r\n  transform: translateX(var(--cx, 0)) scale(0.5) rotate(var(--r, -45deg));\r\n  top: 26px;\r\n  right: 16px;\r\n  transition: transform 0.3s;\r\n}\r\n\r\n.continue-application:after {\r\n  --r: 45deg;\r\n}\r\n\r\n.continue-application:hover {\r\n  --cx: 2px;\r\n  --bg: var(--background-hover);\r\n  --fx: -40px;\r\n  --fr: -60deg;\r\n  --fd: .15s;\r\n  --fds: 0s;\r\n  --pbx: 3px;\r\n  --pby: -3px;\r\n  --pbd: .15s;\r\n  --pex: -24px;\r\n}\r\n');
INSERT INTO `buttons` (`ID`, `HTML`, `CSS`) VALUES
(14, '\r\n<button class=\"editBtn\">\r\n  <svg height=\"1em\" viewBox=\"0 0 512 512\">\r\n    <path\r\n      d=\"M410.3 231l11.3-11.3-33.9-33.9-62.1-62.1L291.7 89.8l-11.3 11.3-22.6 22.6L58.6 322.9c-10.4 10.4-18 23.3-22.2 37.4L1 480.7c-2.5 8.4-.2 17.5 6.1 23.7s15.3 8.5 23.7 6.1l120.3-35.4c14.1-4.2 27-11.8 37.4-22.2L387.7 253.7 410.3 231zM160 399.4l-9.1 22.7c-4 3.1-8.5 5.4-13.3 6.9L59.4 452l23-78.1c1.4-4.9 3.8-9.4 6.9-13.3l22.7-9.1v32c0 8.8 7.2 16 16 16h32zM362.7 18.7L348.3 33.2 325.7 55.8 314.3 67.1l33.9 33.9 62.1 62.1 33.9 33.9 11.3-11.3 22.6-22.6 14.5-14.5c25-25 25-65.5 0-90.5L453.3 18.7c-25-25-65.5-25-90.5 0zm-47.4 168l-144 144c-6.2 6.2-16.4 6.2-22.6 0s-6.2-16.4 0-22.6l144-144c6.2-6.2 16.4-6.2 22.6 0s6.2 16.4 0 22.6z\"\r\n    ></path>\r\n  </svg>\r\n</button>\r\n', '.editBtn {\n  width: 55px;\n  height: 55px;\n  border-radius: 20px;\n  border: none;\n  background-color: rgb(93, 93, 116);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  box-shadow: 0px 5px 10px rgba(0, 0, 0, 0.123);\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n  transition: all 0.3s;\n}\n.editBtn::before {\n  content: \"\";\n  width: 200%;\n  height: 200%;\n  background-color: rgb(102, 102, 141);\n  position: absolute;\n  z-index: 1;\n  transform: scale(0);\n  transition: all 0.3s;\n  border-radius: 50%;\n  filter: blur(10px);\n}\n.editBtn:hover::before {\n  transform: scale(1);\n}\n.editBtn:hover {\n  box-shadow: 0px 5px 10px rgba(0, 0, 0, 0.336);\n}\n\n.editBtn svg {\n  height: 17px;\n  fill: white;\n  z-index: 3;\n  transition: all 0.2s;\n  transform-origin: bottom;\n}\n.editBtn:hover svg {\n  transform: rotate(-15deg) translateX(5px);\n}\n.editBtn::after {\n  content: \"\";\n  width: 25px;\n  height: 1.5px;\n  position: absolute;\n  bottom: 19px;\n  left: -5px;\n  background-color: white;\n  border-radius: 2px;\n  z-index: 2;\n  transform: scaleX(0);\n  transform-origin: left;\n  transition: transform 0.5s ease-out;\n}\n.editBtn:hover::after {\n  transform: scaleX(1);\n  left: 0px;\n  transform-origin: right;\n}\n'),
(15, '\r\n<div class=\"del\">\r\n    <div>\r\n      Hover\r\n    </div>     \r\n</div>\r\n		', '.del {\n  position: relative;\n  top: 0;\n  left: 0;\n  width: 160px;\n  height: 50px;\n  margin: 0;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.del div {\n  width: 100%;\n  height: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: none;\n  box-shadow: 4px 4px 6px 0 rgba(255,255,255,.5),\n              -4px -4px 6px 0 rgba(116, 125, 136, .5), \n    inset -4px -4px 6px 0 rgba(255,255,255,.2),\n    inset 4px 4px 6px 0 rgba(0, 0, 0, .4);\n  border-bottom: 1px solid rgba(255, 255, 255, 0.1);\n  border-top: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 10px;\n  letter-spacing: 1px;\n  color: #000;\n  z-index: 1;\n  transition: .6s;\n}\n\n.del:hover div {\n  letter-spacing: 4px;\n  color: #fff;\n}\n\n.del::after,\n.del::before {\n  content: \';\n  position: absolute;\n  bottom: 0;\n  right: 0;\n  z-index: -99999;\n  transition: all .4s;\n}\n\n.del::after {\n  transform: translate(15px, 15px);\n  width: 35px;\n  height: 35px;\n  background: #000;\n  backdrop-filter: blur(5px);\n  border-radius: 10px;\n}\n\n.del:hover::after {\n  border-radius: 10px;\n  transform: translate(0, 0);\n  width: 100%;\n  height: 100%;\n}\n\n\n\n'),
(16, '\r\n<div class=\"playstation-input\">\r\n  <div id=\"cross-input\">\r\n    <div id=\"cross-title\">CROSS</div>\r\n    <button id=\"cross\"><p>x</p></button>\r\n  </div>\r\n  <div id=\"circle-input\">\r\n    <div id=\"circle-title\">CIRCLE</div>\r\n    <button id=\"circle\"><div></div></button>\r\n  </div>\r\n  <div id=\"square-input\">\r\n    <div id=\"square-title\">SQUARE</div>\r\n    <button id=\"square\"><div></div></button>\r\n  </div>\r\n  <div id=\"triangle-input\">\r\n    <div id=\"triangle-title\">TRIANGLE</div>\r\n    <button id=\"triangle\"><p>△</p></button>\r\n  </div>\r\n</div>\r\n', '\r\n.playstation-input {\r\n  width: 10em;\r\n  height: 10em;\r\n  background-color: #212121;\r\n  border-radius: 50%;\r\n  position: relative;\r\n  transition: all 0.2s ease;\r\n  box-shadow: 0px -1px 1px #969696;\r\n}\r\n\r\n#cross p,\r\n#triangle p {\r\n  font-size: 30px;\r\n  font-family: \"Segoe UI\", Tahoma, Verdana, sans-serif;\r\n  font-weight: 325;\r\n  padding-bottom: 5px;\r\n}\r\n\r\n#cross p {\r\n  color: rgb(124, 178, 232);\r\n  transform: scaleX(1.5);\r\n}\r\n\r\n#triangle p {\r\n  color: rgb(64, 226, 160);\r\n}\r\n\r\n#circle div,\r\n#square div {\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(50%, 0%);\r\n  width: 50%;\r\n  height: 50%;\r\n  background-color: none;\r\n}\r\n\r\n#circle div {\r\n  border-radius: 50%;\r\n  border: solid 2px rgb(255, 102, 102);\r\n}\r\n\r\n#square div {\r\n  border: solid 2px rgb(255, 105, 248);\r\n}\r\n\r\n#cross-title,\r\n#circle-title,\r\n#triangle-title,\r\n#square-title {\r\n  position: absolute;\r\n  display: none;\r\n  font-size: 13px;\r\n  text-shadow: 0px 2px black;\r\n}\r\n\r\n#cross-title {\r\n  color: rgb(124, 178, 232);\r\n}\r\n\r\n#circle-title {\r\n  color: rgb(255, 102, 102);\r\n}\r\n\r\n#triangle-title {\r\n  color: rgb(64, 226, 160);\r\n}\r\n\r\n#square-title {\r\n  color: rgb(255, 105, 248);\r\n}\r\n\r\n#cross-input,\r\n#circle-input,\r\n#triangle-input,\r\n#square-input {\r\n  position: absolute;\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n#cross-input {\r\n  top: 80%;\r\n  left: 50%;\r\n}\r\n\r\n#circle-input {\r\n  top: 50%;\r\n  left: 80%;\r\n}\r\n\r\n#triangle-input {\r\n  top: 20%;\r\n  left: 50%;\r\n}\r\n\r\n#square-input {\r\n  top: 50%;\r\n  left: 20%;\r\n}\r\n\r\n.playstation-input button {\r\n  width: 3.5em;\r\n  height: 3.5em;\r\n  border-radius: 50%;\r\n  border: none;\r\n  background-color: #323232;\r\n  box-shadow:\r\n    inset 0px 1px #969696,\r\n    0px 2px black;\r\n  transition: all 0.1s ease;\r\n  cursor: pointer;\r\n}\r\n\r\n.playstation-input:hover {\r\n  width: 12em;\r\n  height: 12em;\r\n}\r\n\r\n.playstation-input:hover button {\r\n  width: 4em;\r\n  height: 4em;\r\n}\r\n\r\n#cross-input:hover #cross-title,\r\n#triangle-input:hover #triangle-title {\r\n  display: flex;\r\n  top: 125%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n#circle-input:hover #circle-title,\r\n#square-input:hover #square-title {\r\n  display: flex;\r\n  top: 110%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n.playstation-input button:hover {\r\n  filter: brightness(85%);\r\n}\r\n\r\n.playstation-input button:active {\r\n  box-shadow: inset 0px 2px 2px black;\r\n}\r\n\r\n#cross-input:active {\r\n  top: 81%;\r\n}\r\n\r\n#triangle-input:active {\r\n  top: 21%;\r\n}\r\n\r\n#circle-input:active,\r\n#square-input:active {\r\n  top: 51%;\r\n}\r\n\r\n#cross:active p,\r\n#triangle:active p {\r\n  text-shadow: 0px 0px 10px white;\r\n}\r\n\r\n#circle:active div,\r\n#square:active div {\r\n  box-shadow:\r\n    inset 0px 0px 10px -5px white,\r\n    0px 0px 10px -5px white;\r\n}\r\n\r\n.playstation-input:has(#cross:active) {\r\n  box-shadow: 0px -5px 10px rgb(124, 178, 232);\r\n}\r\n\r\n.playstation-input:has(#circle:active) {\r\n  box-shadow: 0px -5px 10px rgb(255, 102, 102);\r\n}\r\n\r\n.playstation-input:has(#triangle:active) {\r\n  box-shadow: 0px -5px 10px rgb(64, 226, 160);\r\n}\r\n\r\n.playstation-input:has(#square:active) {\r\n  box-shadow: 0px -5px 10px rgb(255, 105, 248);\r\n}\r\n'),
(17, '\r\n<div class=\"light-button\">\r\n  <button class=\"bt\">\r\n    <div class=\"light-holder\">\r\n      <div class=\"dot\"></div>\r\n      <div class=\"light\"></div>\r\n    </div>\r\n    <div class=\"button-holder\">\r\n      <svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\">\r\n        <path\r\n          d=\"M12.244 4c.534.003 1.87.016 3.29.073l.504.022c1.429.067 2.857.183 3.566.38c.945.266 1.687 1.04 1.938 2.022c.4 1.56.45 4.602.456 5.339l.001.152v.174c-.007.737-.057 3.78-.457 5.339c-.254.985-.997 1.76-1.938 2.022c-.709.197-2.137.313-3.566.38l-.504.023c-1.42.056-2.756.07-3.29.072l-.235.001h-.255c-1.13-.007-5.856-.058-7.36-.476c-.944-.266-1.687-1.04-1.938-2.022c-.4-1.56-.45-4.602-.456-5.339v-.326c.006-.737.056-3.78.456-5.339c.254-.985.997-1.76 1.939-2.021c1.503-.419 6.23-.47 7.36-.476zM9.999 8.5v7l6-3.5z\"\r\n          fill=\"currentColor\"\r\n        ></path>\r\n      </svg>\r\n      <p>Youtube</p>\r\n    </div>\r\n  </button>\r\n</div>\r\n', '\r\n.light-button button.bt {\r\n  position: relative;\r\n  height: 200px;\r\n  display: flex;\r\n  align-items: flex-end;\r\n  outline: none;\r\n  background: none;\r\n  border: none;\r\n  cursor: pointer;\r\n}\r\n.light-button button.bt .button-holder {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  justify-content: center;\r\n  height: 100px;\r\n  width: 100px;\r\n  background-color: #0a0a0a;\r\n  border-radius: 5px;\r\n  color: #0f0f0f;\r\n  font-weight: 700;\r\n  transition: 300ms;\r\n  outline: #0f0f0f 2px solid;\r\n  outline-offset: 20;\r\n}\r\n.light-button button.bt .button-holder svg {\r\n  height: 50px;\r\n  fill: #0f0f0f;\r\n  transition: 300ms;\r\n}\r\n.light-button button.bt .light-holder {\r\n  position: absolute;\r\n  height: 200px;\r\n  width: 100px;\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n}\r\n.light-button button.bt .light-holder .dot {\r\n  position: absolute;\r\n  top: 0;\r\n  width: 10px;\r\n  height: 10px;\r\n  background-color: #0a0a0a;\r\n  border-radius: 10px;\r\n  z-index: 2;\r\n}\r\n.light-button button.bt .light-holder .light {\r\n  position: absolute;\r\n  top: 0;\r\n  width: 200px;\r\n  height: 200px;\r\n  clip-path: polygon(50% 0%, 25% 100%, 75% 100%);\r\n  background: transparent;\r\n}\r\n.light-button button.bt:hover .button-holder svg {\r\n  fill: #ff0000;\r\n}\r\n.light-button button.bt:hover .button-holder {\r\n  color: rgba(88, 101, 242, 1);\r\n  outline: rgba(88, 101, 242, 1) 2px solid;\r\n  outline-offset: 2px;\r\n}\r\n.light-button button.bt:hover .light-holder .light {\r\n  background: rgb(255, 0, 0);\r\n  background: linear-gradient(\r\n    180deg,\r\n    rgba(255, 0, 0, 1) 0%,\r\n    rgba(255, 0, 0, 0.5) 50%,\r\n    rgba(255, 0, 0, 0) 100%\r\n  );\r\n}\r\n\r\n.light-button button.bt:hover .button-holder svg path {\r\n  fill: #ff0000;\r\n}\r\n'),
(18, '\r\n<a class=\"btn\">\r\n  <div>GET STARTED</div>\r\n</a>\r\n', '\r\n.btn {\r\n  --color: #ffcd39;\r\n  position: relative;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  transition: all 0.5s;\r\n  border: none;\r\n  background-color: transparent;\r\n}\r\n\r\n.btn div {\r\n  letter-spacing: 2px;\r\n  font-weight: bold;\r\n  background: var(--color);\r\n  border-radius: 2rem;\r\n  color: black;\r\n  padding: 1rem;\r\n}\r\n\r\n.btn::before {\r\n  content: \"\";\r\n  z-index: -1;\r\n  background-color: var(--color);\r\n  border: 2px solid black;\r\n  border-radius: 2rem;\r\n  width: 110%;\r\n  height: 100%;\r\n  position: absolute;\r\n  transform: rotate(10deg);\r\n  transition: 0.5s;\r\n  opacity: 0.2;\r\n}\r\n\r\n.btn:hover {\r\n  cursor: pointer;\r\n  filter: brightness(1.2);\r\n  transform: scale(1.1);\r\n}\r\n\r\n.btn:hover::before {\r\n  transform: rotate(0deg);\r\n  opacity: 1;\r\n}\r\n\r\n.btn:active {\r\n  filter: brightness(1.4);\r\n}\r\n'),
(19, '\r\n<button class=\"button\" data-text=\"Awesome\">\r\n    <span class=\"actual-text\">&nbsp;PixelSyntax&nbsp;</span>\r\n    <span aria-hidden=\"true\" class=\"hover-text\">&nbsp;PixelSyntax&nbsp;</span>\r\n</button>', '\r\n.button {\r\n  margin: 0;\r\n  height: auto;\r\n  background: transparent;\r\n  padding: 0;\r\n  border: none;\r\n}\r\n\r\n.button {\r\n  --border-right: 6px;\r\n  --text-stroke-color: rgba(255,255,255,0.6);\r\n  --animation-color: #999999;\r\n  --fs-size: 2em;\r\n  letter-spacing: 3px;\r\n  text-decoration: none;\r\n  font-size: var(--fs-size);\r\n  font-family: \"Arial\";\r\n  position: relative;\r\n  text-transform: uppercase;\r\n  color: transparent;\r\n  -webkit-text-stroke: 1px var(--text-stroke-color);\r\n}\r\n.hover-text {\r\n  position: absolute;\r\n  box-sizing: border-box;\r\n  content: attr(data-text);\r\n  color: var(--animation-color);\r\n  width: 0%;\r\n  inset: 0;\r\n  border-right: var(--border-right) solid var(--animation-color);\r\n  overflow: hidden;\r\n  transition: 0.5s;\r\n  -webkit-text-stroke: 1px var(--animation-color);\r\n}\r\n.button:hover .hover-text {\r\n  width: 100%;\r\n  filter: drop-shadow(0 5px 23px var(--animation-color))\r\n}'),
(20, '\r\n<button>\r\n    <span>Button</span><i></i>\r\n</button>', '\r\nbutton {\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.1em;\r\n  padding: 10px 30px;\r\n  transition: 0.5s;\r\n  position: relative;\r\n  font-size: 17px;\r\n  background: #333;\r\n  border: none;\r\n  color: #fff;\r\n}\r\n\r\nbutton:hover {\r\n  letter-spacing: 0.25em;\r\n  background: #ff1867;\r\n  color: #ff1867;\r\n  box-shadow: 0 0 45px #ff1867;\r\n}\r\n\r\nbutton::before {\r\n  content: \';\r\n  position: absolute;\r\n  inset: 2px;\r\n  background: #222222;\r\n}\r\n\r\nbutton span {\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n\r\nbutton i {\r\n  position: absolute;\r\n  inset: 0;\r\n  display: block;\r\n}\r\n\r\nbutton i::before {\r\n  content: \';\r\n  position: absolute;\r\n  border: 2px solid #ff1867;\r\n  width: 7px;\r\n  height: 4px;\r\n  top: -3.5px;\r\n  left: 80%;\r\n  background: #222222;\r\n  transform: translateX(-50%);\r\n  transition: 0.5s;\r\n}\r\n\r\nbutton:hover i::before {\r\n  width: 20px;\r\n  left: 20%;\r\n}\r\n\r\nbutton i::after {\r\n  content: \';\r\n  position: absolute;\r\n  border: 2px solid #ff1867;\r\n  width: 7px;\r\n  height: 4px;\r\n  bottom: -3.5px;\r\n  left: 20%;\r\n  background: #222222;\r\n  transform: translateX(-50%);\r\n  transition: 0.5s;\r\n}\r\n\r\nbutton:hover i::after {\r\n  width: 20px;\r\n  left: 80%;\r\n}');

