INSERT INTO `cards` (`ID`, `HTML`, `CSS`) VALUES
(1, '\r\n<div class=\"code-editor\">\r\n      <div class=\"header\">\r\n        <span class=\"title\">CSS</span>\r\n       <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" class=\"icon\"><g stroke-width=\"0\" id=\"SVGRepo_bgCarrier\"></g><g stroke-linejoin=\"round\" stroke-linecap=\"round\" id=\"SVGRepo_tracerCarrier\"></g><g id=\"SVGRepo_iconCarrier\"> <path stroke-linecap=\"round\" stroke-width=\"2\" stroke=\"#4C4F5A\" d=\"M6 6L18 18\"></path> <path stroke-linecap=\"round\" stroke-width=\"2\" stroke=\"#4C4F5A\" d=\"M18 6L6 18\"></path> </g></svg>\r\n      </div>\r\n      <div class=\"editor-content\">\r\n        <code class=\"code\">\r\n          <p><span class=\"color-0\">.code-editor </span> <span>{</span></p>\r\n\r\n          <p class=\"property\">\r\n            <span class=\"color-2\">max-width</span><span>:</span>\r\n            <span class=\"color-1\">300px</span>;\r\n          </p>\r\n          <p class=\"property\">\r\n            <span class=\"color-2\">background-color</span><span>:</span>\r\n            <span class=\"color-preview-1\"></span><span class=\"\">#1d1e22</span>;\r\n          </p>\r\n          <p class=\"property\">\r\n            <span class=\"color-2\"> box-shadow</span><span>:</span>\r\n            <span class=\"color-1\">0px 4px 30px  <span class=\"color-preview-2\"></span><span class=\"color-3\">rgba(</span>0, 0, 0, 0.5<span class=\"color-3\">)</span></span>;\r\n          </p>\r\n          <p class=\"property\">\r\n            <span class=\"color-2\">border-radius</span><span>:</span>\r\n            <span class=\"color-1\">8px</span>;\r\n          </p>\r\n          <span>}</span>\r\n        </code>\r\n      </div>\r\n    </div>', '.code-editor {\n  max-width: 300px;\n  background-color: #1d1e22;\n  box-shadow: 0px 4px 30px rgba(0, 0, 0, 0.5);\n  border-radius: 8px;\n  padding: 2px;\n}\n\n.header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  margin: 10px;\n}\n\n.title {\n  font-family: Lato, sans-serif;\n  font-weight: 900;\n  font-size: 14px;\n  letter-spacing: 1.57px;\n  color: rgb(212 212 212);\n}\n\n.icon {\n  width: 20px;\n  transition: .2s ease;\n}\n\n.icon:hover {\n  cursor: pointer;\n  border-radius: 50px;\n  background-color: #6e7281;\n}\n\n.editor-content {\n  margin: 0 10px 10px;\n  color: white;\n}\n\n.property {\n  margin-left: 30px;\n}\n\n.property:hover {\n  cursor: text;\n}\n\n.editor-content .color-0 {\n  color: rgb(86 156 214);\n}\n\n.editor-content .color-1 {\n  color: rgb(182 206 168);\n}\n\n.editor-content .color-2 {\n  color: rgb(156 220 254);\n}\n\n.editor-content .color-3 {\n  color: rgb(207 146 120);\n}\n\n.color-preview-1,.color-preview-2 {\n  height: 8px;\n  width: 8px;\n  border: 1px solid #fff;\n  display: inline-block;\n  margin-right: 3px;\n}\n\n.color-preview-1 {\n  background-color: #1d1e22;\n}\n\n.color-preview-1 {\n  background-color: rgba(0, 0, 0, 0.5);\n}'),
(2, '\r\n<div class=\"card\">\r\n  <div class=\"first-content\">\r\n    <span>First</span>\r\n  </div>\r\n  <div class=\"second-content\">\r\n<span>Second</span>\r\n  </div>\r\n\r\n\r\n</div>', '\r\n.card {\r\n  width: 190px;\r\n  height: 254px;\r\n  background: rgb(103, 225, 255);\r\n  transition: all 0.4s;\r\n  border-radius: 10px;\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  font-size: 30px;\r\n  font-weight: 900;\r\n}\r\n\r\n.card:hover {\r\n  border-radius: 15px;\r\n  cursor: pointer;\r\n  transform: scale(1.2);\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  background: rgb(103, 151, 255);\r\n}\r\n\r\n.first-content {\r\n  height: 100%;\r\n  width: 100%;\r\n  transition: all 0.4s;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  opacity: 1;\r\n  border-radius: 15px;\r\n}\r\n\r\n.card:hover .first-content {\r\n  height: 0px;\r\n  opacity: 0;\r\n}\r\n\r\n.second-content {\r\n  height: 0%;\r\n  width: 100%;\r\n  opacity: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  border-radius: 15px;\r\n  transition: all 0.4s;\r\n  font-size: 0px;\r\n  transform: rotate(90deg) scale(-1);\r\n}\r\n\r\n.card:hover .second-content {\r\n  opacity: 1;\r\n  height: 100%;\r\n  font-size: 1.8rem;\r\n  transform: rotate(0deg);\r\n}\r\n'),
(3, '\r\n<div class=\"container\">\r\n  <div class=\"card1\"></div>\r\n  <div class=\"card2\"></div>\r\n  <div class=\"card3\">\r\n    * Card stacks are awesome and inspired by real card stack at your table.\r\n  </div>\r\n</div>\r\n', '\r\n.container {\r\n  position: relative;\r\n  margin-top: -100px;\r\n  width: 360px;\r\n}\r\n\r\n.container > * {\r\n  width: 340px;\r\n  height: 120px;\r\n  border: solid 1px #bebebe;\r\n  background-color: #1f1f1f;\r\n  position: absolute;\r\n  border-radius: 10px;\r\n  padding: 10px;\r\n  color: #fff;\r\n  box-shadow: 0px 8px 20px -10px #bbbbbb;\r\n  text-shadow: 0px 0px 5px #fff;\r\n  letter-spacing: 1px;\r\n  background-image: radial-gradient(circle 160px at 50% 120%, #353535, #1f1f1f);\r\n}\r\n\r\n.card1 {\r\n  width: 300px;\r\n  margin: -20px 0px 0px 20px;\r\n}\r\n.card2 {\r\n  width: 320px;\r\n  margin: -10px 0px 0px 10px;\r\n}\r\n'),
(4, '\r\n<div class=\"card\">\r\n  <p class=\"heading\">\r\n    Popular this month\r\n  </p>\r\n  <p>\r\n    Powered By\r\n  </p>\r\n  <p>Uiverse\r\n</p></div>', '\r\n.card {\r\n  position: relative;\r\n  width: 190px;\r\n  height: 254px;\r\n  background-color: #000;\r\n  display: flex;\r\n  flex-direction: column;\r\n  justify-content: end;\r\n  padding: 12px;\r\n  gap: 12px;\r\n  border-radius: 8px;\r\n  cursor: pointer;\r\n}\r\n\r\n.card::before {\r\n  content: \';\r\n  position: absolute;\r\n  inset: 0;\r\n  left: -5px;\r\n  margin: auto;\r\n  width: 200px;\r\n  height: 264px;\r\n  border-radius: 10px;\r\n  background: linear-gradient(-45deg, #e81cff 0%, #40c9ff 100% );\r\n  z-index: -10;\r\n  pointer-events: none;\r\n  transition: all 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);\r\n}\r\n\r\n.card::after {\r\n  content: \"\";\r\n  z-index: -1;\r\n  position: absolute;\r\n  inset: 0;\r\n  background: linear-gradient(-45deg, #fc00ff 0%, #00dbde 100% );\r\n  transform: translate3d(0, 0, 0) scale(0.95);\r\n  filter: blur(20px);\r\n}\r\n\r\n.heading {\r\n  font-size: 20px;\r\n  text-transform: capitalize;\r\n  font-weight: 700;\r\n}\r\n\r\n.card p:not(.heading) {\r\n  font-size: 14px;\r\n}\r\n\r\n.card p:last-child {\r\n  color: #e81cff;\r\n  font-weight: 600;\r\n}\r\n\r\n.card:hover::after {\r\n  filter: blur(30px);\r\n}\r\n\r\n.card:hover::before {\r\n  transform: rotate(-90deg) scaleX(1.34) scaleY(0.77);\r\n}\r\n\r\n'),
(5, '<div class=\"card\">\r\n  <div class=\"image\"><span class=\"text\">This is a chair.</span></div>\r\n  <span class=\"title\">Cool Chair</span>\r\n  <span class=\"price\">$100</span>\r\n</div>', '.card {\n  position: relative;\n  width: 11.875em;\n  height: 16.5em;\n  box-shadow: 0px 1px 13px rgba(0,0,0,0.1);\n  cursor: pointer;\n  transition: all 120ms;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background: #fff;\n  padding: 0.5em;\n  padding-bottom: 3.4em;\n}\n\n.card::after {\n  content: \"Add to Cart\";\n  padding-top: 1.25em;\n  padding-left: 1.25em;\n  position: absolute;\n  left: 0;\n  bottom: -60px;\n  background: #00AC7C;\n  color: #fff;\n  height: 2.5em;\n  width: 90%;\n  transition: all 80ms;\n  font-weight: 600;\n  text-transform: uppercase;\n  opacity: 0;\n}\n\n.card .title {\n  font-family: Arial, Helvetica, sans-serif;\n  font-size: 0.9em;\n  position: absolute;\n  left: 0.625em;\n  bottom: 1.875em;\n  font-weight: 400;\n  color: #000;\n}\n\n.card .price {\n  font-family: Impact, Haettenschweiler, \"Arial Narrow Bold\", sans-serif;\n  font-size: 0.9em;\n  position: absolute;\n  left: 0.625em;\n  bottom: 0.625em;\n  color: #000;\n}\n\n.card:hover::after {\n  bottom: 0;\n  opacity: 1;\n}\n\n.card:active {\n  transform: scale(0.98);\n}\n\n.card:active::after {\n  content: \"Added !\";\n  height: 3.125em;\n}\n\n.text {\n  max-width: 55px;\n}\n\n.image {\n  background: rgb(241, 241, 241);\n  width: 100%;\n  height: 100%;\n  display: grid;\n  place-items: center;\n}'),
(6, '\r\n<div class=\"card\">\r\n  <div class=\"card2\">\r\n  </div>\r\n</div>', '.card {\n width: 190px;\n height: 254px;\n background-image: linear-gradient(163deg, #00ff75 0%, #3700ff 100%);\n border-radius: 20px;\n transition: all .3s;\n}\n\n.card2 {\n width: 190px;\n height: 254px;\n background-color: #1a1a1a;\n border-radius:;\n transition: all .2s;\n}\n\n.card2:hover {\n transform: scale(0.98);\n border-radius: 20px;\n}\n\n.card:hover {\n box-shadow: 0px 0px 30px 1px rgba(0, 255, 117, 0.30);\n}'),
(7, '<p class=\"browser-warning\">\r\n  If this looks wonky to you it\'s because this browser doesn\'t support the CSS\r\n  property \'aspect-ratio\'.\r\n</p>\r\n<div class=\"stack\">\r\n  <div class=\"card\">\r\n    <div class=\"image\"></div>\r\n  </div>\r\n</div>', 'img {\n  display: block;\n  max-width: 60%;\n}\n\n.stack {\n  width: 55%;\n  max-width: 400px;\n  transition: 0.25s ease;\n}\n\n.stack:hover {\n  transform: rotate(5deg);\n}\n\n.stack:hover .card:before {\n  transform: translateY(-2%) rotate(-4deg);\n}\n\n.stack:hover .card:after {\n  transform: translateY(2%) rotate(4deg);\n}\n\n.card {\n  aspect-ratio: 3 / 2;\n  border: 4px solid;\n  background-color: #fff;\n  position: relative;\n  transition: 0.15s ease;\n  cursor: pointer;\n  padding: 5% 5% 15% 5%;\n}\n\n.card:before,\n.card:after {\n  content: \"\";\n  display: block;\n  position: absolute;\n  height: 100%;\n  width: 100%;\n  border: 4px solid;\n  background-color: #fff;\n  transform-origin: center center;\n  z-index: -1;\n  transition: 0.15s ease;\n  top: 0;\n  left: 0;\n}\n\n.card:before {\n  transform: translateY(-2%) rotate(-6deg);\n}\n\n.card:after {\n  transform: translateY(2%) rotate(6deg);\n}\n\n.image {\n  width: 100%;\n  border: 4px solid;\n  background-color: #eee;\n  aspect-ratio: 1 / 1;\n  position: relative;\n}\n\n.browser-warning {\n  margin-bottom: 4rem;\n}\n\n@supports (aspect-ratio: 1 / 1) {\n  .browser-warning {\n    display: none;\n  }\n}'),
(8, '\r\n<div class=\"container_chat_bot\">\r\n  <div class=\"container-chat-options\">\r\n    <div class=\"chat\">\r\n      <div class=\"chat-bot\">\r\n        <textarea\r\n          id=\"chat_bot\"\r\n          name=\"chat_bot\"\r\n          placeholder=\"Imagine Something...✦˚\"\r\n        ></textarea>\r\n      </div>\r\n      <div class=\"options\">\r\n        <div class=\"btns-add\">\r\n          <button>\r\n            <svg\r\n              xmlns=\"http://www.w3.org/2000/svg\"\r\n              width=\"20\"\r\n              height=\"20\"\r\n              viewBox=\"0 0 24 24\"\r\n            >\r\n              <path\r\n                fill=\"none\"\r\n                stroke=\"currentColor\"\r\n                stroke-linecap=\"round\"\r\n                stroke-linejoin=\"round\"\r\n                stroke-width=\"2\"\r\n                d=\"M7 8v8a5 5 0 1 0 10 0V6.5a3.5 3.5 0 1 0-7 0V15a2 2 0 0 0 4 0V8\"\r\n              ></path>\r\n            </svg>\r\n          </button>\r\n          <button>\r\n            <svg\r\n              viewBox=\"0 0 24 24\"\r\n              height=\"20\"\r\n              width=\"20\"\r\n              xmlns=\"http://www.w3.org/2000/svg\"\r\n            >\r\n              <path\r\n                d=\"M4 5a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v4a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1zm0 10a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v4a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1zm10 0a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v4a1 1 0 0 1-1 1h-4a1 1 0 0 1-1-1zm0-8h6m-3-3v6\"\r\n                stroke-width=\"2\"\r\n                stroke-linejoin=\"round\"\r\n                stroke-linecap=\"round\"\r\n                stroke=\"currentColor\"\r\n                fill=\"none\"\r\n              ></path>\r\n            </svg>\r\n          </button>\r\n          <button>\r\n            <svg\r\n              viewBox=\"0 0 24 24\"\r\n              height=\"20\"\r\n              width=\"20\"\r\n              xmlns=\"http://www.w3.org/2000/svg\"\r\n            >\r\n              <path\r\n                d=\"M12 22C6.477 22 2 17.523 2 12S6.477 2 12 2s10 4.477 10 10s-4.477 10-10 10m-2.29-2.333A17.9 17.9 0 0 1 8.027 13H4.062a8.01 8.01 0 0 0 5.648 6.667M10.03 13c.151 2.439.848 4.73 1.97 6.752A15.9 15.9 0 0 0 13.97 13zm9.908 0h-3.965a17.9 17.9 0 0 1-1.683 6.667A8.01 8.01 0 0 0 19.938 13M4.062 11h3.965A17.9 17.9 0 0 1 9.71 4.333A8.01 8.01 0 0 0 4.062 11m5.969 0h3.938A15.9 15.9 0 0 0 12 4.248A15.9 15.9 0 0 0 10.03 11m4.259-6.667A17.9 17.9 0 0 1 15.973 11h3.965a8.01 8.01 0 0 0-5.648-6.667\"\r\n                fill=\"currentColor\"\r\n              ></path>\r\n            </svg>\r\n          </button>\r\n        </div>\r\n        <button class=\"btn-submit\">\r\n          <i>\r\n            <svg viewBox=\"0 0 512 512\">\r\n              <path\r\n                fill=\"currentColor\"\r\n                d=\"M473 39.05a24 24 0 0 0-25.5-5.46L47.47 185h-.08a24 24 0 0 0 1 45.16l.41.13l137.3 58.63a16 16 0 0 0 15.54-3.59L422 80a7.07 7.07 0 0 1 10 10L226.66 310.26a16 16 0 0 0-3.59 15.54l58.65 137.38c.06.2.12.38.19.57c3.2 9.27 11.3 15.81 21.09 16.25h1a24.63 24.63 0 0 0 23-15.46L478.39 64.62A24 24 0 0 0 473 39.05\"\r\n              ></path>\r\n            </svg>\r\n          </i>\r\n        </button>\r\n      </div>\r\n    </div>\r\n  </div>\r\n  <div class=\"tags\">\r\n    <span>Create An Image</span>\r\n    <span>Analyse Data</span>\r\n    <span>More</span>\r\n  </div>\r\n</div>\r\n', '.container_chat_bot {\n  display: flex;\n  flex-direction: column;\n  max-width: 260px;\n  width: 100%;\n}\n\n.container_chat_bot .container-chat-options {\n  position: relative;\n  display: flex;\n  background: linear-gradient(\n    to bottom right,\n    #7e7e7e,\n    #363636,\n    #363636,\n    #363636,\n    #363636\n  );\n  border-radius: 16px;\n  padding: 1.5px;\n  overflow: hidden;\n\n  &::after {\n    position: absolute;\n    content: \"\";\n    top: -10px;\n    left: -10px;\n    background: radial-gradient(\n      ellipse at center,\n      #ffffff,\n      rgba(255, 255, 255, 0.3),\n      rgba(255, 255, 255, 0.1),\n      rgba(0, 0, 0, 0),\n      rgba(0, 0, 0, 0),\n      rgba(0, 0, 0, 0),\n      rgba(0, 0, 0, 0)\n    );\n    width: 30px;\n    height: 30px;\n    filter: blur(1px);\n  }\n}\n\n.container_chat_bot .container-chat-options .chat {\n  display: flex;\n  flex-direction: column;\n  background-color: rgba(0, 0, 0, 0.5);\n  border-radius: 15px;\n  width: 100%;\n  overflow: hidden;\n}\n\n.container_chat_bot .container-chat-options .chat .chat-bot {\n  position: relative;\n  display: flex;\n}\n\n.container_chat_bot .chat .chat-bot textarea {\n  background-color: transparent;\n  border-radius: 16px;\n  border: none;\n  width: 100%;\n  height: 50px;\n  color: #ffffff;\n  font-family: sans-serif;\n  font-size: 12px;\n  font-weight: 400;\n  padding: 10px;\n  resize: none;\n  outline: none;\n\n  &::-webkit-scrollbar {\n    width: 10px;\n    height: 10px;\n  }\n\n  &::-webkit-scrollbar-track {\n    background: transparent;\n  }\n\n  &::-webkit-scrollbar-thumb {\n    background: #888;\n    border-radius: 5px;\n  }\n\n  &::-webkit-scrollbar-thumb:hover {\n    background: #555;\n    cursor: pointer;\n  }\n\n  &::placeholder {\n    color: #f3f6fd;\n    transition: all 0.3s ease;\n  }\n  &:focus::placeholder {\n    color: #363636;\n  }\n}\n\n.container_chat_bot .chat .options {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-end;\n  padding: 10px;\n}\n\n.container_chat_bot .chat .options .btns-add {\n  display: flex;\n  gap: 8px;\n\n  & button {\n    display: flex;\n    color: rgba(255, 255, 255, 0.1);\n    background-color: transparent;\n    border: none;\n    cursor: pointer;\n    transition: all 0.3s ease;\n\n    &:hover {\n      transform: translateY(-5px);\n      color: #ffffff;\n    }\n  }\n}\n\n.container_chat_bot .chat .options .btn-submit {\n  display: flex;\n  padding: 2px;\n  background-image: linear-gradient(to top, #292929, #555555, #292929);\n  border-radius: 10px;\n  box-shadow: inset 0 6px 2px -4px rgba(255, 255, 255, 0.5);\n  cursor: pointer;\n  border: none;\n  outline: none;\n  transition: all 0.15s ease;\n\n  & i {\n    width: 30px;\n    height: 30px;\n    padding: 6px;\n    background: rgba(0, 0, 0, 0.1);\n    border-radius: 10px;\n    backdrop-filter: blur(3px);\n    color: #8b8b8b;\n  }\n  & svg {\n    transition: all 0.3s ease;\n  }\n  &:hover svg {\n    color: #f3f6fd;\n    filter: drop-shadow(0 0 5px #ffffff);\n  }\n\n  &:focus svg {\n    color: #f3f6fd;\n    filter: drop-shadow(0 0 5px #ffffff);\n    transform: scale(1.2) rotate(45deg) translateX(-2px) translateY(1px);\n  }\n\n  &:active {\n    transform: scale(0.92);\n  }\n}\n\n.container_chat_bot .tags {\n  padding: 14px 0;\n  display: flex;\n  color: #ffffff;\n  font-size: 10px;\n  gap: 4px;\n\n  & span {\n    padding: 4px 8px;\n    background-color: #1b1b1b;\n    border: 1.5px solid #363636;\n    border-radius: 10px;\n    cursor: pointer;\n    user-select: none;\n  }\n}\n'),
(9, '\r\n<div class=\"card\">\r\n    <div class=\"align\">\r\n        <span class=\"red\"></span>\r\n        <span class=\"yellow\"></span>\r\n        <span class=\"green\"></span>\r\n    </div>\r\n\r\n    <h1>HOVER ME</h1>\r\n    <p>\r\n        Lorem ipsum, dolor sit amet consectetur adipisicing elit. Unde explicabo enim rem odio assumenda?\r\n    </p>\r\n</div>', '.card {\n  width: 190px;\n  height: 120px;\n  padding: 0.5rem;\n  background: rgba(198, 198, 198, 0.34);\n  border-radius: 8px;\n  backdrop-filter: blur(5px);\n  border-bottom: 3px solid rgba(255, 255, 255, 0.440);\n  border-left: 2px  rgba(255, 255, 255, 0.545) outset;\n  box-shadow: -40px 50px 30px rgba(0, 0, 0, 0.280);\n  transform: skewX(10deg);\n  transition: .4s;\n  overflow: hidden;\n  color: white;\n}\n\n.card:hover {\n  height: 254px;\n  transform: skew(0deg);\n}\n\n.align {\n  padding: 1rem;\n  display: flex;\n  flex-direction: row;\n  gap: 5px;\n  align-self: flex-start;\n}\n\n.red {\n  width: 10px;\n  height: 10px;\n  border-radius: 50%;\n  background-color: #ff605c;\n  box-shadow: -5px 5px 5px rgba(0, 0, 0, 0.280);\n}\n\n.yellow {\n  width: 10px;\n  height: 10px;\n  border-radius: 50%;\n  background-color: #ffbd44;\n  box-shadow: -5px 5px 5px rgba(0, 0, 0, 0.280);\n}\n\n.green {\n  width: 10px;\n  height: 10px;\n  border-radius: 50%;\n  background-color: #00ca4e;\n  box-shadow: -5px 5px 5px rgba(0, 0, 0, 0.280);\n}\n\n.card h1 {\n  text-align: center;\n  margin: 1.3rem;\n  color: rgb(218, 244, 237);\n  text-shadow: -10px 5px 10px rgba(0, 0, 0, 0.573);\n}\n\n'),
(10, '\r\n<div class=\"card\">\r\n  <span class=\"card__title\">Newsletter</span>\r\n  <p class=\"card__content\">\r\n    Get existential crisis delivered straight to your inbox every week.\r\n  </p>\r\n  <form class=\"card__form\">\r\n    <input required=\"\" type=\"email\" placeholder=\"Your life\" />\r\n    <button class=\"card__button\">Click me</button>\r\n  </form>\r\n</div>\r\n', '.card {\n  width: 300px;\n  padding: 20px;\n  background: #fff;\n  border: 6px solid #000;\n  box-shadow: 12px 12px 0 #000;\n  transition: transform 0.3s, box-shadow 0.3s;\n}\n\n.card:hover {\n  transform: translate(-5px, -5px);\n  box-shadow: 17px 17px 0 #000;\n}\n\n.card__title {\n  font-size: 32px;\n  font-weight: 900;\n  color: #000;\n  text-transform: uppercase;\n  margin-bottom: 15px;\n  display: block;\n  position: relative;\n  overflow: hidden;\n}\n\n.card__title::after {\n  content: \"\";\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  width: 90%;\n  height: 3px;\n  background-color: #000;\n  transform: translateX(-100%);\n  transition: transform 0.3s;\n}\n\n.card:hover .card__title::after {\n  transform: translateX(0);\n}\n\n.card__content {\n  font-size: 16px;\n  line-height: 1.4;\n  color: #000;\n  margin-bottom: 20px;\n}\n\n.card__form {\n  display: flex;\n  flex-direction: column;\n  gap: 15px;\n}\n\n.card__form input {\n  padding: 10px;\n  border: 3px solid #000;\n  font-size: 16px;\n  font-family: inherit;\n  transition: transform 0.3s;\n  width: calc(100% - 26px); /* Adjust for padding and border */\n}\n\n.card__form input:focus {\n  outline: none;\n  transform: scale(1.05);\n  background-color: #000;\n  color: #ffffff;\n}\n\n.card__button {\n  border: 3px solid #000;\n  background: #000;\n  color: #fff;\n  padding: 10px;\n  font-size: 18px;\n  left: 20%;\n  font-weight: bold;\n  text-transform: uppercase;\n  cursor: pointer;\n  position: relative;\n  overflow: hidden;\n  transition: transform 0.3s;\n  width: 50%;\n  height: 100%;\n}\n\n.card__button::before {\n  content: \"Sure?\";\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 105%;\n  background-color: #5ad641;\n  color: #000;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transform: translateY(100%);\n  transition: transform 0.3s;\n}\n\n.card__button:hover::before {\n  transform: translateY(0);\n}\n\n.card__button:active {\n  transform: scale(0.95);\n}\n\n@keyframes glitch {\n  0% {\n    transform: translate(2px, 2px);\n  }\n  25% {\n    transform: translate(-2px, -2px);\n  }\n  50% {\n    transform: translate(-2px, 2px);\n  }\n  75% {\n    transform: translate(2px, -2px);\n  }\n  100% {\n    transform: translate(2px, 2px);\n  }\n}\n\n.glitch {\n  animation: glitch 0.3s infinite;\n}\n'),
(11, '\r\n<div class=\"flip-card\">\r\n    <div class=\"flip-card-inner\">\r\n        <div class=\"flip-card-front\">\r\n            <p class=\"title\">FLIP CARD</p>\r\n            <p>Hover Me</p>\r\n        </div>\r\n        <div class=\"flip-card-back\">\r\n            <p class=\"title\">BACK</p>\r\n            <p>Leave Me</p>\r\n        </div>\r\n    </div>\r\n</div>', '.flip-card {\n  background-color: transparent;\n  width: 190px;\n  height: 254px;\n  perspective: 1000px;\n  font-family: sans-serif;\n}\n\n.title {\n  font-size: 1.5em;\n  font-weight: 900;\n  text-align: center;\n  margin: 0;\n}\n\n.flip-card-inner {\n  position: relative;\n  width: 100%;\n  height: 100%;\n  text-align: center;\n  transition: transform 0.8s;\n  transform-style: preserve-3d;\n}\n\n.flip-card:hover .flip-card-inner {\n  transform: rotateY(180deg);\n}\n\n.flip-card-front, .flip-card-back {\n  box-shadow: 0 8px 14px 0 rgba(0,0,0,0.2);\n  position: absolute;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  width: 100%;\n  height: 100%;\n  -webkit-backface-visibility: hidden;\n  backface-visibility: hidden;\n  border: 1px solid coral;\n  border-radius: 1rem;\n}\n\n.flip-card-front {\n  background: linear-gradient(120deg, bisque 60%, rgb(255, 231, 222) 88%,\n     rgb(255, 211, 195) 40%, rgba(255, 127, 80, 0.603) 48%);\n  color: coral;\n}\n\n.flip-card-back {\n  background: linear-gradient(120deg, rgb(255, 174, 145) 30%, coral 88%,\n     bisque 40%, rgb(255, 185, 160) 78%);\n  color: white;\n  transform: rotateY(180deg);\n}'),
(12, '\r\n<div class=\"card\">\r\n  <div class=\"imge\">\r\n    <div class=\"Usericon\"></div>\r\n    <p class=\"UserName\"></p>\r\n    <p class=\"Id\"></p>\r\n  </div>\r\n\r\n  <div class=\"Description\"></div>\r\n\r\n  <div class=\"social-media\">\r\n        <a href=\"#\">\r\n            <svg viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\">\r\n                <path d=\"M459.37 151.716c.325 4.548.325 9.097.325 13.645 0 138.72-105.583 298.558-298.558 298.558-59.452 0-114.68-17.219-161.137-47.106 8.447.974 16.568 1.299 25.34 1.299 49.055 0 94.213-16.568 130.274-44.832-46.132-.975-84.792-31.188-98.112-72.772 6.498.974 12.995 1.624 19.818 1.624 9.421 0 18.843-1.3 27.614-3.573-48.081-9.747-84.143-51.98-84.143-102.985v-1.299c13.969 7.797 30.214 12.67 47.431 13.319-28.264-18.843-46.781-51.005-46.781-87.391 0-19.492 5.197-37.36 14.294-52.954 51.655 63.675 129.3 105.258 216.365 109.807-1.624-7.797-2.599-15.918-2.599-24.04 0-57.828 46.782-104.934 104.934-104.934 30.213 0 57.502 12.67 76.67 33.137 23.715-4.548 46.456-13.32 66.599-25.34-7.798 24.366-24.366 44.833-46.132 57.827 21.117-2.273 41.584-8.122 60.426-16.243-14.292 20.791-32.161 39.308-52.628 54.253z\"></path>\r\n            </svg>\r\n        </a>\r\n        <a href=\"#\">\r\n            <svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\">\r\n                <path d=\"M224.1 141c-63.6 0-114.9 51.3-114.9 114.9s51.3 114.9 114.9 114.9S339 319.5 339 255.9 287.7 141 224.1 141zm0 189.6c-41.1 0-74.7-33.5-74.7-74.7s33.5-74.7 74.7-74.7 74.7 33.5 74.7 74.7-33.6 74.7-74.7 74.7zm146.4-194.3c0 14.9-12 26.8-26.8 26.8-14.9 0-26.8-12-26.8-26.8s12-26.8 26.8-26.8 26.8 12 26.8 26.8zm76.1 27.2c-1.7-35.9-9.9-67.7-36.2-93.9-26.2-26.2-58-34.4-93.9-36.2-37-2.1-147.9-2.1-184.9 0-35.8 1.7-67.6 9.9-93.9 36.1s-34.4 58-36.2 93.9c-2.1 37-2.1 147.9 0 184.9 1.7 35.9 9.9 67.7 36.2 93.9s58 34.4 93.9 36.2c37 2.1 147.9 2.1 184.9 0 35.9-1.7 67.7-9.9 93.9-36.2 26.2-26.2 34.4-58 36.2-93.9 2.1-37 2.1-147.8 0-184.8zM398.8 388c-7.8 1