n  border-width: 10px;\n  border-radius: 5px;\n  border-color: #262626;\n  color: #262626;\n  font-size: 15px;\n  font-weight: bold;\n  transform: translateX(70px) translateY(-25px);\n}\n\n.Description {\n  border-color: #141414;\n  background-color: #414141;\n  transform: translate(5px, 6px);\n  width: 180px;\n  height: 130px;\n  border-radius: 5px;\n}\n\n/*______Social Media______*/\n.social-media:before {\n  content: \" \";\n  display: block;\n  width: 100%;\n  height: 2px;\n  transform: translatey(10px);\n  background: #414141;\n}\n\n.social-media a {\n  margin-right: 15px;\n  text-decoration: none;\n  color: inherit;\n}\n\n.social-media a:last-child {\n  margin-right: 0;\n}\n\n.social-media a svg {\n  color: #ff5858;\n  transform: translatex(25px) translateY(20px);\n  width: 20px;\n  fill: currentColor;\n}'),
(13, '\r\n<div class=\"card\">\r\n  <div class=\"head\">Window</div>\r\n  <div class=\"content\">\r\n    This is a neobrutalist-style window with a button and space for any content\r\n    you want!\r\n    <br />\r\n    <button class=\"button\">Button</button>\r\n  </div>\r\n</div>\r\n', '.card {\n  font-family: Montserrat, sans-serif;\n  width: 300px;\n  height: 250px;\n  translate: -6px -6px;\n  background: #ff66a3;\n  border: 3px solid #000000;\n  box-shadow: 12px 12px 0 #000000;\n  overflow: hidden;\n  transition: all 0.3s ease;\n}\n\n.head {\n  font-family: Montserrat, sans-serif;\n  font-size: 14px;\n  font-weight: 900;\n  width: 100%;\n  height: 32px;\n  background: #ffffff;\n  padding: 5px 12px;\n  color: #000000;\n  border-bottom: 3px solid #000000;\n}\n\n.content {\n  padding: 8px 12px;\n  font-size: 14px;\n  font-weight: 600;\n}\n\n.button {\n  padding: 5px 10px;\n  margin-top: 10px;\n  border: 3px solid #000000;\n  box-shadow: 3px 3px 0 #000000;\n  font-weight: 750;\n  background: #4ade80;\n  transition: all 0.3s ease;\n  cursor: pointer;\n}\n\n.button:hover {\n  translate: 1.5px 1.5px;\n  box-shadow: 1.5px 1.5px 0 #000000;\n  background: #1ac2ff;\n}\n\n.button:active {\n  translate: 3px 3px;\n  box-shadow: 0 0 0 #000000;\n}\n\n.card:hover {\n  translate: -6px;\n}\n'),
