\"><path d=\"M25,27l-9,-6.75l-9,6.75v-23h18z\"></path></g></g></svg>\r\n          </div>\r\n          <p class=\"card-footer\">\r\n            30 Mins &nbsp; | &nbsp; 1 Serving\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>', '.card {\n  overflow: visible;\n  width: 190px;\n  height: 254px;\n}\n\n.content {\n  width: 100%;\n  height: 100%;\n  transform-style: preserve-3d;\n  transition: transform 300ms;\n  box-shadow: 0px 0px 10px 1px #000000ee;\n  border-radius: 5px;\n}\n\n.front, .back {\n  background-color: #151515;\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  backface-visibility: hidden;\n  -webkit-backface-visibility: hidden;\n  border-radius: 5px;\n  overflow: hidden;\n}\n\n.back {\n  width: 100%;\n  height: 100%;\n  justify-content: center;\n  display: flex;\n  align-items: center;\n  overflow: hidden;\n}\n\n.back::before {\n  position: absolute;\n  content: ;\n  display: block;\n  width: 160px;\n  height: 160%;\n  background: linear-gradient(90deg, transparent, #ff9966, #ff9966, #ff9966, #ff9966, transparent);\n  animation: rotation_481 5000ms infinite linear;\n}\n\n.back-content {\n  position: absolute;\n  width: 99%;\n  height: 99%;\n  background-color: #151515;\n  border-radius: 5px;\n  color: white;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  gap: 30px;\n}\n\n.card:hover .content {\n  transform: rotateY(180deg);\n}\n\n@keyframes rotation_481 {\n  0% {\n    transform: rotateZ(0deg);\n  }\n\n  0% {\n    transform: rotateZ(360deg);\n  }\n}\n\n.front {\n  transform: rotateY(180deg);\n  color: white;\n}\n\n.front .front-content {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  padding: 10px;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n}\n\n.front-content .badge {\n  background-color: #00000055;\n  padding: 2px 10px;\n  border-radius: 10px;\n  backdrop-filter: blur(2px);\n  width: fit-content;\n}\n\n.description {\n  box-shadow: 0px 0px 10px 5px #00000088;\n  width: 100%;\n  padding: 10px;\n  background-color: #00000099;\n  backdrop-filter: blur(5px);\n  border-radius: 5px;\n}\n\n.title {\n  font-size: 11px;\n  max-width: 100%;\n  display: flex;\n  justify-content: space-between;\n}\n\n.title p {\n  width: 50%;\n}\n\n.card-footer {\n  color: #ffffff88;\n  margin-top: 5px;\n  font-size: 8px;\n}\n\n.front .img {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  object-position: center;\n}\n\n.circle {\n  width: 90px;\n  height: 90px;\n  border-radius: 50%;\n  background-color: #ffbb66;\n  position: relative;\n  filter: blur(15px);\n  animation: floating 2600ms infinite linear;\n}\n\n#bottom {\n  background-color: #ff8866;\n  left: 50px;\n  top: 0px;\n  width: 150px;\n  height: 150px;\n  animation-delay: -800ms;\n}\n\n#right {\n  background-color: #ff2233;\n  left: 160px;\n  top: -80px;\n  width: 30px;\n  height: 30px;\n  animation-delay: -1800ms;\n}\n\n@keyframes floating {\n  0% {\n    transform: translateY(0px);\n  }\n\n  50% {\n    transform: translateY(10px);\n  }\n\n  100% {\n    transform: translateY(0px);\n  }\n}'),
(16, '\r\n<div class=\"card\">\r\n    <p><span>HOVER ME</span></p>\r\n    <p><span>HOVER ME</span></p>\r\n    <p><span>HOVER ME</span></p>\r\n</div>', '.card {\n  width: 210px;\n  height: 254px;\n  border-radius: 4px;\n  background: #212121;\n  display: flex;\n  gap: 5px;\n  padding: .4em;\n}\n\n.card p {\n  height: 100%;\n  flex: 1;\n  overflow: hidden;\n  cursor: pointer;\n  border-radius: 2px;\n  transition: all .5s;\n  background: #212121;\n  border: 1px solid #ff5a91;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.card p:hover {\n  flex: 4;\n}\n\n.card p span {\n  min-width: 14em;\n  padding: .5em;\n  text-align: center;\n  transform: rotate(-90deg);\n  transition: all .5s;\n  text-transform: uppercase;\n  color: #ff568e;\n  letter-spacing: .1em;\n}\n\n.card p:hover span {\n  transform: rotate(0);\n}'),
(17, '\r\n<div class=\"card\">\r\n  <svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M20 5H4V19L13.2923 9.70649C13.6828 9.31595 14.3159 9.31591 14.7065 9.70641L20 15.0104V5ZM2 3.9934C2 3.44476 2.45531 3 2.9918 3H21.0082C21.556 3 22 3.44495 22 3.9934V20.0066C22 20.5552 21.5447 21 21.0082 21H2.9918C2.44405 21 2 20.5551 2 20.0066V3.9934ZM8 11C6.89543 11 6 10.1046 6 9C6 7.89543 6.89543 7 8 7C9.10457 7 10 7.89543 10 9C10 10.1046 9.10457 11 8 11Z\"></path></svg>\r\n  <div class=\"card__content\">\r\n    <p class=\"card__title\">Card Title\r\n    </p><p class=\"card__description\">Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco.</p>\r\n  </div>\r\n</div>\r\n', '\r\n.card {\r\n  position: relative;\r\n  width: 300px;\r\n  height: 200px;\r\n  background: linear-gradient(-45deg, #f89b29 0%, #ff0f7b 100% );\r\n  border-radius: 10px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  overflow: hidden;\r\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\r\n}\r\n\r\n.card svg {\r\n  width: 48px;\r\n  fill: #333;\r\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\r\n}\r\n\r\n.card:hover {\r\n  transform: rotate(-5deg) scale(1.1);\r\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);\r\n}\r\n\r\n.card__content {\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%) rotate(-45deg);\r\n  width: 100%;\r\n  height: 100%;\r\n  padding: 20px;\r\n  box-sizing: border-box;\r\n  background-color: #fff;\r\n  opacity: 0;\r\n  transition: all 0.6s cubic-bezier(0.23, 1, 0.320, 1);\r\n}\r\n\r\n.card:hover .card__content {\r\n  transform: translate(-50%, -50%) rotate(0deg);\r\n  opacity: 1;\r\n}\r\n\r\n.card__title {\r\n  margin: 0;\r\n  font-size: 24px;\r\n  color: #333;\r\n  font-weight: 700;\r\n}\r\n\r\n.card__description {\r\n  margin: 10px 0 0;\r\n  font-size: 14px;\r\n  color: #777;\r\n  line-height: 1.4;\r\n}\r\n\r\n.card:hover svg {\r\n  scale: 0;\r\n  transform: rotate(-45deg);\r\n}\r\n'),
(18, '\r\n <div class=\"book\">\r\n    <p>Hello</p>\r\n    <div class=\"cover\">\r\n        <p>Hover Me</p>\r\n    </div>\r\n   </div>', '.book {\n  position: relative;\n  border-radius: 10px;\n  width: 220px;\n  height: 300px;\n  background-color: whitesmoke;\n  -webkit-box-shadow: 1px 1px 12px #000;\n  box-shadow: 1px 1px 12px #000;\n  -webkit-transform: preserve-3d;\n  -ms-transform: preserve-3d;\n  transform: preserve-3d;\n  -webkit-perspective: 2000px;\n  perspective: 2000px;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  color: #000;\n}\n\n.cover {\n  top: 0;\n  position: absolute;\n  background-color: lightgray;\n  width: 100%;\n  height: 100%;\n  border-radius: 10px;\n  cursor: pointer;\n  -webkit-transition: all 0.5s;\n  transition: all 0.5s;\n  -webkit-transform-origin: 0;\n  -ms-transform-origin: 0;\n  transform-origin: 0;\n  -webkit-box-shadow: 1px 1px 12px #000;\n  box-shadow: 1px 1px 12px #000;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n}\n\n.book:hover .cover {\n  -webkit-transition: all 0.5s;\n  transition: all 0.5s;\n  -webkit-transform: rotatey(-80deg);\n  -ms-transform: rotatey(-80deg);\n  transform: rotatey(-80deg);\n}\n\np {\n  font-size: 20px;\n  font-weight: bolder;\n}'),
(19, '\r\n<div class=\"cards\">\r\n    <div class=\"card red\">\r\n        <p class=\"tip\">Hover Me</p>\r\n        <p class=\"second-text\">Lorem Ipsum</p>\r\n    </div>\r\n    <div class=\"card blue\">\r\n        <p class=\"tip\">Hover Me</p>\r\n        <p class=\"second-text\">Lorem Ipsum</p>\r\n    </div>\r\n    <div class=\"card green\">\r\n        <p class=\"tip\">Hover Me</p>\r\n        <p class=\"second-text\">Lorem Ipsum</p>\r\n    </div>\r\n</div>', '.cards {\n  display: flex;\n  flex-direction: column;\n  gap: 15px;\n}\n\n.cards .red {\n  background-color: #f43f5e;\n}\n\n.cards .blue {\n  background-color: #3b82f6;\n}\n\n.cards .green {\n  background-color: #22c55e;\n}\n\n.cards .card {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-direction: column;\n  text-align: center;\n  height: 100px;\n  width: 250px;\n  border-radius: 10px;\n  color: white;\n  cursor: pointer;\n  transition: 400ms;\n}\n\n.cards .card p.tip {\n  font-size: 1em;\n  font-weight: 700;\n}\n\n.cards .card p.second-text {\n  font-size: .7em;\n}\n\n.cards .card:hover {\n  transform: scale(1.1, 1.1);\n}\n\n.cards:hover > .card:not(:hover) {\n  filter: blur(10px);\n  transform: scale(0.9, 0.9);\n}');
INSERT INTO `cards` (`ID`, `HTML`, `CSS`) VALUES
(20, '\r\n<div class=\"card\">\r\n  <div class=\"details\">\r\n    <div class=\"cardHeader\">CSS Hover Animation</div>\r\n    <div class=\"cardText\">\r\n      Welcome to this card where i have made use of the \"Hover\" effect to add\r\n      some really cool interactions to it. Enjoy\r\n    </div>\r\n    <div class=\"button\">Learn More</div>\r\n  </div>\r\n</div>\r\n', '.card {\n  background: rgba(172, 7, 226, 0.5);\n  position: relative;\n  max-width: 250px;\n  height: 350px;\n  border-radius: 5px;\n  padding: 1rem;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n  justify-content: flex-end;\n  gap: 7.5px;\n  transition: 0.5s ease;\n  color: white;\n}\n\n.card::after {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  background: radial-gradient(\n        35.36% 35.36% at 100% 25%,\n        #0000 66%,\n        #c79013 68% 70%,\n        #0000 72%\n      )\n      32px 32px / calc(2 * 32px) calc(2 * 32px),\n    radial-gradient(\n        35.36% 35.36% at 0 75%,\n        #0000 66%,\n        #c79013 68% 70%,\n        #0000 72%\n      )\n      32px 32px / calc(2 * 32px) calc(2 * 32px),\n    radial-gradient(\n        35.36% 35.36% at 100% 25%,\n        #0000 66%,\n        #c79013 68% 70%,\n        #0000 72%\n      )\n      0 0 / calc(2 * 32px) calc(2 * 32px),\n    radial-gradient(\n        35.36% 35.36% at 0 75%,\n        #0000 66%,\n        #c79013 68% 70%,\n        #0000 72%\n      )\n      0 0 / calc(2 * 32px) calc(2 * 32px),\n    repeating-conic-gradient(#295b3f 0 25%, #0000 0 50%) 0 0 / calc(2 * 32px)\n      calc(2 * 32px),\n    radial-gradient(#0000 66%, #c79013 68% 70%, #0000 72%) 0 calc(32px / 2) /\n      32px 32px #295b3f;\n  opacity: 0.5;\n  transition: 0.3s ease;\n}\n\n.card:hover::after {\n  opacity: 0.25;\n}\n\n.cardHeader {\n  text-transform: uppercase;\n  position: relative;\n  width: max-content;\n  font-weight: bold;\n  transition: all 0.5s ease;\n}\n.cardHeader::after {\n  content: \"\";\n  width: calc(100% + 1rem);\n  height: 2.5px;\n  transform: translateX(calc(-100% - 1rem));\n  background: aqua;\n  bottom: -2px;\n  left: 0;\n  position: absolute;\n  opacity: 0;\n}\n\n.details {\n  z-index: 2;\n  display: flex;\n  flex-direction: column;\n  gap: 5px;\n  transform: translateY(95%);\n  transition: all 0.5s ease;\n}\n\n.button {\n  background-color: aqua;\n  color: black;\n  padding: 2.5px 5px;\n  width: max-content;\n  border-radius: 2.5px;\n}\n.card:hover .details {\n  transform: translateY(0%);\n  transition-delay: 0.5s;\n}\n.card:hover .cardHeader::after {\n  transform: translateX(-1rem);\n  transition: 0.5s ease;\n  opacity: 1;\n}\n.card:hover {\n  transform: scale(1.1);\n  border-radius: 15px;\n}\n');

