INSERT INTO `checkboxes` (`ID`, `HTML`, `CSS`) VALUES
(1, '\r\n<label class=\"container\">\r\n  <input type=\"checkbox\">\r\n  <svg viewBox=\"0 0 64 64\" height=\"2em\" width=\"2em\">\r\n    <path d=\"M 0 16 V 56 A 8 8 90 0 0 8 64 H 56 A 8 8 90 0 0 64 56 V 8 A 8 8 90 0 0 56 0 H 8 A 8 8 90 0 0 0 8 V 16 L 32 48 L 64 16 V 8 A 8 8 90 0 0 56 0 H 8 A 8 8 90 0 0 0 8 V 56 A 8 8 90 0 0 8 64 H 56 A 8 8 90 0 0 64 56 V 16\" pathLength=\"575.0541381835938\" class=\"path\"></path>\r\n  </svg>\r\n</label>', '\r\n.container {\r\n  cursor: pointer;\r\n}\r\n\r\n.container input {\r\n  display: none;\r\n}\r\n\r\n.container svg {\r\n  overflow: visible;\r\n}\r\n\r\n.path {\r\n  fill: none;\r\n  stroke: white;\r\n  stroke-width: 6;\r\n  stroke-linecap: round;\r\n  stroke-linejoin: round;\r\n  transition: stroke-dasharray 0.5s ease, stroke-dashoffset 0.5s ease;\r\n  stroke-dasharray: 241 9999999;\r\n  stroke-dashoffset: 0;\r\n}\r\n\r\n.container input:checked ~ svg .path {\r\n  stroke-dasharray: 70.5096664428711 9999999;\r\n  stroke-dashoffset: -262.2723388671875;\r\n}\r\n'),
(2, '\r\n<div id=\"checklist\">\r\n  <input checked=\"\" value=\"1\" name=\"r\" type=\"checkbox\" id=\"01\">\r\n  <label for=\"01\">Bread</label>\r\n  <input value=\"2\" name=\"r\" type=\"checkbox\" id=\"02\">\r\n  <label for=\"02\">Cheese</label>\r\n  <input value=\"3\" name=\"r\" type=\"checkbox\" id=\"03\">\r\n  <label for=\"03\">Coffee</label>\r\n</div>', '\r\n#checklist {\r\n  --background: #fff;\r\n  --text: #414856;\r\n  --check: #4f29f0;\r\n  --disabled: #c3c8de;\r\n  --width: 100px;\r\n  --height: 180px;\r\n  --border-radius: 10px;\r\n  background: var(--background);\r\n  width: var(--width);\r\n  height: var(--height);\r\n  border-radius: var(--border-radius);\r\n  position: relative;\r\n  box-shadow: 0 10px 30px rgba(65, 72, 86, 0.05);\r\n  padding: 30px 85px;\r\n  display: grid;\r\n  grid-template-columns: 30px auto;\r\n  align-items: center;\r\n  justify-content: center;\r\n}\r\n\r\n#checklist label {\r\n  color: var(--text);\r\n  position: relative;\r\n  cursor: pointer;\r\n  display: grid;\r\n  align-items: center;\r\n  width: fit-content;\r\n  transition: color 0.3s ease;\r\n  margin-right: 20px;\r\n}\r\n\r\n#checklist label::before, #checklist label::after {\r\n  content: \"\";\r\n  position: absolute;\r\n}\r\n\r\n#checklist label::before {\r\n  height: 2px;\r\n  width: 8px;\r\n  left: -27px;\r\n  background: var(--check);\r\n  border-radius: 2px;\r\n  transition: background 0.3s ease;\r\n}\r\n\r\n#checklist label:after {\r\n  height: 4px;\r\n  width: 4px;\r\n  top: 8px;\r\n  left: -25px;\r\n  border-radius: 50%;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"] {\r\n  -webkit-appearance: none;\r\n  -moz-appearance: none;\r\n  position: relative;\r\n  height: 15px;\r\n  width: 15px;\r\n  outline: none;\r\n  border: 0;\r\n  margin: 0 15px 0 0;\r\n  cursor: pointer;\r\n  background: var(--background);\r\n  display: grid;\r\n  align-items: center;\r\n  margin-right: 20px;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]::before, #checklist input[type=\"checkbox\"]::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  height: 2px;\r\n  top: auto;\r\n  background: var(--check);\r\n  border-radius: 2px;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]::before {\r\n  width: 0px;\r\n  right: 60%;\r\n  transform-origin: right bottom;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]::after {\r\n  width: 0px;\r\n  left: 40%;\r\n  transform-origin: left bottom;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]:checked::before {\r\n  animation: check-01 0.4s ease forwards;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]:checked::after {\r\n  animation: check-02 0.4s ease forwards;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]:checked + label {\r\n  color: var(--disabled);\r\n  animation: move 0.3s ease 0.1s forwards;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]:checked + label::before {\r\n  background: var(--disabled);\r\n  animation: slice 0.4s ease forwards;\r\n}\r\n\r\n#checklist input[type=\"checkbox\"]:checked + label::after {\r\n  animation: firework 0.5s ease forwards 0.1s;\r\n}\r\n\r\n@keyframes move {\r\n  50% {\r\n    padding-left: 8px;\r\n    padding-right: 0px;\r\n  }\r\n\r\n  100% {\r\n    padding-right: 4px;\r\n  }\r\n}\r\n\r\n@keyframes slice {\r\n  60% {\r\n    width: 100%;\r\n    left: 4px;\r\n  }\r\n\r\n  100% {\r\n    width: 100%;\r\n    left: -2px;\r\n    padding-left: 0;\r\n  }\r\n}\r\n\r\n@keyframes check-01 {\r\n  0% {\r\n    width: 4px;\r\n    top: auto;\r\n    transform: rotate(0);\r\n  }\r\n\r\n  50% {\r\n    width: 0px;\r\n    top: auto;\r\n    transform: rotate(0);\r\n  }\r\n\r\n  51% {\r\n    width: 0px;\r\n    top: 8px;\r\n    transform: rotate(45deg);\r\n  }\r\n\r\n  100% {\r\n    width: 5px;\r\n    top: 8px;\r\n    transform: rotate(45deg);\r\n  }\r\n}\r\n\r\n@keyframes check-02 {\r\n  0% {\r\n    width: 4px;\r\n    top: auto;\r\n    transform: rotate(0);\r\n  }\r\n\r\n  50% {\r\n    width: 0px;\r\n    top: auto;\r\n    transform: rotate(0);\r\n  }\r\n\r\n  51% {\r\n    width: 0px;\r\n    top: 8px;\r\n    transform: rotate(-45deg);\r\n  }\r\n\r\n  100% {\r\n    width: 10px;\r\n    top: 8px;\r\n    transform: rotate(-45deg);\r\n  }\r\n}\r\n\r\n@keyframes firework {\r\n  0% {\r\n    opacity: 1;\r\n    box-shadow: 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0, 0 0 0 -2px #4f29f0;\r\n  }\r\n\r\n  30% {\r\n    opacity: 1;\r\n  }\r\n\r\n  100% {\r\n    opacity: 0;\r\n    box-shadow: 0 -15px 0 0px #4f29f0, 14px -8px 0 0px #4f29f0, 14px 8px 0 0px #4f29f0, 0 15px 0 0px #4f29f0, -14px 8px 0 0px #4f29f0, -14px -8px 0 0px #4f29f0;\r\n  }\r\n}'),
(3, '\r\n<div class=\"heart-container\" title=\"Like\">\r\n            <input type=\"checkbox\" class=\"checkbox\" id=\"Give-It-An-Id\">\r\n            <div class=\"svg-container\">\r\n                <svg viewBox=\"0 0 24 24\" class=\"svg-outline\" xmlns=\"http://www.w3.org/2000/svg\">\r\n                    <path d=\"M17.5,1.917a6.4,6.4,0,0,0-5.5,3.3,6.4,6.4,0,0,0-5.5-3.3A6.8,6.8,0,0,0,0,8.967c0,4.547,4.786,9.513,8.8,12.88a4.974,4.974,0,0,0,6.4,0C19.214,18.48,24,13.514,24,8.967A6.8,6.8,0,0,0,17.5,1.917Zm-3.585,18.4a2.973,2.973,0,0,1-3.83,0C4.947,16.006,2,11.87,2,8.967a4.8,4.8,0,0,1,4.5-5.05A4.8,4.8,0,0,1,11,8.967a1,1,0,0,0,2,0,4.8,4.8,0,0,1,4.5-5.05A4.8,4.8,0,0,1,22,8.967C22,11.87,19.053,16.006,13.915,20.313Z\">\r\n                    </path>\r\n                </svg>\r\n                <svg viewBox=\"0 0 24 24\" class=\"svg-filled\" xmlns=\"http://www.w3.org/2000/svg\">\r\n                    <path d=\"M17.5,1.917a6.4,6.4,0,0,0-5.5,3.3,6.4,6.4,0,0,0-5.5-3.3A6.8,6.8,0,0,0,0,8.967c0,4.547,4.786,9.513,8.8,12.88a4.974,4.974,0,0,0,6.4,0C19.214,18.48,24,13.514,24,8.967A6.8,6.8,0,0,0,17.5,1.917Z\">\r\n                    </path>\r\n                </svg>\r\n                <svg class=\"svg-celebrate\" width=\"100\" height=\"100\" xmlns=\"http://www.w3.org/2000/svg\">\r\n                    <polygon points=\"10,10 20,20\"></polygon>\r\n                    <polygon points=\"10,50 20,50\"></polygon>\r\n                    <polygon points=\"20,80 30,70\"></polygon>\r\n                    <polygon points=\"90,10 80,20\"></polygon>\r\n                    <polygon points=\"90,50 80,50\"></polygon>\r\n                    <polygon points=\"80,80 70,70\"></polygon>\r\n                </svg>\r\n            </div>\r\n        </div>', '\r\n.heart-container {\r\n  --heart-color: rgb(255, 91, 137);\r\n  position: relative;\r\n  width: 50px;\r\n  height: 50px;\r\n  transition: .3s;\r\n}\r\n\r\n.heart-container .checkbox {\r\n  position: absolute;\r\n  width: 100%;\r\n  height: 100%;\r\n  opacity: 0;\r\n  z-index: 20;\r\n  cursor: pointer;\r\n}\r\n\r\n.heart-container .svg-container {\r\n  width: 100%;\r\n  height: 100%;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n}\r\n\r\n.heart-container .svg-outline,\r\n        .heart-container .svg-filled {\r\n  fill: var(--heart-color);\r\n  position: absolute;\r\n}\r\n\r\n.heart-container .svg-filled {\r\n  animation: keyframes-svg-filled 1s;\r\n  display: none;\r\n}\r\n\r\n.heart-container .svg-celebrate {\r\n  position: absolute;\r\n  animation: keyframes-svg-celebrate .5s;\r\n  animation-fill-mode: forwards;\r\n  display: none;\r\n  stroke: var(--heart-color);\r\n  fill: var(--heart-color);\r\n  stroke-width: 2px;\r\n}\r\n\r\n.heart-container .checkbox:checked~.svg-container .svg-filled {\r\n  display: block\r\n}\r\n\r\n.heart-container .checkbox:checked~.svg-container .svg-celebrate {\r\n  display: block\r\n}\r\n\r\n@keyframes keyframes-svg-filled {\r\n  0% {\r\n    transform: scale(0);\r\n  }\r\n\r\n  25% {\r\n    transform: scale(1.2);\r\n  }\r\n\r\n  50% {\r\n    transform: scale(1);\r\n    filter: brightness(1.5);\r\n  }\r\n}\r\n\r\n@keyframes keyframes-svg-celebrate {\r\n  0% {\r\n    transform: scale(0);\r\n  }\r\n\r\n  50% {\r\n    opacity: 1;\r\n    filter: brightness(1.5);\r\n  }\r\n\r\n  100% {\r\n    transform: scale(1.4);\r\n    opacity: 0;\r\n    display: none;\r\n  }\r\n}'),
(4, '\r\n<label class=\"burger\" for=\"burger\">\r\n  <input type=\"checkbox\" id=\"burger\">\r\n  <span></span>\r\n  <span></span>\r\n  <span></span>\r\n</label>', '\r\n.burger {\r\n  position: relative;\r\n  width: 40px;\r\n  height: 30px;\r\n  background: transparent;\r\n  cursor: pointer;\r\n  display: block;\r\n}\r\n\r\n.burger input {\r\n  display: none;\r\n}\r\n\r\n.burger span {\r\n  display: block;\r\n  position: absolute;\r\n  height: 4px;\r\n  width: 100%;\r\n  background: black;\r\n  border-radius: 9px;\r\n  opacity: 1;\r\n  left: 0;\r\n  transform: rotate(0deg);\r\n  transition: .25s ease-in-out;\r\n}\r\n\r\n.burger span:nth-of-type(1) {\r\n  top: 0px;\r\n  transform-origin: left center;\r\n}\r\n\r\n.burger span:nth-of-type(2) {\r\n  top: 50%;\r\n  transform: translateY(-50%);\r\n  transform-origin: left center;\r\n}\r\n\r\n.burger span:nth-of-type(3) {\r\n  top: 100%;\r\n  transform-origin: left center;\r\n  transform: translateY(-100%);\r\n}\r\n\r\n.burger input:checked ~ span:nth-of-type(1) {\r\n  transform: rotate(45deg);\r\n  top: 0px;\r\n  left: 5px;\r\n}\r\n\r\n.burger input:checked ~ span:nth-of-type(2) {\r\n  width: 0%;\r\n  opacity: 0;\r\n}\r\n\r\n.burger input:checked ~ span:nth-of-type(3) {\r\n  transform: rotate(-45deg);\r\n  top: 28px;\r\n  left: 5px;\r\n}'),
(5, '\r\n<label class=\"container\">\r\n  <input checked=\"checked\" type=\"checkbox\">\r\n  <svg viewBox=\"0 0 640 512\" height=\"1em\" xmlns=\"http://www.w3.org/2000/svg\" class=\"microphone-slash\"><path d=\"M38.8 5.1C28.4-3.1 13.3-1.2 5.1 9.2S-1.2 34.7 9.2 42.9l592 464c10.4 8.2 25.5 6.3 33.7-4.1s6.3-25.5-4.1-33.7L472.1 344.7c15.2-26 23.9-56.3 23.9-88.7V216c0-13.3-10.7-24-24-24s-24 10.7-24 24v40c0 21.2-5.1 41.1-14.2 58.7L416 300.8V96c0-53-43-96-96-96s-96 43-96 96v54.3L38.8 5.1zM344 430.4c20.4-2.8 39.7-9.1 57.3-18.2l-43.1-33.9C346.1 382 333.3 384 320 384c-70.7 0-128-57.3-128-128v-8.7L144.7 210c-.5 1.9-.7 3.9-.7 6v40c0 89.1 66.2 162.7 152 174.4V464H248c-13.3 0-24 10.7-24 24s10.7 24 24 24h72 72c13.3 0 24-10.7 24-24s-10.7-24-24-24H344V430.4z\"></path></svg>\r\n    <svg viewBox=\"0 0 384 512\" height=\"1em\" xmlns=\"http://www.w3.org/2000/svg\" class=\"microphone\"><path d=\"M192 0C139 0 96 43 96 96V256c0 53 43 96 96 96s96-43 96-96V96c0-53-43-96-96-96zM64 216c0-13.3-10.7-24-24-24s-24 10.7-24 24v40c0 89.1 66.2 162.7 152 174.4V464H120c-13.3 0-24 10.7-24 24s10.7 24 24 24h72 72c13.3 0 24-10.7 24-24s-10.7-24-24-24H216V430.4c85.8-11.7 152-85.3 152-174.4V216c0-13.3-10.7-24-24-24s-24 10.7-24 24v40c0 70.7-57.3 128-128 128s-128-57.3-128-128V216z\"></path></svg>\r\n</label>', '\r\n.container {\r\n  --color: #a5a5b0;\r\n  --size: 30px;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  position: relative;\r\n  cursor: pointer;\r\n  font-size: var(--size);\r\n  user-select: none;\r\n  fill: var(--color);\r\n}\r\n\r\n.container .microphone-slash {\r\n  position: absolute;\r\n  animation: keyframes-fill .5s;\r\n}\r\n\r\n.container .microphone {\r\n  position: absolute;\r\n  display: none;\r\n  animation: keyframes-fill .5s;\r\n}\r\n\r\n/* ------ On check event ------ */\r\n.container input:checked ~ .microphone-slash {\r\n  display: none;\r\n}\r\n\r\n.container input:checked ~ .microphone {\r\n  display: block;\r\n}\r\n\r\n/* ------ Hide the default checkbox ------ */\r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n/* ------ Animation ------ */\r\n@keyframes keyframes-fill {\r\n  0% {\r\n    transform: rotate(0deg) scale(0);\r\n    opacity: 0;\r\n  }\r\n\r\n  50% {\r\n    transform: rotate(-10deg) scale(1.2);\r\n  }\r\n}'),
(6, '\r\n<div class=\"checkbox-wrapper\">\r\n  <input checked=\"\" type=\"checkbox\" class=\"check\" id=\"check1-61\">\r\n  <label for=\"check1-61\" class=\"label\">\r\n    <svg width=\"45\" height=\"45\" viewBox=\"0 0 95 95\">\r\n      <rect x=\"30\" y=\"20\" width=\"50\" height=\"50\" stroke=\"black\" fill=\"none\"></rect>\r\n      <g transform=\"translate(0,-952.36222)\">\r\n        <path d=\"m 56,963 c -102,122 6,9 7,9 17,-5 -66,69 -38,52 122,-77 -7,14 18,4 29,-11 45,-43 23,-4\" stroke=\"black\" stroke-width=\"3\" fill=\"none\" class=\"path1\"></path>\r\n      </g>\r\n    </svg>\r\n    <span>Checkbox</span>\r\n  </label>\r\n</div>\r\n\r\n\r\n\r\n', '\r\n.checkbox-wrapper input[type=\"checkbox\"] {\r\n  visibility: hidden;\r\n  display: none;\r\n}\r\n\r\n.checkbox-wrapper *,\r\n  .checkbox-wrapper ::after,\r\n  .checkbox-wrapper ::before {\r\n  box-sizing: border-box;\r\n  user-select: none;\r\n}\r\n\r\n.checkbox-wrapper {\r\n  position: relative;\r\n  display: block;\r\n  overflow: hidden;\r\n}\r\n\r\n.checkbox-wrapper .label {\r\n  cursor: pointer;\r\n}\r\n\r\n.checkbox-wrapper .check {\r\n  width: 50px;\r\n  height: 50px;\r\n  position: absolute;\r\n  opacity: 0;\r\n}\r\n\r\n.checkbox-wrapper .label svg {\r\n  vertical-align: middle;\r\n}\r\n\r\n.checkbox-wrapper .path1 {\r\n  stroke-dasharray: 400;\r\n  stroke-dashoffset: 400;\r\n  transition: .5s stroke-dashoffset;\r\n  opacity: 0;\r\n}\r\n\r\n.checkbox-wrapper .check:checked + label svg g path {\r\n  stroke-dashoffset: 0;\r\n  opacity: 1;\r\n}'),
(7, '\r\n<label class=\"container\">\r\n  <input type=\"checkbox\" />\r\n  <div class=\"checkmark\">\r\n    <svg xmlns=\"http://www.w3.org/2000/svg\" class=\"icon No\" viewBox=\"0 0 16 16\">\r\n      <path\r\n        fill-rule=\"evenodd\"\r\n        d=\"M8 0C3.584 0 0 3.584 0 8s3.584 8 8 8c4.408 0 8-3.584 8-8s-3.592-8-8-8zm5.284 3.688a6.802 6.802 0 0 1 1.545 4.251c-.226-.043-2.482-.503-4.755-.217-.052-.112-.096-.234-.148-.355-.139-.33-.295-.668-.451-.99 2.516-1.023 3.662-2.498 3.81-2.69zM8 1.18c1.735 0 3.323.65 4.53 1.718-.122.174-1.155 1.553-3.584 2.464-1.12-2.056-2.36-3.74-2.551-4A6.95 6.95 0 0 1 8 1.18zm-2.907.642A43.123 43.123 0 0 1 7.627 5.77c-3.193.85-6.013.833-6.317.833a6.865 6.865 0 0 1 3.783-4.78zM1.163 8.01V7.8c.295.01 3.61.053 7.02-.971.199.381.381.772.555 1.162l-.27.078c-3.522 1.137-5.396 4.243-5.553 4.504a6.817 6.817 0 0 1-1.752-4.564zM8 14.837a6.785 6.785 0 0 1-4.19-1.44c.12-.252 1.509-2.924 5.361-4.269.018-.009.026-.009.044-.017a28.246 28.246 0 0 1 1.457 5.18A6.722 6.722 0 0 1 8 14.837zm3.81-1.171c-.07-.417-.435-2.412-1.328-4.868 2.143-.338 4.017.217 4.251.295a6.774 6.774 0 0 1-2.924 4.573z\"\r\n      ></path>\r\n    </svg>\r\n    <p class=\"No name\">ball</p>\r\n    <svg\r\n      viewBox=\"0 0 16 16\"\r\n      class=\"icon Yes\"\r\n      xmlns=\"http://www.w3.org/2000/svg\"\r\n    >\r\n      <path\r\n        d=\"M11.5 6.027a.5.5 0 1 1-1 0 .5.5 0 0 1 1 0zm-1.5 1.5a.5.5 0 1 0 0-1 .5.5 0 0 0 0 1zm2.5-.5a.5.5 0 1 1-1 0 .5.5 0 0 1 1 0zm-1.5 1.5a.5.5 0 1 0 0-1 .5.5 0 0 0 0 1zm-6.5-3h1v1h1v1h-1v1h-1v-1h-1v-1h1v-1z\"\r\n      ></path>\r\n      <path\r\n        d=\"M3.051 3.26a.5.5 0 0 1 .354-.613l1.932-.518a.5.5 0 0 1 .62.39c.655-.079 1.35-.117 2.043-.117.72 0 1.443.041 2.12.126a.5.5 0 0 1 .622-.399l1.932.518a.5.5 0 0 1 .306.729c.14.09.266.19.373.297.408.408.78 1.05 1.095 1.772.32.733.599 1.591.805 2.466.206.875.34 1.78.364 2.606.024.816-.059 1.602-.328 2.21a1.42 1.42 0 0 1-1.445.83c-.636-.067-1.115-.394-1.513-.773-.245-.232-.496-.526-.739-.808-.126-.148-.25