  margin: 0 0.25em;\r\n}\r\n.Yes {\r\n  width: 0;\r\n}\r\n.name.Yes {\r\n  display: none;\r\n}\r\n\r\n/* action custom checkbox */\r\n.container:hover .checkmark,\r\n.container:hover .icon,\r\n.container:hover .name {\r\n  transform: scale(calc(1 + var(--anim-scale)));\r\n}\r\n\r\n.container:active .checkmark,\r\n.container:active .icon,\r\n.container:active .name {\r\n  transform: scale(calc(1 - var(--anim-scale) / 2));\r\n  border-radius: calc(var(--base-radius) * 2);\r\n}\r\n.checkmark::before {\r\n  content: \"\";\r\n  opacity: 0.5;\r\n  transform: scale(1);\r\n  border-radius: var(--base-radius);\r\n  position: absolute;\r\n  box-sizing: border-box;\r\n  left: 0;\r\n  top: 0;\r\n  height: 100%;\r\n  width: 100%;\r\n}\r\n.checkmark:hover:before {\r\n  background-color: hsla(0, 0%, 50%, 0.2);\r\n}\r\n.container input:checked + .checkmark:before {\r\n  animation: boon calc(var(--anim-time)) ease;\r\n  animation-delay: calc(var(--anim-time) / 2);\r\n}\r\n\r\n/* When the checkbox is checked*/\r\n.container input:checked + .checkmark {\r\n  --UnChacked-color: var(--chacked-color);\r\n  fill: var(--chacked-font-color);\r\n  color: var(--chacked-font-color);\r\n}\r\n\r\n.container input:checked ~ .checkmark .No {\r\n  width: 0;\r\n}\r\n.container input:checked ~ .checkmark .name.No {\r\n  display: none;\r\n}\r\n\r\n.container input:checked ~ .checkmark .Yes {\r\n  width: var(--icon-size);\r\n}\r\n.container input:checked ~ .checkmark .name.Yes {\r\n  width: auto;\r\n  display: unset;\r\n}\r\n\r\n/*Animation*/\r\n.container,\r\n.checkmark,\r\n.checkmark:after,\r\n.icon,\r\n.checkmark .name {\r\n  transition: all var(--anim-time);\r\n}\r\n\r\n/*Unuse*/\r\n@keyframes icon-rot {\r\n  50% {\r\n    transform: rotateZ(180deg) scale(calc(1 - var(--anim-scale)));\r\n    border-radius: 1em;\r\n  }\r\n  to {\r\n    transform: rotate(360deg);\r\n    border-radius: var(--base-radius);\r\n  }\r\n}\r\n/*Unuse*/\r\n@keyframes boo {\r\n  80% {\r\n    transform: scale(1.4);\r\n  }\r\n  99% {\r\n    transform: scale(1.7);\r\n    border: 2px solid var(--UnChacked-color);\r\n  }\r\n  to {\r\n    transform: scale(0);\r\n  }\r\n}\r\n'),
(8, '\r\n<label class=\"container\">\r\n  <div class=\"simple-text\">Click me!</div>\r\n  <input checked=\"checked\" type=\"checkbox\" />\r\n  <div class=\"checkmark\"></div>\r\n  <div class=\"torch\">\r\n    <div class=\"head\">\r\n      <div class=\"face top\">\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n      </div>\r\n      <div class=\"face left\">\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n      </div>\r\n      <div class=\"face right\">\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n      </div>\r\n    </div>\r\n    <div class=\"stick\">\r\n      <div class=\"side side-left\">\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n      </div>\r\n      <div class=\"side side-right\">\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n        <div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</label>\r\n', '\r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n.container {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  position: relative;\r\n  cursor: pointer;\r\n  user-select: none;\r\n}\r\n\r\n.simple-text {\r\n  position: absolute;\r\n  bottom: -40px;\r\n  width: 120px;\r\n  text-align: center;\r\n  color: white;\r\n  font-size: 16pt;\r\n  font-weight: 800;\r\n  font-family: monospace;\r\n}\r\n\r\n.torch {\r\n  display: flex;\r\n  justify-content: center;\r\n  height: 150px;\r\n}\r\n\r\n.head,\r\n.stick {\r\n  position: absolute;\r\n  width: 30px;\r\n  transform-style: preserve-3d;\r\n  transform: rotateX(-30deg) rotateY(45deg);\r\n}\r\n\r\n.stick {\r\n  position: relative;\r\n  height: 120px;\r\n}\r\n\r\n.face {\r\n  position: absolute;\r\n  transform-style: preserve-3d;\r\n  width: 30px;\r\n  height: 30px;\r\n  display: grid;\r\n  grid-template-columns: 50% 50%;\r\n  grid-template-rows: 50% 50%;\r\n  background-color: #000000;\r\n}\r\n\r\n.top {\r\n  transform: rotateX(90deg) translateZ(15px);\r\n}\r\n\r\n.left {\r\n  transform: rotateY(-90deg) translateZ(15px);\r\n}\r\n\r\n.right {\r\n  transform: rotateY(0deg) translateZ(15px);\r\n}\r\n\r\n.top div,\r\n.left div,\r\n.right div {\r\n  width: 102%;\r\n  height: 102%;\r\n}\r\n\r\n.top div:nth-child(1),\r\n.left div:nth-child(3),\r\n.right div:nth-child(3) {\r\n  background-color: #ffff9760;\r\n}\r\n\r\n.top div:nth-child(2),\r\n.left div:nth-child(1),\r\n.right div:nth-child(1) {\r\n  background-color: #ffd80060;\r\n}\r\n\r\n.top div:nth-child(3),\r\n.left div:nth-child(4),\r\n.right div:nth-child(4) {\r\n  background-color: #ffffff60;\r\n}\r\n\r\n.top div:nth-child(4),\r\n.left div:nth-child(2),\r\n.right div:nth-child(2) {\r\n  background-color: #ff8f0060;\r\n}\r\n\r\n.side {\r\n  position: absolute;\r\n  width: 30px;\r\n  height: 120px;\r\n  display: grid;\r\n  grid-template-columns: 50% 50%;\r\n  grid-template-rows: repeat(8, 12.5%);\r\n  cursor: pointer;\r\n  translate: 0 12px;\r\n}\r\n\r\n.side-left {\r\n  transform: rotateY(-90deg) translateZ(15px) translateY(8px);\r\n}\r\n\r\n.side-right {\r\n  transform: rotateY(0deg) translateZ(15px) translateY(8px);\r\n}\r\n\r\n.side-left div,\r\n.side-right div {\r\n  width: 103%;\r\n  height: 103%;\r\n}\r\n\r\n.side div:nth-child(1) {\r\n  background-color: #443622;\r\n}\r\n\r\n.side div:nth-child(2),\r\n.side div:nth-child(2) {\r\n  background-color: #2e2517;\r\n}\r\n\r\n.side div:nth-child(3),\r\n.side div:nth-child(5) {\r\n  background-color: #4b3b23;\r\n}\r\n\r\n.side div:nth-child(4),\r\n.side div:nth-child(10) {\r\n  background-color: #251e12;\r\n}\r\n\r\n.side div:nth-child(6) {\r\n  background-color: #292115;\r\n}\r\n\r\n.side div:nth-child(7) {\r\n  background-color: #4b3c26;\r\n}\r\n\r\n.side div:nth-child(8) {\r\n  background-color: #292115;\r\n}\r\n\r\n.side div:nth-child(9) {\r\n  background-color: #4b3a21;\r\n}\r\n\r\n.side div:nth-child(11),\r\n.side div:nth-child(15) {\r\n  background-color: #3d311d;\r\n}\r\n\r\n.side div:nth-child(12) {\r\n  background-color: #2c2315;\r\n}\r\n\r\n.side div:nth-child(13) {\r\n  background-color: #493a22;\r\n}\r\n\r\n.side div:nth-child(14) {\r\n  background-color: #2b2114;\r\n}\r\n\r\n.side div:nth-child(16) {\r\n  background-color: #271e10;\r\n}\r\n\r\n.container input:checked ~ .torch .face {\r\n  filter: drop-shadow(0px 0px 2px rgb(255, 255, 255))\r\n    drop-shadow(0px 0px 10px rgba(255, 237, 156, 0.7))\r\n    drop-shadow(0px 0px 25px rgba(255, 227, 101, 0.4));\r\n}\r\n\r\n.container input:checked ~ .torch .top div:nth-child(1),\r\n.container input:checked ~ .torch .left div:nth-child(3),\r\n.container input:checked ~ .torch .right div:nth-child(3) {\r\n  background-color: #ffff97;\r\n}\r\n\r\n.container input:checked ~ .torch .top div:nth-child(2),\r\n.container input:checked ~ .torch .left div:nth-child(1),\r\n.container input:checked ~ .torch .right div:nth-child(1) {\r\n  background-color: #ffd800;\r\n}\r\n\r\n.container input:checked ~ .torch .top div:nth-child(3),\r\n.container input:checked ~ .torch .left div:nth-child(4),\r\n.container input:checked ~ .torch .right div:nth-child(4) {\r\n  background-color: #ffffff;\r\n}\r\n\r\n.container input:checked ~ .torch .top div:nth-child(4),\r\n.container input:checked ~ .torch .left div:nth-child(2),\r\n.container input:checked ~ .torch .right div:nth-child(2) {\r\n  background-color: #ff8f00;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(1) {\r\n  background-color: #7c623e;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(2),\r\n.container input:checked ~ .torch .side div:nth-child(2) {\r\n  background-color: #4c3d26;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(3),\r\n.container input:checked ~ .torch .side div:nth-child(5) {\r\n  background-color: #937344;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(4),\r\n.container input:checked ~ .torch .side div:nth-child(10) {\r\n  background-color: #3c2f1c;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(6) {\r\n  background-color: #423522;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(7) {\r\n  background-color: #9f7f50;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(8) {\r\n  background-color: #403320;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(9) {\r\n  background-color: #977748;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(11),\r\n.container input:checked ~ .torch .side div:nth-child(15) {\r\n  background-color: #675231;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(12) {\r\n  background-color: #3d301d;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(13) {\r\n  background-color: #987849;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(14) {\r\n  background-color: #3b2e1b;\r\n}\r\n\r\n.container input:checked ~ .torch .side div:nth-child(16) {\r\n  background-color: #372a17;\r\n}\r\n'),
(9, '\r\n<div class=\"checkbox-container\">\r\n  <label class=\"ios-checkbox blue\">\r\n    <input type=\"checkbox\" />\r\n    <div class=\"checkbox-wrapper\">\r\n      <div class=\"checkbox-bg\"></div>\r\n      <svg fill=\"none\" viewBox=\"0 0 24 24\" class=\"checkbox-icon\">\r\n        <path\r\n          stroke-linejoin=\"round\"\r\n          stroke-linecap=\"round\"\r\n          stroke-width=\"3\"\r\n          stroke=\"currentColor\"\r\n          d=\"M4 12L10 18L20 6\"\r\n          class=\"check-path\"\r\n        ></path>\r\n      </svg>\r\n    </div>\r\n  </label>\r\n\r\n  <label class=\"ios-checkbox green\">\r\n    <input type=\"checkbox\" />\r\n    <div class=\"checkbox-wrapper\">\r\n      <div class=\"checkbox-bg\"></div>\r\n      <svg fill=\"none\" viewBox=\"0 0 24 24\" class=\"checkbox-icon\">\r\n        <path\r\n          stroke-linejoin=\"round\"\r\n          stroke-linecap=\"round\"\r\n          stroke-width=\"3\"\r\n          stroke=\"currentColor\"\r\n          d=\"M4 12L10 18L20 6\"\r\n          class=\"check-path\"\r\n        ></path>\r\n      </svg>\r\n    </div>\r\n  </label>\r\n\r\n  <label class=\"ios-checkbox purple\">\r\n    <input type=\"checkbox\" />\r\n    <div class=\"checkbox-wrapper\">\r\n      <div class=\"checkbox-bg\"></div>\r\n      <svg fill=\"none\" viewBox=\"0 0 24 24\" class=\"checkbox-icon\">\r\n        <path\r\n          stroke-linejoin=\"round\"\r\n          stroke-linecap=\"round\"\r\n          stroke-width=\"3\"\r\n          stroke=\"currentColor\"\r\n          d=\"M4 12L10 18L20 6\"\r\n          class=\"check-path\"\r\n        ></path>\r\n      </svg>\r\n    </div>\r\n  </label>\r\n\r\n  <label class=\"ios-checkbox red\">\r\n    <input type=\"checkbox\" />\r\n    <div class=\"checkbox-wrapper\">\r\n      <div class=\"checkbox-bg\"></div>\r\n      <svg fill=\"none\" viewBox=\"0 0 24 24\" class=\"checkbox-icon\">\r\n        <path\r\n          stroke-linejoin=\"round\"\r\n          stroke-linecap=\"round\"\r\n          stroke-width=\"3\"\r\n          stroke=\"currentColor\"\r\n          d=\"M4 12L10 18L20 6\"\r\n          class=\"check-path\"\r\n        ></path>\r\n      </svg>\r\n    </div>\r\n  </label>\r\n</div>\r\n', '\r\n.checkbox-container {\r\n  display: flex;\r\n  gap: 20px;\r\n  padding: 20px;\r\n  background: #f8fafc;\r\n  border-radius: 16px;\r\n  box-shadow:\r\n    0 4px 6px -1px rgba(0, 0, 0, 0.1),\r\n    0 2px 4px -2px rgba(0, 0, 0, 0.05);\r\n}\r\n\r\n.ios-checkbox {\r\n  --checkbox-size: 28px;\r\n  --checkbox-color: #3b82f6;\r\n  --checkbox-bg: #dbeafe;\r\n  --checkbox-border: #93c5fd;\r\n\r\n  position: relative;\r\n  display: inline-block;\r\n  cursor: pointer;\r\n  user-select: none;\r\n  -webkit-tap-highlight-color: transparent;\r\n}\r\n\r\n.ios-checkbox input {\r\n  display: none;\r\n}\r\n\r\n.checkbox-wrapper {\r\n  position: relative;\r\n  width: var(--checkbox-size);\r\n  height: var(--checkbox-size);\r\n  border-radius: 8px;\r\n  transition: transform 0.2s ease;\r\n}\r\n\r\n.checkbox-bg {\r\n  position: absolute;\r\n  inset: 0;\r\n  border-radius: 8px;\r\n  border: 2px solid var(--checkbox-border);\r\n  background: white;\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.checkbox-icon {\r\n  position: absolute;\r\n  inset: 0;\r\n  margin: auto;\r\n  width: 80%;\r\n  height: 80%;\r\n  color: white;\r\n  transform: scale(0);\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.check-path {\r\n  stroke-dasharray: 40;\r\n  stroke-dashoffset: 40;\r\n  transition: stroke-dashoffset 0.3s ease 0.1s;\r\n}\r\n\r\n/* Checked State */\r\n.ios-checkbox input:checked + .checkbox-wrapper .checkbox-bg {\r\n  background: var(--checkbox-color);\r\n  border-color: var(--checkbox-color);\r\n}\r\n\r\n.ios-checkbox input:checked + .checkbox-wrapper .checkbox-icon {\r\n  transform: scale(1);\r\n}\r\n\r\n.ios-checkbox input:checked + .checkbox-wrapper .check-path {\r\n  stroke-dashoffset: 0;\r\n}\r\n\r\n/* Hover Effects */\r\n.ios-checkbox:hover .checkbox-wrapper {\r\n  transform: scale(1.05);\r\n}\r\n\r\n/* Active Animation */\r\n.ios-checkbox:active .checkbox-wrapper {\r\n  transform: scale(0.95);\r\n}\r\n\r\n/* Focus Styles */\r\n.ios-checkbox input:focus + .checkbox-wrapper .checkbox-bg {\r\n  box-shadow: 0 0 0 4px var(--checkbox-bg);\r\n}\r\n\r\n/* Color Themes */\r\n.ios-checkbox.blue {\r\n  --checkbox-color: #3b82f6;\r\n  --checkbox-bg: #dbeafe;\r\n  --checkbox-border: #93c5fd;\r\n}\r\n\r\n.ios-checkbox.green {\r\n  --checkbox-color: #10b981;\r\n  --checkbox-bg: #d1fae5;\r\n  --checkbox-border: #6ee7b7;\r\n}\r\n\r\n.ios-checkbox.purple {\r\n  --checkbox-color: #8b5cf6;\r\n  --checkbox-bg: #ede9fe;\r\n  --checkbox-border: #c4b5fd;\r\n}\r\n\r\n.ios-checkbox.red {\r\n  --checkbox-color: #ef4444;\r\n  --checkbox-bg: #fee2e2;\r\n  --checkbox-border: #fca5a5;\r\n}\r\n\r\n/* Animation */\r\n@keyframes bounce {\r\n  0%,\r\n  100% {\r\n    transform: scale(1);\r\n  }\r\n  50% {\r\n    transform: scale(1.1);\r\n  }\r\n}\r\n\r\n.ios-checkbox input:checked + .checkbox-wrapper {\r\n  animation: bounce 0.3s cubic-bezier(0.4, 0, 0.2, 1);\r\n}\r\n'),
(10, '\r\n<div class=\"advanced-checkbox\">\r\n  <input type=\"checkbox\" id=\"advancedCheckbox\" />\r\n  <label for=\"advancedCheckbox\">\r\n    <div class=\"box\">\r\n      <div class=\"front\"></div>\r\n      <div class=\"back\"></div>\r\n      <div class=\"left\"></div>\r\n      <div class=\"right\"></div>\r\n      <div class=\"top\"></div>\r\n      <div class=\"bottom\"></div>\r\n    </div>\r\n    <span class=\"checkmark\"></span>\r\n  </label>\r\n</div>\r\n', '\r\n.advanced-checkbox {\r\n  display: inline-block;\r\n  perspective: 1000px; \r\n}\r\n\r\n.advanced-checkbox input {\r\n  display: none;\r\n}\r\n\r\n.advanced-checkbox label {\r\n  position: relative;\r\n  display: inline-block;\r\n  width: 80px;\r\n  height: 80px;\r\n  cursor: pointer;\r\n}\r\n\r\n.box {\r\n  position: relative;\r\n  width: 100%;\r\n  height: 100%;\r\n  transform-style: preserve-3d;\r\n  transform: rotateX(0deg) rotateY(0deg);\r\n  transition: transform 1s cubic-bezier(0.68, -0.55, 0.27, 1.55);\r\n}\r\n\r\n.advanced-checkbox input:checked + label .box {\r\n  transform: rotateX(360deg) rotateY(360deg);\r\n}\r\n\r\n.box > div {\r\n  position: absolute;\r\n  width: 100%;\r\n  height: 100%;\r\n  background: linear-gradient(145deg, #333, #111);\r\n  border-radius: 12px;\r\n  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.5);\r\n}\r\n\r\n.front {\r\n  transform: translateZ(40px);\r\n}\r\n.back {\r\n  transform: rotateY(180deg) translateZ(40px);\r\n}\r\n.left {\r\n  transform: rotateY(-90deg) translateZ(40px);\r\n}\r\n.right {\r\n  transform: rotateY(90deg) translateZ(40px);\r\n}\r\n.top {\r\n  transform: rotateX(90deg) translateZ(40px);\r\n}\r\n.bottom {\r\n  transform: rotateX(-90deg) translateZ(40px);\r\n}\r\n\r\n.checkmark {\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  width: 0;\r\n  height: 0;\r\n  border: solid #00ff99;\r\n  border-width: 0 6px 6px 0;\r\n  transform: translate(-50%, -50%) rotate(45deg);\r\n  opacity: 0;\r\n  transition:\r\n    width 0.3s ease,\r\n    height 0.3s ease,\r\n    opacity 0.3s ease;\r\n}\r\n\r\n.advanced-checkbox input:checked + label .checkmark {\r\n  width: 24px;\r\n  height: 48px;\r\n  opacity: 1;\r\n  transition-delay: 1s; \r\n}\r\n'),
(11, '\r\n<label class=\"container\">\r\n  <input type=\"checkbox\">\r\n  <svg id=\"Glyph\" version=\"1.1\" viewBox=\"0 0 32 32\" xml:space=\"preserve\" xmlns=\"http://www.w3.org/2000/svg\" xmlns:xlink=\"http://www.w3.org/1999/xlink\"><path d=\"M29.845,17.099l-2.489,8.725C26.989,27.105,25.804,28,24.473,28H11c-0.553,0-1-0.448-1-1V13  c0-0.215,0.069-0.425,0.198-0.597l5.392-7.24C16.188,4.414,17.05,4,17.974,4C19.643,4,21,5.357,21,7.026V12h5.002  c1.265,0,2.427,0.579,3.188,1.589C29.954,14.601,30.192,15.88,29.845,17.099z\" id=\"XMLID_254_\"></path><path d=\"M7,12H3c-0.553,0-1,0.448-1,1v14c0,0.552,0.447,1,1,1h4c0.553,0,1-0.448,1-1V13C8,12.448,7.553,12,7,12z   M5,25.5c-0.828,0-1.5-0.672-1.5-1.5c0-0.828,0.672-1.5,1.5-1.5c0.828,0,1.5,0.672,1.5,1.5C6.5,24.828,5.828,25.5,5,25.5z\" id=\"XMLID_256_\"></path></svg>\r\n</label>', '\r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n.container {\r\n  display: block;\r\n  position: relative;\r\n  cursor: pointer;\r\n  user-select: none;\r\n}\r\n\r\nsvg {\r\n  position: relative;\r\n  top: 0;\r\n  left: 0;\r\n  height: 50px;\r\n  width: 50px;\r\n  transition: all 0.3s;\r\n  fill: #666;\r\n}\r\n\r\nsvg:hover {\r\n  transform: scale(1.1) rotate(-10deg);\r\n}\r\n\r\n.container input:checked ~ svg {\r\n  fill: #2196F3;\r\n}\r\n'),
(12, '\r\n<div class=\"checkbox-wrapper-23\">\r\n  <input type=\"checkbox\" id=\"check-23\">\r\n  <label for=\"check-23\" style=\"--size: 30px\">\r\n    <svg viewBox=\"0,0,50,50\">\r\n      <path d=\"M5 30 L 20 45 L 45 5\"></path>\r\n    </svg>\r\n  </label>\r\n</div>', '.checkbox-wrapper-23 *,\n  .checkbox-wrapper-23 *:after,\n  .checkbox-wrapper-23 *:before {\n  box-sizing: border-box;\n}\n\n.checkbox-wrapper-23 input {\n  position: absolute;\n  opacity: 0;\n}\n\n.checkbox-wrapper-23 input:checked + label svg path {\n  stroke-dashoffset: 0;\n}\n\n.checkbox-wrapper-23 input:focus + label {\n  transform: scale(1.03);\n}\n\n.checkbox-wrapper-23 input + label {\n  display: block;\n  border: 2px solid rgb(253, 237, 237);\n  width: var(--size);\n  height: var(--size);\n  border-radius: 6px;\n  cursor: pointer;\n  transition: all .2s ease;\n}\n\n.checkbox-wrapper-23 input + label:active {\n  transform: scale(1.05);\n  border-radius: 12px;\n}\n\n.checkbox-wrapper-23 input + label svg {\n  pointer-events: none;\n  padding: 5%;\n}\n\n.checkbox-wrapper-23 input + label svg path {\n  fill: none;\n  stroke: rgb(247, 247, 247);\n  stroke-width: 4px;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n  stroke-dasharray: 100;\n  stroke-dashoffset: 101;\n  transition: all 250ms cubic-bezier(1,0,.37,.91);\n}\n'),
(13, '<label class=\"container\">\n  <input type=\"checkbox\" checked=\"checked\" />\n  <svg\n    class=\"save-regular\"\n    xmlns=\"http://www.w3.org/2000/svg\"\n    height=\"1em\"\n    viewBox=\"0 0 384 512\"\n  >\n    <path\n      d=\"M0 48C0 21.5 21.5 0 48 0l0 48V441.4l130.1-92.9c8.3-6 19.6-6 27.9 0L336 441.4V48H48V0H336c26.5 0 48 21.5 48 48V488c0 9-5 17.2-13 21.3s-17.6 3.4-24.9-1.8L192 397.5 37.9 507.5c-7.3 5.2-16.9 5.9-24.9 1.8S0 497 0 488V48z\"\n    ></path>\n  </svg>\n  <svg\n    class=\"save-solid\"\n    xmlns=\"http://www.w3.org/2000/svg\"\n    height=\"1em\"\n    viewBox=\"0 0 384 512\"\n  >\n    <path\n      d=\"M0 48V487.7C0 501.1 10.9 512 24.3 512c5 0 9.9-1.5 14-4.4L192 400 345.7 507.6c4.1 2.9 9 4.4 14 4.4c13.4 0 24.3-10.9 24.3-24.3V48c0-26.5-21.5-48-48-48H48C21.5 0 0 21.5 0 48z\"\n    ></path>\n  </svg>\n</label>\n', '.container {\n  --color: #ffff00;\n  --size: 30px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n  cursor: pointer;\n  font-size: var(--size);\n  user-select: none;\n  fill: var(--color);\n}\n\n.container .save-regular {\n  position: absolute;\n  animation: keyframes-fill 0.5s;\n  transform-origin: top;\n}\n\n.container .save-solid {\n  position: absolute;\n  animation: keyframes-fill 0.5s;\n  display: none;\n  transform-origin: top;\n}\n\n/* ------ On check event ------ */\n.container input:checked ~ .save-regular {\n  display: none;\n}\n\n.container input:checked ~ .save-solid {\n  display: block;\n}\n\n/* ------ Hide the default checkbox ------ */\n.container input {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n/* ------ Animation ------ */\n@keyframes keyframes-fill {\n  0% {\n    transform: scale(0);\n    opacity: 0;\n  }\n\n  50% {\n    transform: scaleY(1.2);\n  }\n}\n'),
(14, '\r\n<input class=\"dial-checkbox\" type=\"checkbox\" />\r\n', '\r\nbody {\r\n  background: #ede4d1;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  height: 100vh;\r\n}\r\n\r\n.dial-checkbox {\r\n  appearance: none;\r\n  width: 60px;\r\n  height: 60px;\r\n  background: radial-gradient(circle at center, #d7c7b0, #b49a7d);\r\n  border: 4px solid #5a3d2b;\r\n  border-radius: 50%;\r\n  position: relative;\r\n  box-shadow:\r\n    inset -3px -3px 6px #fff,\r\n    inset 3px 3px 6px #a78c6c,\r\n    0 4px 10px rgba(0, 0, 0, 0.2);\r\n  cursor: pointer;\r\n  transition: 0.4s ease;\r\n}\r\n\r\n.dial-checkbox::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  width: 6px;\r\n  height: 20px;\r\n  background: #5a3d2b;\r\n  border-radius: 3px;\r\n  transform-origin: center bottom;\r\n  transform: translate(-50%, -100%) rotate(-45deg);\r\n  transition: 0.4s ease;\r\n}\r\n\r\n.dial-checkbox:checked::before {\r\n  transform: translate(-50%, -100%) rotate(45deg);\r\n  background: #2c1e14;\r\n}\r\n\r\n.dial-checkbox:hover {\r\n  box-shadow:\r\n    inset -2px -2px 4px #fff,\r\n    inset 2px 2px 4px #8b7156,\r\n    0 6px 14px rgba(0, 0, 0, 0.3);\r\n  transform: scale(1.05);\r\n}\r\n'),
(15, '\r\n<div class=\"container\">\r\n      <label>\r\n        <input class=\"play-btn\" type=\"checkbox\">\r\n        <div class=\"play-icon\"></div>\r\n        <div class=\"pause-icon\"></div>\r\n      </label>\r\n    </div>', '\r\n.container {\r\n  width: 120px;\r\n  height: 120px;\r\n  position: relative;\r\n  border-radius: 50%;\r\n}\r\n\r\n.play-btn {\r\n  position: absolute;\r\n  appearance: none;\r\n  width: 100%;\r\n  height: 100%;\r\n  border-radius: 50%;\r\n  background: conic-gradient(#ff6347, #ff6347);\r\n  cursor: pointer;\r\n  outline: none;\r\n}\r\n\r\n.play-btn::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 93%;\r\n  height: 93%;\r\n  background-color: #000;\r\n  border-radius: 50%;\r\n  left: 50%;\r\n  top: 50%;\r\n  transform: translate(-50%, -50%);\r\n}\r\n\r\n.play-btn:checked {\r\n  animation: borderAnimate 700ms ease-in-out 1;\r\n  animation-fill-mode: forwards;\r\n}\r\n\r\n@keyframes borderAnimate {\r\n  0% {\r\n    transform: rotate(0);\r\n    background: conic-gradient(#ff6347, transparent 20%);\r\n  }\r\n\r\n  80% {\r\n    background: conic-gradient(#ff6347, transparent 90%);\r\n  }\r\n\r\n  100% {\r\n    transform: rotate(360deg);\r\n    background: conic-gradient(#ff6347, #ff6347);\r\n  }\r\n}\r\n\r\n.play-icon {\r\n  position: absolute;\r\n  width: 40px;\r\n  height: 40px;\r\n  left: 60%;\r\n  top: 50%;\r\n  background-color: #ff6347;\r\n  transform: translate(-60%, -50%) rotate(90deg);\r\n  clip-path: polygon(50% 15%, 0% 100%, 100% 100%);\r\n  transition: all 400ms ease-in-out;\r\n  cursor: pointer;\r\n}\r\n\r\n.play-btn:checked + .play-icon {\r\n  clip-path: polygon(0 100%, 0% 100%, 100% 100%);\r\n}\r\n\r\n.pause-icon {\r\n  position: absolute;\r\n  width: 40px;\r\n  height: 40px;\r\n  left: 50%;\r\n  top: 50%;\r\n  transform: translate(-50%, -50%);\r\n  cursor: pointer;\r\n}\r\n\r\n.pause-icon::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 0%;\r\n  height: 100%;\r\n  background-color: #ff6347;\r\n  left: 0;\r\n}\r\n\r\n.pause-icon::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 0;\r\n  height: 100%;\r\n  background-color: #ff6347;\r\n  right: 0;\r\n}\r\n\r\n.play-btn:checked ~ .pause-icon::before {\r\n  animation: reveal 300ms ease-in-out 350ms 1;\r\n  animation-fill-mode: forwards;\r\n}\r\n\r\n.play-btn:checked ~ .pause-icon::after {\r\n  animation: reveal 300ms ease-in-out 600ms 1;\r\n  animation-fill-mode: forwards;\r\n}\r\n\r\n@keyframes reveal {\r\n  0% {\r\n    width: 0;\r\n  }\r\n\r\n  100% {\r\n    width: 35%;\r\n  }\r\n}'),
(16, '\r\n<div class=\"customCheckBoxHolder\">\r\n  <input class=\"customCheckBoxInput\" id=\"cCB1\" type=\"checkbox\" />\r\n  <label class=\"customCheckBoxWrapper\" for=\"cCB1\">\r\n    <div class=\"customCheckBox\">\r\n      <div class=\"inner\">One</div>\r\n    </div>\r\n  </label>\r\n\r\n  <input class=\"customCheckBoxInput\" id=\"cCB2\" type=\"checkbox\" />\r\n  <label class=\"customCheckBoxWrapper\" for=\"cCB2\">\r\n    <div class=\"customCheckBox\">\r\n      <div class=\"inner\">Two</div>\r\n    </div>\r\n  </label>\r\n\r\n  <input class=\"customCheckBoxInput\" id=\"cCB3\" type=\"checkbox\" />\r\n  <label class=\"customCheckBoxWrapper\" for=\"cCB3\">\r\n    <div class=\"customCheckBox\">\r\n      <div class=\"inner\">Three</div>\r\n    </div>\r\n  </label>\r\n</div>\r\n', '\r\n.customCheckBoxHolder {\r\n  margin: 5px;\r\n  display: flex;\r\n  flex-direction: column; /* Stack items vertically */\r\n  align-items: center; /* Center items horizontally */\r\n}\r\n\r\n.customCheckBox {\r\n  width: 100%; /* Ensures each checkbox has the same width */\r\n  position: relative;\r\n  overflow: hidden;\r\n  cursor: pointer;\r\n  user-select: none;\r\n  padding: 2px 8px;\r\n  background-color: rgba(0, 0, 0, 0.16);\r\n  border-radius: 0px;\r\n  color: rgba(255, 255, 255, 0.7);\r\n  transition-timing-function: cubic-bezier(0.25, 0.8, 0.25, 1);\r\n  transition-duration: 300ms;\r\n  transition-property: color, background-color, box-shadow;\r\n  display: flex;\r\n  height: 32px;\r\n  align-items: center;\r\n  box-shadow:\r\n    rgba(0, 0, 0, 0.15) 0px 2px 1px 0px inset,\r\n    rgba(255, 255, 255, 0.17) 0px 1px 1px 0px;\r\n  outline: none;\r\n  justify-content: center;\r\n  min-width: 55px;\r\n}\r\n\r\n.customCheckBox:hover {\r\n  background-color: #2c2c2c;\r\n  color: white;\r\n  box-shadow:\r\n    rgba(0, 0, 0, 0.23) 0px -4px 1px 0px inset,\r\n    rgba(255, 255, 255, 0.17) 0px -1px 1px 0px,\r\n    rgba(0, 0, 0, 0.17) 0px 2px 4px 1px;\r\n}\r\n\r\n.customCheckBox .inner {\r\n  font-size: 18px;\r\n  font-weight: 900;\r\n  pointer-events: none;\r\n  transition-timing-function: cubic-bezier(0.25, 0.8, 0.25, 1);\r\n  transition-duration: 300ms;\r\n  transition-property: transform;\r\n  transform: translateY(0px);\r\n}\r\n\r\n.customCheckBox:hover .inner {\r\n  transform: translateY(-2px);\r\n}\r\n\r\n.customCheckBoxWrapper {\r\n  width: 100%; /* Ensures each wrapper takes full width of the holder */\r\n}\r\n\r\n/* Multiple Checkboxes can be chained together for a radio input */\r\n.customCheckBoxWrapper:first-of-type .customCheckBox {\r\n  border-top-left-radius: 5px;\r\n  border-top-right-radius: 5px;\r\n  border-right: 0px;\r\n}\r\n\r\n.customCheckBoxWrapper:last-of-type .customCheckBox {\r\n  border-bottom-right-radius: 5px;\r\n  border-bottom-left-radius: 5px;\r\n  border-left: 0px;\r\n}\r\n\r\n.customCheckBoxInput {\r\n  display: none;\r\n}\r\n\r\n.customCheckBoxInput:checked + .customCheckBoxWrapper .customCheckBox {\r\n  background-color: #2d6737;\r\n  color: white;\r\n  box-shadow:\r\n    rgba(0, 0, 0, 0.23) 0px -4px 1px 0px inset,\r\n    rgba(255, 255, 255, 0.17) 0px -1px 1px 0px,\r\n    rgba(0, 0, 0, 0.17) 0px 2px 4px 1px;\r\n}\r\n\r\n.customCheckBoxInput:checked + .customCheckBoxWrapper .customCheckBox .inner {\r\n  transform: translateY(-2px);\r\n}\r\n\r\n.customCheckBoxInput:checked + .customCheckBoxWrapper .customCheckBox:hover {\r\n  background-color: #34723f;\r\n  box-shadow:\r\n    rgba(0, 0, 0, 0.26) 0px -4px 1px 0px inset,\r\n    rgba(255, 255, 255, 0.17) 0px -1px 1px 0px,\r\n    rgba(0, 0, 0, 0.15) 0px 3px 6px 2px;\r\n}\r\n\r\n.customCheckBoxWrapper .customCheckBox:hover .inner {\r\n  transform: translateY(-2px);\r\n}\r\n'),
(17, '\r\n<div class=\"uv-checkbox-wrapper\">\r\n  <input type=\"checkbox\" id=\"uv-checkbox\" class=\"uv-checkbox\" />\r\n  <label for=\"uv-checkbox\" class=\"uv-checkbox-label\">\r\n    <div class=\"uv-checkbox-icon\">\r\n      <svg viewBox=\"0 0 24 24\" class=\"uv-checkmark\">\r\n        <path d=\"M4.1,12.7 9,17.6 20.3,6.3\" fill=\"none\"></path>\r\n      </svg>\r\n    </div>\r\n    <span class=\"uv-checkbox-text\">Check me!</span>\r\n  </label>\r\n</div>\r\n', '\r\n.uv-checkbox-wrapper {\r\n  display: inline-block;\r\n}\r\n\r\n.uv-checkbox {\r\n  display: none;\r\n}\r\n\r\n.uv-checkbox-label {\r\n  display: flex;\r\n  align-items: center;\r\n  cursor: pointer;\r\n}\r\n\r\n.uv-checkbox-icon {\r\n  position: relative;\r\n  width: 2em;\r\n  height: 2em;\r\n  border: 2px solid #ccc;\r\n  border-radius: 30% 70% 70% 30% / 30% 30% 70% 70%;\r\n  transition: border-color 0.3s ease, border-radius 0.3s ease;\r\n}\r\n\r\n.uv-checkmark {\r\n  position: absolute;\r\n  top: 0.1em;\r\n  left: 0.1em;\r\n  width: 1.6em;\r\n  height: 1.6em;\r\n  fill: none;\r\n  stroke: #fff;\r\n  stroke-width: 2;\r\n  stroke-linecap: round;\r\n  stroke-linejoin: round;\r\n  stroke-dasharray: 24;\r\n  stroke-dashoffset: 24;\r\n  transition: stroke-dashoffset 0.5s cubic-bezier(0.45, 0.05, 0.55, 0.95);\r\n}\r\n\r\n.uv-checkbox-text {\r\n  margin-left: 0.5em;\r\n  transition: color 0.3s ease;\r\n}\r\n\r\n.uv-checkbox:checked + .uv-checkbox-label .uv-checkbox-icon {\r\n  border-color: #6c5ce7;\r\n  border-radius: 70% 30% 30% 70% / 70% 70% 30% 30%;\r\n  background-color: #6c5ce7;\r\n}\r\n\r\n.uv-checkbox:checked + .uv-checkbox-label .uv-checkmark {\r\n  stroke-dashoffset: 0;\r\n}\r\n\r\n.uv-checkbox:checked + .uv-checkbox-label .uv-checkbox-text {\r\n  color: #6c5ce7;\r\n}\r\n');
INSERT INTO `checkboxes` (`ID`, `HTML`, `CSS`) VALUES
(18, '\r\n<label class=\"container\">\r\n  <input checked=\"checked\" type=\"checkbox\" />\r\n  <svg\r\n    fill=\"red\"\r\n    viewBox=\"0 0 448 512\"\r\n    height=\"1em\"\r\n    xmlns=\"http://www.w3.org/2000/svg\"\r\n    class=\"bell-regular\"\r\n  >\r\n    <path\r\n      d=\"M224 0c-17.7 0-32 14.3-32 32V49.9C119.5 61.4 64 124.2 64 200v33.4c0 45.4-15.5 89.5-43.8 124.9L5.3 377c-5.8 7.2-6.9 17.1-2.9 25.4S14.8 416 24 416H424c9.2 0 17.6-5.3 21.6-13.6s2.9-18.2-2.9-25.4l-14.9-18.6C399.5 322.9 384 278.8 384 233.4V200c0-75.8-55.5-138.6-128-150.1V32c0-17.7-14.3-32-32-32zm0 96h8c57.4 0 104 46.6 104 104v33.4c0 47.9 13.9 94.6 39.7 134.6H72.3C98.1 328 112 281.3 112 233.4V200c0-57.4 46.6-104 104-104h8zm64 352H224 160c0 17 6.7 33.3 18.7 45.3s28.3 18.7 45.3 18.7s33.3-6.7 45.3-18.7s18.7-28.3 18.7-45.3z\"\r\n    ></path>\r\n  </svg>\r\n  <svg\r\n    fill=\"green\"\r\n    viewBox=\"0 0 448 512\"\r\n    height=\"1em\"\r\n    xmlns=\"http://www.w3.org/2000/svg\"\r\n    class=\"bell-solid\"\r\n  >\r\n    <path\r\n      d=\"M224 0c-17.7 0-32 14.3-32 32V51.2C119 66 64 130.6 64 208v18.8c0 47-17.3 92.4-48.5 127.6l-7.4 8.3c-8.4 9.4-10.4 22.9-5.3 34.4S19.4 416 32 416H416c12.6 0 24-7.4 29.2-18.9s3.1-25-5.3-34.4l-7.4-8.3C401.3 319.2 384 273.9 384 226.8V208c0-77.4-55-142-128-156.8V32c0-17.7-14.3-32-32-32zm45.3 493.3c12-12 18.7-28.3 18.7-45.3H224 160c0 17 6.7 33.3 18.7 45.3s28.3 18.7 45.3 18.7s33.3-6.7 45.3-18.7z\"\r\n    ></path></svg\r\n></label>\r\n', '\r\n.container {\r\n  --color: #a5a5b0;\r\n  --size: 30px;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  position: relative;\r\n  cursor: pointer;\r\n  font-size: var(--size);\r\n  user-select: none;\r\n  fill: var(--color);\r\n}\r\n\r\n.container .bell-regular {\r\n  position: absolute;\r\n  animation: keyframes-fill 0.5s;\r\n}\r\n\r\n.container .bell-solid {\r\n  position: absolute;\r\n  display: none;\r\n  animation: keyframes-fill 0.5s;\r\n  color: red;\r\n}\r\n\r\n.container input:checked ~ .bell-regular {\r\n  display: none;\r\n}\r\n\r\n.container input:checked ~ .bell-solid {\r\n  display: block;\r\n}\r\n\r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n@keyframes keyframes-fill {\r\n  0% {\r\n    opacity: 0;\r\n  }\r\n\r\n  25% {\r\n    transform: rotate(25deg);\r\n  }\r\n\r\n  50% {\r\n    transform: rotate(-20deg) scale(1.2);\r\n  }\r\n\r\n  75% {\r\n    transform: rotate(15deg);\r\n  }\r\n}\r\n'),
(19, '\r\n<div class=\"wrapper\">\r\n  <input class=\"hidden-trigger\" id=\"toogle\" type=\"checkbox\">\r\n  <label class=\"circle\" for=\"toogle\">\r\n<svg viewBox=\"0 0 48 48\" version=\"1.1\" xml:space=\"preserve\" height=\"48\" width=\"48\" xmlns:xlink=\"http://www.w3.org/1999/xlink\" xmlns=\"http://www.w3.org/2000/svg\" class=\"svg\">\r\n    <image xlink:href=\"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAADAAAAAwCAQAAAD9CzEMAAAAbElEQVR4Ae3XwQnFQAiE4eVVsGAP1mkPFjwvQvYSWCQYCYGZv4Dv5MGB5ghcIiDQI+kCftCzNsAR8y5gYu2rwCBAgMBTgEC3rek2yQEtAZoDjso8AyaKexmIDJUZD40AAQIE0gwx449GgMC9/t0b7GTsa7J+AAAAAElFTkSuQmCC\" height=\"48\" width=\"48\"></image>\r\n  </svg>\r\n  </label>\r\n  \r\n  <div class=\"subs\">\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub1\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub1\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub2\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub2\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub3\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub3\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub4\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub4\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub5\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub5\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub6\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub6\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub7\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub7\"></label>\r\n    </button>\r\n    <button class=\"sub-circle\">\r\n      <input class=\"hidden-sub-trigger\" id=\"sub8\" type=\"radio\" name=\"sub-circle\" value=\"1\">\r\n      <label for=\"sub8\"></label>\r\n    </button>\r\n   </div>\r\n</div>', '\r\nfooter .demo {\r\n  position: absolute;\r\n  bottom: 10px;\r\n  width: 500px;\r\n  margin: 0 auto;\r\n}\r\n\r\nfooter .demo a {\r\n  text-align: center;\r\n  color: #000;\r\n  text-decoration: none;\r\n  font-weight: 100;\r\n  border-bottom: 1px solid #000;\r\n}\r\n\r\n.wrapper {\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n  width: 60px;\r\n  height: 60px;\r\n}\r\n\r\n.circle {\r\n  display: block;\r\n  position: relative;\r\n  padding: 0;\r\n  z-index: 98;\r\n  margin: 0 auto;\r\n  -webkit-box-shadow: 0 6px 10px 0 rgba(0, 0, 0, 0.3);\r\n  box-shadow: 0 6px 10px 0 rgba(0, 0, 0, 0.3);\r\n  border-radius: 50%;\r\n  height: 60px;\r\n  width: 60px;\r\n  background-color: #3F51B5;\r\n  transition: 0.2s;\r\n  text-align: center;\r\n}\r\n\r\n.circle:active {\r\n  transform: scale(0.9);\r\n  box-shadow: 0 2px 15px 0 rgba(0, 0, 0, 0.3);\r\n}\r\n\r\n.circle:hover {\r\n  cursor: pointer;\r\n  background-color: #606fc7;\r\n  box-shadow: 0 8px 15px 0 rgba(0, 0, 0, 0.3);\r\n}\r\n\r\n.circle .svg {\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  margin-left: -15px;\r\n  margin-top: -15px;\r\n  width: 30px;\r\n  height: 30px;\r\n  transition: 0.5s;\r\n  transform: rotate(180deg);\r\n}\r\n\r\n.sub-circle {\r\n  z-index: 0;\r\n  position: absolute;\r\n  height: 40px;\r\n  width: 40px;\r\n  overflow: hidden;\r\n  border-radius: 50%;\r\n  transition: 0.3s;\r\n  transform: scale(0.5);\r\n  opacity: 0;\r\n  padding: 0;\r\n  margin: 0;\r\n  box-shadow: 0 6px 10px 0 rgba(0, 0, 0, 0.3);\r\n  border: none;\r\n}\r\n\r\n.sub-circle label {\r\n  background-color: #F50057;\r\n  display: block;\r\n  color: white;\r\n  width: 100%;\r\n  height: 100%;\r\n  line-height: 40px;\r\n  transition: .5s;\r\n}\r\n\r\n.sub-circle label:hover {\r\n  cursor: pointer;\r\n  background-color: #606fc7;\r\n}\r\n\r\n.subs {\r\n  left: -20px;\r\n  top: -50px;\r\n  width: 40px;\r\n  height: 40px;\r\n  text-align: center;\r\n  z-index: 0;\r\n  margin: 0 auto;\r\n  position: relative;\r\n}\r\n\r\n.hidden-sub-trigger {\r\n  display: none;\r\n}\r\n\r\n.hidden-sub-trigger:checked ~ label {\r\n  background-color: #606fc7;\r\n}\r\n\r\n.hidden-trigger {\r\n  display: none;\r\n}\r\n\r\n.hidden-trigger:checked ~ .circle {\r\n  transform: scale(0.9);\r\n  cursor: pointer;\r\n  background-color: #606fc7;\r\n  box-shadow: 0 8px 15px 0 rgba(0, 0, 0, 0.1);\r\n}\r\n\r\n.hidden-trigger:checked ~ .circle .svg {\r\n  transform: rotate(45deg);\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(1) {\r\n  transform: translate(0px, -100px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.1s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(2) {\r\n  transform: translate(75px, -75px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.2s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(3) {\r\n  transform: translate(100px, 0px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.3s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(4) {\r\n  transform: translate(75px, 75px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.4s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(5) {\r\n  transform: translate(0px, 100px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.5s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(6) {\r\n  transform: translate(-75px, 75px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.6s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(7) {\r\n  transform: translate(-100px, 0px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.7s;\r\n}\r\n\r\n.hidden-trigger:checked ~ .subs button:nth-of-type(8) {\r\n  transform: translate(-75px, -75px) scale(1);\r\n  opacity: 1;\r\n  transition: 0.8s;\r\n}\r\n'),
(20, '\r\n<label class=\"checkbox-wrapper\">\r\n  <input type=\"checkbox\" />\r\n  <div class=\"checkmark\">\r\n    <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\">\r\n      <path\r\n        d=\"M20 6L9 17L4 12\"\r\n        stroke-width=\"3\"\r\n        stroke-linecap=\"round\"\r\n        stroke-linejoin=\"round\"\r\n      ></path>\r\n    </svg>\r\n  </div>\r\n  <span class=\"label\">Neon Checkbox</span>\r\n</label>\r\n', '\r\n.checkbox-wrapper {\r\n  --checkbox-size: 25px;\r\n  --checkbox-color: #00ff88;\r\n  --checkbox-shadow: rgba(0, 255, 136, 0.3);\r\n  --checkbox-border: rgba(0, 255, 136, 0.7);\r\n  display: flex;\r\n  align-items: center;\r\n  position: relative;\r\n  cursor: pointer;\r\n  padding: 10px;\r\n}\r\n\r\n.checkbox-wrapper input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n.checkbox-wrapper .checkmark {\r\n  position: relative;\r\n  width: var(--checkbox-size);\r\n  height: var(--checkbox-size);\r\n  border: 2px solid var(--checkbox-border);\r\n  border-radius: 8px;\r\n  transition: all 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  background: rgba(0, 0, 0, 0.2);\r\n  box-shadow: 0 0 15px var(--checkbox-shadow);\r\n  overflow: hidden;\r\n}\r\n\r\n.checkbox-wrapper .checkmark::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 100%;\r\n  height: 100%;\r\n  background: linear-gradient(45deg, var(--checkbox-color), #00ffcc);\r\n  opacity: 0;\r\n  transition: all 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n  transform: scale(0) rotate(-45deg);\r\n}\r\n\r\n.checkbox-wrapper input:checked ~ .checkmark::before {\r\n  opacity: 1;\r\n  transform: scale(1) rotate(0);\r\n}\r\n\r\n.checkbox-wrapper .checkmark svg {\r\n  width: 0;\r\n  height: 0;\r\n  color: #1a1a1a;\r\n  z-index: 1;\r\n  transition: all 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n  filter: drop-shadow(0 0 2px rgba(0, 0, 0, 0.5));\r\n}\r\n\r\n.checkbox-wrapper input:checked ~ .checkmark svg {\r\n  width: 18px;\r\n  height: 18px;\r\n  transform: rotate(360deg);\r\n}\r\n\r\n.checkbox-wrapper:hover .checkmark {\r\n  border-color: var(--checkbox-color);\r\n  transform: scale(1.1);\r\n  box-shadow:\r\n    0 0 20px var(--checkbox-shadow),\r\n    0 0 40px var(--checkbox-shadow),\r\n    inset 0 0 10px var(--checkbox-shadow);\r\n}\r\n\r\n.checkbox-wrapper input:checked ~ .checkmark {\r\n  animation: pulse 1s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n}\r\n\r\n@keyframes pulse {\r\n  0% {\r\n    transform: scale(1);\r\n    box-shadow: 0 0 20px var(--checkbox-shadow);\r\n  }\r\n  50% {\r\n    transform: scale(0.9);\r\n    box-shadow:\r\n      0 0 30px var(--checkbox-shadow),\r\n      0 0 50px var(--checkbox-shadow);\r\n  }\r\n  100% {\r\n    transform: scale(1);\r\n    box-shadow: 0 0 20px var(--checkbox-shadow);\r\n  }\r\n}\r\n\r\n.checkbox-wrapper .label {\r\n  margin-left: 15px;\r\n  font-family: \"Segoe UI\", sans-serif;\r\n  color: var(--checkbox-color);\r\n  font-size: 18px;\r\n  text-shadow: 0 0 10px var(--checkbox-shadow);\r\n  opacity: 0.9;\r\n  transition: all 0.3s;\r\n}\r\n\r\n.checkbox-wrapper:hover .label {\r\n  opacity: 1;\r\n  transform: translateX(5px);\r\n}\r\n\r\n/* Glowing dots animation */\r\n.checkbox-wrapper::after,\r\n.checkbox-wrapper::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 4px;\r\n  height: 4px;\r\n  border-radius: 50%;\r\n  background: var(--checkbox-color);\r\n  opacity: 0;\r\n  transition: all 0.5s;\r\n}\r\n\r\n.checkbox-wrapper::before {\r\n  left: -10px;\r\n  top: 50%;\r\n}\r\n\r\n.checkbox-wrapper::after {\r\n  right: -10px;\r\n  top: 50%;\r\n}\r\n\r\n.checkbox-wrapper:hover::before {\r\n  opacity: 1;\r\n  transform: translateX(-10px);\r\n  box-shadow: 0 0 10px var(--checkbox-color);\r\n}\r\n\r\n.checkbox-wrapper:hover::after {\r\n  opacity: 1;\r\n  transform: translateX(10px);\r\n  box-shadow: 0 0 10px var(--checkbox-color);\r\n}\r\n');

