(3, '<div class=\"grid\"></div>\n<div id=\"poda\">\n  <div class=\"glow\"></div>\n  <div class=\"darkBorderBg\"></div>\n  <div class=\"darkBorderBg\"></div>\n  <div class=\"darkBorderBg\"></div>\n\n  <div class=\"white\"></div>\n\n  <div class=\"border\"></div>\n\n  <div id=\"main\">\n    <input placeholder=\"Search...\" type=\"text\" name=\"text\" class=\"input\" />\n    <div id=\"input-mask\"></div>\n    <div id=\"pink-mask\"></div>\n    <div class=\"filterBorder\"></div>\n    <div id=\"filter-icon\">\n      <svg\n        preserveAspectRatio=\"none\"\n        height=\"27\"\n        width=\"27\"\n        viewBox=\"4.8 4.56 14.832 15.408\"\n        fill=\"none\"\n      >\n        <path\n          d=\"M8.16 6.65002H15.83C16.47 6.65002 16.99 7.17002 16.99 7.81002V9.09002C16.99 9.56002 16.7 10.14 16.41 10.43L13.91 12.64C13.56 12.93 13.33 13.51 13.33 13.98V16.48C13.33 16.83 13.1 17.29 12.81 17.47L12 17.98C11.24 18.45 10.2 17.92 10.2 16.99V13.91C10.2 13.5 9.97 12.98 9.73 12.69L7.52 10.36C7.23 10.08 7 9.55002 7 9.20002V7.87002C7 7.17002 7.52 6.65002 8.16 6.65002Z\"\n          stroke=\"#d6d6e6\"\n          stroke-width=\"1\"\n          stroke-miterlimit=\"10\"\n          stroke-linecap=\"round\"\n          stroke-linejoin=\"round\"\n        ></path>\n      </svg>\n    </div>\n    <div id=\"search-icon\">\n      <svg\n        xmlns=\"http://www.w3.org/2000/svg\"\n        width=\"24\"\n        viewBox=\"0 0 24 24\"\n        stroke-width=\"2\"\n        stroke-linejoin=\"round\"\n        stroke-linecap=\"round\"\n        height=\"24\"\n        fill=\"none\"\n        class=\"feather feather-search\"\n      >\n        <circle stroke=\"url(#search)\" r=\"8\" cy=\"11\" cx=\"11\"></circle>\n        <line\n          stroke=\"url(#searchl)\"\n          y2=\"16.65\"\n          y1=\"22\"\n          x2=\"16.65\"\n          x1=\"22\"\n        ></line>\n        <defs>\n          <linearGradient gradientTransform=\"rotate(50)\" id=\"search\">\n            <stop stop-color=\"#f8e7f8\" offset=\"0%\"></stop>\n            <stop stop-color=\"#b6a9b7\" offset=\"50%\"></stop>\n          </linearGradient>\n          <linearGradient id=\"searchl\">\n            <stop stop-color=\"#b6a9b7\" offset=\"0%\"></stop>\n            <stop stop-color=\"#837484\" offset=\"50%\"></stop>\n          </linearGradient>\n        </defs>\n      </svg>\n    </div>\n  </div>\n</div>', '.grid {\n  height: 800px;\n  width: 800px;\n  background-image: linear-gradient(to right, #0f0f10 1px, transparent 1px),\n    linear-gradient(to bottom, #0f0f10 1px, transparent 1px);\n  background-size: 1rem 1rem;\n  background-position: center center;\n  position: absolute;\n  z-index: -1;\n  filter: blur(1px);\n}\n.white,\n.border,\n.darkBorderBg,\n.glow {\n  max-height: 70px;\n  max-width: 314px;\n  height: 100%;\n  width: 100%;\n  position: absolute;\n  overflow: hidden;\n  z-index: -1;\n  /* Border Radius */\n  border-radius: 12px;\n  filter: blur(3px);\n}\n.input {\n  background-color: #010201;\n  border: none;\n  /* padding:7px; */\n  width: 301px;\n  height: 56px;\n  border-radius: 10px;\n  color: white;\n  padding-inline: 59px;\n  font-size: 18px;\n}\n#poda {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.input::placeholder {\n  color: #c0b9c0;\n}\n\n.input:focus {\n  outline: none;\n}\n\n#main:focus-within > #input-mask {\n  display: none;\n}\n\n#input-mask {\n  pointer-events: none;\n  width: 100px;\n  height: 20px;\n  position: absolute;\n  background: linear-gradient(90deg, transparent, black);\n  top: 18px;\n  left: 70px;\n}\n#pink-mask {\n  pointer-events: none;\n  width: 30px;\n  height: 20px;\n  position: absolute;\n  background: #cf30aa;\n  top: 10px;\n  left: 5px;\n  filter: blur(20px);\n  opacity: 0.8;\n  //animation:leftright 4s ease-in infinite;\n  transition: all 2s;\n}\n#main:hover > #pink-mask {\n  //animation: rotate 4s linear infinite;\n  opacity: 0;\n}\n\n.white {\n  max-height: 63px;\n  max-width: 307px;\n  border-radius: 10px;\n  filter: blur(2px);\n}\n\n.white::before {\n  content: \"\";\n  z-index: -2;\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(83deg);\n  position: absolute;\n  width: 600px;\n  height: 600px;\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  filter: brightness(1.4);\n  background-image: conic-gradient(\n    rgba(0, 0, 0, 0) 0%,\n    #a099d8,\n    rgba(0, 0, 0, 0) 8%,\n    rgba(0, 0, 0, 0) 50%,\n    #dfa2da,\n    rgba(0, 0, 0, 0) 58%\n  );\n  //  animation: rotate 4s linear infinite;\n  transition: all 2s;\n}\n.border {\n  max-height: 59px;\n  max-width: 303px;\n  border-radius: 11px;\n  filter: blur(0.5px);\n}\n.border::before {\n  content: \"\";\n  z-index: -2;\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(70deg);\n  position: absolute;\n  width: 600px;\n  height: 600px;\n  filter: brightness(1.3);\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  background-image: conic-gradient(\n    #1c191c,\n    #402fb5 5%,\n    #1c191c 14%,\n    #1c191c 50%,\n    #cf30aa 60%,\n    #1c191c 64%\n  );\n  // animation: rotate 4s 0.1s linear infinite;\n  transition: all 2s;\n}\n.darkBorderBg {\n  max-height: 65px;\n  max-width: 312px;\n}\n.darkBorderBg::before {\n  content: \"\";\n  z-index: -2;\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(82deg);\n  position: absolute;\n  width: 600px;\n  height: 600px;\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  background-image: conic-gradient(\n    rgba(0, 0, 0, 0),\n    #18116a,\n    rgba(0, 0, 0, 0) 10%,\n    rgba(0, 0, 0, 0) 50%,\n    #6e1b60,\n    rgba(0, 0, 0, 0) 60%\n  );\n  transition: all 2s;\n}\n#poda:hover > .darkBorderBg::before {\n  transform: translate(-50%, -50%) rotate(262deg);\n}\n#poda:hover > .glow::before {\n  transform: translate(-50%, -50%) rotate(240deg);\n}\n#poda:hover > .white::before {\n  transform: translate(-50%, -50%) rotate(263deg);\n}\n#poda:hover > .border::before {\n  transform: translate(-50%, -50%) rotate(250deg);\n}\n\n#poda:hover > .darkBorderBg::before {\n  transform: translate(-50%, -50%) rotate(-98deg);\n}\n#poda:hover > .glow::before {\n  transform: translate(-50%, -50%) rotate(-120deg);\n}\n#poda:hover > .white::before {\n  transform: translate(-50%, -50%) rotate(-97deg);\n}\n#poda:hover > .border::before {\n  transform: translate(-50%, -50%) rotate(-110deg);\n}\n\n#poda:focus-within > .darkBorderBg::before {\n  transform: translate(-50%, -50%) rotate(442deg);\n  transition: all 4s;\n}\n#poda:focus-within > .glow::before {\n  transform: translate(-50%, -50%) rotate(420deg);\n  transition: all 4s;\n}\n#poda:focus-within > .white::before {\n  transform: translate(-50%, -50%) rotate(443deg);\n  transition: all 4s;\n}\n#poda:focus-within > .border::before {\n  transform: translate(-50%, -50%) rotate(430deg);\n  transition: all 4s;\n}\n\n.glow {\n  overflow: hidden;\n  filter: blur(30px);\n  opacity: 0.4;\n  max-height: 130px;\n  max-width: 354px;\n}\n.glow:before {\n  content: \"\";\n  z-index: -2;\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(60deg);\n  position: absolute;\n  width: 999px;\n  height: 999px;\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  /*border color, change middle color*/\n  background-image: conic-gradient(\n    #000,\n    #402fb5 5%,\n    #000 38%,\n    #000 50%,\n    #cf30aa 60%,\n    #000 87%\n  );\n  /* change speed here */\n  //animation: rotate 4s 0.3s linear infinite;\n  transition: all 2s;\n}\n\n@keyframes rotate {\n  100% {\n    transform: translate(-50%, -50%) rotate(450deg);\n  }\n}\n@keyframes leftright {\n  0% {\n    transform: translate(0px, 0px);\n    opacity: 1;\n  }\n\n  49% {\n    transform: translate(250px, 0px);\n    opacity: 0;\n  }\n  80% {\n    transform: translate(-40px, 0px);\n    opacity: 0;\n  }\n\n  100% {\n    transform: translate(0px, 0px);\n    opacity: 1;\n  }\n}\n\n#filter-icon {\n  position: absolute;\n  top: 8px;\n  right: 8px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  z-index: 2;\n  max-height: 40px;\n  max-width: 38px;\n  height: 100%;\n  width: 100%;\n\n  isolation: isolate;\n  overflow: hidden;\n  /* Border Radius */\n  border-radius: 10px;\n  background: linear-gradient(180deg, #161329, black, #1d1b4b);\n  border: 1px solid transparent;\n}\n.filterBorder {\n  height: 42px;\n  width: 40px;\n  position: absolute;\n  overflow: hidden;\n  top: 7px;\n  right: 7px;\n  border-radius: 10px;\n}\n\n.filterBorder::before {\n  content: \"\";\n\n  text-align: center;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(90deg);\n  position: absolute;\n  width: 600px;\n  height: 600px;\n  background-repeat: no-repeat;\n  background-position: 0 0;\n  filter: brightness(1.35);\n  background-image: conic-gradient(\n    rgba(0, 0, 0, 0),\n    #3d3a4f,\n    rgba(0, 0, 0, 0) 50%,\n    rgba(0, 0, 0, 0) 50%,\n    #3d3a4f,\n    rgba(0, 0, 0, 0) 100%\n  );\n  animation: rotate 4s linear infinite;\n}\n#main {\n  position: relative;\n}\n#search-icon {\n  position: absolute;\n  left: 20px;\n  top: 15px;\n}\n'),
(4, '<form action=\"\" class=\"container\">\n  <div class=\"input-container\">\n    <div class=\"input-content\">\n      <div class=\"input-dist\">\n        <span id=\"SubscribeTXT\">Subscription</span>\n        <div class=\"input-type\">\n          <input placeholder=\"Email\" required type=\"text\" class=\"input-is\">\n          <input placeholder=\"Password\" required type=\"password\" class=\"input-is\">\n        </div>\n        <button>Subscribe</button>\n      </div>\n    </div>\n  </div>\n</form>', '#SubscribeTXT {\n  font-size: 20px;\n  color: #9fc4d0;\n}\n\nbutton {\n  color: #9fc4d0;\n  text-decoration: none;\n  font-size: 25px;\n  border: none;\n  background: none;\n  font-weight: 600;\n  font-family: \"Poppins\", sans-serif;\n  margin: 10px 0 0;\n}\n\nbutton::before {\n  margin-left: auto;\n}\n\nbutton::after, button::before {\n  content: \"\";\n  width: 0%;\n  height: 2px;\n  background: #06aed8;\n  display: block;\n  transition: 0.5s;\n}\n\nbutton:hover::after, button:hover::before {\n  width: 100%;\n}\n\n.container {\n  font-family: \"Segoe UI\", Tahoma, Geneva, Verdana, sans-serif;\n  font-style: italic;\n  font-weight: bold;\n  display: flex;\n  margin: auto;\n  aspect-ratio: 16/9;\n  align-items: center;\n  justify-content: center;\n  flex-wrap: wrap;\n  flex-direction: column;\n  gap: 1em;\n}\n\n.input-container {\n  filter: drop-shadow(46px 36px 24px #4090b5) drop-shadow(-55px -40px 25px #9e30a9);\n  animation: blinkShadowsFilter 8s ease-in infinite;\n}\n\n.input-content {\n  display: grid;\n  align-content: center;\n  justify-items: center;\n  align-items: center;\n  text-align: center;\n  padding-inline: 1em;\n  position: relative;\n}\n\n.input-content::before {\n  content: \"\";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  filter: blur(40px);\n  clip-path: polygon(26% 0, 66% 0, 92% 0, 100% 8%, 100% 89%, 91% 100%, 7% 100%, 0 92%, 0 0);\n  background: rgba(122, 251, 255, 0.56);\n  transition: all 1s ease-in-out;\n}\n\n.input-content::after {\n  content: \"\";\n  position: absolute;\n  width: 98%;\n  height: 98%;\n  box-shadow: inset 0px 0px 20px 20px #212121;\n  background: repeating-linear-gradient(to bottom, transparent 0%, rgba(64, 144, 181, 0.6) 1px, black 3px, hsl(295, 60%, 12%) 5px, #153544 4px, transparent 0.5%),\n              repeating-linear-gradient(to left, hsl(295, 60%, 12%) 100%, hsla(295, 60%, 12%, 0.99) 100%);\n  clip-path: polygon(26% 0, 31% 5%, 61% 5%, 66% 0, 92% 0, 100% 8%, 100% 89%, 91% 100%, 7% 100%, 0 92%, 0 0);\n  animation: backglitch 50ms linear infinite;\n}\n\n.input-dist {\n  z-index: 80;\n  display: grid;\n  align-items: center;\n  text-align: center;\n  width: 100%;\n  padding: 1.2em 1em;\n  grid-template-columns: 1fr;\n}\n\n.input-type {\n  display: flex;\n  flex-wrap: wrap;\n  flex-direction: column;\n  gap: 1em;\n  font-size: 1.1rem;\n  background-color: transparent;\n  width: 100%;\n  border: none;\n}\n\n.input-is {\n  color: #fff;\n  font-size: 0.9rem;\n  background-color: transparent;\n  width: 100%;\n  box-sizing: border-box;\n  padding: 0.7em 0.5em;\n  border: none;\n  transition: all 1s ease-in-out;\n  border-bottom: 1px solid hsl(221, 26%, 43%);\n}\n\n.input-is:hover {\n  background: linear-gradient(90deg, transparent 0%, rgba(102, 224, 255, 0.2) 27%, rgba(102, 224, 255, 0.2) 63%, transparent 100%);\n}\n\n.input-content:focus-within::before {\n  background: hsla(0, 0%, 100%, 0.81);\n}\n\n.input-is:focus {\n  outline: none;\n  border-bottom: 1px solid hsl(192, 100%, 100%);\n  color: hsl(192, 100%, 88%);\n  background: linear-gradient(90deg, transparent 0%, rgba(102, 224, 255, 0.2) 27%, rgba(102, 224, 255, 0.2) 63%, transparent 100%);\n}\n\n.input-is::placeholder {\n  color: hsla(192, 100%, 88%, 0.81);\n}\n\n@keyframes backglitch {\n  0% {\n    box-shadow: inset 0px 20px 20px 30px #212121;\n  }\n  50% {\n    box-shadow: inset 0px -20px 20px 30px hsl(297, 42%, 10%);\n  }\n  100% {\n    box-shadow: inset 0px 20px 20px 30px #212121;\n  }\n}\n\n@keyframes blinkShadowsFilter {\n  0% {\n    filter: drop-shadow(46px 36px 28px rgba(64, 144, 181, 0.34)) drop-shadow(-55px -40px 28px #9e30a9);\n  }\n  25% {\n    filter: drop-shadow(46px -36px 24px rgba(64, 144, 181, 0.9)) drop-shadow(-55px 40px 24px #9e30a9);\n  }\n  50% {\n    filter: drop-shadow(46px 36px 30px rgba(64, 144, 181, 0.9)) drop-shadow(-55px 40px 30px rgba(159, 48, 169, 0.29));\n  }\n  75% {\n    filter: drop-shadow(20px -18px 25px rgba(64, 144, 181, 0.9)) drop-shadow(-20px 20px 25px rgba(159, 48, 169, 0.29));\n  }\n  100% {\n    filter: drop-shadow(46px 36px 28px rgba(64, 144, 181, 0.34)) drop-shadow(-55px -40px 28px #9e30a9);\n  }\n}'),
(5, '<div class=\"futuristic-input\">\n  <div class=\"futuristic-input-space\">\n    <div class=\"futuristic-input-space-2\"></div>\n    <div class=\"triangle-input-up\"></div>\n    <div class=\"triangle-input-bar2\"></div>\n    <div class=\"triangle-input-left\"></div>\n    <div class=\"futuristic-input-space-2\"></div>\n    <div class=\"triangle-input-right2\"></div>\n    <div class=\"triangle-input-bar3\"></div>\n  </div>\n  <div class=\"futuristic-input-space\">\n    <div class=\"triangle-input-up\"></div>\n    <div class=\"triangle-input-bar\"></div>\n  </div>\n  <div class=\"futuristic-input-space\">\n    <div class=\"triangle-input-bar\"></div>\n    <input type=\"text\" name=\"text\" class=\"input\" />\n    <p class=\"futuristic-input-enter\">ENTER</p>\n    <p class=\"futuristic-input-name\">NAME</p>\n  </div>\n  <div class=\"futuristic-input-space\">\n    <div class=\"triangle-input-bar\"></div>\n  </div>\n  <div class=\"futuristic-input-space\">\n    <div class=\"triangle-input-bar\"></div>\n    <div class=\"triangle-input-down\"></div>\n  </div>\n  <div class=\"futuristic-input-space2\">\n    <div class=\"triangle-input-bar3\"></div>\n    <div class=\"triangle-input-left2\"></div>\n    <div class=\"futuristic-input-space-2\"></div>\n    <div class=\"triangle-input-right\"></div>\n    <div class=\"triangle-input-bar2\"></div>\n    <div class=\"triangle-input-down\"></div>\n    <div class=\"futuristic-input-space-2\"></div>\n  </div>\n</div>\n', '.futuristic-input {\n  width: 15em;\n  height: 6em;\n  position: relative;\n  overflow: hidden;\n  --firstcolor: #171033;\n  --secondcolor: #171033;\n  transition: all 0.25s ease-in-out;\n  padding: 0em;\n  margin: 0em;\n  animation: changeborder 2.5s infinite linear;\n}\n\n@keyframes changeborder {\n  0% {\n    border: 0.1em solid #515267;\n    border-left: 0.1em solid white;\n  }\n  25% {\n    border: 0.1em solid #515267;\n    border-top: 0.1em solid white;\n  }\n  50% {\n    border: 0.1em solid #515267;\n    border-right: 0.1em solid white;\n  }\n  70% {\n    border: 0.1em solid #515267;\n    border-bottom: 0.1em solid white;\n  }\n  100% {\n    border: 0.1em solid #515267;\n    border-left: 0.1em solid white;\n  }\n}\n\n.futuristic-input:hover {\n  transform: scale(1.1);\n  animation: spawn-light 1s;\n  animation-iteration-count: 1s;\n}\n\n@keyframes spawn-light {\n  0% {\n    background-color: white;\n    box-shadow: 0em 0em 5em white;\n  }\n  50% {\n    box-shadow: 0em 0em 0em white;\n  }\n  100% {\n    background-color: rgb(255, 255, 255, 0);\n  }\n}\n.input {\n  width: 80%;\n  height: 1.75em;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  border-left: none;\n  border-top: none;\n  border-right: none;\n  border-bottom: 0.15em solid white;\n  background-color: var(--firstcolor);\n  font-weight: bold;\n  padding-left: 0.25em;\n  color: white;\n  outline: none;\n  font-weight: 100;\n}\n.triangle-input-up {\n  width: 0em;\n  height: 0em;\n  border-left: 1em solid transparent;\n  border-bottom: 1em solid var(--secondcolor);\n}\n.triangle-input-left {\n  width: 0em;\n  height: 0em;\n  border-right: 1em solid transparent;\n  border-bottom: 1em solid var(--firstcolor);\n}\n.triangle-input-left2 {\n  width: 0em;\n  height: 0em;\n  border-right: 1em solid transparent;\n  border-bottom: 1em solid white;\n}\n.triangle-input-down {\n  width: 0em;\n  height: 0em;\n  border-bottom: 1em solid transparent;\n  border-left: 1em solid var(--firstcolor);\n}\n.triangle-input-right {\n  width: 0em;\n  height: 0em;\n  border-left: 1em solid transparent;\n  border-top: 1em solid var(--secondcolor);\n}\n.triangle-input-right2 {\n  width: 0em;\n  height: 0em;\n  border-left: 1em solid transparent;\n  border-top: 1em solid white;\n}\n.futuristic-input-space {\n  width: 100%;\n  height: 1em;\n  display: flex;\n}\n\n.futuristic-input-space2 {\n  width: 100%;\n  height: 1em;\n  display: flex;\n  justify-content: flex-end;\n}\n.triangle-input-bar {\n  width: 100%;\n  height: 100%;\n  background-color: var(--firstcolor);\n}\n.triangle-input-bar2 {\n  width: 5em;\n  height: 100%;\n  background-color: var(--firstcolor);\n}\n.triangle-input-bar3 {\n  width: 3em;\n  height: 100%;\n  background-color: white;\n}\n.futuristic-input-space-2 {\n  width: 2em;\n  height: 1em;\n  display: flex;\n}\n\n.futuristic-input-enter {\n  color: white;\n  top: -0.35em;\n  position: absolute;\n  left: 3.2em;\n  font-weight: bold;\n  animation: color-change 2.5s infinite linear;\n  -webkit-text-stroke: 0.01em white;\n  font-size: 1.25em;\n  text-shadow: 1em 0em 1em white;\n}\n\n.futuristic-input-name {\n  color: white;\n  bottom: -0.4em;\n  position: absolute;\n  right: 3.25em;\n  font-weight: bold;\n  animation: color-change 2.5s infinite linear 0.5s;\n  -webkit-text-stroke: 0.01em white;\n  font-size: 1.25em;\n  text-shadow: -2em 0em 1em white;\n}\n\n@keyframes color-change {\n  0% {\n    color: white;\n  }\n  25% {\n    color: white;\n  }\n  30% {\n    color: transparent;\n  }\n  35% {\n    color: white;\n  }\n  40% {\n    color: transparent;\n  }\n  45% {\n    color: white;\n  }\n  100% {\n    color: white;\n  }\n}\n'),
(6, '<div class=\"input-add-friend\">\n  <div class=\"input-add-friend-title\"><p>Add a friend</p></div>\n  <div class=\"input-add-friend-input\">\n    <input\n      name=\"text\"\n      placeholder=\"000000\"\n      class=\"input\"\n      minlength=\"6\"\n      maxlength=\"6\"\n      required=\"\"\n    />\n    <p class=\"input-add-friend-text\">-----</p>\n    <div class=\"input-add-friend-input-behind\"></div>\n    <input\n      type=\"checkbox\"\n      id=\"input-add-friend-checkbox\"\n      class=\"input-add-friend-checkbox\"\n      hidden=\"\"\n    />\n    <label class=\"button\" for=\"input-add-friend-checkbox\"\n      ><p>Check Code</p></label\n    >\n    <svg\n      xmlns=\"http://www.w3.org/2000/svg\"\n      width=\"35\"\n      height=\"35\"\n      viewBox=\"0 0 24 24\"\n      fill=\"none\"\n      stroke=\"#a974ff\"\n      stroke-width=\"1\"\n      stroke-linecap=\"round\"\n      stroke-linejoin=\"round\"\n    >\n      <path d=\"M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2\"></path>\n      <circle cx=\"8.5\" cy=\"7\" r=\"4\"></circle>\n      <line x1=\"20\" y1=\"8\" x2=\"20\" y2=\"14\"></line>\n      <line x1=\"23\" y1=\"11\" x2=\"17\" y2=\"11\"></line>\n    </svg>\n  </div>\n</div>\n', '.input-add-friend {\n  width: 17em;\n  height: 11em;\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  --color: rgb(169, 116, 255);\n  --background-color: rgb(36, 34, 39);\n}\n\n.input-add-friend .input-add-friend-title {\n  display: flex;\n  align-self: flex-start;\n  margin-left: 0.5em;\n}\n.input-add-friend-title {\n  width: 8em;\n  height: 2em;\n  background-color: var(--background-color);\n  color: white;\n  display: flex;\n  justify-content: center;\n  font-weight: bold;\n  font-family: monospace, sans-serif;\n  box-shadow:\n    -0.05em 0em var(--color),\n    -0.05em -0.05em var(--color),\n    0.05em -0.05em var(--color);\n  position: relative;\n  z-index: 1;\n  align-items: center;\n}\n.input-add-friend-input {\n  width: 16em;\n  height: 8em;\n  background-color: var(--background-color);\n\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n  gap: 1em;\n  font-weight: bold;\n  box-shadow:\n    -0.05em 0em var(--color),\n    -0.05em 0.05em var(--color),\n    0.05em 0.05em var(--color),\n    0.05em -0.05em var(--color),\n    0em 0em 2.5em 0em rgb(121, 174, 30, 0.15);\n  position: relative;\n  z-index: 0;\n  animation: change-box-shadow 5s linear infinite;\n}\n\n@keyframes change-box-shadow {\n  0% {\n    box-shadow:\n      -0.05em 0em var(--color),\n      -0.05em 0.05em var(--color),\n      0.05em 0.05em var(--color),\n      0.05em -0.05em var(--color),\n      0em 0em 2.5em 0em rgb(169, 116, 255, 0);\n  }\n  50% {\n    box-shadow:\n      -0.05em 0em var(--color),\n      -0.05em 0.05em var(--color),\n      0.05em 0.05em var(--color),\n      0.05em -0.05em var(--color),\n      0em 0em 2.5em 0em rgb(169, 116, 255, 0.25);\n  }\n  100% {\n    box-shadow:\n      -0.05em 0em var(--color),\n      -0.05em 0.05em var(--color),\n      0.05em 0.05em var(--color),\n      0.05em -0.05em var(--color),\n      0em 0em 2.5em 0em rgb(169, 116, 255, 0);\n  }\n}\n.input-add-friend-input input {\n  width: 16em;\n  height: 2.5em;\n\n  border: solid 0.5em transparent;\n  font-family: monospace, sans-serif;\n  color: var(--background-color);\n  font-weight: bold;\n  outline: none;\n  padding-left: 3.5em;\n  letter-spacing: 1em;\n  background-color: transparent;\n  position: relative;\n  z-index: 4;\n}\n\n.input::placeholder {\n  color: var(--background-color);\n  font-weight: bold;\n  font-family: monospace, sans-serif;\n}\n\n.input-add-friend-checkbox:hover + label {\n  opacity: 75%;\n}\n\n.input-add-friend-checkbox:hover + label p {\n  font-size: 14px;\n  transition: all 0.25s ease-in-out;\n}\n\n.input-add-friend-checkbox + label {\n  width: 13.25em;\n  height: 2.25em;\n  border: solid 0.5em var(--color);\n  background-color: var(--color);\n  font-family: monospace, sans-serif;\n  color: var(--background-color);\n  font-weight: bold;\n  outline: none;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  transition: all 0.25s ease-in-out;\n}\n\n.input-add-friend svg {\n  position: absolute;\n  top: -2.25em;\n  right: 0em;\n}\n\n.input-add-friend-checkbox:active + label {\n  background-color: white;\n  border: white;\n}\n\n.input-add-friend:has(.input-add-friend-checkbox:checked) {\n  filter: hue-rotate(-120deg);\n  transition: all 0.25s ease-in-out;\n}\n\n.input-add-friend-checkbox:checked ~ svg {\n  animation: jumpicon 0.75s infinite linear;\n  animation-iteration-count: 1;\n}\n\n@keyframes jumpicon {\n  0% {\n    top: -2.25em;\n    transform: rotate(0deg) scale(1);\n  }\n  25% {\n    top: -2.5em;\n    transform: rotate(0deg) scale(1.15);\n  }\n  50% {\n    top: -2.5em;\n    transform: rotate(10deg) scale(1.15);\n  }\n  75% {\n    top: -2.5em;\n    transform: rotate(-10deg) scale(1.15);\n  }\n  95% {\n    transform: rotate(0deg) scale(1);\n  }\n  100% {\n    top: -2.25em;\n    transform: rotate(0deg) scale(1);\n  }\n}\n\n.input-add-friend-text {\n  color: var(--background-color);\n  position: absolute;\n  letter-spacing: 0.85em;\n  top: 1.65em;\n  left: 5.25em;\n  z-index: 3;\n}\n\n.input-add-friend-input-behind {\n  width: 13.25em;\n  height: 2.25em;\n  top: 1.35em;\n  font-family: monospace, sans-serif;\n  color: var(--background-color);\n  font-weight: bold;\n  background-color: rgb(255, 255, 255);\n  position: absolute;\n  z-index: 2;\n}\n'),
(7, '<div class=\"container\">\n  <div class=\"folder\">\n    <div class=\"top\"></div>\n    <div class=\"bottom\"></div>\n  </div>\n  <label class=\"custom-file-upload\">\n    <input class=\"title\" type=\"file\" />\n    Choose a file\n  </label>\n</div>\n', '.container {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  padding: 20px;\n  background: linear-gradient(135deg, #6dd5ed, #2193b0);\n  border-radius: 15px;\n  box-shadow: 0 15px 30px rgba(0, 0, 0, 0.2);\n}\n\n.folder {\n  position: relative;\n  animation: float 2.5s infinite ease-in-out;\n  transition: transform 0.3s ease;\n}\n\n.folder:hover {\n  transform: scale(1.05);\n}\n\n.folder .top {\n  background: linear-gradient(135deg, #ff9a56, #ff6f56);\n  width: 80px;\n  height: 20px;\n  border-radius: 12px 12px 0 0;\n  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.2);\n  position: relative;\n  z-index: 2;\n}\n\n.folder .bottom {\n  background: linear-gradient(135deg, #ffe563, #ffc663);\n  width: 120px;\n  height: 80px;\n  box-shadow: 0 15px 30px rgba(0, 0, 0, 0.3);\n  border-radius: 0 10px 10px 10px;\n  position: relative;\n  top: -10px;\n}\n\n.custom-file-upload {\n  font-size: 1.1em;\n  color: #ffffff;\n  text-align: center;\n  margin-top: 20px;\n  padding: 15px 25px;\n  background: rgba(255, 255, 255, 0.2);\n  border: none;\n  border-radius: 10px;\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);\n  cursor: pointer;\n  transition: background 0.3s ease;\n  display: inline-block;\n  width: 220px;\n}\n\n.custom-file-upload:hover {\n  background: rgba(255, 255, 255, 0.4);\n}\n\n.custom-file-upload input[type=\"file\"] {\n  display: none;\n}\n\n@keyframes float {\n  0% {\n    transform: translateY(0px);\n  }\n\n  50% {\n    transform: translateY(-20px);\n  }\n\n  100% {\n    transform: translateY(0px);\n  }\n}\n'),
(8, '<div class=\"input-wrapper\">\n  <input class=\"input\" name=\"text\" placeholder=\"Type here...\" type=\"text\" />\n</div>\n', '.input-wrapper {\n  position: relative;\n  width: 50%;\n  max-width: 300px;\n  padding: 3px;\n  border-radius: 1.7rem;\n  overflow: hidden;\n}\n\n.input-wrapper input {\n  background-color: #f5f5f5;\n  border: 2px solid #ddd;\n  padding: 1.2rem 1rem 1.2rem 3rem; /* Increased left padding for emoji */\n  font-size: 1.1rem;\n  width: 100%;\n  border-radius: 1.5rem;\n  color: #ff7f7f;\n  box-shadow: 0 0.4rem #dfd9d9, inset 0 0 0 transparent;\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);\n  position: relative;\n  z-index: 2;\n}\n\n.input-wrapper input:focus {\n  outline: none;\n  border-color: #4a90e2; /* Changed to blue */\n  box-shadow: 0 0.6rem #dfd9d9, 0 0 15px rgba(74, 144, 226, 0.7); /* Blue glow */\n  transform: translateY(-3px) scale(1.01);\n}\n\n.input-wrapper input::placeholder {\n  color: #a0c0e8; /* Lighter blue for placeholder */\n  transition: all 0.3s ease;\n}\n\n.input-wrapper input:focus::placeholder {\n  opacity: 0;\n  transform: translateX(10px);\n}\n\n/* Emoji styles */\n.input-wrapper::after {\n  content: \"😎\";\n  position: absolute;\n  left: 1rem;\n  top: 50%;\n  transform: translateY(-50%);\n  font-size: 1.2rem;\n  z-index: 3;\n  transition: all 0.3s ease;\n}\n\n/* Emoji animations */\n@keyframes dance {\n  0%,\n  100% {\n    transform: translateY(-50%) rotate(0deg);\n  }\n  25% {\n    transform: translateY(-50%) rotate(-20deg) scale(1.1);\n  }\n  75% {\n    transform: translateY(-50%) rotate(20deg) scale(1.1);\n  }\n}\n\n.input-wrapper:hover::after {\n  animation: dance 0.5s ease infinite;\n}\n\n.input-wrapper:focus-within::after {\n  content: \"😂\";\n  animation: dance 0.3s ease infinite;\n}\n\n.input-wrapper input::placeholder {\n  color: #ccc;\n  transition: all 0.3s ease;\n}\n\n.input-wrapper input:focus::placeholder {\n  opacity: 0;\n  transform: translateX(10px);\n}\n\n/* Psychedelic background effect */\n.input-wrapper::before {\n  content: \"\";\n  position: absolute;\n  top: -50%;\n  left: -50%;\n  width: 200%;\n  height: 200%;\n  background: conic-gradient(\n    from 0deg,\n    #4a90e2,\n    #6aa9e9,\n    #8bc1f0,\n    #add9f7,\n    #d0f0ff,\n    #add9f7,\n    #8bc1f0,\n    #6aa9e9,\n    #4a90e2\n  );\n  animation: rotate 4s linear infinite;\n  opacity: 0;\n  transition: opacity 0.3s ease;\n  z-index: 1;\n}\n\n.input-wrapper:hover::before,\n.input-wrapper:focus-within::before {\n  opacity: 1;\n}\n\n@keyframes rotate {\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n/* Shockwave effect on focus */\n@keyframes shockwave {\n  0% {\n    transform: scale(1);\n    box-shadow: 0 0 0 0 rgba(255, 127, 127, 0.4);\n  }\n  70% {\n    transform: scale(1.02);\n    box-shadow: 0 0 0 20px rgba(255, 127, 127, 0);\n  }\n  100% {\n    transform: scale(1);\n    box-shadow: 0 0 0 0 rgba(255, 127, 127, 0);\n  }\n}\n\n.input-wrapper:focus-within {\n  animation: shockwave 0.5s ease-out;\n}\n\n/* Floating label effect */\n.input-wrapper {\n  --label-size: 0.8rem;\n  --label-transform: translateY(-170%) scale(0.8);\n}\n\n.input-wrapper input:placeholder-shown + label {\n  transform: translateY(-50%);\n  font-size: 1rem;\n}\n\n.input-wrapper label {\n  position: absolute;\n  left: 1rem;\n  top: 50%;\n  transform: var(--label-transform);\n  font-size: var(--label-size);\n  color: #ff7f7f;\n  transition: all 0.3s ease;\n  pointer-events: none;\n  z-index: 3;\n}\n\n.input-wrapper input:not(:placeholder-shown) + label,\n.input-wrapper input:focus + label {\n  transform: var(--label-transform);\n  font-size: var(--label-size);\n}\n'),
(9, '<input placeholder=\"Search The Matrix\">', 'input {\n  display: inline-block;\n  max-width: 196px;\n  -webkit-box-sizing: content-box;\n  -moz-box-sizing: content-box;\n  box-sizing: content-box;\n  padding: 10px 20px;\n  border: 5px solid #1fbc00;\n  -webkit-border-radius: 11px;\n  border-radius: 11px;\n  font: normal 19px/normal \"Courier New\", Courier, monospace;\n  color: rgba(42,255,0,1);\n  -o-text-overflow: clip;\n  text-overflow: clip;\n  background: rgba(45,45,45,1);\n  box-shadow: 0 0 9px 4px rgba(0,0,0,0.15) , -1px 4px 8px -1px rgba(0,0,0,0.49) inset;\n  text-shadow: 1px 1px 0 rgba(255,255,255,0.66);\n  transition: all 200ms cubic-bezier(0.42, 0, 0.58, 1);\n  -webkit-transform: rotateX(-16.62deg) rotateY(-28.64788975654116deg);\n  transform: rotateX(-16.62deg) rotateY(-28.64788975654116deg);\n}\n\ninput:hover {\n  -webkit-transform: rotateX(-15.62deg) rotateY(-23.65deg);\n  transform: rotateX(-15.62deg) rotateY(-23.65deg);\n}\n\n.search__icon {\n  height: 1.3em;\n  width: 1.3em;\n  fill: #b4b4b4;\n}\n\ninput:focus {\n  outline: none;\n}'),
(10, '<div class=\"card\">\n  <div class=\"terminal\">\n    <div class=\"terminal-header\">\n      <span class=\"terminal-title\">\n        <svg\n          class=\"terminal-icon\"\n          width=\"16\"\n          height=\"16\"\n          viewBox=\"0 0 24 24\"\n          fill=\"none\"\n          stroke=\"currentColor\"\n          stroke-width=\"2\"\n          stroke-linecap=\"round\"\n          stroke-linejoin=\"round\"\n        >\n          <path d=\"M4 17l6-6-6-6M12 19h8\"></path>\n        </svg>\n        Terminal\n      </span>\n    </div>\n    <div class=\"terminal-body\">\n      <div class=\"command-line\">\n        <span class=\"prompt\">password:</span>\n        <div class=\"input-wrapper\">\n          <input\n            type=\"password\"\n            class=\"input-field\"\n            placeholder=\"Enter password\"\n          />\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n', '.card {\n  background-color: rgba(217, 217, 217, 0.18);\n  backdrop-filter: blur(8px);\n  border-radius: 12px;\n  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);\n  overflow: hidden;\n  width: 400px;\n}\n\n.terminal-header {\n  background-color: #202425;\n  padding: 10px 15px;\n  display: flex;\n  align-items: center;\n}\n\n.terminal-title {\n  color: #ffffff;\n  font-size: 14px;\n  font-weight: 600;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.terminal-icon {\n  color: #006adc;\n}\n\n.terminal-body {\n  background-color: #202425;\n  color: #ffffff;\n  padding: 15px;\n  font-family: \"Courier New\", Courier, monospace;\n}\n\n.command-line {\n  display: flex;\n  align-items: center;\n}\n\n.prompt {\n  color: #ffffff;\n  margin-right: 10px;\n}\n\n.input-wrapper {\n  position: relative;\n  flex-grow: 1;\n}\n\n.input-field {\n  background-color: transparent;\n  border: none;\n  color: #006adc;\n  font-family: inherit;\n  font-size: 14px;\n  outline: none;\n  width: 100%;\n  padding-right: 10px;\n}\n\n.input-field::placeholder {\n  color: rgba(255, 255, 255, 0.5);\n}\n\n.input-wrapper::after {\n  content: \"\";\n  position: absolute;\n  right: 0;\n  top: 50%;\n  transform: translateY(-50%);\n  width: 8px;\n  height: 15px;\n  background-color: #ffffff;\n  animation: blink 1s step-end infinite;\n}\n\n@keyframes blink {\n  0%,\n  100% {\n    opacity: 1;\n  }\n  50% {\n    opacity: 0;\n  }\n}\n'),
(11, '<div class=\"input-container\">\n  <p class=\"bash-text\">\n    <span class=\"user\">user</span><span class=\"vm\">@ui-verse</span>:<span class=\"char\">~</span>$\n  </p>\n  <input class=\"input\" placeholder=\"sudo rm -rf css/\" type=\"text\">\n</div>', '.input-container {\n  display: flex;\n  align-items: center;\n  background-color: #0F172A;\n  padding: 10px 15px;\n  gap: 5px;\n  border-radius: 20px;\n}\n\n.input-container .bash-text {\n  font-size: .8rem;\n  color: white;\n}\n\n.input-container .bash-text .user {\n  color: #E879F9;\n}\n\n.input-container .bash-text .vm {\n  color: #2DD4BF;\n}\n\n.input-container .bash-text .char {\n  color: #A78BFA;\n}\n\n.input-container input[type=text].input {\n  background-color: transparent;\n  border: none;\n  outline: none;\n  color: white;\n}'),
(12, '<div class=\"info-panels\">\n  <div class=\"input-color-group-one\">\n    <input class=\"input-color\" autocomplete=\"on\" name=\"text\" type=\"text\" required=\"\" placeholder=\"255, 255, 255, 0.5\">\n		<label class=\"color-label\">RGBA</label>\n		<button class=\"btn-copy\">\n	  	<svg class=\"svgs\" id=\"icon-btn-copy\" xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 24 24\"><path d=\"M15.98,13.96h-4.74c-.13,0-.24-.11-.24-.24V7.07c0-.13,.11-.24,.24-.24h4.74c.13,0,.24,.11,.24,.24v6.64c0,.13-.11,.24-.24,.24Zm-6.77-7.72V14.55c0,.66,.53,1.19,1.19,1.19h6.41c.66,0,1.19-.53,1.19-1.19V6.24c0-.66-.53-1.19-1.19-1.19h-6.41c-.66,0-1.19,.53-1.19,1.19Z\"></path><path d=\"M15.68,18.95H7.19c-.66,0-1.19-.53-1.19-1.19V7.37c0-.49,.4-.89,.89-.89s.89,.4,.89,.89v9.57c0,.13,.1,.23,.23,.23h7.67c.49,0,.89,.4,.89,.89s-.4,.89-.89,.89Z\"></path></svg>		\n		</button>\n  </div>\n</div>', '.info-panels {\n  --color-icon: #fff;\n  --color-input: #ccc;\n  --color-border: #9e9e9e;\n  --color-border-hover: #1a73e8;\n  --all-transition: all .2s ease-out;\n  --input-focus-opacity: .3;\n}\n\n.input-color-group-one {\n  position: relative;\n}\n\n.input-color {\n  max-width: 230px;\n  min-width: 150px;\n  border: 1.5px solid var(--color-border);\n  border-radius: 80px;\n  background: none;\n  padding: 16px;\n  font-size: 16px;\n  transition: var(--all-transition);\n}\n\n.input-color:focus {\n  color: var(--color-input);\n  outline: none;\n  border: 1.5px solid var(--color-border-hover);\n}\n\n.input-color:valid {\n  color: var(--color-input);\n  outline: none;\n}\n\n.input-color::-webkit-input-placeholder {\n  color: var(--color-input);\n}\n\n.input-color::-moz-input-placeholder {\n  color: var(--color-input);\n}\n\n.input-color::-ms-input-placeholder {\n  color: var(--color-input);\n}\n\n.input-color:focus::-webkit-input-placeholder, input-color:valid::-webkit-input-placeholder {\n  opacity: var(--input-focus-opacity);\n}\n\n.input-color:focus::-moz-input-placeholder, input-color:valid::-moz-input-placeholder {\n  opacity: var(--input-focus-opacity);\n}\n\n.input-color:focus::-ms-input-placeholder, input-color:valid::-ms-input-placeholder {\n  opacity: var(--input-focus-opacity);\n}\n\n.color-label {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  color: var(--color-border);\n  font-weight: 600;\n  padding: 0 5px;\n  border: 1.5px solid var(--color-border);\n  border-radius: 20px;\n  top: -11.5px;\n  left: 25px;\n  background-color: transparent;\n  cursor: default;\n  backdrop-filter: blur(10px);\n  transition: var(--all-transition);\n}\n\n.input-color:focus ~ .color-label, input-color:valid ~ .color-label {\n  color: var(--color-border-hover);\n  border: 1.5px solid var(--color-border-hover);\n}\n\n.btn-copy {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 24px;\n  height: 24px;\n  border: 1.5px solid var(--color-border);\n  border-radius: 50%;\n  top: -11.5px;\n  right: 25px;\n  background-color: transparent;\n  cursor: pointer;\n  backdrop-filter: blur(10px);\n  transition: var(--all-transition);\n}\n\n.btn-copy:hover {\n  background-color: var(--color-border);\n  transform: scale(1.2);\n}\n\n.btn-copy:active {\n  transform: scale(1.1);\n}\n\n.input-color:focus ~ .btn-copy {\n  border: 1.5px solid var(--color-border-hover);\n}\n\n.input-color:valid .input-color:focus ~ .btn-copy {\n  border: 1.5px solid var(--color-border);\n}\n\n.input-color:focus ~ .btn-copy:hover {\n  background-color: var(--color-border-hover);\n}\n\n#icon-btn-copy {\n  fill: var(--color-border);\n}\n\n.btn-copy:hover #icon-btn-copy {\n  fill: var(--color-icon);\n}\n\n.input-color:focus ~ .btn-copy #icon-btn-copy {\n  fill: var(--color-border-hover);\n}\n\n.input-color:focus ~ .btn-copy:hover #icon-btn-copy, .input-color:valid ~ .btn-copy:hover #icon-btn-copy {\n  fill: var(--color-icon);\n}');
INSERT INTO `inputs` (`ID`, `HTML`, `CSS`) VALUES
(13, '<div class=\"ui-wrapper\">\n    <input checked=\"\" id=\"Austria\" name=\"flag\" type=\"radio\">\n    <input id=\"Belgium\" name=\"flag\" type=\"radio\">\n    <input id=\"Bulgaria\" name=\"flag\" type=\"radio\">\n    <input id=\"Croatia\" name=\"flag\" type=\"radio\">\n    <input id=\"Cyprus\" name=\"flag\" type=\"radio\">\n    <input id=\"Czech\" name=\"flag\" type=\"radio\">\n    <input id=\"Denmark\" name=\"flag\" type=\"radio\">\n    <input id=\"Estonia\" name=\"flag\" type=\"radio\">\n    <input id=\"Finland\" name=\"flag\" type=\"radio\">\n    <input id=\"France\" name=\"flag\" type=\"radio\">\n    <input id=\"Germany\" name=\"flag\" type=\"radio\">\n    <input id=\"Greece\" name=\"flag\" type=\"radio\">\n    <input id=\"Hungary\" name=\"flag\" type=\"radio\">\n    <input id=\"Iceland\" name=\"flag\" type=\"radio\">\n    <input id=\"Ireland\" name=\"flag\" type=\"radio\">\n    <input id=\"Italy\" name=\"flag\" type=\"radio\">\n    <input id=\"Latvia\" name=\"flag\" type=\"radio\">\n    <input id=\"Liechtenstein\" name=\"flag\" type=\"radio\">\n    <input id=\"Lithuania\" name=\"flag\" type=\"radio\">\n    <input id=\"Luxembourg\" name=\"flag\" type=\"radio\">\n    <input id=\"Malta\" name=\"flag\" type=\"radio\">\n    <input id=\"Netherlands\" name=\"flag\" type=\"radio\">\n    <input id=\"Norway\" name=\"flag\" type=\"radio\">\n    <input id=\"Poland\" name=\"flag\" type=\"radio\">\n    <input id=\"Portugal\" name=\"flag\" type=\"radio\">\n    <input id=\"Romania\" name=\"flag\" type=\"radio\">\n    <input id=\"Slovakia\" name=\"flag\" type=\"radio\">\n    <input id=\"Slovenia\" name=\"flag\" type=\"radio\">\n    <input id=\"Spain\" name=\"flag\" type=\"radio\">\n    <input id=\"Sweden\" name=\"flag\" type=\"radio\">\n    <input class=\"dropdown-checkbox\" name=\"dropdown\" id=\"dropdown\" type=\"checkbox\">\n    <label class=\"dropdown-container\" for=\"dropdown\"></label>\n    <div class=\"input-wrapper\">\n        <legend>\n          <label for=\"phonenumber\">\n            Phonenumber*\n          </label>\n        </legend>\n        <div class=\"textfield\">\n            <input pattern=\"d+\" maxlength=\"11\" id=\"phonenumber\" type=\"text\">\n            <span class=\"invalid-msg\">This is not a valid phone number</span>\n        </div>\n    </div>\n    <div class=\"select-wrapper\">\n        <ul>\n            <li class=\"Austria\"><label for=\"Austria\"><span>🇦🇹</span>Austria (+43)</label></li>\n            <li class=\"Belgium\"><label for=\"Belgium\"><span>🇧🇪</span>Belgium (+32)</label></li>\n            <li class=\"Bulgaria\"><label for=\"Bulgaria\"><span>🇧🇬</span>Bulgaria (+359)</label></li>\n            <li class=\"Croatia\"><label for=\"Croatia\"><span>🇭🇷</span>Croatia (+385)</label></li>\n            <li class=\"Cyprus\"><label for=\"Cyprus\"><span>🇨🇾</span>Cyprus (+357)</label></li>\n            <li class=\"Czech\"><label for=\"Czech\"><span>🇨🇿</span>Czech Republic (+420)</label></li>\n            <li class=\"Denmark\"><label for=\"Denmark\"><span>🇩🇰</span>Denmark (+45)</label></li>\n            <li class=\"Estonia\"><label for=\"Estonia\"><span>🇪🇪</span>Estonia (+372)</label></li>\n            <li class=\"Finland\"><label for=\"Finland\"><span>🇫🇮</span>Finland (+358)</label></li>\n            <li class=\"France\"><label for=\"France\"><span>🇫🇷</span>France (+33)</label></li>\n            <li class=\"Germany\"><label for=\"Germany\"><span>🇩🇪</span>Germany (+49)</label></li>\n            <li class=\"Greece\"><label for=\"Greece\"><span>🇬🇷</span>Greece (+30)</label></li>\n            <li class=\"Hungary\"><label for=\"Hungary\"><span>🇭🇺</span>Hungary (+36)</label></li>\n            <li class=\"Iceland\"><label for=\"Iceland\"><span>🇮🇸</span>Iceland (+354)</label></li>\n            <li class=\"Ireland\"><label for=\"Ireland\"><span>🇮🇪</span>Republic of Ireland (+353)</label></li>\n            <li class=\"Italy\"><label for=\"Italy\"><span>🇮🇹</span>Italy (+39)</label></li>\n            <li class=\"Latvia\"><label for=\"Latvia\"><span>🇱🇻</span>Latvia (+371)</label></li>\n            <li class=\"Liechtenstein\"><label for=\"Liechtenstein\"><span>🇱🇮</span>Liechtenstein (+423)</label></li>\n            <li class=\"Lithuania\"><label for=\"Lithuania\"><span>🇱🇹</span>Lithuania (+370)</label></li>\n            <li class=\"Luxembourg\"><label for=\"Luxembourg\"><span>🇱🇺</span>Luxembourg (+352)</label></li>\n            <li class=\"Malta\"><label for=\"Malta\"><span>🇲🇹</span>Malta (+356)</label></li>\n            <li class=\"Netherlands\"><label for=\"Netherlands\"><span>🇳🇱</span>Netherlands (+31)</label></li>\n            <li class=\"Norway\"><label for=\"Norway\"><span>🇳🇴</span>Norway (+47)</label></li>\n            <li class=\"Poland\"><label for=\"Poland\"><span>🇵🇱</span>Poland (+48)</label></li>\n            <li class=\"Portugal\"><label for=\"Portugal\"><span>🇵🇹</span>Portugal (+351)</label></li>\n            <li class=\"Romania\"><label for=\"Romania\"><span>🇷🇴</span>Romania (+40)</label></li>\n            <li class=\"Slovakia\"><label for=\"Slovakia\"><span>🇸🇰</span>Slovakia (+421)</label></li>\n            <li class=\"Slovenia\"><label for=\"Slovenia\"><span>🇸🇮</span>Slovenia (+386)</label></li>\n            <li class=\"Spain\"><label for=\"Spain\"><span>🇪🇸</span>Spain (+34)</label></li>\n            <li class=\"Sweden\"><label for=\"Sweden\"><span>🇸🇪</span>Sweden (+46)</label></li>\n        </ul>\n    </div>\n</div>', '.ui-wrapper {\n  --width: 250px;\n  --height: 50px;\n  --background: #fff;\n  --text-color: rgb(73, 73, 73);\n  --border-color: rgb(185, 184, 184);\n  --border-focus-color: rgb(0, 110, 255);\n  --shadow-color: rgba(34, 60, 80, 0.2);\n  --shadow-focus-color: rgba(0, 110, 255, 0.2);\n  --dropdown-button-color: #e6e6e6;\n  --dropdown-button-hover-color: #dad9d9;\n}\n\n.ui-wrapper *,\n.ui-wrapper *::before,\n.ui-wrapper *::after {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n  font-family: sans-serif;\n  color: var(--text-color);\n}\n\n.ui-wrapper {\n  width: var(--width);\n  height: var(--height);\n  display: -webkit-inline-box;\n  display: -ms-inline-flexbox;\n  display: inline-flex;\n  border-radius: 10px;\n  position: relative;\n  border: 1px solid var(--border-color);\n  background-color: var(--background);\n  -webkit-box-pack: justify;\n  -ms-flex-pack: justify;\n  justify-content: space-between;\n  padding-right: 10px;\n  -webkit-box-shadow: 0px 2px 5px 0px var(--shadow-color);\n  box-shadow: 0px 2px 5px 0px var(--shadow-color);\n  -webkit-transition: .4s;\n  -o-transition: .4s;\n  transition: .4s;\n  -webkit-user-select: none;\n  -moz-user-select: none;\n  -ms-user-select: none;\n  user-select: none;\n}\n\n.ui-wrapper>input {\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  appearance: none;\n  margin: 0;\n  width: 0;\n  height: 0;\n  opacity: 0;\n  position: absolute;\n  left: 9999px;\n}\n\n.dropdown-container {\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  padding: 0 10px;\n  cursor: pointer;\n  border-radius: 9px 0 0 9px;\n  background-color: var(--dropdown-button-color);\n}\n\n.dropdown-container::before {\n  content: \"🇦🇹\";\n  font-size: 20px;\n  background: none !important;\n}\n\n.dropdown-container::after {\n  content: \"\";\n  background-image: url(\"data:image/svg+xml;base64,\");\n  width: 12px;\n  height: 12px;\n  background-position: center;\n  background-size: cover;\n  margin-left: 5px;\n  -webkit-transition: .2s;\n  -o-transition: .2s;\n  transition: .2s;\n}\n\n.select-wrapper {\n  width: var(--width);\n  position: absolute;\n  top: calc(var(--height) + 20px);\n  left: 0;\n  opacity: 0;\n  visibility: hidden;\n  -webkit-transition: .2s;\n  -o-transition: .2s;\n  transition: .2s;\n}\n\n.select-wrapper ul {\n  width: 100%;\n  background-color: white;\n  border-radius: 10px;\n  padding: 10px;\n  margin: 0;\n  list-style: none;\n  height: 300px;\n  display: -webkit-inline-box;\n  display: -ms-inline-flexbox;\n  display: inline-flex;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  -webkit-box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);\n  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);\n  overflow-y: auto;\n  white-space: nowrap;\n}\n\n.select-wrapper ul li {\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n  padding: 5px;\n  border-radius: 5px;\n}\n\n.select-wrapper ul li label {\n  width: 100%;\n}\n\n.select-wrapper ul li,\n.select-wrapper ul li * {\n  cursor: pointer;\n}\n\n.select-wrapper ul li:hover {\n  background: lightgray;\n}\n\n.select-wrapper ul li span {\n  display: inline-block;\n  margin-right: 15px;\n}\n\n.input-wrapper {\n  width: 100%;\n  padding-left: 10px;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-orient: vertical;\n  -webkit-box-direction: normal;\n  -ms-flex-direction: column;\n  flex-direction: column;\n  -webkit-box-pack: center;\n  -ms-flex-pack: center;\n  justify-content: center;\n  row-gap: 2px;\n}\n\n.input-wrapper legend {\n  font-size: 11px;\n}\n\n.input-wrapper .textfield {\n  width: 100%;\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-box-align: center;\n  -ms-flex-align: center;\n  align-items: center;\n}\n\n.input-wrapper .textfield::before {\n  content: \"+31\";\n  margin-right: 5px;\n  white-space: nowrap;\n}\n\n.input-wrapper .textfield input {\n  width: 100%;\n  font-size: 16px;\n  outline: none;\n  border: none;\n  background: none;\n}\n\n.invalid-msg {\n  font-size: 12px;\n  position: absolute;\n  color: red;\n  top: 115%;\n  left: 0;\n  opacity: 0;\n  visibility: hidden;\n  -webkit-transition: .2s;\n  -o-transition: .2s;\n  transition: .2s;\n}\n\n/* actions */\n\n#phonenumber:invalid+.invalid-msg {\n  top: 110%;\n  opacity: 1;\n  visibility: visible;\n}\n\n.ui-wrapper:focus-within {\n  border-color: var(--border-focus-color);\n  -webkit-box-shadow: 0px 2px 5px 0px var(--shadow-focus-color);\n  box-shadow: 0px 2px 5px 0px var(--shadow-focus-color);\n}\n\n.dropdown-container:hover {\n  background-color: var(--dropdown-button-hover-color);\n}\n\n.dropdown-checkbox:checked~.select-wrapper {\n  top: calc(var(--height) + 5px);\n  opacity: 1;\n  visibility: visible;\n}\n\n.dropdown-checkbox:checked+.dropdown-container::after {\n  rotate: 180deg;\n  translate: 0 -2px;\n}\n\n.ui-wrapper input#Austria:checked~.dropdown-container::before,\n.ui-wrapper input#Austria:checked~.select-wrapper li.Austria {\n  content: \"🇦🇹\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Belgium:checked~.dropdown-container::before,\n.ui-wrapper input#Belgium:checked~.select-wrapper li.Belgium {\n  content: \"🇧🇪\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Bulgaria:checked~.dropdown-container::before,\n.ui-wrapper input#Bulgaria:checked~.select-wrapper li.Bulgaria {\n  content: \"🇧🇬\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Croatia:checked~.dropdown-container::before,\n.ui-wrapper input#Croatia:checked~.select-wrapper li.Croatia {\n  content: \"🇭🇷\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Cyprus:checked~.dropdown-container::before,\n.ui-wrapper input#Cyprus:checked~.select-wrapper li.Cyprus {\n  content: \"🇨🇾\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Czech:checked~.dropdown-container::before,\n.ui-wrapper input#Czech:checked~.select-wrapper li.Czech {\n  content: \"🇨🇿\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Denmark:checked~.dropdown-container::before,\n.ui-wrapper input#Denmark:checked~.select-wrapper li.Denmark {\n  content: \"🇩🇰\";\n  background-color: lightgray;\n}\n\n.ui-wrapper input#Estonia:checked~.dropdown-container::before,\n.ui-wrapper input#Est