(14, '<div class=\"input-container\">\n<input class=\"input\" name=\"text\" type=\"text\">\n<label class=\"label\" for=\"input\">Enter Your Name</label>\n<div class=\"topline\"></div>\n<div class=\"underline\"></div>\n</div>', '.input-container {\n  position: relative;\n}\n\n.input {\n  padding: 10px;\n  height: 40px;\n  border: 2px solid #0B2447;\n  border-top: none;\n  font-size: 16px;\n  background: transparent;\n  outline: none;\n  box-shadow: 7px 7px 0px 0px #0B2447;\n  transition: all 0.5s;\n}\n\n.input:focus {\n  box-shadow: none;\n  transition: all 0.5s;\n}\n\n.label {\n  position: absolute;\n  top: 10px;\n  left: 10px;\n  color: #0B2447;\n  transition: all 0.5s;\n  transform: scale(0);\n  z-index: -1;\n}\n\n.input-container .topline {\n  position: absolute;\n  content: \"\";\n  background-color: #0B2447;\n  width: 0%;\n  height: 2px;\n  right: 0;\n  top: 0;\n  transition: all 0.5s;\n}\n\n.input-container input[type=\"text\"]:focus ~ .topline {\n  width: 35%;\n  transition: all 0.5s;\n}\n\n.input-container .underline {\n  position: absolute;\n  content: \"\";\n  background-color: #0B2447;\n  width: 0%;\n  height: 2px;\n  right: 0;\n  bottom: 0;\n  transition: all 0.5s;\n}\n\n.input-container input[type=\"text\"]:focus ~ .underline {\n  width: 100%;\n  transition: all 0.5s;\n}\n\n.input-container input[type=\"text\"]:focus ~ .label {\n  top: -10px;\n  transform: scale(1);\n  transition: all 0.5s;\n}'),
(15, '<button class=\"button\">\n  <span class=\"shadow\"></span>\n  <span class=\"edge\"></span>\n  <div class=\"front\">\n    <span>Start Session</span>\n    <svg fill=\"currentColor\" viewBox=\"0 0 20 20\" class=\"arrow\">\n      <path\n        clip-rule=\"evenodd\"\n        d=\"M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z\"\n        fill-rule=\"evenodd\"\n      ></path>\n    </svg>\n  </div>\n</button>\n', '.button {\n  position: relative;\n  border: none;\n  background: transparent;\n  padding: 0;\n  outline: none;\n  cursor: pointer;\n  font-family: monospace;\n  font-weight: 300;\n  text-transform: uppercase;\n  font-size: 1.25rem;\n}\n\n.button .shadow {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.25);\n  border-radius: 0.5rem;\n  transform: translateY(0.125rem);\n  transition: transform 600ms cubic-bezier(0.3, 0.7, 0.4, 1);\n}\n\n.button .edge {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  border-radius: 0.5rem;\n  background: linear-gradient(\n    to left,\n    hsl(217, 33%, 16%) 0%,\n    hsl(217, 33%, 32%) 8%,\n    hsl(217, 33%, 32%) 92%,\n    hsl(217, 33%, 16%) 100%\n  );\n}\n\n.button .front {\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 0.75rem 1.5rem;\n  color: white;\n  background: linear-gradient(to right, #f27121, #e94057, #8a2387);\n  border-radius: 0.5rem;\n  transform: translateY(-0.25rem);\n  gap: 0.75rem;\n  transition: transform 600ms cubic-bezier(0.3, 0.7, 0.4, 1);\n}\n\n.button .front .arrow {\n  margin-left: 0.5rem;\n  display: inline-block;\n  width: 1.25rem;\n  height: 1.25rem;\n  transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);\n  fill: currentColor;\n}\n\n.button:hover .shadow {\n  transform: translateY(0.25rem);\n  transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);\n}\n\n.button:hover .front {\n  transform: translateY(-0.375rem);\n  transition: transform 250ms cubic-bezier(0.3, 0.7, 0.4, 1.5);\n  filter: brightness(115%);\n}\n\n.button:hover .front .arrow {\n  transform: translateX(0.25rem);\n}\n\n.button:active .shadow {\n  transform: translateY(0.0625rem);\n  transition: transform 34ms;\n}\n\n.button:active .front {\n  transform: translateY(-0.125rem);\n  transition: transform 34ms;\n}\n\n.button .front span {\n  user-select: none;\n}\n'),
(16, '<input type=\"text\" autocomplete=\"off\" placeholder=\"Type your text\" name=\"text\" class=\"input\">', '.input {\n  /* fallback for old browsers */\n  background: -webkit-linear-gradient(to right, #f7797d, #FBD786, #C6FFDD);\n  /* Chrome 10-25, Safari 5.1-6 */\n  background: linear-gradient(to right, #f7797d, #FBD786, #C6FFDD);\n /* W3C, IE 10+/ Edge, Firefox 16+, Chrome 26+, Opera 12+, Safari 7+ */\n  background-repeat: no-repeat;\n  border-radius: 89% 29% 90% 23% / 0% 100% 0% 100%;\n  border-color: transparent;\n  width: 200px;\n  height: 50px;\n  padding: 20px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  text-align: center;\n  font-weight: 500;\n  font-family: inherit;\n  box-shadow: 23px 23px 46px #bebebe,\n             -23px -23px 46px #ffffff;\n}\n\n.input::placeholder {\n  color: white;\n}'),
(17, '<div class=\"input__container\">\n  <label class=\"input__label\">Username</label>\n  <input placeholder=\"Enter your username\" class=\"input\" name=\"text\" type=\"text\">\n  <p class=\"input__description\">What do you want to call yourself?</p>\n</div>', '.input__container {\n  max-width: 200px;\n  display: flex;\n  flex-direction: column;\n  gap: 6px;\n  background: rgba(255, 255, 255, 0.3);\n  padding: 15px;\n  border-radius: 20px;\n  position: relative;\n}\n\n.input__container::before {\n  content: \"\";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  z-index: -1;\n  filter: blur(25px);\n  border-radius: 20px;\n  background-color: #e499ff;\n  background-image: radial-gradient(at 47% 69%, hsla(17,62%,65%,1) 0px, transparent 50%),\nradial-gradient(at 9% 32%, hsla(222,75%,60%,1) 0px, transparent 50%);\n}\n\n.input__label {\n  display: block;\n  margin-left: 0.4em;\n  color: #000;\n  text-transform: uppercase;\n  font-size: 0.9em;\n  font-weight: bold;\n}\n\n.input__description {\n  font-size: 0.6em;\n  font-weight: bold;\n  text-align: center;\n  color: rgba(0, 0, 0, 0.5);\n}\n\n.input {\n  border: none;\n  outline: none;\n  width: 100%;\n  padding: 0.6em;\n  padding-left: 0.9em;\n  border-radius: 20px;\n  background: #fff;\n  transition: background 300ms, color 300ms;\n}\n\n.input:hover,.input:focus {\n  background: rgb(0, 0, 0);\n  color: #fff;\n}'),
(18, '<div class=\"input-container\">\n  <div class=\"input-field-container\">\n    <input type=\"text\" class=\"holo-input\" placeholder=\"John\" />\n    <div class=\"input-border\"></div>\n    <div class=\"holo-scan-line\"></div>\n    <div class=\"input-glow\"></div>\n    <div class=\"input-active-indicator\"></div>\n    <div class=\"input-label\">First name</div>\n\n    <div class=\"input-data-visualization\">\n      <div class=\"data-segment\" style=\"--index: 1;\"></div>\n      <div class=\"data-segment\" style=\"--index: 2;\"></div>\n      <div class=\"data-segment\" style=\"--index: 3;\"></div>\n      <div class=\"data-segment\" style=\"--index: 4;\"></div>\n      <div class=\"data-segment\" style=\"--index: 5;\"></div>\n      <div class=\"data-segment\" style=\"--index: 6;\"></div>\n      <div class=\"data-segment\" style=\"--index: 7;\"></div>\n      <div class=\"data-segment\" style=\"--index: 8;\"></div>\n      <div class=\"data-segment\" style=\"--index: 9;\"></div>\n      <div class=\"data-segment\" style=\"--index: 10;\"></div>\n      <div class=\"data-segment\" style=\"--index: 11;\"></div>\n      <div class=\"data-segment\" style=\"--index: 12;\"></div>\n      <div class=\"data-segment\" style=\"--index: 13;\"></div>\n      <div class=\"data-segment\" style=\"--index: 14;\"></div>\n      <div class=\"data-segment\" style=\"--index: 15;\"></div>\n      <div class=\"data-segment\" style=\"--index: 16;\"></div>\n      <div class=\"data-segment\" style=\"--index: 17;\"></div>\n      <div class=\"data-segment\" style=\"--index: 18;\"></div>\n      <div class=\"data-segment\" style=\"--index: 19;\"></div>\n      <div class=\"data-segment\" style=\"--index: 20;\"></div>\n    </div>\n\n    <div class=\"input-particles\">\n      <div\n        class=\"input-particle\"\n        style=\"--index: 1; top: 20%; left: 10%;\"\n      ></div>\n      <div\n        class=\"input-particle\"\n        style=\"--index: 2; top: 65%; left: 25%;\"\n      ></div>\n      <div\n        class=\"input-particle\"\n        style=\"--index: 3; top: 40%; left: 40%;\"\n      ></div>\n      <div\n        class=\"input-particle\"\n        style=\"--index: 4; top: 75%; left: 60%;\"\n      ></div>\n      <div\n        class=\"input-particle\"\n        style=\"--index: 5; top: 30%; left: 75%;\"\n      ></div>\n      <div\n        class=\"input-particle\"\n        style=\"--index: 6; top: 60%; left: 90%;\"\n      ></div>\n    </div>\n\n    <div class=\"input-holo-overlay\"></div>\n\n    <div class=\"interface-lines\">\n      <div class=\"interface-line\"></div>\n      <div class=\"interface-line\"></div>\n      <div class=\"interface-line\"></div>\n      <div class=\"interface-line\"></div>\n    </div>\n\n    <div class=\"hex-decoration\"></div>\n    <div class=\"input-status\">Ready for input</div>\n    <div class=\"power-indicator\"></div>\n\n    <div class=\"input-decoration\">\n      <div class=\"decoration-dot\"></div>\n      <div class=\"decoration-line\"></div>\n      <div class=\"decoration-dot\"></div>\n      <div class=\"decoration-line\"></div>\n      <div class=\"decoration-dot\"></div>\n      <div class=\"decoration-line\"></div>\n      <div class=\"decoration-dot\"></div>\n    </div>\n  </div>\n</div>\n', '.input-container {\n  position: relative;\n  width: 400px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  z-index: 10;\n}\n\n.input-field-container {\n  position: relative;\n  width: 100%;\n  margin-bottom: 30px;\n}\n\n.holo-input {\n  width: 100%;\n  height: 60px;\n  background: rgba(0, 12, 36, 0.7);\n  border: none;\n  outline: none;\n  padding: 0 60px 0 20px;\n  color: rgba(0, 195, 255, 0.9);\n  font-family: \"Orbitron\", sans-serif;\n  font-size: 18px;\n  letter-spacing: 1px;\n  backdrop-filter: blur(5px);\n  -webkit-backdrop-filter: blur(5px);\n  border-radius: 4px;\n  box-shadow:\n    0 0 15px rgba(0, 140, 255, 0.3),\n    inset 0 0 10px rgba(0, 0, 0, 0.8);\n  transition: all 0.3s ease;\n  text-shadow: 0 0 5px rgba(0, 160, 255, 0.7);\n  z-index: 1;\n}\n\n.holo-input::placeholder {\n  color: rgba(0, 110, 200, 0.4);\n  transition: all 0.3s ease;\n}\n\n.input-border {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  pointer-events: none;\n  border: 1px solid rgba(0, 150, 255, 0.4);\n  border-radius: 4px;\n  z-index: 2;\n}\n\n.input-border::before,\n.input-border::after {\n  content: \"\";\n  position: absolute;\n  width: 20px;\n  height: 20px;\n  border: 1px solid rgba(0, 150, 255, 0.7);\n  z-index: 2;\n  transition: all 0.3s ease;\n}\n\n.input-border::before {\n  top: -1px;\n  left: -1px;\n  border-right: none;\n  border-bottom: none;\n}\n\n.input-border::after {\n  bottom: -1px;\n  right: -1px;\n  border-left: none;\n  border-top: none;\n}\n\n.holo-scan-line {\n  position: absolute;\n  width: 100%;\n  height: 2px;\n  background: linear-gradient(\n    90deg,\n    rgba(0, 0, 0, 0) 0%,\n    rgba(0, 150, 255, 0.5) 20%,\n    rgba(255, 255, 255, 0.8) 50%,\n    rgba(0, 150, 255, 0.5) 80%,\n    rgba(0, 0, 0, 0) 100%\n  );\n  top: 0;\n  left: 0;\n  opacity: 0;\n  filter: blur(1px);\n  z-index: 3;\n  pointer-events: none;\n  transition: opacity 0.3s ease;\n}\n\n.input-glow {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  background: radial-gradient(\n    ellipse at center,\n    rgba(0, 150, 255, 0.1) 0%,\n    rgba(0, 0, 0, 0) 70%\n  );\n  opacity: 0;\n  border-radius: 4px;\n  z-index: 0;\n  transition: opacity 0.3s ease;\n  pointer-events: none;\n}\n\n.input-active-indicator {\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  background: rgba(0, 150, 255, 0.7);\n  border-radius: 50%;\n  right: 20px;\n  top: 25px;\n  opacity: 0.3;\n  box-shadow: 0 0 10px rgba(0, 150, 255, 0.5);\n  transition: all 0.3s ease;\n  z-index: 2;\n}\n\n.input-label {\n  position: absolute;\n  top: -30px;\n  left: 0;\n  color: rgba(0, 150, 255, 0.7);\n  font-size: 14px;\n  font-weight: 500;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  transition: all 0.3s ease;\n  pointer-events: none;\n  text-shadow: 0 0 5px rgba(0, 150, 255, 0.5);\n}\n\n.input-data-visualization {\n  position: absolute;\n  width: calc(100% - 40px);\n  height: 3px;\n  bottom: 12px;\n  left: 20px;\n  display: flex;\n  justify-content: space-between;\n  z-index: 2;\n  opacity: 0;\n  transition: opacity 0.3s ease;\n  pointer-events: none;\n}\n\n.data-segment {\n  width: 4%;\n  height: 100%;\n  background: rgba(0, 150, 255, 0.3);\n  transition: all 0.5s ease;\n}\n\n.data-segment:nth-child(even) {\n  height: 5px;\n  transform: translateY(-1px);\n}\n\n.input-particles {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  pointer-events: none;\n  z-index: 3;\n  overflow: hidden;\n  border-radius: 4px;\n}\n\n.input-particle {\n  position: absolute;\n  width: 4px;\n  height: 4px;\n  background: rgba(0, 150, 255, 0.7);\n  border-radius: 50%;\n  opacity: 0;\n  filter: blur(1px);\n  transition: all 0.3s ease;\n  box-shadow: 0 0 5px rgba(0, 150, 255, 0.7);\n}\n\n.input-holo-overlay {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  background-image: linear-gradient(\n    90deg,\n    rgba(0, 150, 255, 0.05) 25%,\n    rgba(0, 150, 255, 0.02) 50%,\n    rgba(0, 150, 255, 0.05) 75%\n  );\n  background-size: 8px 100%;\n  opacity: 0.5;\n  pointer-events: none;\n  z-index: 4;\n  mix-blend-mode: overlay;\n}\n\n.interface-lines {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n  pointer-events: none;\n  z-index: 2;\n}\n\n.interface-line {\n  position: absolute;\n  background: rgba(0, 150, 255, 0.3);\n  transition: all 0.3s ease;\n}\n\n.interface-line:nth-child(1) {\n  width: 20px;\n  height: 1px;\n  top: 15px;\n  right: 15px;\n}\n\n.interface-line:nth-child(2) {\n  width: 1px;\n  height: 20px;\n  top: 15px;\n  right: 15px;\n}\n\n.interface-line:nth-child(3) {\n  width: 1px;\n  height: 20px;\n  bottom: 15px;\n  left: 15px;\n}\n\n.interface-line:nth-child(4) {\n  width: 20px;\n  height: 1px;\n  bottom: 15px;\n  left: 15px;\n}\n\n.hex-decoration {\n  position: absolute;\n  width: 30px;\n  height: 34px;\n  background: transparent;\n  clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%);\n  border: 1px solid rgba(0, 150, 255, 0.3);\n  right: -15px;\n  top: 50%;\n  transform: translateY(-50%);\n  opacity: 1;\n  transition: all 0.3s ease;\n  z-index: 2;\n}\n\n.input-status {\n  position: absolute;\n  bottom: -25px;\n  right: 0;\n  font-size: 12px;\n  color: rgba(0, 150, 255, 0.5);\n  letter-spacing: 1px;\n  opacity: 0;\n  transition: all 0.3s ease;\n  pointer-events: none;\n  text-transform: uppercase;\n}\n\n@keyframes scan-animation {\n  0% {\n    top: 0;\n    opacity: 0;\n  }\n  10% {\n    opacity: 1;\n  }\n  90% {\n    opacity: 1;\n  }\n  100% {\n    top: 100%;\n    opacity: 0;\n  }\n}\n\n@keyframes data-pulse {\n  0% {\n    transform: scaleY(1);\n  }\n  50% {\n    transform: scaleY(1.8);\n  }\n  100% {\n    transform: scaleY(1);\n  }\n}\n\n@keyframes particle-float {\n  0%,\n  100% {\n    transform: translateY(0);\n  }\n  50% {\n    transform: translateY(-10px);\n  }\n}\n\n.holo-input:focus {\n  background: rgba(0, 22, 46, 0.8);\n  box-shadow:\n    0 0 20px rgba(0, 150, 255, 0.4),\n    inset 0 0 15px rgba(0, 0, 0, 0.9);\n  color: rgba(0, 210, 255, 1);\n}\n\n.holo-input:focus::placeholder {\n  color: rgba(0, 150, 255, 0.3);\n  transform: translateX(10px);\n}\n\n.holo-input:focus ~ .input-border {\n  border-color: rgba(0, 180, 255, 0.7);\n}\n\n.holo-input:focus ~ .input-border::before,\n.holo-input:focus ~ .input-border::after {\n  border-color: rgba(0, 180, 255, 1);\n  width: 30px;\n  height: 30px;\n}\n\n.holo-input:focus ~ .holo-scan-line {\n  opacity: 1;\n  animation: scan-animation 2s infinite ease-in-out;\n}\n\n.holo-input:focus ~ .input-glow {\n  opacity: 1;\n}\n\n.holo-input:focus ~ .input-active-indicator {\n  opacity: 1;\n  background: rgba(0, 200, 255, 1);\n  box-shadow: 0 0 15px rgba(0, 200, 255, 0.7);\n  transform: scale(1.2);\n}\n\n.holo-input:focus ~ .input-label {\n  color: rgba(0, 200, 255, 1);\n  text-shadow: 0 0 10px rgba(0, 200, 255, 0.7);\n  transform: translateY(-5px);\n}\n\n.holo-input:focus ~ .input-data-visualization {\n  opacity: 1;\n}\n\n.holo-input:focus ~ .input-data-visualization .data-segment {\n  animation: data-pulse 2s infinite;\n  animation-delay: calc(var(--index) * 0.1s);\n}\n\n.holo-input:focus ~ .input-status {\n  opacity: 1;\n}\n\n.holo-input:focus ~ .interface-lines .interface-line {\n  background: rgba(0, 200, 255, 0.6);\n}\n\n.holo-input:focus ~ .hex-decoration {\n  border-color: rgba(0, 200, 255, 0.6);\n  box-shadow: 0 0 10px rgba(0, 200, 255, 0.3);\n  transform: translateY(-50%) rotate(30deg);\n}\n\n.holo-input:focus ~ .input-particles .input-particle {\n  opacity: 1;\n  animation: particle-float 3s infinite ease-in-out;\n  animation-delay: calc(var(--index) * 0.2s);\n}\n\n.holo-input:hover {\n  background: rgba(0, 15, 40, 0.75);\n}\n\n.holo-input:hover ~ .input-active-indicator {\n  opacity: 0.6;\n}\n\n.holo-input:hover ~ .hex-decoration {\n  border-color: rgba(0, 180, 255, 0.5);\n}\n\n.power-indicator {\n  position: absolute;\n  width: 100%;\n  height: 2px;\n  background: linear-gradient(\n    90deg,\n    rgba(0, 180, 255, 0.7) 0%,\n    rgba(0, 180, 255, 0.3) 100%\n  );\n  bottom: 0;\n  left: 0;\n  transform: scaleX(0);\n  transform-origin: left;\n  transition: transform 0.3s ease;\n  z-index: 3;\n}\n\n.holo-input:focus ~ .power-indicator {\n  transform: scaleX(1);\n}\n\n.input-decoration {\n  position: absolute;\n  top: 50%;\n  left: -30px;\n  transform: translateY(-50%);\n  width: 20px;\n  height: 100%;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  align-items: flex-start;\n  opacity: 0.7;\n  transition: all 0.3s ease;\n  z-index: 2;\n  pointer-events: none;\n}\n\n.decoration-dot {\n  width: 4px;\n  height: 4px;\n  background: rgba(0, 150, 255, 0.7);\n  border-radius: 50%;\n  margin: 3px 0;\n}\n\n.decoration-line {\n  width: 15px;\n  height: 1px;\n  background: rgba(0, 150, 255, 0.5);\n  margin: 3px 0;\n}\n\n.holo-input:focus ~ .input-decoration {\n  opacity: 1;\n  transform: translateY(-50%) translateX(-5px);\n}\n\n.holo-input:focus ~ .input-decoration .decoration-dot {\n  background: rgba(0, 200, 255, 1);\n  box-shadow: 0 0 5px rgba(0, 200, 255, 0.7);\n}\n\n.holo-input:focus ~ .input-decoration .decoration-line {\n  background: rgba(0, 200, 255, 0.7);\n  box-shadow: 0 0 3px rgba(0, 200, 255, 0.5);\n}\n'),
(19, '<div class=\"input-container\">\n  <input\n    class=\"input\"\n    name=\"text\"\n    type=\"text\"\n    placeholder=\"Search the internet...\"\n  />\n</div>\n', '.input {\n  width: 100%;\n  max-width: 270px;\n  height: 60px;\n  padding: 12px;\n  font-size: 18px;\n  font-family: \"Courier New\", monospace;\n  color: #000;\n  background-color: #fff;\n  border: 4px solid #000;\n  border-radius: 0;\n  outline: none;\n  transition: all 0.3s ease;\n  box-shadow: 8px 8px 0 #000;\n}\n\n.input::placeholder {\n  color: #888;\n}\n\n.input:hover {\n  transform: translate(-4px, -4px);\n  box-shadow: 12px 12px 0 #000;\n}\n\n.input:focus {\n  background-color: #000;\n  color: #fff;\n  border-color: #ffffff;\n}\n\n.input:focus::placeholder {\n  color: #fff;\n}\n\n@keyframes typing {\n  from {\n    width: 0;\n  }\n  to {\n    width: 100%;\n  }\n}\n\n@keyframes blink {\n  50% {\n    border-color: transparent;\n  }\n}\n\n.input:focus::after {\n  content: \"|\";\n  position: absolute;\n  right: 10px;\n  animation: blink 0.7s step-end infinite;\n}\n\n.input:valid {\n  animation: typing 2s steps(30, end);\n}\n.input-container {\n  position: relative;\n  width: 100%;\n  max-width: 270px;\n}\n\n.input {\n  width: 100%;\n  height: 60px;\n  padding: 12px;\n  font-size: 18px;\n  font-family: \"Courier New\", monospace;\n  color: #000;\n  background-color: #fff;\n  border: 4px solid #000;\n  border-radius: 0;\n  outline: none;\n  transition: all 0.3s ease;\n  box-shadow: 8px 8px 0 #000;\n}\n\n.input::placeholder {\n  color: #888;\n}\n\n.input:hover {\n  transform: translate(-4px, -4px);\n  box-shadow: 12px 12px 0 #000;\n}\n\n.input:focus {\n  background-color: #010101;\n  color: #fff;\n  border-color: #d6d9dd;\n}\n\n.input:focus::placeholder {\n  color: #fff;\n}\n\n@keyframes shake {\n  0% {\n    transform: translateX(0);\n  }\n  25% {\n    transform: translateX(-5px) rotate(-5deg);\n  }\n  50% {\n    transform: translateX(5px) rotate(5deg);\n  }\n  75% {\n    transform: translateX(-5px) rotate(-5deg);\n  }\n  100% {\n    transform: translateX(0);\n  }\n}\n\n.input:focus {\n  animation: shake 0.5s ease-in-out;\n}\n\n@keyframes glitch {\n  0% {\n    transform: none;\n    opacity: 1;\n  }\n  7% {\n    transform: skew(-0.5deg, -0.9deg);\n    opacity: 0.75;\n  }\n  10% {\n    transform: none;\n    opacity: 1;\n  }\n  27% {\n    transform: none;\n    opacity: 1;\n  }\n  30% {\n    transform: skew(0.8deg, -0.1deg);\n    opacity: 0.75;\n  }\n  35% {\n    transform: none;\n    opacity: 1;\n  }\n  52% {\n    transform: none;\n    opacity: 1;\n  }\n  55% {\n    transform: skew(-1deg, 0.2deg);\n    opacity: 0.75;\n  }\n  50% {\n    transform: none;\n    opacity: 1;\n  }\n  72% {\n    transform: none;\n    opacity: 1;\n  }\n  75% {\n    transform: skew(0.4deg, 1deg);\n    opacity: 0.75;\n  }\n  80% {\n    transform: none;\n    opacity: 1;\n  }\n  100% {\n    transform: none;\n    opacity: 1;\n  }\n}\n\n.input:not(:placeholder-shown) {\n  animation: glitch 1s linear infinite;\n}\n\n.input-container::after {\n  content: \"|\";\n  position: absolute;\n  right: 10px;\n  top: 50%;\n  transform: translateY(-50%);\n  color: #000;\n  animation: blink 0.7s step-end infinite;\n}\n\n@keyframes blink {\n  50% {\n    opacity: 0;\n  }\n}\n\n.input:focus + .input-container::after {\n  color: #fff;\n}\n\n.input:not(:placeholder-shown) {\n  font-weight: bold;\n  letter-spacing: 1px;\n  text-shadow: 0px 0px 0 #000;\n}\n'),
(20, '<div class=\"input__container\">\n  <div class=\"shadow__input\"></div>\n  <button class=\"input__button__shadow\">\n    <svg fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 20 20\" height=\"20px\" width=\"20px\">\n      <path d=\"M4 9a5 5 0 1110 0A5 5 0 014 9zm5-7a7 7 0 104.2 12.6.999.999 0 00.093.107l3 3a1 1 0 001.414-1.414l-3-3a.999.999 0 00-.107-.093A7 7 0 009 2z\" fill-rule=\"evenodd\" fill=\"#17202A\"></path>\n    </svg>\n  </button>\n  <input type=\"text\" name=\"text\" class=\"input__search\" placeholder=\"What do you want to search?\">\n</div>', '.input__container {\n  position: relative;\n  background: rgba(255, 255, 255, 0.664);\n  padding: 10px 15px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 5px;\n  border-radius: 22px;\n  max-width: 300px;\n  transition: transform 400ms;\n  transform-style: preserve-3d;\n  transform: rotateX(15deg) rotateY(-20deg);\n  perspective: 500px;\n}\n\n.shadow__input {\n  content: \"\";\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  left: 0;\n  bottom: 0;\n  z-index: -1;\n  filter: blur(30px);\n  border-radius: 20px;\n  background-color: #999cff;\n  background-image: radial-gradient(at 85% 51%, hsla(60,60%,61%,1) 0px, transparent 50%),\n    radial-gradient(at 74% 68%, hsla(235,69%,77%,1) 0px, transparent 50%),\n    radial-gradient(at 64% 79%, hsla(284,72%,73%,1) 0px, transparent 50%),\n    radial-gradient(at 75% 16%, hsla(283,60%,72%,1) 0px, transparent 50%),\n    radial-gradient(at 90% 65%, hsla(153,70%,64%,1) 0px, transparent 50%),\n    radial-gradient(at 91% 83%, hsla(283,74%,69%,1) 0px, transparent 50%),\n    radial-gradient(at 72% 91%, hsla(213,75%,75%,1) 0px, transparent 50%);\n}\n\n.input__button__shadow {\n  cursor: pointer;\n  border: none;\n  background: none;\n  transition: transform 400ms, background 400ms;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: 12px;\n  padding: 5px;\n}\n\n.input__button__shadow:hover {\n  background: rgba(255, 255, 255, 0.411);\n}\n\n.input__search {\n  width: 100%;\n  border-radius: 20px;\n  outline: none;\n  border: none;\n  padding: 8px;\n  position: relative;\n}');

