(2, '\r\n<div class=\"🤚\">\r\n	<div class=\"👉\"></div>\r\n	<div class=\"👉\"></div>\r\n	<div class=\"👉\"></div>\r\n	<div class=\"👉\"></div>\r\n	<div class=\"🌴\"></div>		\r\n	<div class=\"👍\"></div>\r\n</div>', '.🤚 {\n  --skin-color: #E4C560;\n  --tap-speed: 0.6s;\n  --tap-stagger: 0.1s;\n  position: relative;\n  width: 80px;\n  height: 60px;\n  margin-left: 80px;\n}\n\n.🤚:before {\n  content: \';\n  display: block;\n  width: 180%;\n  height: 75%;\n  position: absolute;\n  top: 70%;\n  right: 20%;\n  background-color: black;\n  border-radius: 40px 10px;\n  filter: blur(10px);\n  opacity: 0.3;\n}\n\n.🌴 {\n  display: block;\n  width: 100%;\n  height: 100%;\n  position: absolute;\n  top: 0;\n  left: 0;\n  background-color: var(--skin-color);\n  border-radius: 10px 40px;\n}\n\n.👍 {\n  position: absolute;\n  width: 120%;\n  height: 38px;\n  background-color: var(--skin-color);\n  bottom: -18%;\n  right: 1%;\n  transform-origin: calc(100% - 20px) 20px;\n  transform: rotate(-20deg);\n  border-radius: 30px 20px 20px 10px;\n  border-bottom: 2px solid rgba(0, 0, 0, 0.1);\n  border-left: 2px solid rgba(0, 0, 0, 0.1);\n}\n\n.👍:after {\n  width: 20%;\n  height: 60%;\n  content: \';\n  background-color: rgba(255, 255, 255, 0.3);\n  position: absolute;\n  bottom: -8%;\n  left: 5px;\n  border-radius: 60% 10% 10% 30%;\n  border-right: 2px solid rgba(0, 0, 0, 0.05);\n}\n\n.👉 {\n  position: absolute;\n  width: 80%;\n  height: 35px;\n  background-color: var(--skin-color);\n  bottom: 32%;\n  right: 64%;\n  transform-origin: 100% 20px;\n  animation-duration: calc(var(--tap-speed) * 2);\n  animation-timing-function: ease-in-out;\n  animation-iteration-count: infinite;\n  transform: rotate(10deg);\n}\n\n.👉:before {\n  content: \';\n  position: absolute;\n  width: 140%;\n  height: 30px;\n  background-color: var(--skin-color);\n  bottom: 8%;\n  right: 65%;\n  transform-origin: calc(100% - 20px) 20px;\n  transform: rotate(-60deg);\n  border-radius: 20px;\n}\n\n.👉:nth-child(1) {\n  animation-delay: 0;\n  filter: brightness(70%);\n  animation-name: tap-upper-1;\n}\n\n.👉:nth-child(2) {\n  animation-delay: var(--tap-stagger);\n  filter: brightness(80%);\n  animation-name: tap-upper-2;\n}\n\n.👉:nth-child(3) {\n  animation-delay: calc(var(--tap-stagger) * 2);\n  filter: brightness(90%);\n  animation-name: tap-upper-3;\n}\n\n.👉:nth-child(4) {\n  animation-delay: calc(var(--tap-stagger) * 3);\n  filter: brightness(100%);\n  animation-name: tap-upper-4;\n}\n\n@keyframes tap-upper-1 {\n  0%, 50%, 100% {\n    transform: rotate(10deg) scale(0.4);\n  }\n\n  40% {\n    transform: rotate(50deg) scale(0.4);\n  }\n}\n\n@keyframes tap-upper-2 {\n  0%, 50%, 100% {\n    transform: rotate(10deg) scale(0.6);\n  }\n\n  40% {\n    transform: rotate(50deg) scale(0.6);\n  }\n}\n\n@keyframes tap-upper-3 {\n  0%, 50%, 100% {\n    transform: rotate(10deg) scale(0.8);\n  }\n\n  40% {\n    transform: rotate(50deg) scale(0.8);\n  }\n}\n\n@keyframes tap-upper-4 {\n  0%, 50%, 100% {\n    transform: rotate(10deg) scale(1);\n  }\n\n  40% {\n    transform: rotate(50deg) scale(1);\n  }\n}\n'),
(3, '\r\n<div class=\"container\">\r\n  <span></span>\r\n  <span></span>\r\n  <span></span>\r\n  <span></span>\r\n</div>', '.container {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  border-radius: 50%;\n  height: 96px;\n  width: 96px;\n  animation: rotate_3922 1.2s linear infinite;\n  background-color: #9b59b6;\n  background-image: linear-gradient(#9b59b6, #84cdfa, #5ad1cd);\n}\n\n.container span {\n  position: absolute;\n  border-radius: 50%;\n  height: 100%;\n  width: 100%;\n  background-color: #9b59b6;\n  background-image: linear-gradient(#9b59b6, #84cdfa, #5ad1cd);\n}\n\n.container span:nth-of-type(1) {\n  filter: blur(5px);\n}\n\n.container span:nth-of-type(2) {\n  filter: blur(10px);\n}\n\n.container span:nth-of-type(3) {\n  filter: blur(25px);\n}\n\n.container span:nth-of-type(4) {\n  filter: blur(50px);\n}\n\n.container::after {\n  content: \"\";\n  position: absolute;\n  top: 10px;\n  left: 10px;\n  right: 10px;\n  bottom: 10px;\n  background-color: #fff;\n  border: solid 5px #ffffff;\n  border-radius: 50%;\n}\n\n@keyframes rotate_3922 {\n  from {\n    transform: translate(-50%, -50%) rotate(0deg);\n  }\n\n  to {\n    transform: translate(-50%, -50%) rotate(360deg);\n  }\n}\n'),
(4, '\r\n<div class=\"lava-lamp\">\r\n  <div class=\"bubble\"></div>\r\n  <div class=\"bubble1\"></div>\r\n  <div class=\"bubble2\"></div>\r\n  <div class=\"bubble3\"></div>\r\n</div>\r\n', '@keyframes drop {\n  0% {\n    transform: translateY(0px);\n  }\n  50% {\n    transform: translateY(80px);\n  }\n  100% {\n    transform: translateY(0px);\n  }\n}\n\n.lava-lamp {\n  position: relative;\n  width: 50px;\n  height: 100px;\n  background: #000;\n  border-radius: 25px;\n  overflow: hidden;\n}\n\n.bubble {\n  position: absolute;\n  top: 0;\n  width: 20px;\n  height: 20px;\n  background: linear-gradient(to bottom, #e64980, #ff8787);\n  border-radius: 50%;\n  left: 15px;\n  animation: drop 5s ease-in-out infinite;\n}\n.bubble1 {\n  position: absolute;\n  top: 0;\n  width: 20px;\n  height: 20px;\n  background: linear-gradient(to bottom, #82c91e, #3bc9db);\n  border-radius: 50%;\n  left: 1px;\n  animation: drop 3s ease-in-out infinite;\n}\n.bubble2 {\n  position: absolute;\n  top: 0;\n  width: 20px;\n  height: 20px;\n  background: linear-gradient(to bottom, #7950f2, #f783ac);\n  border-radius: 50%;\n  left: 30px;\n  animation: drop 4s ease-in-out infinite;\n}\n.bubble3 {\n  position: absolute;\n  top: 0;\n  width: 20px;\n  height: 20px;\n  background: linear-gradient(to bottom, #4481eb, #04befe);\n  border-radius: 50%;\n  left: 20px;\n  animation: drop 6s ease-in-out infinite;\n}\n'),
(5, '\r\n		<svg class=\"pl\" viewBox=\"0 0 160 160\" width=\"160px\" height=\"160px\" xmlns=\"http://www.w3.org/2000/svg\">\r\n			<defs>\r\n				<linearGradient id=\"grad\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\r\n					<stop offset=\"0%\" stop-color=\"#000\"></stop>\r\n					<stop offset=\"100%\" stop-color=\"#fff\"></stop>\r\n				</linearGradient>\r\n				<mask id=\"mask1\">\r\n					<rect x=\"0\" y=\"0\" width=\"160\" height=\"160\" fill=\"url(#grad)\"></rect>\r\n				</mask>\r\n				<mask id=\"mask2\">\r\n					<rect x=\"28\" y=\"28\" width=\"104\" height=\"104\" fill=\"url(#grad)\"></rect>\r\n				</mask>\r\n			</defs>\r\n			\r\n			<g>\r\n				<g class=\"pl__ring-rotate\">\r\n					<circle class=\"pl__ring-stroke\" cx=\"80\" cy=\"80\" r=\"72\" fill=\"none\" stroke=\"hsl(223,90%,55%)\" stroke-width=\"16\" stroke-dasharray=\"452.39 452.39\" stroke-dashoffset=\"452\" stroke-linecap=\"round\" transform=\"rotate(-45,80,80)\"></circle>\r\n				</g>\r\n			</g>\r\n			<g mask=\"url(#mask1)\">\r\n				<g class=\"pl__ring-rotate\">\r\n					<circle class=\"pl__ring-stroke\" cx=\"80\" cy=\"80\" r=\"72\" fill=\"none\" stroke=\"hsl(193,90%,55%)\" stroke-width=\"16\" stroke-dasharray=\"452.39 452.39\" stroke-dashoffset=\"452\" stroke-linecap=\"round\" transform=\"rotate(-45,80,80)\"></circle>\r\n				</g>\r\n			</g>\r\n			\r\n			<g>\r\n				<g stroke-width=\"4\" stroke-dasharray=\"12 12\" stroke-dashoffset=\"12\" stroke-linecap=\"round\" transform=\"translate(80,80)\">\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(-135,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(-90,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(-45,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(0,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(45,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(90,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(135,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,10%,90%)\" points=\"0,2 0,14\" transform=\"rotate(180,0,0) translate(0,40)\"></polyline>\r\n				</g>\r\n			</g>\r\n			<g mask=\"url(#mask1)\">\r\n				<g stroke-width=\"4\" stroke-dasharray=\"12 12\" stroke-dashoffset=\"12\" stroke-linecap=\"round\" transform=\"translate(80,80)\">\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(-135,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(-90,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(-45,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(0,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(45,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(90,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(135,0,0) translate(0,40)\"></polyline>\r\n					<polyline class=\"pl__tick\" stroke=\"hsl(223,90%,80%)\" points=\"0,2 0,14\" transform=\"rotate(180,0,0) translate(0,40)\"></polyline>\r\n				</g>\r\n			</g>\r\n			\r\n			<g>\r\n				<g transform