mation-delay: -0.75s;\n}\n\n.pl__tick:nth-child(7) {\n  animation-delay: -0.5s;\n}\n\n.pl__tick:nth-child(8) {\n  animation-delay: -0.25s;\n}\n\n/* Animations */\n@keyframes arrows42 {\n  from {\n    transform: rotate(45deg);\n  }\n\n  to {\n    transform: rotate(405deg);\n  }\n}\n\n@keyframes ringRotate42 {\n  from {\n    transform: rotate(0);\n  }\n\n  to {\n    transform: rotate(720deg);\n  }\n}\n\n@keyframes ringStroke42 {\n  from,\n	to {\n    stroke-dashoffset: 452;\n    transform: rotate(-45deg);\n  }\n\n  50% {\n    stroke-dashoffset: 169.5;\n    transform: rotate(-180deg);\n  }\n}\n\n@keyframes tick42 {\n  from,\n	3%,\n	47%,\n	to {\n    stroke-dashoffset: -12;\n  }\n\n  14%,\n	36% {\n    stroke-dashoffset: 0;\n  }\n}'),
(6, '\r\n<div class=\"loader\">\r\n  <div class=\"box\">\r\n    <div class=\"logo\">\r\n      <svg\r\n        xmlns=\"http://www.w3.org/2000/svg\"\r\n        fill=\"none\"\r\n        viewBox=\"0 0 94 94\"\r\n        class=\"svg\"\r\n      >\r\n        <path\r\n          d=\"M38.0481 4.82927C38.0481 2.16214 40.018 0 42.4481 0H51.2391C53.6692 0 55.6391 2.16214 55.6391 4.82927V40.1401C55.6391 48.8912 53.2343 55.6657 48.4248 60.4636C43.6153 65.2277 36.7304 67.6098 27.7701 67.6098C18.8099 67.6098 11.925 65.2953 7.11548 60.6663C2.37183 56.0036 3.8147e-06 49.2967 3.8147e-06 40.5456V4.82927C3.8147e-06 2.16213 1.96995 0 4.4 0H13.2405C15.6705 0 17.6405 2.16214 17.6405 4.82927V39.1265C17.6405 43.7892 18.4805 47.2018 20.1605 49.3642C21.8735 51.5267 24.4759 52.6079 27.9678 52.6079C31.4596 52.6079 34.0127 51.5436 35.6268 49.4149C37.241 47.2863 38.0481 43.8399 38.0481 39.0758V4.82927Z\"\r\n        ></path>\r\n        <path\r\n          d=\"M86.9 61.8682C86.9 64.5353 84.9301 66.6975 82.5 66.6975H73.6595C71.2295 66.6975 69.2595 64.5353 69.2595 61.8682V4.82927C69.2595 2.16214 71.2295 0 73.6595 0H82.5C84.9301 0 86.9 2.16214 86.9 4.82927V61.8682Z\"\r\n        ></path>\r\n        <path\r\n          d=\"M2.86102e-06 83.2195C2.86102e-06 80.5524 1.96995 78.3902 4.4 78.3902H83.6C86.0301 78.3902 88 80.5524 88 83.2195V89.1707C88 91.8379 86.0301 94 83.6 94H4.4C1.96995 94 0 91.8379 0 89.1707L2.86102e-06 83.2195Z\"\r\n        ></path>\r\n      </svg>\r\n    </div>\r\n  </div>\r\n  <div class=\"box\"></div>\r\n  <div class=\"box\"></div>\r\n  <div class=\"box\"></div>\r\n  <div class=\"box\"></div>\r\n</div>\r\n', '.loader {\n  --size: 250px;\n  --duration: 2s;\n  --logo-color: grey;\n  --background: linear-gradient(\n    0deg,\n    rgba(50, 50, 50, 0.2) 0%,\n    rgba(100, 100, 100, 0.2) 100%\n  );\n  height: var(--size);\n  aspect-ratio: 1;\n  position: relative;\n}\n\n.loader .box {\n  position: absolute;\n  background: rgba(100, 100, 100, 0.15);\n  background: var(--background);\n  border-radius: 50%;\n  border-top: 1px solid rgba(100, 100, 100, 1);\n  box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  backdrop-filter: blur(5px);\n  animation: ripple var(--duration) infinite ease-in-out;\n}\n\n.loader .box:nth-child(1) {\n  inset: 40%;\n  z-index: 99;\n}\n\n.loader .box:nth-child(2) {\n  inset: 30%;\n  z-index: 98;\n  border-color: rgba(100, 100, 100, 0.8);\n  animation-delay: 0.2s;\n}\n\n.loader .box:nth-child(3) {\n  inset: 20%;\n  z-index: 97;\n  border-color: rgba(100, 100, 100, 0.6);\n  animation-delay: 0.4s;\n}\n\n.loader .box:nth-child(4) {\n  inset: 10%;\n  z-index: 96;\n  border-color: rgba(100, 100, 100, 0.4);\n  animation-delay: 0.6s;\n}\n\n.loader .box:nth-child(5) {\n  inset: 0%;\n  z-index: 95;\n  border-color: rgba(100, 100, 100, 0.2);\n  animation-delay: 0.8s;\n}\n\n.loader .logo {\n  position: absolute;\n  inset: 0;\n  display: grid;\n  place-content: center;\n  padding: 30%;\n}\n\n.loader .logo svg {\n  fill: var(--logo-color);\n  width: 100%;\n  animation: color-change var(--duration) infinite ease-in-out;\n}\n\n@keyframes ripple {\n  0% {\n    transform: scale(1);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  }\n  50% {\n    transform: scale(1.3);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 30px 20px -0px;\n  }\n  100% {\n    transform: scale(1);\n    box-shadow: rgba(0, 0, 0, 0.3) 0px 10px 10px -0px;\n  }\n}\n\n@keyframes color-change {\n  0% {\n    fill: var(--logo-color);\n  }\n  50% {\n    fill: white;\n  }\n  100% {\n    fill: var(--logo-color);\n  }\n}\n'),
(7, '<div class=\"loader\">\n  <div class=\"loader__inner\"></div>\n  <div class=\"loader__orbit\">\n    <div class=\"loader__dot\"></div>\n    <div class=\"loader__dot\"></div>\n    <div class=\"loader__dot\"></div>\n    <div class=\"loader__dot\"></div>\n  </div>\n</div>\n', '.loader {\n  position: relative;\n  width: 200px;\n  height: 200px;\n  border-radius: 50%;\n  /* smooth background */\n  background: radial-gradient(\n    circle,\n    rgba(255, 255, 255, 0.05) 30%,\n    transparent 70%\n  );\n  overflow: hidden;\n}\n\n/* outside circle */\n.loader::before {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  border-radius: 50%;\n  border: 4px solid transparent;\n  border-top-color: rgba(255, 255, 255, 0.6);\n  animation: loader-spin 2s linear infinite;\n}\n\n/* rotating circle */\n.loader::after {\n  content: \"\";\n  position: absolute;\n  inset: 10%;\n  border-radius: 50%;\n  background: conic-gradient(from 90deg, rgba(255, 255, 255, 0.2), transparent);\n  filter: blur(2px);\n  animation: loader-spin-reverse 1.5s linear infinite;\n}\n\n/* center circle */\n.loader__inner {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  width: 30px;\n  height: 30px;\n  background: rgba(255, 255, 255, 0.9);\n  border-radius: 50%;\n  transform: translate(-50%, -50%);\n  box-shadow: 0 0 15px rgba(255, 255, 255, 0.6);\n  animation: loader-pulse 1s ease-in-out infinite;\n}\n\n/* Container */\n.loader__orbit {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  animation: orbit-rotate 3s linear infinite;\n}\n\n/* dots */\n.loader__dot {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  width: 8px;\n  height: 8px;\n  background: rgba(255, 255, 255, 0.8);\n  border-radius: 50%;\n}\n\n/* 4 dots */\n.loader__dot:nth-child(1) {\n  transform: rotate(0deg) translate(60px);\n}\n.loader__dot:nth-child(2) {\n  transform: rotate(90deg) translate(60px);\n}\n.loader__dot:nth-child(3) {\n  transform: rotate(180deg) translate(60px);\n}\n.loader__dot:nth-child(4) {\n  transform: rotate(270deg) translate(60px);\n}\n\n/* Animations */\n\n@keyframes loader-spin {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes loader-spin-reverse {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(-360deg);\n  }\n}\n\n@keyframes loader-pulse {\n  0%,\n  100% {\n    transform: translate(-50%, -50%) scale(1);\n  }\n  50% {\n    transform: translate(-50%, -50%) scale(1.2);\n  }\n}\n\n@keyframes orbit-rotate {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n'),
(8, '<div class=\"loader\">\n  <svg viewBox=\"0 0 80 80\">\n    <circle r=\"32\" cy=\"40\" cx=\"40\" id=\"test\"></circle>\n  </svg>\n</div>\n\n<div class=\"loader triangle\">\n  <svg viewBox=\"0 0 86 80\">\n    <polygon points=\"43 8 79 72 7 72\"></polygon>\n  </svg>\n</div>\n\n<div class=\"loader\">\n  <svg viewBox=\"0 0 80 80\">\n    <rect height=\"64\" width=\"64\" y=\"8\" x=\"8\"></rect>\n  </svg>\n</div>\n', '.loader {\n  --path: #2f3545;\n  --dot: #5628ee;\n  --duration: 3s;\n  width: 44px;\n  height: 44px;\n  position: relative;\n}\n\n.loader:before {\n  content: \"\";\n  width: 6px;\n  height: 6px;\n  border-radius: 50%;\n  position: absolute;\n  display: block;\n  background: var(--dot);\n  top: 37px;\n  left: 19px;\n  transform: translate(-18px, -18px);\n  animation: dotRect var(--duration) cubic-bezier(0.785, 0.135, 0.15, 0.86)\n    infinite;\n}\n\n.loader svg {\n  display: block;\n  width: 100%;\n  height: 100%;\n}\n\n.loader svg rect,\n.loader svg polygon,\n.loader svg circle {\n  fill: none;\n  stroke: var(--path);\n  stroke-width: 10px;\n  stroke-linejoin: round;\n  stroke-linecap: round;\n}\n\n.loader svg polygon {\n  stroke-dasharray: 145 76 145 76;\n  stroke-dashoffset: 0;\n  animation: pathTriangle var(--duration) cubic-bezier(0.785, 0.135, 0.15, 0.86)\n    infinite;\n}\n\n.loader svg rect {\n  stroke-dasharray: 192 64 192 64;\n  stroke-dashoffset: 0;\n  animation: pathRect 3s cubic-bezier(0.785, 0.135, 0.15, 0.86) infinite;\n}\n\n.loader svg circle {\n  stroke-dasharray: 150 50 150 50;\n  stroke-dashoffset: 75;\n  animation: pathCircle var(--duration) cubic-bezier(0.785, 0.135, 0.15, 0.86)\n    infinite;\n}\n\n.loader.triangle {\n  width: 48px;\n}\n\n.loader.triangle:before {\n  left: 21px;\n  transform: translate(-10px, -18px);\n  animation: dotTriangle var(--duration) cubic-bezier(0.785, 0.135, 0.15, 0.86)\n    infinite;\n}\n\n@keyframes pathTriangle {\n  33% {\n    stroke-dashoffset: 74;\n  }\n\n  66% {\n    stroke-dashoffset: 147;\n  }\n\n  100% {\n    stroke-dashoffset: 221;\n  }\n}\n\n@keyframes dotTriangle {\n  33% {\n    transform: translate(0, 0);\n  }\n\n  66% {\n    transform: translate(10px, -18px);\n  }\n\n  100% {\n    transform: translate(-10px, -18px);\n  }\n}\n\n@keyframes pathRect {\n  25% {\n    stroke-dashoffset: 64;\n  }\n\n  50% {\n    stroke-dashoffset: 128;\n  }\n\n  75% {\n    stroke-dashoffset: 192;\n  }\n\n  100% {\n    stroke-dashoffset: 256;\n  }\n}\n\n@keyframes dotRect {\n  25% {\n    transform: translate(0, 0);\n  }\n\n  50% {\n    transform: translate(18px, -18px);\n  }\n\n  75% {\n    transform: translate(0, -36px);\n  }\n\n  100% {\n    transform: translate(-18px, -18px);\n  }\n}\n\n@keyframes pathCircle {\n  25% {\n    stroke-dashoffset: 125;\n  }\n\n  50% {\n    stroke-dashoffset: 175;\n  }\n\n  75% {\n    stroke-dashoffset: 225;\n  }\n\n  100% {\n    stroke-dashoffset: 275;\n  }\n}\n\n.loader {\n  display: inline-block;\n  margin: 0 16px;\n}\n'),
