(15, '<div class=\"loader\"></div>\n', '.loader {\n  position: relative;\n  width: 100px;\n  height: 100px;\n  border-radius: 50%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: radial-gradient(circle, #03dac6, #6200ea);\n  border: 8px solid transparent;\n  border-top-color: #03dac6;\n  border-bottom-color: #6200ea;\n  animation: spin 2s linear infinite;\n}\n\n.loader::before {\n  content: \"1\";\n  position: absolute;\n  font-size: 24px;\n  font-weight: bold;\n  color: white;\n  animation: count 10s linear infinite;\n}\n\n@keyframes spin {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes count {\n  0% {\n    content: \"1\";\n  }\n  1% {\n    content: \"2\";\n  }\n  2% {\n    content: \"3\";\n  }\n  3% {\n    content: \"4\";\n  }\n  4% {\n    content: \"5\";\n  }\n  5% {\n    content: \"6\";\n  }\n  6% {\n    content: \"7\";\n  }\n  7% {\n    content: \"8\";\n  }\n  8% {\n    content: \"9\";\n  }\n  9% {\n    content: \"10\";\n  }\n  10% {\n    content: \"11\";\n  }\n  11% {\n    content: \"12\";\n  }\n  12% {\n    content: \"13\";\n  }\n  13% {\n    content: \"14\";\n  }\n  14% {\n    content: \"15\";\n  }\n  15% {\n    content: \"16\";\n  }\n  16% {\n    content: \"17\";\n  }\n  17% {\n    content: \"18\";\n  }\n  18% {\n    content: \"19\";\n  }\n  19% {\n    content: \"20\";\n  }\n  20% {\n    content: \"21\";\n  }\n  21% {\n    content: \"22\";\n  }\n  22% {\n    content: \"23\";\n  }\n  23% {\n    content: \"24\";\n  }\n  24% {\n    content: \"25\";\n  }\n  25% {\n    content: \"26\";\n  }\n  26% {\n    content: \"27\";\n  }\n  27% {\n    content: \"28\";\n  }\n  28% {\n    content: \"29\";\n  }\n  29% {\n    content: \"30\";\n  }\n  30% {\n    content: \"31\";\n  }\n  31% {\n    content: \"32\";\n  }\n  32% {\n    content: \"33\";\n  }\n  33% {\n    content: \"34\";\n  }\n  34% {\n    content: \"35\";\n  }\n  35% {\n    content: \"36\";\n  }\n  36% {\n    content: 