(16, '<div id=\"page\">\n        <div id=\"container\">\n            <div id=\"ring\"></div>\n            <div id=\"ring\"></div>\n            <div id=\"ring\"></div>\n            <div id=\"ring\"></div>\n            <div id=\"h3\">loading</div>\n        </div>\n</div>', '#page {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n#container {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  position: relative;\n}\n\n#h3 {\n  color: rgb(82, 79, 79);\n}\n\n#ring {\n  width: 190px;\n  height: 190px;\n  border: 1px solid transparent;\n  border-radius: 50%;\n  position: absolute;\n}\n\n#ring:nth-child(1) {\n  border-bottom: 8px solid rgb(240, 42, 230);\n  animation: rotate1 2s linear infinite;\n}\n\n@keyframes rotate1 {\n  from {\n    transform: rotateX(50deg) rotateZ(110deg);\n  }\n\n  to {\n    transform: rotateX(50deg) rotateZ(470deg);\n  }\n}\n\n#ring:nth-child(2) {\n  border-bottom: 8px solid rgb(240, 19, 67);\n  animation: rotate2 2s linear infinite;\n}\n\n@keyframes rotate2 {\n  from {\n    transform: rotateX(20deg) rotateY(50deg) rotateZ(20deg);\n  }\n\n  to {\n    transform: rotateX(20deg) rotateY(50deg) rotateZ(380deg);\n  }\n}\n\n#ring:nth-child(3) {\n  border-bottom: 8px solid rgb(3, 170, 170);\n  animation: rotate3 2s linear infinite;\n}\n\n@keyframes rotate3 {\n  from {\n    transform: rotateX(40deg) rotateY(130deg) rotateZ(450deg);\n  }\n\n  to {\n    transform: rotateX(40deg) rotateY(130deg) rotateZ(90deg);\n  }\n}\n\n#ring:nth-child(4) {\n  border-bottom: 8px solid rgb(207, 135, 1);\n  animation: rotate4 2s linear infinite;\n}\n\n@keyframes rotate4 {\n  from {\n    transform: rotateX(70deg) rotateZ(270deg);\n  }\n\n  to {\n    transform: rotateX(70deg) rotateZ(630deg);\n  }\n}\n/* Improving visualization in light mode */'),
(17, '<div id=\"container\">\n  <label class=\"loading-title\">Loading ...</label>\n  <span class=\"loading-circle sp1\">\n    <span class=\"loading-circle sp2\">\n      <span class=\"loading-circle sp3\"></span>\n    </span>\n  </span>\n</div>', '#container {\n  width: 100px;\n  height: 125px;\n  margin: auto auto;\n}\n\n.loading-title {\n  display: block;\n  text-align: center;\n  font-size: 20px;\n  font-family: \"Inter\", sans-serif;\n  font-weight: bold;\n  padding-bottom: 15px;\n  color: #888;\n}\n\n.loading-circle {\n  display: block;\n  border-left: 5px solid;\n  border-top-left-radius: 100%;\n  border-top: 5px solid;\n  margin: 5px;\n  animation-name: Loader_611;\n  animation-duration: 1500ms;\n  animation-timing-function: linear;\n  animation-delay: 0s;\n  animation-iteration-count: infinite;\n  animation-direction: normal;\n  animation-fill-mode: forwards;\n}\n\n.sp1 {\n  border-left-color: #F44336;\n  border-top-color: #F44336;\n  width: 40px;\n  height: 40px;\n}\n\n.sp2 {\n  border-left-color: #FFC107;\n  border-top-color: #FFC107;\n  width: 30px;\n  height: 30px;\n}\n\n.sp3 {\n  width: 20px;\n  height: 20px;\n  border-left-color: #8bc34a;\n  border-top-color: #8bc34a;\n}\n\n@keyframes Loader_611 {\n  0% {\n    transform: rotate(0deg);\n    transform-origin: right bottom;\n  }\n\n  25% {\n    transform: rotate(90deg);\n    transform-origin: right bottom;\n  }\n\n  50% {\n    transform: rotate(180deg);\n    transform-origin: right bottom;\n  }\n\n  75% {\n    transform: rotate(270deg);\n    transform-origin: right bottom;\n  }\n\n  100% {\n    transform: rotate(360deg);\n    transform-origin: right bottom;\n  }\n}'),
(18, '    <div class=\"container\">\n        <div class=\"loader\"><span></span></div>\n        <div class=\"loader\"><span></span></div>\n        <div class=\"loader\"><i></i></div>\n        <div class=\"loader\"><i></i></div>\n    </div>', '.container {\n  position: relative;\n  width: 100%;\n  height: 200px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  -webkit-box-reflect: below 0 linear-gradient(transparent, transparent, #0005);\n}\n\n.container .loader {\n  position: absolute;\n  width: 200px;\n  height: 200px;\n  border-radius: 50%;\n  animation: animate 2s linear infinite;\n}\n\n.container .loader:nth-child(2),\n.container .loader:nth-child(4) {\n  animation-delay: -1s;\n}\n\n@keyframes animate {\n  0% {\n    transform: rotate(0deg);\n    filter: hue-rotate(360deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n    filter: hue-rotate(0deg);\n  }\n}\n\n.container .loader:nth-child(1)::before,\n.container .loader:nth-child(2)::before {\n  content: \';\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 50%;\n  height: 100%;\n  background: linear-gradient(to top, transparent, rgba(0,255,249, 0.4));\n  background-size: 100px 180px;\n  background-repeat: no-repeat;\n  border-top-left-radius: 100px;\n  border-bottom-left-radius: 100px;\n}\n\n.container .loader i {\n  position: absolute;\n  top: 0;\n  left: 50%;\n  transform: translateX(-50%);\n  width: 20px;\n  height: 20px;\n  background: #00fff9;\n  border-radius: 50%;\n  z-index: 100;\n  box-shadow: 0 0 10px #00fff9,\n    0 0 30px #00fff9,\n    0 0 40px #00fff9,\n    0 0 50px #00fff9,\n    0 0 60px #00fff9,\n    0 0 70px #00fff9,\n    0 0 80px #00fff9,\n    0 0 90px #00fff9,\n    0 0 100px #00fff9;\n}\n\n.container .loader span {\n  position: absolute;\n  inset: 20px;\n  background: #e8e8e8;\n  border-radius: 50%;\n  z-index: 1;\n}'),
(19, '<div class=\"solar-system\">\n  <div class=\"sun\">\n    <div class=\"corona\"></div>\n  </div>\n\n  <div class=\"orbit mercury-orbit\">\n    <div class=\"planet mercury\"></div>\n  </div>\n\n  <div class=\"orbit venus-orbit\">\n    <div class=\"planet venus\"></div>\n  </div>\n\n  <div class=\"orbit earth-orbit\">\n    <div class=\"planet earth\">\n      <div class=\"moon\"></div>\n    </div>\n\n    <div class=\"iss\">\n      <div class=\"iss-panels\"></div>\n    </div>\n  </div>\n\n  <div class=\"orbit mars-orbit\">\n    <div class=\"planet mars\"></div>\n  </div>\n\n  <div class=\"stars\">\n    <div class=\"star star-1\"></div>\n    <div class=\"star star-2\"></div>\n    <div class=\"star star-3\"></div>\n    <div class=\"star star-4\"></div>\n    <div class=\"star star-5\"></div>\n  </div>\n</div>\n', '.solar-system {\n  position: relative;\n  width: 20rem;\n  height: 20rem;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.sun {\n  position: absolute;\n  width: 5rem;\n  height: 5rem;\n  border-radius: 50%;\n  background: linear-gradient(to bottom right, #f59e0b, #ea580c, #dc2626);\n  animation: pulse 2s ease-in-out infinite;\n  box-shadow: 0 0 60px rgba(255, 165, 0, 0.5);\n  z-index: 4;\n}\n\n.sun::before {\n  content: \"\";\n  position: absolute;\n  inset: -2px;\n  border-radius: 50%;\n  background: linear-gradient(\n    to bottom right,\n    rgba(255, 236, 153, 0.2),\n    rgba(220, 38, 38, 0.2)\n  );\n  animation: spin 3s linear infinite;\n}\n\n.corona {\n  position: absolute;\n  inset: -1rem;\n  border-radius: 50%;\n  background: linear-gradient(\n    to bottom right,\n    rgba(245, 158, 11, 0.2),\n    rgba(220, 38, 38, 0.2)\n  );\n  filter: blur(8px);\n  animation: pulse 2s ease-in-out infinite;\n}\n\n/* Orbity */\n.orbit {\n  position: absolute;\n  border-radius: 50%;\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.mercury-orbit {\n  width: 8rem;\n  height: 8rem;\n}\n\n.venus-orbit {\n  width: 11rem;\n  height: 11rem;\n}\n\n.earth-orbit {\n  width: 14rem;\n  height: 14rem;\n  z-index: 2;\n}\n\n.mars-orbit {\n  width: 18rem;\n  height: 18rem;\n}\n\n/* Planety */\n.planet {\n  position: absolute;\n  border-radius: 50%;\n  z-index: 3;\n}\n\n.mercury {\n  width: 0.75rem;\n  height: 0.75rem;\n  background: linear-gradient(to bottom right, #d1d5db, #9ca3af);\n  box-shadow: 0 0 15px rgba(156, 163, 175, 0.5);\n  --orbit-width: 8rem;\n  animation: orbit 4s linear infinite;\n}\n\n.venus {\n  width: 1rem;\n  height: 1rem;\n  background: linear-gradient(to bottom right, #fef3c7, #fcd34d);\n  box-shadow: 0 0 15px rgba(252, 211, 77, 0.5);\n  --orbit-width: 11rem;\n  animation: orbit 6s linear infinite;\n}\n\n.earth {\n  width: 1.25rem;\n  height: 1.25rem;\n  background: linear-gradient(to bottom right, #60a5fa, #34d399);\n  box-shadow: 0 0 15px rgba(96, 165, 250, 0.5);\n  --orbit-width: 14rem;\n  animation: orbit 8s linear infinite;\n}\n\n.moon {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  width: 0.5rem;\n  height: 0.5rem;\n  border-radius: 50%;\n  background: #d1d5db;\n  box-shadow: inset 0 0 4px rgba(156, 163, 175, 0.5);\n  animation: orbit 2s linear infinite;\n}\n\n.mars {\n  width: 1rem;\n  height: 1rem;\n  background: linear-gradient(to bottom right, #f87171, #dc2626);\n  box-shadow: 0 0 15px rgba(220, 38, 38, 0.5);\n  --orbit-width: 18rem;\n  animation: orbit 10s linear infinite;\n}\n\n/* ISS */\n.iss {\n  position: absolute;\n  width: 0.6rem;\n  height: 0.3rem;\n  background: #e5e7eb;\n  border-radius: 2px;\n  box-shadow: 0 0 10px rgba(255, 255, 255, 0.5);\n  z-index: 3;\n  --iss-orbit: 7.5rem;\n  animation: iss-orbit 5s linear infinite;\n}\n\n.iss-panels {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  width: 1.2rem;\n  height: 0.15rem;\n  background: linear-gradient(to right, #60a5fa, #93c5fd);\n  transform: translate(-50%, -50%);\n  box-shadow: 0 0 5px rgba(96, 165, 250, 0.5);\n}\n\n.iss::after {\n  content: \"\";\n  position: absolute;\n  inset: -1px;\n  background: white;\n  border-radius: 2px;\n  opacity: 0;\n  animation: iss-flare 1.5s linear infinite;\n}\n\n/* Gwiazdy */\n.stars {\n  position: absolute;\n  inset: -2.5rem;\n  z-index: 1;\n}\n\n.star {\n  position: absolute;\n  width: 0.25rem;\n  height: 0.25rem;\n  background: white;\n  border-radius: 50%;\n}\n\n.star-1 {\n  top: 25%;\n  left: 25%;\n  animation: ping 2s ease-in-out infinite;\n}\n.star-2 {\n  top: 75%;\n  left: 33%;\n  animation: ping 3s ease-in-out infinite 0.5s;\n}\n.star-3 {\n  top: 33%;\n  right: 25%;\n  animation: ping 2.5s ease-in-out infinite 0.7s;\n}\n.star-4 {\n  bottom: 25%;\n  right: 33%;\n  animation: ping 2.7s ease-in-out infinite 0.3s;\n}\n.star-5 {\n  top: 50%;\n  right: 50%;\n  animation: ping 2.3s ease-in-out infinite 0.8s;\n}\n\n/* Animacje */\n@keyframes orbit {\n  from {\n    transform: rotate(0deg) translateX(calc(var(--orbit-width) / 2))\n      rotate(0deg);\n  }\n  to {\n    transform: rotate(360deg) translateX(calc(var(--orbit-width) / 2))\n      rotate(-360deg);\n  }\n}\n\n@keyframes iss-orbit {\n  from {\n    transform: rotate(0deg) translateX(var(--iss-orbit)) rotate(0deg);\n  }\n  to {\n    transform: rotate(360deg) translateX(var(--iss-orbit)) rotate(-360deg);\n  }\n}\n\n@keyframes iss-tilt {\n  0%,\n  100% {\n    transform: rotate(-15deg);\n  }\n  50% {\n    transform: rotate(15deg);\n  }\n}\n\n@keyframes iss-flare {\n  0%,\n  100% {\n    opacity: 0;\n  }\n  50% {\n    opacity: 0.3;\n  }\n}\n\n@keyframes pulse {\n  50% {\n    opacity: 0.8;\n  }\n}\n\n@keyframes ping {\n  75%,\n  100% {\n    transform: scale(2);\n    opacity: 0;\n  }\n}\n\n@keyframes spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n'),
(20, '<div class=\"cssloader\">\n  <div class=\"triangle1\"></div>\n  <div class=\"triangle2\"></div>\n  <p class=\"text\">Please Wait</p>\n</div>\n', '.triangle1 {\n  width: 0;\n  height: 0;\n  border-style: solid;\n  border-width: 50px 50px 0 0;\n  border-color: #8086e0 transparent transparent transparent;\n  margin: 0 auto;\n  animation: shk1 1s ease-in-out infinite normal;\n}\n\n.triangle2 {\n  width: 0;\n  height: 0;\n  border-style: solid;\n  border-width: 0 0 50px 50px;\n  border-color: transparent transparent #6554b388 transparent;\n  margin: -50px auto 0;\n  animation: shk2 1s ease-in-out infinite alternate;\n}\n@keyframes shk1 {\n  0% {\n    transform: rotate(-360deg);\n  }\n\n  100% {\n  }\n}\n\n@keyframes shk2 {\n  0% {\n    transform: rotate(360deg);\n  }\n  100% {\n  }\n}\n\n.text {\n  color: #949494;\n  margin: 30px auto;\n  text-align: center;\n  font-weight: 500;\n  letter-spacing: 4px;\n}\n');

