INSERT INTO `radio` (`ID`, `HTML`, `CSS`) VALUES
(1, '<div class=\"container\">\n    <div class=\"pane\">\n        <label class=\"label\">\n            <span>Yes</span>\n            <input id=\"left\" class=\"input\" name=\"radio\" type=\"radio\">\n        </label>\n        <label class=\"label\">\n            <span>No</span>\n            <input id=\"middle\" class=\"input\" checked=\"checked\" name=\"radio\" type=\"radio\">\n        </label>\n        <label class=\"label\">\n            <span>Idk</span>\n            <input id=\"right\" class=\"input\" name=\"radio\" type=\"radio\">\n        </label>\n        <span class=\"selection\"></span>\n    </div>\n</div>', '.container {\n  transform-style: preserve-3d;\n  perspective: 1000px;\n}\n\n.pane {\n  outline: 2px solid #00ff6a;\n  box-shadow: 0 0 10px #00ff6a77, inset 0 0 10px #00ff6a77;\n  height: 1cm;\n  width: 4.5cm;\n  border-radius: 5px;\n  position: relative;\n  overflow: hidden;\n  transition: 0.7s ease;\n}\n\n.input {\n  display: none;\n}\n\n.label {\n  height: 1cm;\n  width: 1.5cm;\n  float: left;\n  font-weight: 600;\n  letter-spacing: -1px;\n  font-size: 14px;\n  padding: 0px;\n  position: relative;\n  z-index: 1;\n  color: #00ff6a;\n  text-align: center;\n  padding-top: 10px;\n}\n\n.selection {\n  display: none;\n  position: absolute;\n  height: 1cm;\n  width: calc(4.5cm / 3);\n  z-index: 0;\n  left: 0;\n  top: 0;\n  box-shadow: 0 0 10px #00ff6a77;\n  transition: .15s ease;\n}\n\n.label:has(input:checked) {\n  color: #212121;\n}\n\n.pane:has(.label:nth-child(1):hover) {\n  transform: rotateY(-30deg);\n}\n\n.pane:has(.label:nth-child(3):hover) {\n  transform: rotateY(35deg);\n}\n\n.label:has(input:checked) ~ .selection {\n  background-color: #00ff6a;\n  display: inline-block;\n}\n\n.label:nth-child(1):has(input:checked) ~ .selection {\n  transform: translateX(calc(4.5cm * 0/3));\n}\n\n.label:nth-child(2):has(input:checked) ~ .selection {\n  transform: translateX(calc(4.5cm * 1/3));\n}\n\n.label:nth-child(3):has(input:checked) ~ .selection {\n  transform: translateX(calc(4.5cm * 2/3));\n}'),
(2, '<div class=\"radio-input\">\n  <label class=\"label\">\n    <input value=\"value-1\" name=\"value-radio\" id=\"value-1\" type=\"radio\" />\n    <span class=\"text\">Play</span>\n  </label>\n  <label class=\"label\">\n    <input value=\"value-1\" name=\"value-radio\" id=\"value-1\" type=\"radio\" />\n    <span class=\"text\">Stop</span>\n  </label>\n  <label class=\"label\">\n    <input value=\"value-1\" name=\"value-radio\" id=\"value-1\" type=\"radio\" />\n    <span class=\"text\">Reset</span>\n  </label>\n</div>\n', '.radio-input {\n  display: flex;\n  align-items: center;\n  gap: 2px;\n  background-color: black;\n  padding: 4px;\n  border-radius: 10px;\n  z-index: -1;\n}\n\n.radio-input input {\n  display: none;\n}\n\n.radio-input .label {\n  width: 90px;\n  height: 60px;\n  background: linear-gradient(to bottom, #333333, rgb(36, 35, 35));\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  padding: 8px;\n  transition: all 0.1s linear;\n  border-top: 1px solid #4e4d4d;\n  background-color: #333333;\n  position: relative;\n  cursor: pointer;\n  box-shadow: 0px 17px 5px 1px rgba(0, 0, 0, 0.2);\n}\n\n.label:has(input[type=\"radio\"]:checked) {\n  box-shadow: 0px 17px 5px 1px rgba(0, 0, 0, 0);\n  background: linear-gradient(to bottom, #1d1d1d, #1d1d1d);\n  border-top: none;\n}\n\n.label:first-child {\n  border-top-left-radius: 6px;\n  border-bottom-left-radius: 6px;\n}\n\n.label:last-child {\n  border-top-right-radius: 6px;\n  border-bottom-right-radius: 6px;\n}\n\n.label::before {\n  content: \"\";\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 103%;\n  height: 100%;\n  border-radius: 10px;\n  background: linear-gradient(\n    to bottom,\n    transparent 10%,\n    transparent,\n    transparent 90%\n  );\n  transition: all 0.1s linear;\n  z-index: -1;\n}\n\n.label:has(input[type=\"radio\"]:checked)::before {\n  background: linear-gradient(\n    to bottom,\n    transparent 10%,\n    #cae2fd63,\n    transparent 90%\n  );\n}\n\n.label .text {\n  color: black;\n  font-size: 15px;\n  line-height: 12px;\n  padding: 0px;\n  font-weight: 800;\n  text-transform: uppercase;\n  transition: all 0.1s linear;\n  text-shadow:\n    -1px -1px 1px rgb(224, 224, 224, 0.1),\n    0px 2px 3px rgb(0, 0, 0, 0.3);\n}\n\n.label input[type=\"radio\"]:checked + .text {\n  color: rgb(202, 226, 253);\n  text-shadow: 0px 0px 12px #cae2fd;\n}\n'),
