it;\n  &:before {\n    position: absolute;\n    z-index: -1;\n    content: \"\";\n    display: block;\n    border-radius: 8px;\n    width: 100%;\n    height: 100%;\n    top: 0;\n    transform: translateX(100%);\n    transition: transform 0.2s ease-in;\n    transform-origin: center right;\n    background-color: #eee;\n  }\n\n  &:hover,\n  &:focus {\n    outline: 0;\n    width: 130px;\n\n    &:before,\n    .link-title {\n      transform: translateX(0);\n      opacity: 1;\n    }\n  }\n}\n\n.link-icon {\n  width: 28px;\n  height: 28px;\n  display: block;\n  flex-shrink: 0;\n  left: 18px;\n  position: absolute;\n  svg {\n    width: 28px;\n    height: 28px;\n  }\n}\n\n.link-title {\n  transform: translateX(100%);\n  transition: transform 0.2s ease-in;\n  transform-origin: center right;\n  display: block;\n  text-align: center;\n  text-indent: 28px;\n  width: 100%;\n}\n'),
(4, '<div class=\"radio-input\">\n  <div class=\"switch-panel\">\n    <div class=\"track-groove\"></div>\n  </div>\n  <div class=\"selector\">\n    <div class=\"choice\">\n      <div class=\"input-container\">\n        <input\n          class=\"choice-switch\"\n          checked=\"true\"\n          value=\"power\"\n          name=\"mech-selector\"\n          id=\"power\"\n          type=\"radio\"\n        />\n        <div class=\"lever\"></div>\n      </div>\n      <label for=\"power\" class=\"choice-plate\">Power</label>\n    </div>\n    <div class=\"choice\">\n      <div class=\"input-container\">\n        <input\n          class=\"choice-switch\"\n          value=\"boost\"\n          name=\"mech-selector\"\n          id=\"boost\"\n          type=\"radio\"\n        />\n        <div class=\"lever\"></div>\n      </div>\n      <label for=\"boost\" class=\"choice-plate\">Boost</label>\n    </div>\n    <div class=\"choice\">\n      <div class=\"input-container\">\n        <input\n          class=\"choice-switch\"\n          value=\"ignite\"\n          name=\"mech-selector\"\n          id=\"ignite\"\n          type=\"radio\"\n        />\n        <div class=\"lever\"></div>\n      </div>\n      <label for=\"ignite\" class=\"choice-plate\">Ignite</label>\n    </div>\n  </div>\n</div>\n', '.radio-input {\n  display: flex;\n  height: 280px;\n  width: 290px;\n  align-items: center;\n  justify-content: center;\n  background: linear-gradient(135deg, #3c3c3c, #2b2b2b);\n  padding: 25px;\n  border-radius: 12px;\n  box-shadow:\n    inset 0 0 20px rgba(0, 0, 0, 0.5),\n    0 0 30px rgba(0, 0, 0, 0.3);\n  position: relative;\n  overflow: hidden;\n}\n\n.switch-panel {\n  z-index: 1;\n  height: 240px;\n  width: 70px;\n  margin-right: 30px;\n  background: linear-gradient(to bottom, #4a4a4a, #383838);\n  border-radius: 10px;\n  box-shadow:\n    inset 0 5px 15px rgba(0, 0, 0, 0.6),\n    inset 0 -5px 15px rgba(100, 100, 100, 0.2);\n  position: relative;\n  border: 3px solid #555;\n}\n\n.track-groove {\n  position: absolute;\n  inset: 10px;\n  background: linear-gradient(90deg, #333, #444);\n  border-radius: 5px;\n  box-shadow: inset 0 0 10px rgba(0, 0, 0, 0.8);\n}\n\n.selector {\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  height: 220px;\n}\n\n.choice {\n  display: flex;\n  align-items: center;\n  position: relative;\n  transition: transform 0.2s cubic-bezier(0.6, -0.3, 0.4, 1.3);\n}\n\n.choice:hover {\n  transform: scale(1.02);\n}\n\n.input-container {\n  position: relative;\n  width: 36px;\n  height: 36px;\n  margin-right: 20px;\n  z-index: 2;\n  perspective: 500px;\n}\n\n.choice-switch {\n  appearance: none;\n  height: 100%;\n  width: 100%;\n  border-radius: 8px;\n  border: 3px solid #666;\n  cursor: pointer;\n  background: linear-gradient(45deg, #5a5a5a, #4a4a4a);\n  box-shadow:\n    inset 0 2px 5px rgba(0, 0, 0, 0.5),\n    0 2px 5px rgba(0, 0, 0, 0.3);\n  transition:\n    border-color 0.3s ease,\n    box-shadow 0.3s ease;\n}\n\n.choice-switch:hover {\n  border-color: #888;\n  box-shadow:\n    inset 0 2px 5px rgba(0, 0, 0, 0.5),\n    0 0 10px rgba(255, 215, 0, 0.4);\n}\n\n.lever {\n  z-index: 1;\n  position: absolute;\n  width: 28px;\n  height: 28px;\n  top: 50%;\n  left: -73px;\n  transform: translateY(-50%) rotateX(30deg);\n  border-radius: 6px;\n  background: linear-gradient(135deg, #ffd700, #d4af37);\n  box-shadow:\n    0 3px 10px rgba(0, 0, 0, 0.5),\n    inset 0 2px 4px rgba(255, 255, 255, 0.3);\n  transition:\n    left 0.6s cubic-bezier(0.68, -0.55, 0.27, 1.55),\n    transform 0.4s cubic-bezier(0.7, 0, 0.3, 1.5),\n    box-shadow 0.3s ease;\n  will-change: left, transform;\n}\n\n.choice-switch:checked + .lever {\n  left: 5px;\n  transform: translateY(-50%) rotateX(0deg);\n  box-shadow:\n    0 5px 15px rgba(255, 215, 0, 0.6),\n    inset 0 2px 4px rgba(255, 255, 255, 0.3);\n}\n\n.lever::after {\n  content: \"\";\n  position: absolute;\n  inset: -10px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(255, 215, 0, 0.3), transparent);\n  opacity: 0;\n  transition: opacity 0.2s ease;\n}\n\n.choice-switch:checked + .lever::after {\n  opacity: 0.4;\n  animation: glowPulse 1.5s infinite cubic-bezier(0.4, 0, 0.6, 1);\n}\n\n@keyframes glowPulse {\n  0% {\n    transform: scale(1);\n    opacity: 0.4;\n  }\n  50% {\n    transform: scale(1.3);\n    opacity: 0.2;\n  }\n  100% {\n    transform: scale(1);\n    opacity: 0.4;\n  }\n}\n\n.choice-plate {\n  color: #d4af37;\n  font-size: 16px;\n  font-weight: 700;\n  font-family: \"Arial\", sans-serif;\n  text-transform: uppercase;\n  cursor: pointer;\n  padding: 6px 12px;\n  background: linear-gradient(to bottom, #444, #333);\n  border: 2px solid #666;\n  border-radius: 6px;\n  box-shadow:\n    inset 0 2px 4px rgba(0, 0, 0, 0.4),\n    0 2px 4px rgba(0, 0, 0, 0.2);\n  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.5);\n  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55);\n  letter-spacing: 1.5px;\n  position: relative;\n}\n\n.choice-plate:hover {\n  color: #ffd700;\n  border-color: #888;\n  box-shadow:\n    inset 0 2px 4px rgba(0, 0, 0, 0.4),\n    0 0 10px rgba(255, 215, 0, 0.4);\n}\n\n.choice-switch:checked ~ .choice-plate {\n  color: #ffd700;\n  border-color: #ffd700;\n  box-shadow:\n    inset 0 2px 4px rgba(0, 0, 0, 0.4),\n    0 0 15px rgba(255, 215, 0, 0.6);\n  animation: plateGlow 0.8s infinite alternate;\n}\n\n@keyframes plateGlow {\n  0% {\n    text-shadow:\n      0 1px 2px rgba(0, 0, 0, 0.5),\n      0 0 5px rgba(255, 215, 0, 0.5);\n  }\n  100% {\n    text-shadow:\n      0 1px 2px rgba(0, 0, 0, 0.5),\n      0 0 10px rgba(255, 215, 0, 0.8);\n  }\n}\n\n.choice:hover .choice-switch:not(:checked) {\n  border-color: #777;\n}\n\n.radio-input::before {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  opacity: 0.05;\n  pointer-events: none;\n}\n'),
