inputs > * {\n  margin: 6px;\n}\n\n.radio-input:checked + .radio-tile {\n  border-color: #4d8bff;\n  box-shadow: 0 5px 10px rgba(255, 255, 255, 0.1);\n  color: #4d8bff;\n}\n\n.radio-input:checked + .radio-tile:before {\n  transform: scale(1);\n  opacity: 1;\n  background-color: #4d8bff;\n  border-color: #4d8bff;\n}\n\n.radio-input:checked + .radio-tile .radio-icon svg {\n  fill: #4d8bff;\n}\n\n.radio-input:checked + .radio-tile .radio-label {\n  color: #4d8bff;\n}\n\n.radio-input:focus + .radio-tile {\n  border-color: #4d8bff;\n  box-shadow:\n    0 5px 10px rgba(255, 255, 255, 0.1),\n    0 0 0 4px #3a6abf;\n}\n\n.radio-input:focus + .radio-tile:before {\n  transform: scale(1);\n  opacity: 1;\n}\n\n.radio-tile {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  width: 80px;\n  min-height: 80px;\n  border-radius: 0.5rem;\n  border: 2px solid #4a5265;\n  background-color: #1e2129;\n  box-shadow: 0 5px 10px rgba(255, 255, 255, 0.05);\n  transition: 0.15s ease;\n  cursor: pointer;\n  position: relative;\n}\n\n.radio-tile:before {\n  content: \"\";\n  position: absolute;\n  display: block;\n  width: 0.75rem;\n  height: 0.75rem;\n  border: 2px solid #4a5265;\n  background-color: #1e2129;\n  border-radius: 50%;\n  top: 0.25rem;\n  left: 0.25rem;\n  opacity: 0;\n  transform: scale(0);\n  transition: 0.25s ease;\n}\n\n.radio-tile:hover {\n  border-color: #4d8bff;\n}\n\n.radio-tile:hover:before {\n  transform: scale(1);\n  opacity: 1;\n}\n\n.radio-icon svg {\n  width: 2rem;\n  height: 2rem;\n  fill: #b6b6b6;\n}\n\n.radio-label {\n  color: #8f8f8f;\n  transition: 0.375s ease;\n  text-align: center;\n  font-size: 13px;\n}\n\n.radio-input {\n  clip: rect(0 0 0 0);\n  -webkit-clip-path: inset(100%);\n  clip-path: inset(100%);\n  height: 1px;\n  overflow: hidden;\n  position: absolute;\n  white-space: nowrap;\n  width: 1px;\n}\n'),
