on>\n  <button class=\"value\">\n    <svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 24 25\" fill=\"none\">\n      <path\n        fill-rule=\"evenodd\"\n        fill=\"#7D8590\"\n        d=\"m11.9572 4.31201c-3.35401 0-6.00906 2.59741-6.00906 5.67742v3.29037c0 .1986-.05916.3927-.16992.5576l-1.62529 2.4193-.01077.0157c-.18701.2673-.16653.5113-.07001.6868.10031.1825.31959.3528.67282.3528h14.52603c.2546 0 .5013-.1515.6391-.3968.1315-.2343.1117-.4475-.0118-.6093-.0065-.0085-.0129-.0171-.0191-.0258l-1.7269-2.4194c-.121-.1695-.186-.3726-.186-.5809v-3.29037c0-1.54561-.6851-3.023-1.7072-4.00431-1.1617-1.01594-2.6545-1.67311-4.3019-1.67311zm-8.00906 5.67742c0-4.27483 3.64294-7.67742 8.00906-7.67742 2.2055 0 4.1606.88547 5.6378 2.18455.01.00877.0198.01774.0294.02691 1.408 1.34136 2.3419 3.34131 2.3419 5.46596v2.97007l1.5325 2.1471c.6775.8999.6054 1.9859.1552 2.7877-.4464.795-1.3171 1.4177-2.383 1.4177h-14.52603c-2.16218 0-3.55087-2.302-2.24739-4.1777l1.45056-2.1593zm4.05187 11.32257c0-.5523.44772-1 1-1h5.99999c.5523 0 1 .4477 1 1s-.4477 1-1 1h-5.99999c-.55228 0-1-.4477-1-1z\"\n        clip-rule=\"evenodd\"\n      ></path>\n    </svg>\n    Notifications\n  </button>\n</div>', '.input {\n  display: flex;\n  flex-direction: column;\n  width: 200px;\n  background-color: #0d1117;\n  justify-content: center;\n  border-radius: 10px;\n  transition: 1s;\n  padding: 10px;\n  overflow: hidden;\n}\n\n.value {\n  font-size: 15px;\n  background-color: transparent;\n  border: none;\n  padding: 10px;\n  color: white;\n  display: flex;\n  position: relative;\n  gap: 5px;\n  cursor: pointer;\n  border-radius: 10px;\n  transition: 1s;\n  box-sizing: border-box;\n}\n\n.value:not(:active):hover,\n.value:focus {\n  display: flex;\n  box-sizing: border-box;\n  border: 2px solid #1a1f24;\n  color: #637185;\n}\n\n.value:focus,\n.value:active {\n  background-color: #1a1f24;\n  outline: none;\n  margin-left: 17px;\n}\n\n.value::before {\n  content: \"\";\n  position: absolute;\n  top: 5px;\n  left: -15px;\n  width: 5px;\n  height: 80%;\n  background-color: #2f81f7;\n  border-radius: 5px;\n  opacity: 0;\n  transition: 1s;\n}\n\n.value:focus::before,\n.value:active::before {\n  opacity: 1;\n}\n\n.value svg {\n  width: 20px;\n}\n\n.input:hover > :not(.value:hover) {\n  transition: 300ms;\n  filter: blur(1.5px);\n  transform: scale(0.95, 0.95);\n}\n'),
(7, '<div class=\"radio-container\">\n  <input checked=\"\" id=\"radio-free\" name=\"radio\" type=\"radio\" />\n  <label for=\"radio-free\">Free</label>\n  <input id=\"radio-basic\" name=\"radio\" type=\"radio\" />\n  <label for=\"radio-basic\">Basic</label>\n  <input id=\"radio-premium\" name=\"radio\" type=\"radio\" />\n  <label for=\"radio-premium\">Premium</label>\n\n  <div class=\"glider-container\">\n    <div class=\"glider\"></div>\n  </div>\n</div>\n', '.radio-container {\n  --main-color: #f7e479;\n  --main-color-opacity: #f7e4791c;\n\n  /* change this according inputs count */\n  --total-radio: 3;\n\n  display: flex;\n  flex-direction: column;\n  position: relative;\n  padding-left: 0.5rem;\n}\n.radio-container input {\n  cursor: pointer;\n  appearance: none;\n}\n.radio-container .glider-container {\n  position: absolute;\n  left: 0;\n  top: 0;\n  bottom: 0;\n  background: linear-gradient(\n    0deg,\n    rgba(0, 0, 0, 0) 0%,\n    rgba(27, 27, 27, 1) 50%,\n    rgba(0, 0, 0, 0) 100%\n  );\n  width: 1px;\n}\n.radio-container .glider-container .glider {\n  position: relative;\n  height: calc(100% / var(--total-radio));\n  width: 100%;\n  background: linear-gradient(\n    0deg,\n    rgba(0, 0, 0, 0) 0%,\n    var(--main-color) 50%,\n    rgba(0, 0, 0, 0) 100%\n  );\n  transition: transform 0.5s cubic-bezier(0.37, 1.95, 0.66, 0.56);\n}\n.radio-container .glider-container .glider::before {\n  content: \"\";\n  position: absolute;\n  height: 60%;\n  width: 300%;\n  top: 50%;\n  transform: translateY(-50%);\n  background: var(--main-color);\n  filter: blur(10px);\n}\n.radio-container .glider-container .glider::after {\n  content: \"\";\n  position: absolute;\n  left: 0;\n  height: 100%;\n  width: 150px;\n  background: linear-gradient(\n    90deg,\n    var(--main-color-opacity) 0%,\n    rgba(0, 0, 0, 0) 100%\n  );\n}\n.radio-container label {\n  cursor: pointer;\n  padding: 1rem;\n  position: relative;\n  color: grey;\n  transition: all 0.3s ease-in-out;\n}\n\n.radio-container input:checked + label {\n  color: var(--main-color);\n}\n\n.radio-container input:nth-of-type(1):checked ~ .glider-container .glider {\n  transform: translateY(0);\n}\n\n.radio-container input:nth-of-type(2):checked ~ .glider-container .glider {\n  transform: translateY(100%);\n}\n\n.radio-container input:nth-of-type(3):checked ~ .glider-container .glider {\n  transform: translateY(200%);\n}\n\n.radio-container input:nth-of-type(4):checked ~ .glider-container .glider {\n  transform: translateY(300%);\n}\n\n.radio-container input:nth-of-type(5):checked ~ .glider-container .glider {\n  transform: translateY(400%);\n}\n\n.radio-container input:nth-of-type(6):checked ~ .glider-container .glider {\n  transform: translateY(500%);\n}\n\n.radio-container input:nth-of-type(7):checked ~ .glider-container .glider {\n  transform: translateY(600%);\n}\n\n.radio-container input:nth-of-type(8):checked ~ .glider-container .glider {\n  transform: translateY(700%);\n}\n\n.radio-container input:nth-of-type(9):checked ~ .glider-container .glider {\n  transform: translateY(800%);\n}\n\n.radio-container input:nth-of-type(10):checked ~ .glider-container .glider {\n  transform: translateY(900%);\n}\n'),
(8, '<section>\n  <label title=\"home\" for=\"home\" class=\"label\">\n    <input id=\"home\" name=\"page\" type=\"radio\" checked=\"\" />\n    <svg\n      xmlns=\"http://www.w3.org/2000/svg\"\n      viewBox=\"0 0 21 20\"\n      height=\"20\"\n      width=\"21\"\n      class=\"icon home\"\n    >\n      <path\n        fill=\"inherit\"\n        d=\"M18.9999 6.01002L12.4499 0.770018C11.1699 -0.249982 9.16988 -0.259982 7.89988 0.760018L1.34988 6.01002C0.409885 6.76002 -0.160115 8.26002 0.0398848 9.44002L1.29988 16.98C1.58988 18.67 3.15988 20 4.86988 20H15.4699C17.1599 20 18.7599 18.64 19.0499 16.97L20.3099 9.43002C20.4899 8.26002 19.9199 6.76002 18.9999 6.01002ZM10.9199 16C10.9199 16.41 10.5799 16.75 10.1699 16.75C9.75988 16.75 9.41988 16.41 9.41988 16V13C9.41988 12.59 9.75988 12.25 10.1699 12.25C10.5799 12.25 10.9199 12.59 10.9199 13V16Z\"\n      ></path>\n    </svg>\n  </label>\n  <label title=\"cart\" for=\"cart\" class=\"label\">\n    <input id=\"cart\" name=\"page\" type=\"radio\" />\n    <svg\n      xmlns=\"http://www.w3.org/2000/svg\"\n      fill=\"inherit\"\n      viewBox=\"0 0 18 20\"\n      height=\"20\"\n      width=\"18\"\n      class=\"icon cart\"\n    >\n      <path\n        fill=\"inherit\"\n        d=\"M16.8035 6.96427C16.1335 6.22427 15.1235 5.79427 13.7235 5.64427V4.88427C13.7235 3.51427 13.1435 2.19427 12.1235 1.27427C11.6202 0.812823 11.025 0.462927 10.3771 0.247511C9.72909 0.032095 9.04292 -0.0439787 8.3635 0.0242742C5.9735 0.254274 3.9635 2.56427 3.9635 5.06427V5.64427C2.5635 5.79427 1.5535 6.22427 0.883496 6.96427C-0.0865043 8.04427 -0.0565042 9.48427 0.0534958 10.4843L0.753496 16.0543C0.963496 18.0043 1.7535 20.0043 6.0535 20.0043H11.6335C15.9335 20.0043 16.7235 18.0043 16.9335 16.0643L17.6335 10.4743C17.7435 9.48427 17.7635 8.04427 16.8035 6.96427ZM8.5035 1.41427C8.98813 1.36559 9.47758 1.41913 9.94023 1.57143C10.4029 1.72372 10.8284 1.97138 11.1894 2.29841C11.5503 2.62544 11.8387 3.02456 12.0357 3.46998C12.2328 3.91539 12.3343 4.39721 12.3335 4