(15, '\n<div class=\"container\">\n\n    \n    <div class=\"de\">\n\n        \n        <div class=\"den\">\n\n            \n            <hr class=\"line\">\n            <hr class=\"line\">\n            <hr class=\"line\">\n\n            \n            <div class=\"switch\">\n\n                \n                <label for=\"switch_off\"><span>OFF</span></label>\n                <label for=\"switch_1\"><span>1</span></label>\n                <label for=\"switch_2\"><span>2</span></label>\n                <label for=\"switch_3\"><span>3</span></label>\n                <label for=\"switch_4\"><span>4</span></label>\n                <label for=\"switch_5\"><span>5</span></label>\n\n                \n                <input type=\"radio\" checked=\"\" name=\"switch\" id=\"switch_off\">\n                <input type=\"radio\" name=\"switch\" id=\"switch_1\">\n                <input type=\"radio\" name=\"switch\" id=\"switch_2\">\n                <input type=\"radio\" name=\"switch\" id=\"switch_3\">\n                <input type=\"radio\" name=\"switch\" id=\"switch_4\">\n                <input type=\"radio\" name=\"switch\" id=\"switch_5\">\n\n                \n                <div class=\"light\"><span></span></div>\n\n                \n                <div class=\"dot\"><span></span></div>\n\n                \n                <div class=\"dene\">\n                    <div class=\"denem\">\n                        <div class=\"deneme\">\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>', '\n.container .origin {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  z-index: 111;\n  width: 2px;\n  height: 2px;\n  margin: -1px 0 0 -1px;\n  background-color: #f50;\n}\n\n.de {\n  user-select: none;\n  position: relative;\n  width: 230px;\n  height: 230px;\n  border-radius: 100%;\n  box-shadow: 0 0 25px rgba(0, 0, 0, .1);\n  background-color: transparent;\n}\n\n.de .den, .de .dene, .de .denem, .de .deneme, .de .light, .de .dot {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n}\n\n.den {\n  position: relative;\n  width: 220px;\n  height: 220px;\n  margin: -110px 0 0 -110px;\n  border-radius: 100%;\n  box-shadow: inset 0 3px 10px rgba(0, 0, 0, .6), 0 2px 20px rgba(255, 255, 255, 1);\n  background: #888888;\n  background: -moz-radial-gradient(center, ellipse cover, #888888 0%, #333333 100%);\n  background: -webkit-gradient(radial, center center, 0px, center center, 100%, color-stop(0%, #888888), color-stop(100%, #333333));\n  background: -webkit-radial-gradient(center, ellipse cover, #888888 0%, #333333 100%);\n  background: -o-radial-gradient(center, ellipse cover, #888888 0%, #333333 100%);\n}\n\n.dene {\n  z-index: 4;\n  width: 140px;\n  height: 140px;\n  margin: -70px 0 0 -70px;\n  border-radius: 100%;\n  box-shadow: inset 0 2px 2px rgba(255, 255, 255, .4), 0 3px 13px rgba(0, 0, 0, .85);\n  background: #f2f6f5;\n  background: -moz-linear-gradient(top, #f2f6f5 0%, #cbd5d6 100%);\n  background: -webkit-gradient(linear, left top, left bottom, color-stop(0%, #f2f6f5), color-stop(100%, #cbd5d6));\n  background: -webkit-linear-gradient(top, #f2f6f5 0%, #cbd5d6 100%);\n  background: -o-linear-gradient(top, #f2f6f5 0%, #cbd5d6 100%);\n}\n\n.denem {\n  width: 120px;\n  height: 120px;\n  margin: -60px 0 0 -60px;\n  border-radius: 100%;\n  background: #cbd5d6;\n  background: -moz-linear-gradient(top, #cbd5d6 0%, #f2f6f5 100%);\n  background: -webkit-gradient(linear, left top, left bottom, color-stop(0%, #cbd5d6), color-stop(100%, #f2f6f5));\n  background: -webkit-linear-gradient(top, #cbd5d6 0%, #f2f6f5 100%);\n  background: -o-linear-gradient(top, #cbd5d6 0%, #f2f6f5 100%);\n}\n\n.deneme {\n  width: 100px;\n  height: 100px;\n  margin: -50px 0 0 -50px;\n  border-radius: 100%;\n  box-shadow: inset 0 2px 3px rgba(255, 255, 255, .6), 0 8px 20px rgba(0, 0, 0, .9);\n  background: #eef7f6;\n  background: -moz-linear-gradient(top, #eef7f6 0%, #8d989a 100%);\n  background: -webkit-gradient(linear, left top, left bottom, color-stop(0%, #eef7f6), color-stop(100%, #8d989a));\n  background: -webkit-linear-gradient(top, #eef7f6 0%, #8d989a 100%);\n  background: -o-linear-gradient(top, #eef7f6 0%, #8d989a 100%);\n}\n\n.den .switch {\n  z-index: 3;\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n}\n\n.den .switch label {\n  z-index: 2;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  width: 50%;\n  height: 70px;\n  margin-top: -35px;\n  transform-origin: 0% 50%;\n  -webkit-transform-origin: 0% 50%;\n  -o-transform-origin: 0% 50%;\n}\n\n.den .switch label:after {\n  content: \"\";\n  position: absolute;\n  top: 6px;\n  left: 1px;\n  width: 100%;\n  height: 30px;\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den .switch label:before {\n  content: \"\";\n  position: absolute;\n  bottom: 6px;\n  left: 1px;\n  width: 100%;\n  height: 30px;\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den .switch label span {\n  z-index: 2;\n  position: absolute;\n  top: 0;\n  right: 0;\n  width: 40px;\n  height: 100%;\n  font-weight: bold;\n  font-size: 15px;\n  line-height: 70px;\n  text-align: center;\n  color: #eee;\n  text-shadow: 0 1px 0 #444;\n}\n\n.den .switch label:nth-child(1) {\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n}\n\n.den .switch label:nth-child(1) span {\n  right: 2px;\n  font-size: 13px;\n  transform: rotate(90deg);\n  -webkit-transform: rotate(90deg);\n  -o-transform: rotate(90deg);\n}\n\n.den .switch label:nth-child(2) {\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den .switch label:nth-child(2) span {\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den .switch label:nth-child(3) {\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den .switch label:nth-child(3) span {\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den .switch label:nth-child(4) {\n  transform: rotate(90deg);\n  -webkit-transform: rotate(90deg);\n  -o-transform: rotate(90deg);\n}\n\n.den .switch label:nth-child(4) span {\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n}\n\n.den .switch label:nth-child(5) {\n  transform: rotate(150deg);\n  -webkit-transform: rotate(150deg);\n  -o-transform: rotate(150deg);\n}\n\n.den .switch label:nth-child(5) span {\n  transform: rotate(-150deg);\n  -webkit-transform: rotate(-150deg);\n  -o-transform: rotate(-150deg);\n}\n\n.den .switch label:nth-child(6) {\n  transform: rotate(210deg);\n  -webkit-transform: rotate(210deg);\n  -o-transform: rotate(210deg);\n}\n\n.den .switch label:nth-child(6) span {\n  transform: rotate(-210deg);\n  -webkit-transform: rotate(-210deg);\n  -o-transform: rotate(-210deg);\n}\n\n.den .switch input {\n  position: absolute;\n  opacity: 0;\n  visibility: hidden;\n}\n\n/* SWITCH LIGHT */\n\n.den .light {\n  z-index: 1;\n  width: 50%;\n  height: 100px;\n  margin-top: -50px;\n  transform-origin: 0% 50%;\n  -webkit-transform-origin: 0% 50%;\n  -o-transform-origin: 0% 50%;\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n  -webkit-transition: all .5s;\n  transition: all .5s;\n  -o-transition: all .5s;\n}\n\n.den .light span {\n  opacity: .4;\n  position: absolute;\n  top: 0;\n  left: 15px;\n  width: 100px;\n  height: 100px;\n  background: -moz-radial-gradient(center, ellipse cover, rgba(184, 163, 204, 1) 0%, rgba(159, 197, 224, 0.42) 42%, rgba(111, 113, 179, 0) 72%, rgba(67, 34, 137, 0) 100%);\n  background: -webkit-gradient(radial, center center, 0px, center center, 100%, color-stop(0%, rgba(184, 163, 204, 1)), color-stop(42%, rgba(159, 197, 224, 0.42)), color-stop(72%, rgba(111, 113, 179, 0)), color-stop(100%, rgba(67, 34, 137, 0)));\n  background: -webkit-radial-gradient(center, ellipse cover, rgba(184, 163, 204, 1) 0%, rgba(159, 197, 224, 0.42) 42%, rgba(111, 113, 179, 0) 72%, rgba(67, 34, 137, 0) 100%);\n  background: -o-radial-gradient(center, ellipse cover, rgba(184, 163, 204, 1) 0%, rgba(159, 197, 224, 0.42) 42%, rgba(111, 113, 179, 0) 72%, rgba(67, 34, 137, 0) 100%);\n}\n\n/* SWITCH LIGHT POSITION */\n\n.den #switch_off:checked ~ .light {\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n}\n\n.den #switch_1:checked ~ .light {\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den #switch_2:checked ~ .light {\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den #switch_3:checked ~ .light {\n  transform: rotate(90deg);\n  -webkit-transform: rotate(90deg);\n  -o-transform: rotate(90deg);\n}\n\n.den #switch_4:checked ~ .light {\n  transform: rotate(150deg);\n  -webkit-transform: rotate(150deg);\n  -o-transform: rotate(150deg);\n}\n\n.den #switch_5:checked ~ .light {\n  transform: rotate(210deg);\n  -webkit-transform: rotate(210deg);\n  -o-transform: rotate(210deg);\n}\n\n/* SWITCH LIGHT */\n\n.den .dot {\n  z-index: 6;\n  width: 50%;\n  height: 12px;\n  margin-top: -6px;\n  transform-origin: 0% 50%;\n  -webkit-transform-origin: 0% 50%;\n  -o-transform-origin: 0% 50%;\n  transition: all .5s;\n  -moz-transition: all .5s;\n  -o-transition: all .5s;\n}\n\n.den .dot span {\n  position: absolute;\n  top: 0;\n  left: 30px;\n  width: 12px;\n  height: 12px;\n  border-radius: 100%;\n  background: #dae2e4;\n  background: -moz-linear-gradient(top, #dae2e4 0%, #ecf5f4 100%);\n  background: -webkit-gradient(linear, left top, left bottom, color-stop(0%, #dae2e4), color-stop(100%, #ecf5f4));\n  background: -webkit-linear-gradient(top, #dae2e4 0%, #ecf5f4 100%);\n  background: -o-linear-gradient(top, #dae2e4 0%, #ecf5f4 100%);\n}\n\n/* SWITCH LIGHT POSITION */\n\n.den #switch_off:checked ~ .dot {\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n}\n\n.den #switch_off:checked ~ .dot span {\n  transform: rotate(90deg);\n  -webkit-transform: rotate(90deg);\n  -o-transform: rotate(90deg);\n}\n\n.den #switch_1:checked ~ .dot {\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den #switch_1:checked ~ .dot span {\n  opacity: .9;\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den #switch_2:checked ~ .dot {\n  transform: rotate(30deg);\n  -webkit-transform: rotate(30deg);\n  -o-transform: rotate(30deg);\n}\n\n.den #switch_2:checked ~ .dot span {\n  opacity: .5;\n  transform: rotate(-30deg);\n  -webkit-transform: rotate(-30deg);\n  -o-transform: rotate(-30deg);\n}\n\n.den #switch_3:checked ~ .dot {\n  transform: rotate(90deg);\n  -webkit-transform: rotate(90deg);\n  -o-transform: rotate(90deg);\n}\n\n.den #switch_3:checked ~ .dot span {\n  opacity: .4;\n  transform: rotate(-90deg);\n  -webkit-transform: rotate(-90deg);\n  -o-transform: rotate(-90deg);\n}\n\n.den #switch_4:checked ~ .dot {\n  transform: rotate(150deg);\n  -webkit-transform: rotate(150deg);\n  -o-transform: rotate(150deg);\n}\n\n.den #switch_4:checked ~ .dot span {\n  opacity: .5;\n  transform: rotate(-150deg);\n  -webkit-transform: rotate(-150deg);\n  -o-transform: rotate(-150deg);\n}\n\n.den #switch_5:checked ~ .dot {\n  transform: rotate(210deg);\n  -webkit-transform: rotate(210deg);\n  -o-transform: rotate(210deg);\n}\n\n.den #switch_5:checked ~ .dot span {\n  opacity: .9;\n  transform: rotate(-210deg);\n  -webkit-transform: rotate(-210deg);\n  -o-transform: rotate(-210deg);\n}\n\n/* LINE */\n\n.den hr.line {\n  z-index: 1;\n  position: absolute;\n  top: 50%;\n  width: 100%;\n  height: 0;\n  margin-top: -1px;\n  border-width: 1px 0;\n  border-style: solid;\n  border-top-color: #3c3d3f;\n  border-bottom-color: #666769;\n}\n\n.den hr.line:nth-child(1) {\n  transform: rotate(-60deg);\n  -webkit-transform: rotate(-60deg);\n  -o-transform: rotate(-60deg);\n}\n\n.den hr.line:nth-child(2) {\n  transform: rotate(60deg);\n  -webkit-transform: rotate(60deg);\n  -o-transform: rotate(60deg);\n}'),
(16, '<div class=\"radio-input\">\n  <div class=\"center\"></div>\n  <label class=\"label spring\">\n    <input type=\"radio\" id=\"value-1\" name=\"value-radio\" value=\"value-1\" />\n    <span class=\"text spring\">Spring</span>\n  </label>\n  <label class=\"label summer\">\n    <input type=\"radio\" id=\"value-2\" name=\"value-radio\" value=\"value-2\" />\n    <span class=\"text summer\">Summer</span>\n  </label>\n  <label class=\"label autumn\">\n    <input type=\"radio\" id=\"value-3\" name=\"value-radio\" value=\"value-3\" />\n    <span class=\"text autumn\">Autumn</span>\n  </label>\n  <label class=\"label winter\">\n    <input type=\"radio\" id=\"value-4\" name=\"value-radio\" value=\"value-4\" />\n    <span class=\"text winter\">Winter</span>\n  </label>\n</div>\n', '.radio-input {\n  width: 210px;\n  height: 210px;\n  background-color: black;\n  border-radius: 30px;\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  padding: 6px;\n  gap: 4px;\n  position: relative;\n  z-index: -1;\n}\n\n.radio-input input {\n  display: none;\n}\n\n.radio-input .label {\n  background: linear-gradient(to bottom, #333333, rgb(36, 35, 35));\n  border-radius: 22px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  border-top: 1px solid #4e4d4d;\n  cursor: pointer;\n  transition-property: all;\n  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);\n  transition-duration: 200ms;\n  box-shadow: 0px 0px 5px 1px rgba(0, 0, 0, 0.2);\n}\n\n.label:has(input[type=\"radio\"]:checked) {\n  box-shadow: 0px 17px 5px 1px rgba(0, 0, 0, 0);\n  background: linear-gradient(to bottom, #1d1d1d, #1d1d1d);\n  border-top: none;\n}\n\n.label::before {\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  scale: 1.02;\n  border-radius: 25px;\n  background: linear-gradient(\n      to bottom,\n      transparent 10%,\n      transparent,\n      transparent 90%\n    ),\n    linear-gradient(to left, transparent 10%, transparent, transparent 90%);\n  transition-property: all;\n  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);\n  transition-duration: 200ms;\n  z-index: -1;\n}\n\n.label.spring:has(input[type=\"radio\"]:checked)::before {\n  background: linear-gradient(\n      to bottom,\n      transparent 10%,\n      #d88fa3,\n      transparent 90%\n    ),\n    linear-gradient(to left, transparent 10%, #d88fa3, transparent 90%);\n}\n\n.label.summer:has(input[type=\"radio\"]:checked)::before {\n  background: linear-gradient(\n      to bottom,\n      transparent 10%,\n      #e6b800,\n      transparent 90%\n    ),\n    linear-gradient(to left, transparent 10%, #e6b800, transparent 90%);\n}\n\n.label.autumn:has(input[type=\"radio\"]:checked)::before {\n  background: linear-gradient(\n      to bottom,\n      transparent 10%,\n      #c76b00,\n      transparent 90%\n    ),\n    linear-gradient(to left, transparent 10%, #c76b00, transparent 90%);\n}\n\n.label.winter:has(input[type=\"radio\"]:checked)::before {\n  background: linear-gradient(\n      to bottom,\n      transparent 10%,\n      #7fa8c4,\n      transparent 90%\n    ),\n    linear-gradient(to left, transparent 10%, #7fa8c4, transparent 90%);\n}\n\n.label .text {\n  color: black;\n  font-size: 13px;\n  line-height: 12px;\n  padding: 0px;\n  font-weight: 700;\n  text-transform: uppercase;\n  transition: all 0.1s linear;\n  text-shadow:\n    -1px -1px 1px rgb(224, 224, 224, 0.1),\n    0px 2px 3px rgb(0, 0, 0, 0.3);\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n}\n\n.label input[type=\"radio\"]:checked + .spring {\n  color: #ffc0cb;\n  text-shadow: 0px 0px 12px #d88fa3;\n}\n\n.label input[type=\"radio\"]:checked + .summer {\n  color: #ffd700;\n  text-shadow: 0px 0px 12px #e6b800;\n}\n\n.label input[type=\"radio\"]:checked + .autumn {\n  color: #ff8c00;\n  text-shadow: 0px 0px 12px #c76b00;\n}\n\n.label input[type=\"radio\"]:checked + .winter {\n  color: #add8e6;\n  text-shadow: 0px 0px 12px #7fa8c4;\n}\n\n.center {\n  width: 12px;\n  height: 12px;\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%) rotate(45deg);\n  background-color: #333333;\n  border-radius: 2px;\n  border: 1px solid #4e4d4d;\n  transition: all 0.12s linear;\n}\n\n.radio-input:has(.spring input:checked) .center {\n  border-left: 1px solid #ffc0cbb2;\n  box-shadow: inset 11px 0px 10px -12px #ffc0cbdc;\n}\n\n.radio-input:has(.summer input:checked) .center {\n  border-top: 1px solid#ffd900d8;\n  box-shadow: inset 0px 11px 10px -12px #ffd700;\n}\n\n.radio-input:has(.autumn input:checked) .center {\n  border-bottom: 1px solid #ff8c00b2;\n  box-shadow: inset 0px -11px 10px -12px #ff8c00;\n}\n\n.radio-input:has(.winter input:checked) .center {\n  border-right: 1px solid #add8e694;\n  box-shadow: inset -11px 0px 10px -12px #add8e6;\n}\n'),
(17, '<div class=\"radio\">\n  <input\n    label=\"Yes\"\n    type=\"radio\"\n    id=\"male\"\n    name=\"gender\"\n    value=\"male\"\n    checked=\"\"\n  />\n  <input label=\"No\" type=\"radio\" id=\"female\" name=\"gender\" value=\"female\" />\n  <input\n    label=\"I hate making decisions 🤷🏻‍♂️\"\n    type=\"radio\"\n    id=\"other\"\n    name=\"gender\"\n    value=\"other\"\n  />\n</div>\n', '.radio {\n  background: #454857;\n  padding: 4px;\n  border-radius: 3px;\n  box-shadow: inset 0 0 0 3px rgba(35, 33, 45, 0.3),\n    0 0 0 3px rgba(185, 185, 185, 0.3);\n  position: relative;\n}\n\n.radio input {\n  width: auto;\n  height: 100%;\n  -webkit-appearance: none;\n  -moz-appearance: none;\n  appearance: none;\n  outline: none;\n  cursor: pointer;\n  border-radius: 2px;\n  padding: 4px 8px;\n  background: #454857;\n  color: #bdbdbdbd;\n  font-size: 14px;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto,\n    \"Helvetica Neue\", Arial, \"Noto Sans\", sans-serif, \"Apple Color Emoji\",\n    \"Segoe UI Emoji\", \"Segoe UI Symbol\", \"Noto Color Emoji\";\n  transition: all 100ms linear;\n}\n\n.radio input:checked {\n  background-image: linear-gradient(180deg, #95d891, #74bbad);\n  color: #fff;\n  box-shadow: 0 1px 1px #0000002e;\n  text-shadow: 0 1px 0px #79485f7a;\n  -webkit-animation: rubberBand 1s both;\n  animation: rubberBand 1s both;\n}\n\n.radio input:before {\n  content: attr(label);\n  display: inline-block;\n  text-align: center;\n  width: 100%;\n}\n\n@-webkit-keyframes rubberBand {\n  0% {\n    -webkit-transform: scale3d(1, 1, 1);\n    transform: scale3d(1, 1, 1);\n  }\n\n  30% {\n    -webkit-transform: scale3d(1.25, 0.75, 1);\n    transform: scale3d(1.25, 0.75, 1);\n  }\n\n  40% {\n    -webkit-transform: scale3d(0.75, 1.25, 1);\n    transform: scale3d(0.75, 1.25, 1);\n  }\n\n  50% {\n    -webkit-transform: scale3d(1.15, 0.85, 1);\n    transform: scale3d(1.15, 0.85, 1);\n  }\n\n  65% {\n    -webkit-transform: scale3d(0.95, 1.05, 1);\n    transform: scale3d(0.95, 1.05, 1);\n  }\n\n  75% {\n    -webkit-transform: scale3d(1.05, 0.95, 1);\n    transform: scale3d(1.05, 0.95, 1);\n  }\n\n  100% {\n    -webkit-transform: scale3d(1, 1, 1);\n    transform: scale3d(1, 1, 1);\n  }\n}\n\n@keyframes rubberBand {\n  0% {\n    -webkit-transform: scale3d(1, 1, 1);\n    transform: scale3d(1, 1, 1);\n  }\n\n  30% {\n    -webkit-transform: scale3d(1.25, 0.75, 1);\n    transform: scale3d(1.25, 0.75, 1);\n  }\n\n  40% {\n    -webkit-transform: scale3d(0.75, 1.25, 1);\n    transform: scale3d(0.75, 1.25, 1);\n  }\n\n  50% {\n    -webkit-transform: scale3d(1.15, 0.85, 1);\n    transform: scale3d(1.15, 0.85, 1);\n  }\n\n  65% {\n    -webkit-transform: scale3d(0.95, 1.05, 1);\n    transform: scale3d(0.95, 1.05, 1);\n  }\n\n  75% {\n    -webkit-transform: scale3d(1.05, 0.95, 1);\n    transform: scale3d(1.05, 0.95, 1);\n  }\n\n  100% {\n    -webkit-transform: scale3d(1, 1, 1);\n    transform: scale3d(1, 1, 1);\n  }\n}\n'),
(18, '<div class=\"container\">\n  <div class=\"radio-wrapper\">\n    <input class=\"input\" name=\"btn\" id=\"value-1\" type=\"radio\">\n    <div class=\"btn\">\n      <span aria-hidden=\"\">_</span>Cyber\n      <span class=\"btn__glitch\" aria-hidden=\"\">_Cyber🦾</span>\n      <label class=\"number\">r1</label>\n    </div>\n  </div>\n  <div class=\"radio-wrapper\">\n    <input class=\"input\" name=\"btn\" id=\"value-2\" checked=\"true\" type=\"radio\">\n    <div class=\"btn\">\n      _Radio<span aria-hidden=\"\">_</span>\n      <span class=\"btn__glitch\" aria-hidden=\"\">_R_a_d_i_o_</span>\n      <label class=\"number\">r2</label>\n    </div>\n  </div>\n  <div class=\"radio-wrapper\">\n    <input class=\"input\" name=\"btn\" id=\"value-3\" type=\"radio\">\n    <div class=\"btn\">\n      Buttons<span aria-hidden=\"\"></span>\n      <span class=\"btn__glitch\" aria-hidden=\"\">Buttons_</span>\n      <label class=\"number\">r3</label>\n    </div> \n  </div>\n</div>\n\n', '.container {\n  display: flex;\n  flex-direction: row;\n}\n\n.radio-wrapper {\n  position: relative;\n  height: 38px;\n  width: 84px;\n  margin: 3px;\n}\n\n.radio-wrapper .input {\n  position: absolute;\n  height: 100%;\n  width: 100%;\n  margin: 0;\n  cursor: pointer;\n  z-index: 10;\n  opacity: 0;\n}\n\n.btn {\n  --primary: #ff184c;\n  --shadow-primary: #fded00;\n  --color: white;\n  --font-size: 9px;\n  --shadow-primary-hue: 180;\n  --shadow-secondary-hue: 60;\n  --shadow-secondary: hsl(var(--shadow-secondary-hue), 90%, 60%);\n  --clip: polygon(11% 0, 95% 0, 100% 25%, 90% 90%, 95% 90%, 85% 90%, 85% 100%, 7% 100%, 0 80%);\n  --border: 5px;\n  --shimmy-distance: 5;\n  --clip-one: polygon(0 2%, 100% 2%, 100% 95%, 95% 95%, 95% 90%, 85% 90%, 85% 95%, 8% 95%, 0 70%);\n  --clip-two: polygon(0 78%, 100% 78%, 100% 100%, 95% 100%, 95% 90%, 85% 90%, 85% 100%, 8% 100%, 0 78%);\n  --clip-three: polygon(0 44%, 100% 44%, 100% 54%, 95% 54%, 95% 54%, 85% 54%, 85% 54%, 8% 54%, 0 54%);\n  --clip-four: polygon(0 0, 100% 0, 100% 0, 95% 0, 95% 0, 85% 0, 85% 0, 8% 0, 0 0);\n  --clip-five: polygon(0 0, 100% 0, 100% 0, 95% 0, 95% 0, 85% 0, 85% 0, 8% 0, 0 0);\n  --clip-six: polygon(0 40%, 100% 40%, 100% 85%, 95% 85%, 95% 85%, 85% 85%, 85% 85%, 8% 85%, 0 70%);\n  --clip-seven: polygon(0 63%, 100% 63%, 100% 80%, 95% 80%, 95% 80%, 85% 80%, 85% 80%, 8% 80%, 0 70%);\n  color: var(--color);\n  text-transform: uppercase;\n  font-size: var(--font-size);\n  letter-spacing: 3px;\n  position: relative;\n  font-weight: 900;\n  width: 100%;\n  height: 100%;\n  line-height: 38px;\n  text-align: center;\n  transition: background 0.2s, 0.3s;\n}\n\n.input:checked + .btn {\n  --primary: #8B00FF;\n  --shadow-primary: #00e572;\n}\n\n.input:hover + .btn {\n  --primary: #cc133c;\n  --font-size: 11px;\n}\n\n.btn:after, .btn:before {\n  content: \';\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  clip-path: var(--clip);\n  z-index: -1;\n}\n\n.btn:before {\n  background: var(--shadow-primary);\n  transform: translate(var(--border), 0);\n}\n\n.btn:after {\n  background: var(--primary);\n}\n\n.btn__tag {\n  position: absolute;\n  padding: 1px 4px;\n  letter-spacing: 1px;\n  line-height: 1;\n  bottom: -5%;\n  right: 5%;\n  font-weight: normal;\n  color: hsl(0, 0%, 0%);\n  font-size: var(--label-size);\n}\n\n.btn__glitch {\n  position: absolute;\n  top: calc(var(--border) * -1);\n  left: calc(var(--border) * -1);\n  right: calc(var(--border) * -1);\n  bottom: calc(var(--border) * -1);\n  background: var(--shadow-primary);\n  text-shadow: 2px 2px var(--shadow-primary), -2px -2px var(--shadow-secondary);\n  clip-path: var(--clip);\n  animation: glitch 2s infinite;\n  display: none;\n}\n\n.input:hover + .btn .btn__glitch {\n  display: block;\n}\n\n.input:checked + .btn .btn__glitch {\n  display: block;\n  animation: glitch 5s infinite;\n}\n\n.btn__glitch:before {\n  content: \';\n  position: absolute;\n  top: calc(var(--border) * 1);\n  right: calc(var(--border) * 1);\n  bottom: calc(var(--border) * 1);\n  left: calc(var(--border) * 1);\n  clip-path: var(--clip);\n  background: var(--primary);\n  z-index: -1;\n}\n\n@keyframes glitch {\n  0% {\n    clip-path: var(--clip-one);\n  }\n\n  2%, 8% {\n    clip-path: var(--clip-two);\n    transform: translate(calc(var(--shimmy-distance) * -1%), 0);\n  }\n\n  6% {\n    clip-path: var(--clip-two);\n    transform: translate(calc(var(--shimmy-distance) * 1%), 0);\n  }\n\n  9% {\n    clip-path: var(--clip-two);\n    transform: translate(0, 0);\n  }\n\n  10% {\n    clip-path: var(--clip-three);\n    transform: translate(calc(var(--shimmy-distance) * 1%), 0);\n  }\n\n  13% {\n    clip-path: var(--clip-three);\n    transform: translate(0, 0);\n  }\n\n  14%, 21% {\n    clip-path: var(--clip-four);\n    transform: translate(calc(var(--shimmy-distance) * 1%), 0);\n  }\n\n  25% {\n    clip-path: var(--clip-five);\n    transform: translate(calc(var(--shimmy-distance) * 1%), 0);\n  }\n\n  30% {\n    clip-path: var(--clip-five);\n    transform: translate(calc(var(--shimmy-distance) * -1%), 0);\n  }\n\n  35%, 45% {\n    clip-path: var(--clip-six);\n    transform: translate(calc(var(--shimmy-distance) * -1%));\n  }\n\n  40% {\n    clip-path: var(--clip-six);\n    transform: translate(calc(var(--shimmy-distance) * 1%));\n  }\n\n  50% {\n    clip-path: var(--clip-six);\n    transform: translate(0, 0);\n  }\n\n  55% {\n    clip-path: var(--clip-seven);\n    transform: translate(calc(var(--shimmy-distance) * 1%), 0);\n  }\n\n  60% {\n    clip-path: var(--clip-seven);\n    transform: translate(0, 0);\n  }\n\n  31%, 61%, 100% {\n    clip-path: var(--clip-four);\n  }\n}\n\n.number {\n  background: var(--shadow-primary);\n  color: #323232;\n  font-size: 5.5px;\n  font-weight: 700;\n  letter-spacing: 1px;\n  position: absolute;\n  width: 15px;\n  height: 6px;\n  top: 0;\n  left: 81%;\n  line-height: 6.2px;\n}\n');
INSERT INTO `radio` (`ID`, `HTML`, `CSS`) VALUES
(19, '<label id=\"topleft\" class=\"container\">\n  <input name=\"my-radio-button\" type=\"radio\">\n  <label id=\"tl\">Top <br>Left</label>\n  <div class=\"selected\"></div>\n</label>\n&nbsp;\n<label id=\"topright\" class=\"container\">\n  <input name=\"my-radio-button\" type=\"radio\">\n  <label id=\"tr\">Top<br>Right</label>\n  <div class=\"selected\"></div>\n</label>\n<br>\n<br>\n<label id=\"bottomleft\" class=\"container\">\n  <input name=\"my-radio-button\" type=\"radio\">\n  <label id=\"bl\">Bottom <br>Left</label>\n  <div class=\"selected\"></div>\n</label>\n&nbsp;\n<label id=\"bottomright\" class=\"container\">\n  <input name=\"my-radio-button\" type=\"radio\">\n  <label id=\"br\">Bottom <br>Right</label>\n  <div class=\"selected\"></div>\n</label>', '.container input[type=\"radio\"] {\n  position: absolute;\n  opacity: 0;\n  cursor: pointer;\n  height: 0;\n  width: 0;\n}\n\n.container {\n  display: inline-block;\n  position: relative;\n  cursor: pointer;\n  font-size: 17px;\n  width: 4em;\n  height: 4em;\n  user-select: none;\n  border: 4px solid;\n  border-image-slice: 1;\n  background-color: #212121;\n}\n\nlabel {\n  font-size: 12px;\n  margin-top: -6px;\n  font-family: \'Lucida Sans\', \'Lucida Sans Regular\', \'Lucida Grande\', \'Lucida Sans Unicode\', Geneva, Verdana, sans-serif;\n  text-align: center;\n  visibility: visible;\n}\n\n#topleft {\n  border-image-source: linear-gradient(-45deg, #743ad5, #d53a9d);\n  color: white;\n}\n\n#topright {\n  border-image-source: linear-gradient(45deg, #743ad5, #d53a9d);\n  color: white;\n}\n\n#bottomleft {\n  border-image-source: linear-gradient(-135deg, #743ad5, #d53a9d);\n  color: white;\n}\n\n#bottomright {\n  border-image-source: linear-gradient(135deg, #743ad5, #d53a9d);\n  color: white;\n}\n\n.selected {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n}\n\n#topleft:hover {\n  border-image-source: linear-gradient(-45deg, #743ad5, #d53a9d);\n  background-image: linear-gradient(-45deg, #743ad5, #d53a9d);\n}\n\n#topright:hover {\n  border-image-source: linear-gradient(45deg, #743ad5, #d53a9d);\n  background-image: linear-gradient(45deg, #743ad5, #d53a9d);\n}\n\n#bottomleft:hover {\n  border-image-source: linear-gradient(-135deg, #743ad5, #d53a9d);\n  background-image: linear-gradient(-135deg, #743ad5, #d53a9d);\n}\n\n#bottomright:hover {\n  border-image-source: linear-gradient(135deg, #743ad5, #d53a9d);\n  background-image: linear-gradient(135deg, #743ad5, #d53a9d);\n}\n\n#topleft input[type=\"radio\"]:checked ~ .selected {\n  box-shadow: 5px 5px 25px #743ad5,\n              -5px -5px 25px #d53a9d;\n  border-image-slice: 1;\n}\n\n#topright input[type=\"radio\"]:checked ~ .selected {\n  box-shadow: -5px 5px 25px #743ad5,\n              5px -5px 25px #d53a9d;\n  border-image-slice: 1;\n}\n\n#bottomleft input[type=\"radio\"]:checked ~ .selected {\n  box-shadow: -5px 5px 25px #d53a9d,\n              5px -5px 25px #743ad5;\n  border-image-slice: 1;\n}\n\n#bottomright input[type=\"radio\"]:checked ~ .selected {\n  box-shadow: -5px -5px 25px #743ad5,\n              5px 5px 25px #d53a9d;\n  border-image-slice: 1;\n}'),
(20, '<div class=\"radio-input\">\n    <input checked=\"\" value=\"color-1\" name=\"color\" id=\"color-1\" type=\"radio\">\n    <label for=\"color-1\">\n      <span>\n        <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\"><g stroke-width=\"0\" id=\"SVGRepo_bgCarrier\"></g><g stroke-linejoin=\"round\" stroke-linecap=\"round\" id=\"SVGRepo_tracerCarrier\"></g><g id=\"SVGRepo_iconCarrier\"> <g id=\"Interface / Check\"> <path stroke-linejoin=\"round\" stroke-linecap=\"round\" stroke-width=\"2\" stroke=\"#ffffff\" d=\"M6 12L10.2426 16.2426L18.727 7.75732\" id=\"Vector\"></path> </g> </g></svg>\n      </span>\n    </label>\n  \n    <input value=\"color-2\" name=\"color\" id=\"color-2\" type=\"radio\">\n    <label for=\"color-2\">\n      <span>\n        <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\"><g stroke-width=\"0\" id=\"SVGRepo_bgCarrier\"></g><g stroke-linejoin=\"round\" stroke-linecap=\"round\" id=\"SVGRepo_tracerCarrier\"></g><g id=\"SVGRepo_iconCarrier\"> <g id=\"Interface / Check\"> <path stroke-linejoin=\"round\" stroke-linecap=\"round\" stroke-width=\"2\" stroke=\"#ffffff\" d=\"M6 12L10.2426 16.2426L18.727 7.75732\" id=\"Vector\"></path> </g> </g></svg>\n      </span>\n    </label>\n  \n    <input value=\"color-3\" name=\"color\" id=\"color-3\" type=\"radio\">\n    <label for=\"color-3\">\n      <span>\n        <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\"><g stroke-width=\"0\" id=\"SVGRepo_bgCarrier\"></g><g stroke-linejoin=\"round\" stroke-linecap=\"round\" id=\"SVGRepo_tracerCarrier\"></g><g id=\"SVGRepo_iconCarrier\"> <g id=\"Interface / Check\"> <path stroke-linejoin=\"round\" stroke-linecap=\"round\" stroke-width=\"2\" stroke=\"#ffffff\" d=\"M6 12L10.2426 16.2426L18.727 7.75732\" id=\"Vector\"></path> </g> </g></svg>\n      </span>\n    </label>\n\n</div>', '.radio-input {\n  background-color: #fff;\n  padding: 20px;\n  border-radius: 20px;\n  display: flex;\n}\n\n.radio-input input[type=radio] {\n  display: none;\n}\n\n.radio-input input[type=radio] + label {\n  color: #333;\n  font-family: Arial, sans-serif;\n  font-size: 14px;\n}\n\n.radio-input input[type=radio] + label span {\n  display: inline-block;\n  width: 40px;\n  height: 40px;\n  margin: -1px 4px 0 0;\n  vertical-align: middle;\n  cursor: pointer;\n  border-radius: 50%;\n  border: 2px solid #FFFFFF;\n  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.33);\n  background-repeat: no-repeat;\n  background-position: center;\n  text-align: center;\n  line-height: 44px;\n}\n\n.radio-input input[type=radio] + label span svg {\n  opacity: 0;\n  transition: all 0.3s ease;\n}\n\n.radio-input input[type=radio]#color-1 + label span {\n  background-color: #2ecc71;\n}\n\n.radio-input input[type=radio]#color-2 + label span {\n  background-color: #3498db;\n}\n\n.radio-input input[type=radio]#color-3 + label span {\n  background-color: #f1c40f;\n}\n\n.radio-input input[type=radio]:checked + label span svg {\n  opacity: 1;\n}\n\n.radio-input:has(input[type=radio]#color-1:checked) {\n  background-color: #2ecc71;\n}\n\n.radio-input:has(input[type=radio]#color-2:checked) {\n  background-color: #3498db;\n}\n\n.radio-input:has(input[type=radio]#color-3:checked) {\n  background-color: #f1c40f;\n}\n');

