INSERT INTO `togleswitches` (`ID`, `HTML`, `CSS`) VALUES
(1, '\n<label class=\"switch\">\n  <input class=\"cb\" type=\"checkbox\" />\n  <span class=\"toggle\">\n    <span class=\"left\">off</span>\n    <span class=\"right\">on</span>\n  </span>\n</label>\n', '\n.switch {\n  font-size: 17px;\n  position: relative;\n  display: inline-block;\n  width: 5em;\n  height: 2.5em;\n  user-select: none;\n}\n\n/* Hide default HTML checkbox */\n.switch .cb {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.toggle {\n  position: absolute;\n  cursor: pointer;\n  width: 100%;\n  height: 100%;\n  background-color: #373737;\n  border-radius: 0.1em;\n  transition: 0.4s;\n  text-transform: uppercase;\n  font-weight: 700;\n  overflow: hidden;\n  box-shadow: -0.3em 0 0 0 #373737, -0.3em 0.3em 0 0 #373737,\n    0.3em 0 0 0 #373737, 0.3em 0.3em 0 0 #373737, 0 0.3em 0 0 #373737;\n}\n\n.toggle > .left {\n  position: absolute;\n  display: flex;\n  width: 50%;\n  height: 88%;\n  background-color: #f3f3f3;\n  color: #373737;\n  left: 0;\n  bottom: 0;\n  align-items: center;\n  justify-content: center;\n  transform-origin: right;\n  transform: rotateX(10deg);\n  transform-style: preserve-3d;\n  transition: all 150ms;\n}\n\n.left::before {\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  background-color: rgb(206, 206, 206);\n  transform-origin: center left;\n  transform: rotateY(90deg);\n}\n\n.left::after {\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  background-color: rgb(112, 112, 112);\n  transform-origin: center bottom;\n  transform: rotateX(90deg);\n}\n\n.toggle > .right {\n  position: absolute;\n  display: flex;\n  width: 50%;\n  height: 88%;\n  background-color: #f3f3f3;\n  color: rgb(206, 206, 206);\n  right: 1px;\n  bottom: 0;\n  align-items: center;\n  justify-content: center;\n  transform-origin: left;\n  transform: rotateX(10deg) rotateY(-45deg);\n  transform-style: preserve-3d;\n  transition: all 150ms;\n}\n\n.right::before {\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  background-color: rgb(206, 206, 206);\n  transform-origin: center right;\n  transform: rotateY(-90deg);\n}\n\n.right::after {\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  background-color: rgb(112, 112, 112);\n  transform-origin: center bottom;\n  transform: rotateX(90deg);\n}\n\n.switch input:checked + .toggle > .left {\n  transform: rotateX(10deg) rotateY(45deg);\n  color: rgb(206, 206, 206);\n}\n\n.switch input:checked + .toggle > .right {\n  transform: rotateX(10deg) rotateY(0deg);\n  color: #487bdb;\n}\n'),
(2, '\r\n<label class=\"switch\">\r\n  <input type=\"checkbox\" class=\"chk\">\r\n  <span class=\"slider\"></span>\r\n</label>', '\r\n.switch {\r\n  font-size: 17px;\r\n  position: relative;\r\n  display: inline-block;\r\n  width: 1.2em;\r\n  height: 3.3em;\r\n}\r\n\r\n.switch .chk {\r\n  opacity: 0;\r\n  width: 0;\r\n  height: 0;\r\n}\r\n\r\n/* The slider */\r\n.slider {\r\n  position: absolute;\r\n  cursor: pointer;\r\n  top: 0;\r\n  left: 0;\r\n  right: 0;\r\n  bottom: 0;\r\n  background-color: #ccc;\r\n  transition: .4s;\r\n  border-radius: 5px;\r\n}\r\n\r\n.slider:before {\r\n  position: absolute;\r\n  content: \"\";\r\n  height: .5em;\r\n  width: 2.4em;\r\n  border-radius: 5px;\r\n  left: -0.6em;\r\n  top: 0.2em;\r\n  background-color: white;\r\n  box-shadow: 0 6px 7px rgba(0,0,0,0.3);\r\n  transition: .4s;\r\n}\r\n\r\n.slider:before, .slider:after {\r\n  content: \"\";\r\n  display: block;\r\n}\r\n\r\n.slider:after {\r\n  background: linear-gradient(transparent 50%, rgba(255, 255, 255, 0.15) 0) 0 50% / 50% 100%,\r\n		repeating-linear-gradient(90deg,rgb(255, 255, 255) 0,rgb(255, 255, 255),rgb(255, 255, 255) 20%,rgb(255, 255, 255) 20%,rgb(255, 255, 255) 40%) 0 50% / 50% 100%,\r\n		radial-gradient(circle at 50% 50%,rgb(255, 255, 255) 25%, transparent 26%);\r\n  background-repeat: no-repeat;\r\n  border: 0.25em solid transparent;\r\n  border-left: 0.4em solid #ffffff;\r\n  border-right: 0 solid transparent;\r\n  transition: border-left-color 0.1s 0.3s ease-out, transform 0.3s ease-out;\r\n  transform: translateX(-22.5%) rotate(90deg);\r\n  transform-origin: 25% 50%;\r\n  position: relative;\r\n  top: 0.5em;\r\n  left: 0.55em;\r\n  width: 2em;\r\n  height: 1em;\r\n  box-sizing: border-box;\r\n}\r\n\r\n.chk:checked + .slider {\r\n  background-color: limegreen;\r\n}\r\n\r\n.chk:focus + .slider {\r\n  box-shadow: 0 0 1px limegreen;\r\n}\r\n\r\n.chk:checked + .slider:before {\r\n  transform: translateY(2.3em);\r\n}\r\n\r\n.chk:checked + .slider:after {\r\n  transform: rotateZ(90deg) rotateY(180deg) translateY(0.45em) translateX(-1.4em);\r\n}'),
(3, '\r\n<div class=\"container\">\r\n  <label class=\"label\">\r\n    <input type=\"checkbox\" class=\"input\" />\r\n    <span class=\"circle\"\r\n      ><svg\r\n        class=\"icon\"\r\n        aria-hidden=\"true\"\r\n        xmlns=\"http://www.w3.org/2000/svg\"\r\n        fill=\"none\"\r\n        viewBox=\"0 0 24 24\"\r\n      >\r\n        <path\r\n          stroke=\"currentColor\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n          stroke-width=\"1.5\"\r\n          d=\"M12 19V5m0 14-4-4m4 4 4-4\"\r\n        ></path>\r\n      </svg>\r\n      <div class=\"square\"></div>\r\n    </span>\r\n    <p class=\"title\">Download</p>\r\n    <p class=\"title\">Open</p>\r\n  </label>\r\n</div>\r\n', '\r\n.container {\r\n  padding: 0;\r\n  margin: 0;\r\n  box-sizing: border-box;\r\n  font-family: Arial, Helvetica, sans-serif;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n}\r\n\r\n.label {\r\n  background-color: transparent;\r\n  border: 2px solid rgb(91, 91, 240);\r\n  display: flex;\r\n  align-items: center;\r\n  border-radius: 50px;\r\n  width: 160px;\r\n  cursor: pointer;\r\n  transition: all 0.4s ease;\r\n  padding: 5px;\r\n  position: relative;\r\n}\r\n\r\n.label::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  top: 0;\r\n  bottom: 0;\r\n  left: 0;\r\n  right: 0;\r\n  background-color: #fff;\r\n  width: 8px;\r\n  height: 8px;\r\n  transition: all 0.4s ease;\r\n  border-radius: 100%;\r\n  margin: auto;\r\n  opacity: 0;\r\n  visibility: hidden;\r\n}\r\n\r\n.label .input {\r\n  display: none;\r\n}\r\n\r\n.label .title {\r\n  font-size: 17px;\r\n  color: #fff;\r\n  transition: all 0.4s ease;\r\n  position: absolute;\r\n  right: 18px;\r\n  bottom: 14px;\r\n  text-align: center;\r\n}\r\n\r\n.label .title:last-child {\r\n  opacity: 0;\r\n  visibility: hidden;\r\n}\r\n\r\n.label .circle {\r\n  height: 45px;\r\n  width: 45px;\r\n  border-radius: 50%;\r\n  background-color: rgb(91, 91, 240);\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  transition: all 0.4s ease;\r\n  position: relative;\r\n  box-shadow: 0 0 0 0 rgb(255, 255, 255);\r\n  overflow: hidden;\r\n}\r\n\r\n.label .circle .icon {\r\n  color: #fff;\r\n  width: 30px;\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n  transition: all 0.4s ease;\r\n}\r\n\r\n.label .circle .square {\r\n  aspect-ratio: 1;\r\n  width: 15px;\r\n  border-radius: 2px;\r\n  background-color: #fff;\r\n  opacity: 0;\r\n  visibility: hidden;\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n  transition: all 0.4s ease;\r\n}\r\n\r\n.label .circle::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  background-color: #3333a8;\r\n  width: 100%;\r\n  height: 0;\r\n  transition: all 0.4s ease;\r\n}\r\n\r\n.label:has(.input:checked) {\r\n  width: 57px;\r\n  animation: installed 0.4s ease 3.5s forwards;\r\n}\r\n\r\n.label:has(.input:checked)::before {\r\n  animation: rotate 3s ease-in-out 0.4s forwards;\r\n}\r\n\r\n.label .input:checked + .circle {\r\n  animation:\r\n    pulse 1s forwards,\r\n    circleDelete 0.2s ease 3.5s forwards;\r\n  rotate: 180deg;\r\n}\r\n\r\n.label .input:checked + .circle::before {\r\n  animation: installing 3s ease-in-out forwards;\r\n}\r\n\r\n.label .input:checked + .circle .icon {\r\n  opacity: 0;\r\n  visibility: hidden;\r\n}\r\n\r\n.label .input:checked ~ .circle .square {\r\n  opacity: 1;\r\n  visibility: visible;\r\n}\r\n\r\n.label .input:checked ~ .title {\r\n  opacity: 0;\r\n  visibility: hidden;\r\n}\r\n\r\n.label .input:checked ~ .title:last-child {\r\n  animation: showInstalledMessage 0.4s ease 3.5s forwards;\r\n}\r\n\r\n@keyframes pulse {\r\n  0% {\r\n    scale: 0.95;\r\n    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.7);\r\n  }\r\n  70% {\r\n    scale: 1;\r\n    box-shadow: 0 0 0 16px rgba(255, 255, 255, 0);\r\n  }\r\n  100% {\r\n    scale: 0.95;\r\n    box-shadow: 0 0 0 0 rgba(255, 255, 255, 0);\r\n  }\r\n}\r\n\r\n@keyframes installing {\r\n  from {\r\n    height: 0;\r\n  }\r\n  to {\r\n    height: 100%;\r\n  }\r\n}\r\n\r\n@keyframes rotate {\r\n  0% {\r\n    transform: rotate(-90deg) translate(27px) rotate(0);\r\n    opacity: 1;\r\n    visibility: visible;\r\n  }\r\n  99% {\r\n    transform: rotate(270deg) translate(27px) rotate(270deg);\r\n    opacity: 1;\r\n    visibility: visible;\r\n  }\r\n  100% {\r\n    opacity: 0;\r\n    visibility: hidden;\r\n  }\r\n}\r\n\r\n@keyframes installed {\r\n  100% {\r\n    width: 150px;\r\n    border-color: rgb(35, 174, 35);\r\n  }\r\n}\r\n\r\n@keyframes circleDelete {\r\n  100% {\r\n    opacity: 0;\r\n    visibility: hidden;\r\n  }\r\n}\r\n\r\n@keyframes showInstalledMessage {\r\n  100% {\r\n    opacity: 1;\r\n    visibility: visible;\r\n    right: 56px;\r\n  }\r\n}\r\n'),
(4, '\r\n<label class=\"theme-switch\">\r\n  <input type=\"checkbox\" class=\"theme-switch__checkbox\">\r\n  <div class=\"theme-switch__container\">\r\n    <div class=\"theme-switch__clouds\"></div>\r\n    <div class=\"theme-switch__stars-container\">\r\n      <svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 144 55\" fill=\"none\">\r\n        <path fill-rule=\"evenodd\" clip-rule=\"evenodd\" d=\"M135.831 3.00688C135.055 3.85027 134.111 4.29946 133 4.35447C134.111 4.40947 135.055 4.85867 135.831 5.71123C136.607 6.55462 136.996 7.56303 136.996 8.72727C136.996 7.95722 137.172 7.25134 137.525 6.59129C137.886 5.93124 138.372 5.39954 138.98 5.00535C139.598 4.60199 140.268 4.39114 141 4.35447C139.88 4.2903 138.936 3.85027 138.16 3.00688C137.384 2.16348 136.996 1.16425 136.996 0C136.996 1.16425 136.607 2.16348 135.831 3.00688ZM31 23.3545C32.1114 23.2995 33.0551 22.8503 33.8313 22.0069C34.6075 21.1635 34.9956 20.1642 34.9956 19C34.9956 20.1642 35.3837 21.1635 36.1599 22.0069C36.9361 22.8503 37.8798 23.2903 39 23.3545C38.2679 23.3911 37.5976 23.602 36.9802 24.0053C36.3716 24.3995 35.8864 24.9312 35.5248 25.5913C35.172 26.2513 34.9956 26.9572 34.9956 27.7273C34.9956 26.563 34.6075 25.5546 33.8313 24.7112C33.0551 23.8587 32.1114 23.4095 31 23.3545ZM0 36.3545C1.11136 36.2995 2.05513 35.8503 2.83131 35.0069C3.6075 34.1635 3.99559 33.1642 3.99559 32C3.99559 33.1642 4.38368 34.1635 5.15987 35.0069C5.93605 35.8503 6.87982 36.2903 8 36.3545C7.26792 36.3911 6.59757 36.602 5.98015 37.0053C5.37155 37.3995 4.88644 37.9312 4.52481 38.5913C4.172 39.2513 3.99559 39.9572 3.99559 40.7273C3.99559 39.563 3.6075 38.5546 2.83131 37.7112C2.05513 36.8587 1.11136 36.4095 0 36.3545ZM56.8313 24.0069C56.0551 24.8503 55.1114 25.2995 54 25.3545C55.1114 25.4095 56.0551 25.8587 56.8313 26.7112C57.6075 27.5546 57.9956 28.563 57.9956 29.7273C57.9956 28.9572 58.172 28.2513 58.5248 27.5913C58.8864 26.9312 59.3716 26.3995 59.9802 26.0053C60.5976 25.602 61.2679 25.3911 62 25.3545C60.8798 25.2903 59.9361 2