y size */\n  --container-width: 5.625em;\n  --container-height: 2.5em;\n  --container-radius: 6.25em;\n  /* radius 0 - minecraft mode :) */\n  --container-light-bg: #3D7EAE;\n  --container-night-bg: #1D1F2C;\n  --circle-container-diameter: 3.375em;\n  --sun-moon-diameter: 2.125em;\n  --sun-bg: #ECCA2F;\n  --moon-bg: #C4C9D1;\n  --spot-color: #959DB1;\n  --circle-container-offset: calc((var(--circle-container-diameter) - var(--container-height)) / 2 * -1);\n  --stars-color: #fff;\n  --clouds-color: #F3FDFF;\n  --back-clouds-color: #AACADF;\n  --transition: .5s cubic-bezier(0, -0.02, 0.4, 1.25);\n  --circle-transition: .3s cubic-bezier(0, -0.02, 0.35, 1.17);\n}\n\n.theme-switch, .theme-switch *, .theme-switch *::before, .theme-switch *::after {\n  -webkit-box-sizing: border-box;\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n  font-size: var(--toggle-size);\n}\n\n.theme-switch__container {\n  width: var(--container-width);\n  height: var(--container-height);\n  background-color: var(--container-light-bg);\n  border-radius: var(--container-radius);\n  overflow: hidden;\n  cursor: pointer;\n  -webkit-box-shadow: 0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94);\n  box-shadow: 0em -0.062em 0.062em rgba(0, 0, 0, 0.25), 0em 0.062em 0.125em rgba(255, 255, 255, 0.94);\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n  position: relative;\n}\n\n.theme-switch__container::before {\n  content: \"\";\n  position: absolute;\n  z-index: 1;\n  inset: 0;\n  -webkit-box-shadow: 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset, 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset;\n  box-shadow: 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset, 0em 0.05em 0.187em rgba(0, 0, 0, 0.25) inset;\n  border-radius: var(--container-radius)\n}\n\n.theme-switch__checkbox {\n  display: none;\n}\n\n.theme-switch__circle-container {\n  width: var(--circle-container-diameter);\n  height: var(--circle-container-diameter);\n  background-color: rgba(255, 255, 255, 0.1);\n  position: absolute;\n  left: var(--circle-container-offset);\n  top: var(--circle-container-offset);\n  border-radius: var(--container-radius);\n  -webkit-box-shadow: inset 0 0 0 3.375em rgba(255, 255, 255, 0.1), inset 0 0 0 3.375em rgba(255, 255, 255, 0.1), 0 0 0 0.625em rgba(255, 255, 255, 0.1), 0 0 0 1.25em rgba(255, 255, 255, 0.1);\n  box-shadow: inset 0 0 0 3.375em rgba(255, 255, 255, 0.1), inset 0 0 0 3.375em rgba(255, 255, 255, 0.1), 0 0 0 0.625em rgba(255, 255, 255, 0.1), 0 0 0 1.25em rgba(255, 255, 255, 0.1);\n  display: -webkit-box;\n  display: -ms-flexbox;\n  display: flex;\n  -webkit-transition: var(--circle-transition);\n  -o-transition: var(--circle-transition);\n  transition: var(--circle-transition);\n  pointer-events: none;\n}\n\n.theme-switch__sun-moon-container {\n  pointer-events: auto;\n  position: relative;\n  z-index: 2;\n  width: var(--sun-moon-diameter);\n  height: var(--sun-moon-diameter);\n  margin: auto;\n  border-radius: var(--container-radius);\n  background-color: var(--sun-bg);\n  -webkit-box-shadow: 0.062em 0.062em 0.062em 0em rgba(254, 255, 239, 0.61) inset, 0em -0.062em 0.062em 0em #a1872a inset;\n  box-shadow: 0.062em 0.062em 0.062em 0em rgba(254, 255, 239, 0.61) inset, 0em -0.062em 0.062em 0em #a1872a inset;\n  -webkit-filter: drop-shadow(0.062em 0.125em 0.125em rgba(0, 0, 0, 0.25)) drop-shadow(0em 0.062em 0.125em rgba(0, 0, 0, 0.25));\n  filter: drop-shadow(0.062em 0.125em 0.125em rgba(0, 0, 0, 0.25)) drop-shadow(0em 0.062em 0.125em rgba(0, 0, 0, 0.25));\n  overflow: hidden;\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n}\n\n.theme-switch__moon {\n  -webkit-transform: translateX(100%);\n  -ms-transform: translateX(100%);\n  transform: translateX(100%);\n  width: 100%;\n  height: 100%;\n  background-color: var(--moon-bg);\n  border-radius: inherit;\n  -webkit-box-shadow: 0.062em 0.062em 0.062em 0em rgba(254, 255, 239, 0.61) inset, 0em -0.062em 0.062em 0em #969696 inset;\n  box-shadow: 0.062em 0.062em 0.062em 0em rgba(254, 255, 239, 0.61) inset, 0em -0.062em 0.062em 0em #969696 inset;\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n  position: relative;\n}\n\n.theme-switch__spot {\n  position: absolute;\n  top: 0.75em;\n  left: 0.312em;\n  width: 0.75em;\n  height: 0.75em;\n  border-radius: var(--container-radius);\n  background-color: var(--spot-color);\n  -webkit-box-shadow: 0em 0.0312em 0.062em rgba(0, 0, 0, 0.25) inset;\n  box-shadow: 0em 0.0312em 0.062em rgba(0, 0, 0, 0.25) inset;\n}\n\n.theme-switch__spot:nth-of-type(2) {\n  width: 0.375em;\n  height: 0.375em;\n  top: 0.937em;\n  left: 1.375em;\n}\n\n.theme-switch__spot:nth-last-of-type(3) {\n  width: 0.25em;\n  height: 0.25em;\n  top: 0.312em;\n  left: 0.812em;\n}\n\n.theme-switch__clouds {\n  width: 1.25em;\n  height: 1.25em;\n  background-color: var(--clouds-color);\n  border-radius: var(--container-radius);\n  position: absolute;\n  bottom: -0.625em;\n  left: 0.312em;\n  -webkit-box-shadow: 0.937em 0.312em var(--clouds-color), -0.312em -0.312em var(--back-clouds-color), 1.437em 0.375em var(--clouds-color), 0.5em -0.125em var(--back-clouds-color), 2.187em 0 var(--clouds-color), 1.25em -0.062em var(--back-clouds-color), 2.937em 0.312em var(--clouds-color), 2em -0.312em var(--back-clouds-color), 3.625em -0.062em var(--clouds-color), 2.625em 0em var(--back-clouds-color), 4.5em -0.312em var(--clouds-color), 3.375em -0.437em var(--back-clouds-color), 4.625em -1.75em 0 0.437em var(--clouds-color), 4em -0.625em var(--back-clouds-color), 4.125em -2.125em 0 0.437em var(--back-clouds-color);\n  box-shadow: 0.937em 0.312em var(--clouds-color), -0.312em -0.312em var(--back-clouds-color), 1.437em 0.375em var(--clouds-color), 0.5em -0.125em var(--back-clouds-color), 2.187em 0 var(--clouds-color), 1.25em -0.062em var(--back-clouds-color), 2.937em 0.312em var(--clouds-color), 2em -0.312em var(--back-clouds-color), 3.625em -0.062em var(--clouds-color), 2.625em 0em var(--back-clouds-color), 4.5em -0.312em var(--clouds-color), 3.375em -0.437em var(--back-clouds-color), 4.625em -1.75em 0 0.437em var(--clouds-color), 4em -0.625em var(--back-clouds-color), 4.125em -2.125em 0 0.437em var(--back-clouds-color);\n  -webkit-transition: 0.5s cubic-bezier(0, -0.02, 0.4, 1.25);\n  -o-transition: 0.5s cubic-bezier(0, -0.02, 0.4, 1.25);\n  transition: 0.5s cubic-bezier(0, -0.02, 0.4, 1.25);\n}\n\n.theme-switch__stars-container {\n  position: absolute;\n  color: var(--stars-color);\n  top: -100%;\n  left: 0.312em;\n  width: 2.75em;\n  height: auto;\n  -webkit-transition: var(--transition);\n  -o-transition: var(--transition);\n  transition: var(--transition);\n}\n\n/* actions */\n\n.theme-switch__checkbox:checked + .theme-switch__container {\n  background-color: var(--container-night-bg);\n}\n\n.theme-switch__checkbox:checked + .theme-switch__container .theme-switch__circle-container {\n  left: calc(100% - var(--circle-container-offset) - var(--circle-container-diameter));\n}\n\n.theme-switch__checkbox:checked + .theme-switch__container .theme-switch__circle-container:hover {\n  left: calc(100% - var(--circle-container-offset) - var(--circle-container-diameter) - 0.187em)\n}\n\n.theme-switch__circle-container:hover {\n  left: calc(var(--circle-container-offset) + 0.187em);\n}\n\n.theme-switch__checkbox:checked + .theme-switch__container .theme-switch__moon {\n  -webkit-transform: translate(0);\n  -ms-transform: translate(0);\n  transform: translate(0);\n}\n\n.theme-switch__checkbox:checked + .theme-switch__container .theme-switch__clouds {\n  bottom: -4.062em;\n}\n\n.theme-switch__checkbox:checked + .theme-switch__container .theme-switch__stars-container {\n  top: 50%;\n  -webkit-transform: translateY(-50%);\n  -ms-transform: translateY(-50%);\n  transform: translateY(-50%);\n}'),
(5, '\r\n<input type=\"checkbox\" id=\"lock\" />\r\n<label for=\"lock\" class=\"lock-label\">\r\n  <span class=\"lock-wrapper\">\r\n    <span class=\"shackle\"></span>\r\n    <svg\r\n      class=\"lock-body\"\r\n      width=\"\"\r\n      height=\"\"\r\n      viewBox=\"0 0 28 28\"\r\n      fill=\"none\"\r\n      xmlns=\"http://www.w3.org/2000/svg\"\r\n    >\r\n      <path\r\n        fill-rule=\"evenodd\"\r\n        clip-rule=\"evenodd\"\r\n        d=\"M0 5C0 2.23858 2.23858 0 5 0H23C25.7614 0 28 2.23858 28 5V23C28 25.7614 25.7614 28 23 28H5C2.23858 28 0 25.7614 0 23V5ZM16 13.2361C16.6137 12.6868 17 11.8885 17 11C17 9.34315 15.6569 8 14 8C12.3431 8 11 9.34315 11 11C11 11.8885 11.3863 12.6868 12 13.2361V18C12 19.1046 12.8954 20 14 20C15.1046 20 16 19.1046 16 18V13.2361Z\"\r\n        fill=\"white\"\r\n      ></path>\r\n    </svg>\r\n  </span>\r\n</label>\r\n', '#lock {\n  display: none;\n}\n.lock-label {\n  width: 45px;\n  height: 45px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background-color: rgb(80, 80, 80);\n  border-radius: 15px;\n  cursor: pointer;\n  transition: all 0.3s;\n}\n.lock-wrapper {\n  width: fit-content;\n  height: fit-content;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  transform: rotate(-10deg);\n}\n.shackle {\n  background-color: transparent;\n  height: 9px;\n  width: 14px;\n  border-top-right-radius: 10px;\n  border-top-left-radius: 10px;\n  border-top: 3px solid white;\n  border-left: 3px solid white;\n  border-right: 3px solid white;\n  transition: all 0.3s;\n}\n.lock-body {\n  width: 15px;\n}\n#lock:checked + .lock-label .lock-wrapper .shackle {\n  transform: rotateY(150deg) translateX(3px);\n  transform-origin: right;\n}\n#lock:checked + .lock-label {\n  background-color: rgb(167, 71, 245);\n}\n.lock-label:active {\n  transform: scale(0.9);\n}\n'),
(6, '\r\n<div class=\"love\">\r\n  <input id=\"switch\" type=\"checkbox\">\r\n  <label class=\"love-heart\" for=\"switch\">\r\n    <i class=\"left\"></i>\r\n    <i class=\"right\"></i>\r\n    <i class=\"bottom\"></i>\r\n    <div class=\"round\"></div>\r\n  </label>\r\n</div>', '.love-heart:before,#switch {\n display: none;\n}\n\n.love-heart, .love-heart::after {\n border-color: hsl(231deg 28% 86%);\n border: 1px solid;\n border-top-left-radius: 100px;\n border-top-right-radius: 100px;\n width: 10px;\n height: 8px;\n border-bottom: 0\n}\n\n.round {\n position: absolute;\n z-index: 1;\n width: 8px;\n height: 8px;\n background: hsl(0deg 0% 100%);\n box-shadow: rgb(0 0 0 / 24%) 0px 0px 4px 0px;\n border-radius: 100%;\n left: 0px;\n bottom: -1px;\n transition: all .5s ease;\n animation: check-animation2 .5s forwards;\n}\n\ninput:checked + label .round {\n transform: translate(0px, 0px);\n animation: check-animation .5s forwards;\n background-color: hsl(0deg 0% 100%);\n}\n\n@keyframes check-animation {\n 0% {\n  transform: translate(0px, 0px);\n }\n\n 50% {\n  transform: translate(0px, 7px);\n }\n\n 100% {\n  transform: translate(7px, 7px);\n }\n}\n\n@keyframes check-animation2 {\n 0% {\n  transform: translate(7px, 7px);\n }\n\n 50% {\n  transform: translate(0px, 7px);\n }\n\n 100% {\n  transform: translate(0px, 0px);\n }\n}\n\n.love-heart {\n box-sizing: border-box;\n position: relative;\n transform: rotate(-45deg) translate(-50%, -33px) scale(4);\n display: block;\n border-color: hsl(231deg 28% 86%);\n cursor: pointer;\n top: 0;\n}\n\ninput:checked + .love-heart, input:checked + .love-heart::after, input:checked + .love-heart .bottom {\n border-color: hsl(347deg 81% 61%);\n box-shadow: inset 6px -5px 0px 2px hsl(347deg 99% 72%);\n}\n\n.love-heart::after, .love-heart .bottom {\n content: \"\";\n display: block;\n box-sizing: border-box;\n position: absolute;\n border-color: hsl(231deg 28% 86%);\n}\n\n.love-heart::after {\n right: -9px;\n transform: rotate(90deg);\n top: 7px;\n}\n\n.love-heart .bottom {\n width: 11px;\n height: 11px;\n border-left: 1px solid;\n border-bottom: 1px solid;\n border-color: hsl(231deg 28% 86%);\n left: -1px;\n top: 5px;\n border-radius: 0px 0px 0px 5px;\n}\n'),
(7, '\r\n<div class=\"container\">  \r\n  <input class=\"label-check\" id=\"label-check\" type=\"checkbox\">\r\n    <label for=\"label-check\" class=\"hamburger-label\">\r\n      <div class=\"line1\"></div>\r\n      <div class=\"line2\"></div>\r\n      <div class=\"line3\"></div>\r\n    <label></label></label></div>', '\r\n.label-check {\r\n  display: none;\r\n}\r\n\r\n.hamburger-label {\r\n  width: 70px;\r\n  height: 58px;\r\n  display: block;\r\n  cursor: pointer;\r\n}\r\n\r\n.hamburger-label div {\r\n  width: 70px;\r\n  height: 6px;\r\n  background-color: #fff;\r\n  position: absolute;\r\n}\r\n\r\n.line1 {\r\n  transition: all .3s;\r\n}\r\n\r\n.line2 {\r\n  margin: 18px 0 0 0;\r\n  transition: 0.3s;\r\n}\r\n\r\n.line3 {\r\n  margin: 36px 0 0 0;\r\n  transition: 0.3s;\r\n}\r\n\r\n#label-check:checked + .hamburger-label .line1 {\r\n  transform: rotate(35deg) scaleX(.55) translate(39px, -4.5px);\r\n  border-radius: 50px 50px 50px 0;\r\n}\r\n\r\n#label-check:checked + .hamburger-label .line3 {\r\n  transform: rotate(-35deg) scaleX(.55) translate(39px, 4.5px);\r\n  border-radius: 0 50px 50px 50px;\r\n}\r\n\r\n#label-check:checked + .hamburger-label .line2 {\r\n  border-top-right-radius: 50px;\r\n  border-bottom-right-radius: 50px;\r\n  width: 45px;\r\n}'),
(8, '\r\n<div class=\"toggle-cont\">\r\n  <input class=\"toggle-input\" id=\"toggle\" name=\"toggle\" type=\"checkbox\" />\r\n  <label class=\"toggle-label\" for=\"toggle\">\r\n    <div class=\"cont-label-play\">\r\n      <span class=\"label-play\"></span>\r\n    </div>\r\n  </label>\r\n</div>\r\n', '.toggle-cont {\n  width: 100px;\n  height: 50px;\n  border-radius: 9999px;\n}\n\n.toggle-cont .toggle-input {\n  display: none;\n}\n\n.toggle-cont .toggle-label {\n  cursor: pointer;\n  position: relative;\n  display: inline-block;\n  padding: 6px;\n  width: 100%;\n  height: 100%;\n  background: #272727;\n  border-radius: 9999px;\n  box-sizing: content-box;\n  box-shadow: 0px 0px 16px -8px #fefefe;\n}\n\n.toggle-cont .toggle-label .cont-label-play {\n  position: relative;\n  width: 50px;\n  aspect-ratio: 1 / 1;\n  background: #5e5e5e;\n  border-radius: 9999px;\n  transition: all 0.5s cubic-bezier(1, 0, 0, 1);\n}\n\n.toggle-cont .toggle-input:checked + .toggle-label .cont-label-play {\n  background: #f43f5e;\n  transform: translateX(50px);\n}\n\n.toggle-cont .toggle-label .label-play {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  display: inline-block;\n  width: 24px;\n  aspect-ratio: 1 / 1;\n  background: #fefefe;\n  border-radius: 4px;\n  clip-path: polygon(25% 0, 75% 50%, 25% 100%, 25% 51%);\n  transition: all 0.5s cubic-bezier(1, 0, 0, 1);\n}\n\n.toggle-cont .toggle-input:checked + .toggle-label .label-play {\n  width: 20px;\n  clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);\n}\n'),
(9, '\r\n<div class=\"container\">\r\n  <div class=\"toggle\">\r\n    <span></span>\r\n    <span></span>\r\n    <span></span>\r\n  </div>\r\n</div>\r\n', '\r\n.toggle {\r\n  position: relative;\r\n  width: 70px;\r\n  height: 70px;\r\n  background-color: rgb(1, 103, 255);\r\n  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.08);\r\n  border-radius: 50%;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  cursor: pointer;\r\n  overflow: hidden;\r\n}\r\n\r\n.toggle span {\r\n  position: absolute;\r\n  height: 2px;\r\n  width: 40px;\r\n  background-color: rgb(255, 255, 255);\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: 0.5s;\r\n}\r\n\r\n.toggle span:nth-child(1) {\r\n  transform: translateY(-15px);\r\n  width: 25px;\r\n  left: 15px;\r\n}\r\n\r\n.toggle.toggle:hover span:nth-child(1) {\r\n  width: 40px;\r\n  transform: translateY(0px) rotate(45deg);\r\n  transition-delay: 0.125s;\r\n}\r\n\r\n.toggle span:nth-child(2) {\r\n  transform: translateY(15px);\r\n  width: 15px;\r\n  left: 15px;\r\n}\r\n\r\n.toggle.toggle:hover span:nth-child(2) {\r\n  width: 40px;\r\n  transform: translateY(0px) rotate(315deg);\r\n  transition-delay: 0.125s;\r\n}\r\n\r\n.toggle:hover span:nth-child(3) {\r\n  transform: translateX(60px);\r\n}\r\n'),
(10, '\r\n<input\r\n  value=\"favorite-button\"\r\n  name=\"favorite-checkbox\"\r\n  id=\"favorite\"\r\n  checked=\"checked\"\r\n  type=\"checkbox\"\r\n/>\r\n<label class=\"container\" for=\"favorite\">\r\n  <svg\r\n    class=\"feather feather-heart\"\r\n    stroke-linejoin=\"round\"\r\n    stroke-linecap=\"round\"\r\n    stroke-width=\"2\"\r\n    stroke=\"currentColor\"\r\n    fill=\"none\"\r\n    viewBox=\"0 0 24 24\"\r\n    height=\"24\"\r\n    width=\"24\"\r\n    xmlns=\"http://www.w3.org/2000/svg\"\r\n  >\r\n    <path\r\n      d=\"M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z\"\r\n    ></path>\r\n  </svg>\r\n  <div class=\"action\">\r\n    <span class=\"option-1\">Add to Favorites</span>\r\n    <span class=\"option-2\">Added to Favorites</span>\r\n  </div>\r\n</label>\r\n', '.container {\n  background-color: rgb(36, 36, 36);\n  display: flex;\n  align-items: center;\n  gap: 14px;\n  padding: 10px 15px 10px 10px;\n  cursor: pointer;\n  user-select: none;\n  border-radius: 10px;\n  box-shadow: rgba(46, 46, 46, 0.2) 0px 8px 24px;\n  color: rgb(255, 255, 255);\n}\n\n#favorite {\n  display: none;\n}\n\n#favorite:checked + .container svg {\n  fill: hsl(0deg 100% 50%);\n  stroke: hsl(0deg 100% 50%);\n  animation: heartButton 1s;\n}\n\n@keyframes heartButton {\n  0% {\n    transform: scale(1);\n  }\n\n  25% {\n    transform: scale(1.3);\n  }\n\n  50% {\n    transform: scale(1);\n  }\n\n  75% {\n    transform: scale(1.3);\n  }\n\n  100% {\n    transform: scale(1);\n  }\n}\n\n#favorite + .container .action {\n  position: relative;\n  overflow: hidden;\n  display: grid;\n}\n\n#favorite + .container .action span {\n  grid-column-start: 1;\n  grid-column-end: 1;\n  grid-row-start: 1;\n  grid-row-end: 1;\n  transition: all 0.5s;\n}\n\n#favorite + .container .action span.option-1 {\n  transform: translate(0px, 0%);\n  opacity: 1;\n}\n\n#favorite:checked + .container .action span.option-1 {\n  transform: translate(0px, -100%);\n  opacity: 0;\n}\n\n#favorite + .container .action span.option-2 {\n  transform: translate(0px, 100%);\n  opacity: 0;\n}\n\n#favorite:checked + .container .action span.option-2 {\n  transform: translate(0px, 0%);\n  opacity: 1;\n}\n'),
(11, '\r\n<label for=\"filter\" class=\"switch\" aria-label=\"Toggle Filter\">\r\n  <input type=\"checkbox\" id=\"filter\" />\r\n  <span>Latest</span>\r\n  <span>Popular</span>\r\n</label>\r\n', '\r\n.switch {\r\n  --_switch-bg-clr: #70a9c5;\r\n  --_switch-padding: 4px; /* padding around button*/\r\n  --_slider-bg-clr: rgba(12, 74, 110, 0.65); /* slider color unchecked */\r\n  --_slider-bg-clr-on: rgba(12, 74, 110, 1); /* slider color checked */\r\n  --_slider-txt-clr: #ffffff;\r\n  --_label-padding: 1rem 2rem;\r\n  --_switch-easing: cubic-bezier(\r\n    0.47,\r\n    1.64,\r\n    0.41,\r\n    0.8\r\n  ); /* easing on toggle switch */\r\n  color: white;\r\n  width: fit-content;\r\n  display: flex;\r\n  justify-content: center;\r\n  position: relative;\r\n  border-radius: 9999px;\r\n  cursor: pointer;\r\n  display: grid;\r\n  grid-template-columns: repeat(2, minmax(0, 1fr));\r\n  position: relative;\r\n  isolation: isolate;\r\n}\r\n\r\n.switch input[type=\"checkbox\"] {\r\n  position: absolute;\r\n  width: 1px;\r\n  height: 1px;\r\n  padding: 0;\r\n  margin: -1px;\r\n  overflow: hidden;\r\n  clip: rect(0, 0, 0, 0);\r\n  white-space: nowrap;\r\n  border-width: 0;\r\n}\r\n.switch > span {\r\n  display: grid;\r\n  place-content: center;\r\n  transition: opacity 300ms ease-in-out 150ms;\r\n  padding: var(--_label-padding);\r\n}\r\n.switch::before,\r\n.switch::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  border-radius: inherit;\r\n  transition: inset 150ms ease-in-out;\r\n}\r\n/* switch slider */\r\n.switch::before {\r\n  background-color: var(--_slider-bg-clr);\r\n  inset: var(--_switch-padding) 50% var(--_switch-padding)\r\n    var(--_switch-padding);\r\n  transition:\r\n    inset 500ms var(--_switch-easing),\r\n    background-color 500ms ease-in-out;\r\n  z-index: -1;\r\n  box-shadow:\r\n    inset 0 1px 1px rgba(0, 0, 0, 0.3),\r\n    0 1px rgba(255, 255, 255, 0.3);\r\n}\r\n/* switch bg color */\r\n.switch::after {\r\n  background-color: var(--_switch-bg-clr);\r\n  inset: 0;\r\n  z-index: -2;\r\n}\r\n/* switch hover & focus */\r\n.switch:focus-within::after {\r\n  inset: -0.25rem;\r\n}\r\n.switch:has(input:checked):hover > span:first-of-type,\r\n.switch:has(input:not(:checked)):hover > span:last-of-type {\r\n  opacity: 1;\r\n  transition-delay: 0ms;\r\n  transition-duration: 100ms;\r\n}\r\n/* switch hover */\r\n.switch:has(input:checked):hover::before {\r\n  inset: var(--_switch-padding) var(--_switch-padding) var(--_switch-padding)\r\n    45%;\r\n}\r\n.switch:has(input:not(:checked)):hover::before {\r\n  inset: var(--_switch-padding) 45% var(--_switch-padding)\r\n    var(--_switch-padding);\r\n}\r\n/* checked - move slider to right */\r\n.switch:has(input:checked)::before {\r\n  background-color: var(--_slider-bg-clr-on);\r\n  inset: var(--_switch-padding) var(--_switch-padding) var(--_switch-padding)\r\n    50%;\r\n}\r\n/* checked - set opacity */\r\n.switch > span:last-of-type,\r\n.switch > input:checked + span:first-of-type {\r\n  opacity: 0.75;\r\n}\r\n.switch > input:checked ~ span:last-of-type {\r\n  opacity: 1;\r\n}\r\n'),
(12, '\r\n<label class=\"switch\">\r\n  <input class=\"chk_85\" type=\"checkbox\">\r\n  <span class=\"slider\">\r\n    <svg viewBox=\"0 0 100 100\" version=\"1.1\" xmlns=\"http://www.w3.org/2000/svg\" class=\"torch\">\r\n    <path d=\"M 63.85,54.65 Q 62.77,54.13 61.88,53.31 Q 54.13,46.12 46.31,37.69 Q 43.88,35.06 44.29,31.53 Q 44.51,29.56 46.54,25.87 Q 56.15,8.39 59.06,3.56 Q 60.59,1.03 63.83,2.41 Q 67.73,4.07 71.11,6.55 Q 72.85,7.82 77.51,11.86 Q 89.11,21.92 96.94,34.06 Q 100.09,38.95 95.24,41.73 Q 83.77,48.31 72.16,54.64 Q 68.24,56.77 63.85,54.65 Z\" fill=\"#ffffff\"></path>\r\n    <path d=\"M 14.03,66.29 Q 27.40,51.66 40.57,37.33 A 0.54,0.54 52.1 0 1 41.44,37.44 Q 43.25,40.72 45.58,43.04 Q 47.66,45.11 47.71,45.17 Q 54.67,52.58 62.60,58.93 A 0.44,0.43 43.0 0 1 62.63,59.59 Q 42.87,77.87 22.77,95.78 Q 20.75,97.58 19.20,97.93 Q 16.72,98.49 14.81,96.94 Q 6.88,90.47 2.81,84.94 Q 1.47,83.11 2.03,80.84 Q 2.37,79.43 4.04,77.51 Q 8.97,71.84 14.03,66.29 ZM 42.9269,57.1766 A 3.76 3.76 0.0 0 0 37.6102,57.0930 L 33.1721,61.3938 A 3.76 3.76 0.0 0 0 33.0886,66.7106 L 33.3531,66.9834 A 3.76 3.76 0.0 0 0 38.6698,67.0670 L 43.1079,62.7662 A 3.76 3.76 0.0 0 0 43.1914,57.4494 L 42.9269,57.1766 Z\" fill=\"#ffffff\"></path>\r\n    </svg>\r\n    <svg class=\"b\" width=\"100%\" height=\"50%\" version=\"1.1\" xmlns=\"http://www.w3.org/2000/svg\">\r\n    <path d=\"M29 20L31 22\" class=\"bling_85\"></path>\r\n    <path d=\"M31.5 15H34.5\" class=\"bling_85\"></path>\r\n    <path d=\"M29 10L31 8\" class=\"bling_85\"></path>\r\n    </svg>\r\n  </span>\r\n</label>', '.switch {\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 3.8em;\n  height: 3.8em;\n}\n\n.torch {\n  margin-top: 0.9em;\n  margin-left: 0.95em;\n  width: 30px;\n  height: 30px;\n  transform: rotate(-45deg);\n}\n\n.slider .b {\n  position: relative;\n  top: -3.3em;\n  transform: rotate(270deg);\n}\n\n.slider .bling_85 {\n  stroke: #fff;\n  stroke-width: 2.5;\n  stroke-linecap: round;\n  stroke-dasharray: 3;\n  stroke-dashoffset: 15;\n  transition: all 0.3s ease;\n}\n\n/* Hide default HTML checkbox */\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n/* The slider */\n.slider {\n  position: absolute;\n  cursor: pointer;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  transition: .4s;\n  border-radius: 50%;\n  background-color: rgba(116, 115, 115, 0.2);\n  backdrop-filter: blur(5px);\n  -webkit-backdrop-filter: blur(5px);\n  border: 1px solid rgba(255, 255, 255, 0.3);\n}\n\n.chk_85:checked + .slider {\n  animation: tap 0.3s linear forwards;\n}\n\n.chk_85:checked + .slider .bling_85 {\n  animation: bling_8561328 0.3s linear forwards;\n  animation-delay: 0.2s;\n}\n\n.chk_85:checked + .slider {\n  background-color: #FFA133;\n}\n\n.chk_85:focus + .slider {\n  box-shadow: 0 0 1px #FFA133;\n}\n\n@keyframes bling_8561328 {\n  50% {\n    stroke-dasharray: 3;\n    stroke-dashoffset: 12;\n  }\n\n  100% {\n    stroke-dasharray: 3;\n    stroke-dashoffset: 9;\n  }\n}\n\n@keyframes tap {\n  50% {\n    scale: 0.9;\n  }\n\n  100% {\n    scale: 1;\n  }\n}'),
(13, '\r\n<label class=\"switch\">\r\n  <input type=\"checkbox\" />\r\n  <span class=\"slider\"></span>\r\n  <div class=\"battery\"></div>\r\n</label>\r\n', '\r\n.switch {\r\n  font-size: 17px;\r\n  position: relative;\r\n  display: inline-block;\r\n  width: 6em;\r\n  height: 6em;\r\n}\r\n\r\n.switch input {\r\n  opacity: 0;\r\n  width: 0;\r\n  height: 0;\r\n}\r\n\r\n.slider {\r\n  inset: 0;\r\n  background-color: #333;\r\n  border-radius: 30px;\r\n}\r\n\r\n.slider:before {\r\n  height: 0.8em;\r\n  width: 1.1em;\r\n  inset: 44px 28px;\r\n  background: #eee;\r\n  border-radius: 4px;\r\n}\r\n\r\n.battery {\r\n  height: 1.4em;\r\n  width: 2.9em;\r\n  inset: 39px 23px;\r\n  border: 2px solid #eee;\r\n  border-radius: 8px;\r\n}\r\n\r\n.battery:before {\r\n  height: 0.4em;\r\n  width: 0.1em;\r\n  inset: 0.4em 50px;\r\n  border: none;\r\n  border-radius: 0% 100% 100% 0% / 0% 50% 50% 0%;\r\n  background: #eee;\r\n}\r\n\r\n.switch input:checked + .slider {\r\n  background-color: #eee;\r\n  box-shadow: 0 0 1px #eee;\r\n}\r\n\r\n.switch input:checked ~ .battery {\r\n  border: 2px solid #111;\r\n}\r\n\r\n.switch input:checked ~ .battery:before {\r\n  background: #111;\r\n}\r\n\r\n.switch input:checked + .slider:before {\r\n  background: rgb(255, 176, 85);\r\n  animation: lowbattery 1.6s linear;\r\n}\r\n\r\n@keyframes lowbattery {\r\n  0% {\r\n    width: 1.1em;\r\n  }\r\n  40% {\r\n    width: 2.3em;\r\n  }\r\n  70% {\r\n    width: 2.3em;\r\n  }\r\n  100% {\r\n    width: 1.1em;\r\n  }\r\n}\r\n\r\n.slider,\r\n.battery,\r\n.slider:before,\r\n.battery:before {\r\n  position: absolute;\r\n  content: \"\";\r\n  transition: 0.5s;\r\n}\r\n'),
(14, '\r\n<label class=\"switch\">\r\n    <input type=\"checkbox\">\r\n    <span class=\"slider\">\r\n        <span class=\"circle\"></span>\r\n    </span>\r\n</label>', '\r\n\r\n.switch {\r\n  font-size: 17px;\r\n  position: relative;\r\n  display: inline-block;\r\n  width: 3.5em;\r\n  height: .5em;\r\n}\r\n\r\n.switch input {\r\n  opacity: 0;\r\n  width: 0;\r\n  height: 0;\r\n}\r\n\r\n.slider {\r\n  position: absolute;\r\n  cursor: pointer;\r\n  top: 0;\r\n  left: 0;\r\n  right: 0;\r\n  bottom: 0;\r\n  background-color: #5B5B5B;\r\n  transition: .4s;\r\n  border-radius: 30px;\r\n  display: flex;\r\n  align-items: center;\r\n}\r\n\r\n.slider .circle {\r\n  background-color: #212121;\r\n  height: 3em;\r\n  width: 3em;\r\n  border-radius: 50%;\r\n  position: absolute;\r\n  left: 0;\r\n  transform: translateX(-50%);\r\n  transition: .4s;\r\n}\r\n\r\n.slider .circle::before {\r\n  position: absolute;\r\n  content: \"\";\r\n  height: 2.3em;\r\n  width: 2.3em;\r\n  border-radius: 50%;\r\n  left: 50%;\r\n  top: 50%;\r\n  transform: translate(-50%, -50%);\r\n  background-color: rgb(182, 182, 182);\r\n  transition: .4s;\r\n}\r\n\r\n.slider .circle::after {\r\n  content: \';\r\n  background-color: #212121;\r\n  height: 1.7em;\r\n  width: 1.7em;\r\n  border-radius: 50%;\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  transform: translate(-50%, -50%);\r\n  transition: .4s;\r\n}\r\n\r\ninput:checked + .slider .circle {\r\n  transform: translateX(2em);\r\n  transition: .4s;\r\n}\r\n\r\ninput:checked + .slider .circle::before {\r\n  background-color: #e1e1e1;\r\n  transition: .4s;\r\n}\r\n\r\ninput:checked + .slider .circle::after {\r\n  width: 0;\r\n  height: 0;\r\n  transition: .4s;\r\n}'),
(15, '\r\n    <input id=\"checkbox\" type=\"checkbox\">\r\n    <label class=\"switch\" for=\"checkbox\">\r\n        <svg viewBox=\"0 0 448 512\" class=\"svg\"><path d=\"M320 48a48 48 0 1 0 -96 0 48 48 0 1 0 96 0zM125.7 175.5c9.9-9.9 23.4-15.5 37.5-15.5c1.9 0 3.8 .1 5.6 .3L137.6 254c-9.3 28 1.7 58.8 26.8 74.5l86.2 53.9-25.4 88.8c-4.9 17 5 34.7 22 39.6s34.7-5 39.6-22l28.7-100.4c5.9-20.6-2.6-42.6-20.7-53.9L238 299l30.9-82.4 5.1 12.3C289 264.7 323.9 288 362.7 288H384c17.7 0 32-14.3 32-32s-14.3-32-32-32H362.7c-12.9 0-24.6-7.8-29.5-19.7l-6.3-15c-14.6-35.1-44.1-61.9-80.5-73.1l-48.7-15c-11.1-3.4-22.7-5.2-34.4-5.2c-31 0-60.8 12.3-82.7 34.3L57.4 153.4c-12.5 12.5-12.5 32.8 0 45.3s32.8 12.5 45.3 0l23.1-23.1zM91.2 352H32c-17.7 0-32 14.3-32 32s14.3 32 32 32h69.6c19 0 36.2-11.2 43.9-28.5L157 361.6l-9.5-6c-17.5-10.9-30.5-26.8-37.9-44.9L91.2 352z\"></path></svg>Start\r\n    </label>\r\n', '\r\n#checkbox {\r\n  display: none;\r\n}\r\n\r\n.switch {\r\n  position: relative;\r\n  width: 90px;\r\n  height: 90px;\r\n  background-color: rgb(99, 99, 99);\r\n  border-radius: 50%;\r\n  z-index: 1;\r\n  cursor: pointer;\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  justify-content: center;\r\n  gap: 5px;\r\n  font-size: 0.9em;\r\n  font-weight: 700;\r\n  color: rgb(37, 37, 37);\r\n  border: 2px solid rgb(126, 126, 126);\r\n  box-shadow: 0px 0px 3px rgb(2, 2, 2) inset;\r\n}\r\n\r\n.svg {\r\n  position: relative;\r\n  width: 30%;\r\n  height: 30%;\r\n  border-radius: 50%;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n}\r\n\r\n.svg path {\r\n  fill: rgb(37, 37, 37);\r\n}\r\n\r\n#checkbox:checked + .switch .svg {\r\n  filter: drop-shadow(0px 0px 3px rgb(222, 151, 255));\r\n}\r\n\r\n#checkbox:checked + .switch .svg path {\r\n  fill: rgb(255, 255, 255);\r\n}\r\n\r\n#checkbox:checked + .switch {\r\n  box-shadow: 0px 0px 1px rgb(222, 151, 255) inset,\r\n      0px 0px 2px rgb(222, 151, 255) inset,\r\n      0px 0px 10px rgb(222, 151, 255) inset,\r\n      0px 0px 40px rgb(222, 151, 255),\r\n      0px 0px 100px rgb(222, 151, 255),\r\n      0px 0px 5px rgb(222, 151, 255);\r\n  border: 2px solid rgb(255, 255, 255);\r\n  background-color: rgb(152, 107, 172);\r\n  color: rgb(255, 255, 255);\r\n}\r\n  \r\n'),
(16, '<div class=\"btn-container\">\r\n	\r\n			<label class=\"switch btn-color-mode-switch\">\r\n		        <input value=\"1\" id=\"color_mode\" name=\"color_mode\" type=\"checkbox\">\r\n		        <label class=\"btn-color-mode-switch-inner\" data-off=\"AM\" data-on=\"PM\" for=\"color_mode\"></label>\r\n		    </label>\r\n        \r\n	</div>', '\r\n.btn-container {\r\n  display: table-cell;\r\n  vertical-align: middle;\r\n  text-align: center;\r\n}\r\n\r\n.btn-color-mode-switch {\r\n  display: inline-block;\r\n  margin: 0px;\r\n  position: relative;\r\n}\r\n\r\n.btn-color-mode-switch > label.btn-color-mode-switch-inner {\r\n  margin: 0px;\r\n  width: 140px;\r\n  height: 40px;\r\n  background-color: #fcce8a;\r\n  border-radius: 26px;\r\n  overflow: hidden;\r\n  position: relative;\r\n  transition: all 0.3s ease;\r\n    /*box-shadow: 0px 0px 8px 0px rgba(17, 17, 17, 0.34) inset;*/\r\n  display: block;\r\n}\r\n\r\n.btn-color-mode-switch > label.btn-color-mode-switch-inner:before {\r\n  content: attr(data-on);\r\n  position: absolute;\r\n  font-size: 20px;\r\n  font-weight: 600;\r\n  top: 7px;\r\n  right: 20px;\r\n  color: #222;\r\n}\r\n\r\n.btn-color-mode-switch > label.btn-color-mode-switch-inner:after {\r\n  content: attr(data-off);\r\n  width: 70px;\r\n  height: 25px;\r\n  background: #fff;\r\n  border-radius: 26px;\r\n  position: absolute;\r\n  font-size: 20px;\r\n  display: flex;\r\n  justify-content: center;\r\n  left: 2px;\r\n  top: 2px;\r\n  text-align: center;\r\n  transition: all 0.3s ease;\r\n  box-shadow: 0px 0px 6px -2px #111;\r\n  padding: 5px 0px;\r\n  color: #222;\r\n  font-weight: 600;\r\n}\r\n\r\n.btn-color-mode-switch input[type=\"checkbox\"] {\r\n  cursor: pointer;\r\n  width: 50px;\r\n  height: 25px;\r\n  opacity: 0;\r\n  position: absolute;\r\n  top: 0;\r\n  z-index: 1;\r\n  margin: 0px;\r\n}\r\n\r\n.btn-color-mode-switch input[type=\"checkbox\"]:checked + label.btn-color-mode-switch-inner {\r\n  background-color: #fcce8a;\r\n}\r\n\r\n.btn-color-mode-switch input[type=\"checkbox\"]:checked + label.btn-color-mode-switch-inner:after {\r\n  content: attr(data-on);\r\n  left: 68px;\r\n}\r\n\r\n.btn-color-mode-switch input[type=\"checkbox\"]:checked + label.btn-color-mode-switch-inner:before {\r\n  content: attr(data-off);\r\n  right: auto;\r\n  left: 20px;\r\n}\r\n\r\n'),
(17, '\r\n<input id=\"checkboxInput\" type=\"checkbox\" />\r\n<label class=\"toggleSwitch\" for=\"checkboxInput\">\r\n  <div class=\"speaker\">\r\n    <svg viewBox=\"0 0 75 75\" version=\"1.0\" xmlns=\"http://www.w3.org/2000/svg\">\r\n      <path\r\n        style=\"stroke:#fff;stroke-width:5;stroke-linejoin:round;fill:#fff;\"\r\n        d=\"M39.389,13.769 L22.235,28.606 L6,28.606 L6,47.699 L21.989,47.699 L39.389,62.75 L39.389,13.769z\"\r\n      ></path>\r\n      <path\r\n        style=\"fill:none;stroke:#fff;stroke-width:5;stroke-linecap:round\"\r\n        d=\"M48,27.6a19.5,19.5 0 0 1 0,21.4M55.1,20.5a30,30 0 0 1 0,35.6M61.6,14a38.8,38.8 0 0 1 0,48.6\"\r\n      ></path>\r\n    </svg>\r\n  </div>\r\n\r\n  <div class=\"mute-speaker\">\r\n    <svg stroke-width=\"5\" stroke=\"#fff\" viewBox=\"0 0 75 75\" version=\"1.0\">\r\n      <path\r\n        stroke-linejoin=\"round\"\r\n        fill=\"#fff\"\r\n        d=\"m39,14-17,15H6V48H22l17,15z\"\r\n      ></path>\r\n      <path\r\n        stroke-linecap=\"round\"\r\n        fill=\"#fff\"\r\n        d=\"m49,26 20,24m0-24-20,24\"\r\n      ></path>\r\n    </svg>\r\n  </div>\r\n</label>\r\n', '\r\n.toggleSwitch {\r\n  width: 50px;\r\n  height: 50px;\r\n  position: relative;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  background-color: rgb(39, 39, 39);\r\n  border-radius: 50%;\r\n  cursor: pointer;\r\n  transition-duration: 0.3s;\r\n  box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.13);\r\n  overflow: hidden;\r\n}\r\n\r\n#checkboxInput {\r\n  display: none;\r\n}\r\n\r\n.bell {\r\n  width: 18px;\r\n}\r\n\r\n.bell path {\r\n  fill: white;\r\n}\r\n\r\n.speaker {\r\n  width: 100%;\r\n  height: 100%;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  z-index: 2;\r\n  transition-duration: 0.3s;\r\n}\r\n\r\n.speaker svg {\r\n  width: 18px;\r\n}\r\n\r\n.mute-speaker {\r\n  position: absolute;\r\n  width: 100%;\r\n  height: 100%;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  opacity: 0;\r\n  z-index: 3;\r\n  transition-duration: 0.3s;\r\n}\r\n\r\n.mute-speaker svg {\r\n  width: 18px;\r\n}\r\n\r\n#checkboxInput:checked + .toggleSwitch .speaker {\r\n  opacity: 0;\r\n  transition-duration: 0.3s;\r\n}\r\n\r\n#checkboxInput:checked + .toggleSwitch .mute-speaker {\r\n  opacity: 1;\r\n  transition-duration: 0.3s;\r\n  background-color: red;\r\n}\r\n\r\n#checkboxInput:active + .toggleSwitch {\r\n  transform: scale(0.7);\r\n}\r\n\r\n#checkboxInput:hover + .toggleSwitch {\r\n  background-color: rgb(61, 61, 61);\r\n}\r\n');
INSERT INTO `togleswitches` (`ID`, `HTML`, `CSS`) VALUES
(18, '\r\n<div>\r\n  <input id=\"checkbox-input\" type=\"checkbox\" />\r\n  <label class=\"switch\" for=\"checkbox-input\">\r\n    <svg\r\n      xml:space=\"preserve\"\r\n      style=\"enable-background:new 0 0 128 128\"\r\n      viewBox=\"0 0 128 128\"\r\n      height=\"3em\"\r\n      xmlns=\"http://www.w3.org/2000/svg\"\r\n    >\r\n      <path\r\n        d=\"M77.547 120.684h-5.765l-1.698 3.012a7.477 7.477 0 0 1-6.513 3.804h-.003a7.479 7.479 0 0 1-6.513-3.804l-1.698-3.012h-5.765v-4.06h27.956v4.06z\"\r\n        style=\"fill:#51514c\"\r\n      ></path>\r\n      <path\r\n        d=\"M77.547 113.65H49.591v-4.279h27.956v4.279zm0-11.711H49.591v4.279h27.956v-4.279zm38.587-32.576-12.209-3.271.92-3.434 12.209 3.271-.92 3.434zm-104.268 0-.92-3.434 12.209-3.271.92 3.434-12.209 3.271zm92.979-24.913-.92-3.434 12.209-3.272.92 3.434-12.209 3.272zm-81.69 0-12.209-3.272.92-3.434 12.209 3.272-.92 3.434zM94.82 25.247l-2.514-2.514 8.938-8.938 2.514 2.514-8.938 8.938zm-61.64 0-8.937-8.938 2.514-2.514 8.937 8.938-2.514 2.514zm43.358-11.618-3.434-.92L76.376.5l3.434.92-3.272 12.209zm-25.076 0L48.191 1.42 51.625.5l3.272 12.209-3.435.92z\"\r\n        style=\"fill:#a7a79b\"\r\n      ></path>\r\n      <path\r\n        d=\"M59.802 64.141h7.535v34.934h-7.535V64.141zm3.767-44.754c-18.485-.53-33.631 14.817-33.631 33.824 0 9.781 4.016 18.581 10.431 24.753 5.637 5.423 9.222 13.147 9.222 21.111h7.84V64.141H51.75c-4.44 0-8.051-3.612-8.051-8.051s3.612-8.051 8.051-8.051 8.052 3.612 8.052 8.051v5.681h7.535V56.09c0-4.44 3.612-8.051 8.052-8.051 4.44 0 8.051 3.612 8.051 8.051s-3.612 8.051-8.051 8.051h-5.682v34.934h7.84c0-7.964 3.584-15.688 9.222-21.111C93.184 71.792 97.2 62.992 97.2 53.211c0-19.008-15.146-34.355-33.631-33.824zM51.75 50.408a5.687 5.687 0 0 0-5.681 5.681 5.687 5.687 0 0 0 5.681 5.681h5.682v-5.681a5.688 5.688 0 0 0-5.682-5.681zM75.389 61.77h-5.682v-5.681a5.688 5.688 0 0 1 5.682-5.681 5.687 5.687 0 0 1 5.681 5.681 5.687 5.687 0 0 1-5.681 5.681z\"\r\n        style=\"fill:#ffffff\"\r\n      ></path>\r\n    </svg>\r\n  </label>\r\n</div>\r\n', '#checkbox-input {\n  display: none;\n}\n\n.switch {\n  width: fit-content;\n  padding: 10px;\n  background-color: rgb(46, 46, 46);\n  border-radius: 50px;\n  z-index: 1;\n  cursor: pointer;\n  display: flex;\n  transition: all 0.7s;\n}\n\n#checkbox-input:checked + .switch {\n  background-color: rgb(161, 91, 0);\n  box-shadow: 0px 0px 100px rgb(255, 196, 0);\n}\n'),
(19, '\r\n\r\n    <div class=\"switch\">\r\n        <label for=\"toggle\">\r\n            <div class=\"background\"></div>\r\n            <input checked=\"\" type=\"checkbox\" class=\"toggle-switch\" id=\"toggle\">\r\n            <div class=\"cookie\">\r\n                <span class=\"cookie-part-1\"></span>\r\n                <span class=\"cookie-part-2\"></span>\r\n                <span class=\"cookie-part-3\"></span>\r\n                <span class=\"cookie-part-4\"></span>\r\n                <span class=\"chocolate-chips-1a\"></span>\r\n                <span class=\"chocolate-chips-1b\"></span>\r\n                <span class=\"chocolate-chips-1c\"></span>\r\n                <span class=\"chocolate-chips-1d\"></span>\r\n                <span class=\"chocolate-chips-2a\"></span>\r\n                <span class=\"chocolate-chips-2b\"></span>\r\n                <span class=\"chocolate-chips-2c\"></span>\r\n                <span class=\"chocolate-chips-2d\"></span>\r\n                <span class=\"chocolate-chips-2e\"></span>\r\n                <span class=\"chocolate-chips-3a\"></span>\r\n                <span class=\"chocolate-chips-3b\"></span>\r\n                <span class=\"chocolate-chips-3c\"></span>\r\n                <span class=\"chocolate-chips-4a\"></span>\r\n                <span class=\"chocolate-chips-4b\"></span>\r\n                <span class=\"chocolate-chips-4c\"></span>\r\n            </div>\r\n        </label>\r\n    </div>', '\r\n.container {\r\n  height: 100%;\r\n  background: #f4f4f4;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  flex-direction: column;\r\n}\r\n\r\n.title {\r\n  height: 25%;\r\n  font-family: Cookie;\r\n  font-size: 48pt;\r\n  text-align: center;\r\n}\r\n\r\n.switch {\r\n  --cookie-size: 3em;\r\n  --outer-border: 0.5em;\r\n  --inner-border: 0.5em;\r\n  --border-color: #d8a04d;\r\n  --height: calc(var(--cookie-size) + (2 * (var(--outer-border) + var(--inner-border))));\r\n  --width: calc(var(--height) * 2);\r\n  position: relative;\r\n  width: var(--width);\r\n  height: var(--height);\r\n}\r\n\r\n.switch input {\r\n  display: none;\r\n}\r\n\r\n.switch label {\r\n  cursor: pointer;\r\n}\r\n\r\n.switch input:checked ~ .cookie {\r\n  transform: translateX(calc(var(--width) / 2)) rotate(360deg);\r\n  color: #d8a04d;\r\n  background-color: currentColor;\r\n}\r\n\r\n.switch input:checked ~ .cookie span[class^=\"cookie-part-\"],\r\n.switch input:checked ~ .cookie span[class^=\"chocolate-chips-\"] {\r\n  transform: translate(0px, 0px);\r\n}\r\n\r\n.background {\r\n  height: 100%;\r\n  border-radius: calc(var(--width) / 4);\r\n  border: var(--outer-border) solid var(--border-color);\r\n  background: linear-gradient(to right, #484848 0%,#202020 100%);\r\n}\r\n\r\n.cookie {\r\n  --chip-size: calc(var(--cookie-size) / 8);\r\n  --split-offset: calc(var(--cookie-size) / 24);\r\n  position: absolute;\r\n  top: calc(var(--outer-border) + var(--inner-border));\r\n  left: calc(var(--outer-border) + var(--inner-border));\r\n  ;\r\n    width: var(--cookie-size);\r\n  height: var(--cookie-size);\r\n  border-radius: 50%;\r\n  transition: transform 1s linear;\r\n}\r\n\r\n.cookie span[class^=\"cookie-part-\"] {\r\n  position: absolute;\r\n  width: 100%;\r\n  height: 100%;\r\n  border-radius: 50%;\r\n  color: #d8a04d;\r\n  background-color: currentColor;\r\n}\r\n\r\n.cookie-part-1 {\r\n  clip-path: polygon(0% 0%, 55% 0%, 52% 8%, 55% 10%, 55% 16%, 52% 19%, 52% 24%, 47% 26%, 45% 30%, 50% 33%, 47% 37%, 47% 42%, 51% 47%, 47% 49%, 40% 50%, 34% 50%, 30% 53%, 25% 53%, 20% 56%, 16% 56%, 14% 61%, 0% 60%);\r\n  transform: translate(calc(var(--split-offset) * -1), calc(var(--split-offset) * -1));\r\n}\r\n\r\n.cookie-part-2 {\r\n  clip-path: polygon(55% 0%, 100% 0%, 100% 72%, 88% 68%, 84% 61%, 78% 60%, 77% 56%, 75% 53%, 71% 55%, 66% 50%, 63% 47%, 58% 49%, 56% 44%, 51% 47%, 47% 42%, 47% 37%, 50% 33%, 45% 30%, 47% 26%, 52% 24%, 52% 19%, 55% 16%, 55% 10%, 52% 8%);\r\n  transform: translate(calc(var(--split-offset) * 1), calc(var(--split-offset) * -1));\r\n}\r\n\r\n.cookie-part-3 {\r\n  clip-path: polygon(0% 60%, 14% 61%, 16% 56%, 20% 56%, 25% 53%, 30% 53%, 34% 50%, 40% 50%, 47% 49%, 51% 47%, 55% 53%, 60% 56%, 56% 62%, 53% 67%, 57% 72%, 57% 81%, 57% 87%, 63% 92%, 60% 100%, 0% 100%);\r\n  transform: translate(calc(var(--split-offset) * -1), calc(var(--split-offset) * 1));\r\n}\r\n\r\n.cookie-part-4 {\r\n  clip-path: polygon(100% 100%, 100% 72%, 88% 68%, 84% 61%, 78% 60%, 77% 56%, 75% 53%, 71% 55%, 66% 50%, 63% 47%, 58% 49%, 56% 44%, 51% 47%, 55% 53%, 60% 56%, 56% 62%, 53% 67%, 57% 72%, 57% 81%, 57% 87%, 63% 92%, 60% 100%);\r\n  transform: translate(calc(var(--split-offset) * 1), calc(var(--split-offset) * 1));\r\n}\r\n\r\n.cookie span[class^=\"chocolate-chips-\"] {\r\n  position: absolute;\r\n  color: #754e27;\r\n  background-color: #865729;\r\n  height: var(--chip-size);\r\n  width: var(--chip-size);\r\n  border-radius: 50%;\r\n  box-shadow: inset -0.35em 0;\r\n}\r\n\r\n.cookie .chocolate-chips-1a {\r\n  top: 41%;\r\n  left: 5%;\r\n}\r\n\r\n.cookie .chocolate-chips-1b {\r\n  top: 20%;\r\n  left: 18%;\r\n}\r\n\r\n.cookie .chocolate-chips-1c {\r\n  top: 35%;\r\n  left: 33%;\r\n}\r\n\r\n.cookie .chocolate-chips-1d {\r\n  top: 6%;\r\n  left: 39%;\r\n}\r\n\r\n.cookie .chocolate-chips-2a {\r\n  --chip-size: calc(var(--cookie-size) / 10);\r\n  top: 24%;\r\n  right: 35%;\r\n}\r\n\r\n.cookie .chocolate-chips-2b {\r\n  top: 36%;\r\n  right: 23%;\r\n}\r\n\r\n.cookie .chocolate-chips-2c {\r\n  top: 7%;\r\n  right: 29%;\r\n}\r\n\r\n.cookie .chocolate-chips-2d {\r\n  top: 42%;\r\n  right: 7%;\r\n}\r\n\r\n.cookie .chocolate-chips-2e {\r\n  top: 19%;\r\n  right: 12%;\r\n}\r\n\r\n.cookie .chocolate-chips-3a {\r\n  --chip-size: calc(var(--cookie-size) / 6);\r\n  bottom: 24%;\r\n  left: 18%;\r\n}\r\n\r\n.cookie .chocolate-chips-3b {\r\n  bottom: 34%;\r\n  left: 42%;\r\n}\r\n\r\n.cookie .chocolate-chips-3c {\r\n  bottom: 9%;\r\n  left: 39%;\r\n}\r\n\r\n.cookie .chocolate-chips-4a {\r\n  bottom: 27%;\r\n  right: 29%;\r\n}\r\n\r\n.cookie .chocolate-chips-4b {\r\n  bottom: 12%;\r\n  right: 23%;\r\n}\r\n\r\n.cookie .chocolate-chips-4c {\r\n  --chip-size: calc(var(--cookie-size) / 12);\r\n  bottom: 28%;\r\n  right: 17%;\r\n}\r\n\r\n.cookie span[class^=\"chocolate-chips-1\"] {\r\n  transform: translate(calc(var(--split-offset) * -1), calc(var(--split-offset) * -1));\r\n}\r\n\r\n.cookie span[class^=\"chocolate-chips-2\"] {\r\n  transform: translate(calc(var(--split-offset) * 1), calc(var(--split-offset) * -1));\r\n}\r\n\r\n.cookie span[class^=\"chocolate-chips-3\"] {\r\n  transform: translate(calc(var(--split-offset) * -1), calc(var(--split-offset) * 1));\r\n}\r\n\r\n.cookie span[class^=\"chocolate-chips-4\"] {\r\n  transform: translate(calc(var(--split-offset) * 1), calc(var(--split-offset) * 1));\r\n}\r\n'),
(20, '\r\n<div class=\"toggle-container\">\r\n  <input class=\"toggle-input\" id=\"toggle\" type=\"checkbox\" />\r\n  <label class=\"toggle-label\" for=\"toggle\">\r\n    <div class=\"face\">\r\n      <div class=\"eye left-eye\"></div>\r\n      <div class=\"toggle-switch\"></div>\r\n      <div class=\"eye right-eye\"></div>\r\n      <div class=\"smile\"></div>\r\n    </div>\r\n  </label>\r\n</div>\r\n', '\r\n.toggle-container {\r\n  position: relative;\r\n  width: 160px;\r\n  height: 80px;\r\n}\r\n\r\n.toggle-input {\r\n  display: none;\r\n}\r\n\r\n.toggle-label {\r\n  position: relative;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  width: 140px;\r\n  height: 60px;\r\n  background: #ff4c4c;\r\n  border-radius: 30px;\r\n  box-shadow: 0 5px #b93737;\r\n  transition: background 0.3s ease-in-out;\r\n  cursor: pointer;\r\n  padding: 0 10px;\r\n}\r\n\r\n.face {\r\n  position: relative;\r\n  width: 100%;\r\n  height: 100%;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  transition: all 0.3s ease-in-out;\r\n}\r\n\r\n.eye {\r\n  position: relative;\r\n  width: 10px;\r\n  height: 10px;\r\n  background: white;\r\n  border-radius: 50%;\r\n  transition: all 0.3s ease-in-out;\r\n}\r\n\r\n.smile {\r\n  position: absolute;\r\n  bottom: 30px;\r\n  left: 50%;\r\n  width: 40px;\r\n  height: 20px;\r\n  border: 2px solid transparent;\r\n  border-radius: 50%;\r\n  transform: translateX(-50%);\r\n  transition: all 0.3s ease-in-out;\r\n}\r\n\r\n.toggle-switch {\r\n  position: relative;\r\n  width: 35px;\r\n  height: 20px;\r\n  background: white;\r\n  border-radius: 10px;\r\n  box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.3);\r\n  margin: 0 10px;\r\n  z-index: 1;\r\n}\r\n\r\n.toggle-switch:before {\r\n  content: \"\";\r\n  position: absolute;\r\n  width: 15px;\r\n  height: 15px;\r\n  background: #ff4c4c;\r\n  border-radius: 50%;\r\n  transition: all 0.3s ease-in-out;\r\n  top: 50%;\r\n  left: 3px;\r\n  transform: translateY(-50%);\r\n}\r\n\r\n.toggle-input:checked + .toggle-label .toggle-switch:before {\r\n  background: #28a745;\r\n  left: 16px;\r\n}\r\n\r\n.toggle-input:checked + .toggle-label .smile {\r\n  border-bottom-color: #fff;\r\n  border-top: none;\r\n  bottom: 10px;\r\n}\r\n\r\n.toggle-input:not(:checked) + .toggle-label .smile {\r\n  border-top-color: #fff;\r\n  border-bottom: none;\r\n  bottom: 0;\r\n}\r\n\r\n.toggle-input:checked + .toggle-label {\r\n  background: #ced10a;\r\n  box-shadow: 0 5px #74c027;\r\n}\r\n\r\n.toggle-input:not(:checked) + .toggle-label {\r\n  background: #252422;\r\n  box-shadow: 0 5px #484d48;\r\n  bottom: 5px;\r\n}\r\n\r\n.toggle-label:hover .eye {\r\n  width: 20px;\r\n  height: 20px;\r\n}\r\n\r\n@keyframes blink {\r\n  0%,\r\n  90%,\r\n  100% {\r\n    height: 10px;\r\n  }\r\n  95% {\r\n    height: 2px;\r\n  }\r\n}\r\n\r\n.left-eye {\r\n  animation: blink 3s infinite;\r\n}\r\n\r\n.right-eye {\r\n  animation: blink 3s infinite;\r\n}\r\n');

