INSERT INTO `user_input` (`ID`, `HTML`, `CSS`, `TYPE`) VALUES
(1, '<!-- From Uiverse.io by satyamchaudharydev --> \r\n<button>\r\n    Sign up\r\n    <div class=\"arrow-wrapper\">\r\n        <div class=\"arrow\"></div>\r\n\r\n    </div>\r\n</button>', '/* From Uiverse.io by satyamchaudharydev */ \r\nbutton {\r\n  --primary-color: #645bff;\r\n  --secondary-color: #fff;\r\n  --hover-color: #111;\r\n  --arrow-width: 10px;\r\n  --arrow-stroke: 2px;\r\n  box-sizing: border-box;\r\n  border: 0;\r\n  border-radius: 20px;\r\n  color: var(--secondary-color);\r\n  padding: 1em 1.8em;\r\n  background: var(--primary-color);\r\n  display: flex;\r\n  transition: 0.2s background;\r\n  align-items: center;\r\n  gap: 0.6em;\r\n  font-weight: bold;\r\n}\r\n\r\nbutton .arrow-wrapper {\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n}\r\n\r\nbutton .arrow {\r\n  margin-top: 1px;\r\n  width: var(--arrow-width);\r\n  background: var(--primary-color);\r\n  height: var(--arrow-stroke);\r\n  position: relative;\r\n  transition: 0.2s;\r\n}\r\n\r\nbutton .arrow::before {\r\n  content: \"\";\r\n  box-sizing: border-box;\r\n  position: absolute;\r\n  border: solid var(--secondary-color);\r\n  border-width: 0 var(--arrow-stroke) var(--arrow-stroke) 0;\r\n  display: inline-block;\r\n  top: -3px;\r\n  right: 3px;\r\n  transition: 0.2s;\r\n  padding: 3px;\r\n  transform: rotate(-45deg);\r\n}\r\n\r\nbutton:hover {\r\n  background-color: var(--hover-color);\r\n}\r\n\r\nbutton:hover .arrow {\r\n  background: var(--secondary-color);\r\n}\r\n\r\nbutton:hover .arrow:before {\r\n  right: 0;\r\n}', 'BUTTONS'),
(2, '<!-- From Uiverse.io by MikeAndrewDesigner --> \r\n<label class=\"container\">\r\n  <input checked=\"checked\" type=\"checkbox\">\r\n  <div class=\"checkmark\"></div>\r\n</label>', '/* From Uiverse.io by MikeAndrewDesigner */ \r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n.container {\r\n  display: block;\r\n  position: relative;\r\n  cursor: pointer;\r\n  font-size: 30px;\r\n  user-select: none;\r\n}\r\n\r\n.checkmark {\r\n  position: relative;\r\n  top: 0;\r\n  left: 0;\r\n  height: 1.6em;\r\n  width: 1.6em;\r\n  border-radius: 50%;\r\n  background: #ffeded38;\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.checkmark {\r\n  opacity: 0.4;\r\n}\r\n\r\n.container input:checked ~ .checkmark {\r\n  background: linear-gradient(144deg,#af40ff,#5b42f3 50%,#00ddeb);\r\n  opacity: 0.9;\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.checkmark:after {\r\n  content: \"\";\r\n  position: absolute;\r\n  display: none;\r\n}\r\n\r\n.container input:checked ~ .checkmark:after {\r\n  display: block;\r\n}\r\n\r\n.container .checkmark:after {\r\n  left: 0.61em;\r\n  top: 0.43em;\r\n  width: 0.25em;\r\n  height: 0.5em;\r\n  border: solid rgb(255, 255, 255);\r\n  border-width: 0 0.15em 0.15em 0;\r\n  transform: rotate(45deg);\r\n}', 'CHECKBOXES'),
(3, '<!-- From Uiverse.io by MikeAndrewDesigner --> \r\n<label class=\"container\">\r\n  <input checked=\"checked\" type=\"checkbox\">\r\n  <div class=\"checkmark\"></div>\r\n</label>', '/* From Uiverse.io by MikeAndrewDesigner */ \r\n.container input {\r\n  position: absolute;\r\n  opacity: 0;\r\n  cursor: pointer;\r\n  height: 0;\r\n  width: 0;\r\n}\r\n\r\n.container {\r\n  display: block;\r\n  position: relative;\r\n  cursor: pointer;\r\n  font-size: 30px;\r\n  user-select: none;\r\n}\r\n\r\n.checkmark {\r\n  position: relative;\r\n  top: 0;\r\n  left: 0;\r\n  height: 1.6em;\r\n  width: 1.6em;\r\n  border-radius: 50%;\r\n  background: #ffeded38;\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.checkmark {\r\n  opacity: 0.4;\r\n}\r\n\r\n.container input:checked ~ .checkmark {\r\n  background: linear-gradient(144deg,#af40ff,#5b42f3 50%,#00ddeb);\r\n  opacity: 0.9;\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.checkmark:after {\r\n  content: \"\";\r\n  position: absolute;\r\n  display: none;\r\n}\r\n\r\n.container input:checked ~ .checkmark:after {\r\n  display: block;\r\n}\r\n\r\n.container .checkmark:after {\r\n  left: 0.61em;\r\n  top: 0.43em;\r\n  width: 0.25em;\r\n  height: 0.5em;\r\n  border: solid rgb(255, 255, 255);\r\n  border-width: 0 0.15em 0.15em 0;\r\n  transform: rotate(45deg);\r\n}', 'CHECKBOXES'),
(4, '<!-- From Uiverse.io by suleymanlaarabidev --> \r\n<div class=\"card\">\r\n  <div class=\"first-content\">\r\n    <span>First</span>\r\n  </div>\r\n  <div class=\"second-content\">\r\n<span>Second</span>\r\n  </div>\r\n\r\n\r\n</div>', '/* From Uiverse.io by suleymanlaarabidev */ \r\n.card {\r\n  width: 190px;\r\n  height: 254px;\r\n  background: rgb(103, 225, 255);\r\n  transition: all 0.4s;\r\n  border-radius: 10px;\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  font-size: 30px;\r\n  font-weight: 900;\r\n}\r\n\r\n.card:hover {\r\n  border-radius: 15px;\r\n  cursor: pointer;\r\n  transform: scale(1.2);\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  background: rgb(103, 151, 255);\r\n}\r\n\r\n.first-content {\r\n  height: 100%;\r\n  width: 100%;\r\n  transition: all 0.4s;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  opacity: 1;\r\n  border-radius: 15px;\r\n}\r\n\r\n.card:hover .first-content {\r\n  height: 0px;\r\n  opacity: 0;\r\n}\r\n\r\n.second-content {\r\n  height: 0%;\r\n  width: 100%;\r\n  opacity: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  border-radius: 15px;\r\n  transition: all 0.4s;\r\n  font-size: 0px;\r\n  transform: rotate(90deg) scale(-1);\r\n}\r\n\r\n.card:hover .second-content {\r\n  opacity: 1;\r\n  height: 100%;\r\n  font-size: 1.8rem;\r\n  transform: rotate(0deg);\r\n}\r\n', 'CARDS'),
(5, '<!-- From Uiverse.io by suleymanlaarabidev --> \r\n<div class=\"card\">\r\n  <div class=\"first-content\">\r\n    <span>First</span>\r\n  </div>\r\n  <div class=\"second-content\">\r\n<span>Second</span>\r\n  </div>\r\n\r\n\r\n</div>', '/* From Uiverse.io by suleymanlaarabidev */ \r\n.card {\r\n  width: 190px;\r\n  height: 254px;\r\n  background: rgb(103, 225, 255);\r\n  transition: all 0.4s;\r\n  border-radius: 10px;\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  font-size: 30px;\r\n  font-weight: 900;\r\n}\r\n\r\n.card:hover {\r\n  border-radius: 15px;\r\n  cursor: pointer;\r\n  transform: scale(1.2);\r\n  box-shadow: 0px 0px 10px 5px  rgba(0, 0, 0, 0.705);\r\n  background: rgb(103, 151, 255);\r\n}\r\n\r\n.first-content {\r\n  height: 100%;\r\n  width: 100%;\r\n  transition: all 0.4s;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  opacity: 1;\r\n  border-radius: 15px;\r\n}\r\n\r\n.card:hover .first-content {\r\n  height: 0px;\r\n  opacity: 0;\r\n}\r\n\r\n.second-content {\r\n  height: 0%;\r\n  width: 100%;\r\n  opacity: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  border-radius: 15px;\r\n  transition: all 0.4s;\r\n  font-size: 0px;\r\n  transform: rotate(90deg) scale(-1);\r\n}\r\n\r\n.card:hover .second-content {\r\n  opacity: 1;\r\n  height: 100%;\r\n  font-size: 1.8rem;\r\n  transform: rotate(0deg);\r\n}\r\n', 'CARDS'),
(6, '<!-- From Uiverse.io by Z4drus --> \r\n<div class=\"loader\">\r\n  <div class=\"loader__inner\"></div>\r\n  <div class=\"loader__orbit\">\r\n    <div class=\"loader__dot\"></div>\r\n    <div class=\"loader__dot\"></div>\r\n    <div class=\"loader__dot\"></div>\r\n    <div class=\"loader__dot\"></div>\r\n  </div>\r\n</div>\r\n', '/* From Uiverse.io by Z4drus */ \r\n.loader {\r\n  position: relative;\r\n  width: 200px;\r\n  height: 200px;\r\n  border-radius: 50%;\r\n  /* smooth background */\r\n  background: radial-gradient(\r\n    circle,\r\n    rgba(255, 255, 255, 0.05) 30%,\r\n    transparent 70%\r\n  );\r\n  overflow: hidden;\r\n}\r\n\r\n/* outside circle */\r\n.loader::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  inset: 0;\r\n  border-radius: 50%;\r\n  border: 4px solid transparent;\r\n  border-top-color: rgba(255, 255, 255, 0.6);\r\n  animation: loader-spin 2s linear infinite;\r\n}\r\n\r\n/* rotating circle */\r\n.loader::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  inset: 10%;\r\n  border-radius: 50%;\r\n  background: conic-gradient(from 90deg, rgba(255, 255, 255, 0.2), transparent);\r\n  filter: blur(2px);\r\n  animation: loader-spin-reverse 1.5s linear infinite;\r\n}\r\n\r\n/* center circle */\r\n.loader__inner {\r\n  position: absolute;\r\n  top: 50%;\r\n  left: 50%;\r\n  width: 30px;\r\n  height: 30px;\r\n  background: rgba(255, 255, 255, 0.9);\r\n  border-radius: 50%;\r\n  transform: translate(-50%, -50%);\r\n  box-shadow: 0 0 15px rgba(255, 255, 255, 0.6);\r\n  animation: loader-pulse 1s ease-in-out infinite;\r\n}\r\n\r\n/* Container */\r\n.loader__orbit {\r\n  position: absolute;\r\n  top: 0;\r\n  left: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  animation: orbit-rotate 3s linear infinite;\r\n}\r\n\r\n/* dots */\r\n.loader__dot {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 50%;\r\n  width: 8px;\r\n  height: 8px;\r\n  background: rgba(255, 255, 255, 0.8);\r\n  border-radius: 50%;\r\n}\r\n\r\n/* 4 dots */\r\n.loader__dot:nth-child(1) {\r\n  transform: rotate(0deg) translate(60px);\r\n}\r\n.loader__dot:nth-child(2) {\r\n  transform: rotate(90deg) translate(60px);\r\n}\r\n.loader__dot:nth-child(3) {\r\n  transform: rotate(180deg) translate(60px);\r\n}\r\n.loader__dot:nth-child(4) {\r\n  transform: rotate(270deg) translate(60px);\r\n}\r\n\r\n/* Animations */\r\n\r\n@keyframes loader-spin {\r\n  0% {\r\n    transform: rotate(0deg);\r\n  }\r\n  100% {\r\n    transform: rotate(360deg);\r\n  }\r\n}\r\n\r\n@keyframes loader-spin-reverse {\r\n  0% {\r\n    transform: rotate(0deg);\r\n  }\r\n  100% {\r\n    transform: rotate(-360deg);\r\n  }\r\n}\r\n\r\n@keyframes loader-pulse {\r\n  0%,\r\n  100% {\r\n    transform: translate(-50%, -50%) scale(1);\r\n  }\r\n  50% {\r\n    transform: translate(-50%, -50%) scale(1.2);\r\n  }\r\n}\r\n\r\n@keyframes orbit-rotate {\r\n  0% {\r\n    transform: rotate(0deg);\r\n  }\r\n  100% {\r\n    transform: rotate(360deg);\r\n  }\r\n}\r\n', 'LOADERS'),
